function rng(n,s=0){return((Math.sin(n*127.1+s*311.7+19.3)*43758.5453)%1+1)%1;}
function seedOf(id){return id.split("").reduce((a,c)=>a+c.charCodeAt(0),0);}
function Sprig({seed:s=0,color:c=T.lichen,w=160,h=110}){const e=[];for(let i=0;i<5;i++){let x=rng(i,s)*w*0.6+w*0.1,y=rng(i+10,s)*h*0.6+h*0.2,d=`M${x},${y}`;for(let k=0;k<4;k++){const dx=(rng(i*8+k,s)-0.3)*55,dy=(rng(i*8+k+1,s)-0.35)*40;const cx=x+dx*0.5+(rng(i*8+k+2,s)-0.5)*16,cy=y+dy*0.5+(rng(i*8+k+3,s)-0.5)*16;x+=dx;y+=dy;d+=` Q${cx},${cy} ${x},${y}`;}e.push(<path key={i} d={d} fill="none" stroke={c} strokeWidth={rng(i+30,s)*1.6+0.3} opacity={rng(i+40,s)*0.45+0.12} strokeLinecap="round"/>);}for(let i=0;i<18;i++){const a=rng(i,s)*Math.PI*2,r=Math.sqrt(rng(i+50,s))*(Math.min(w,h)/2-4);e.push(<circle key={`d${i}`} cx={w/2+r*Math.cos(a)} cy={h/2+r*Math.sin(a)} r={rng(i+100,s)*2.4+0.3} fill={c} opacity={rng(i+150,s)*0.5+0.08}/>);}return <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{overflow:"visible"}}>{e}</svg>;}
function Rings({seed:s=0,color:c=T.stone,size=90}){const e=[];for(let r=0;r<4;r++){const rad=(r+1)*size/5.5+rng(r,s)*size*0.07,pts=[];for(let a=0;a<14;a++){const ang=(a/14)*Math.PI*2,j=(rng(r*20+a,s)-0.5)*size*0.05;pts.push([size/2+(rad+j)*Math.cos(ang),size/2+(rad+j)*Math.sin(ang)]);}e.push(<path key={r} d={"M"+pts.map(p=>p.join(",")).join("L")+"Z"} fill="none" stroke={c} strokeWidth={0.9} opacity={0.1+r*0.03}/>);}for(let i=0;i<22;i++){const a=rng(i,s)*Math.PI*2,r=Math.sqrt(rng(i+50,s))*(size/2-3);e.push(<circle key={`d${i}`} cx={size/2+r*Math.cos(a)} cy={size/2+r*Math.sin(a)} r={rng(i+100,s)*2+0.3} fill={c} opacity={rng(i+150,s)*0.45+0.07}/>);}return <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{overflow:"visible"}}>{e}</svg>;}
function Spores({seed:s=0,color:c=T.spore,size=80}){const e=[];for(let i=0;i<45;i++){const a=rng(i,s)*Math.PI*2,r=Math.sqrt(rng(i+100,s))*(size/2-4);e.push(<circle key={i} cx={size/2+r*Math.cos(a)} cy={size/2+r*Math.sin(a)} r={rng(i+200,s)*2.8+0.4} fill={c} opacity={rng(i+300,s)*0.65+0.15}/>);}for(let i=0;i<10;i++){const a=rng(i+50,s)*Math.PI*2,r1=rng(i+150,s)*(size/2-8),r2=r1+rng(i+250,s)*18+4,a2=a+rng(i+350,s)*0.5-0.25;e.push(<line key={`l${i}`} x1={size/2+r1*Math.cos(a)} y1={size/2+r1*Math.sin(a)} x2={size/2+r2*Math.cos(a2)} y2={size/2+r2*Math.sin(a2)} stroke={c} strokeWidth={0.6} opacity={0.25}/>);}return <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{overflow:"visible"}}><circle cx={size/2} cy={size/2} r={size/2-1} fill="none" stroke={c} strokeWidth={0.5} opacity={0.2}/>{e}</svg>;}
function Scratches({seed:s=0,color:c=T.ochre,w=100,h=70}){const e=[];for(let i=0;i<10;i++){const x=rng(i,s)*w*0.85+w*0.05,y=rng(i+10,s)*h*0.85+h*0.05,len=rng(i+20,s)*w*0.2+w*0.03,ang=rng(i+30,s)*Math.PI;e.push(<line key={i} x1={x} y1={y} x2={x+len*Math.cos(ang)} y2={y+len*Math.sin(ang)} stroke={c} strokeWidth={rng(i+40,s)*1.8+0.4} opacity={rng(i+50,s)*0.38+0.07} strokeLinecap="round"/>);}return <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{overflow:"visible"}}>{e}</svg>;}
function TMarks({seed:s=0,color:c=T.terra,w=100,h=70}){const e=[];for(let i=0;i<7;i++){const x0=rng(i,s)*w*0.7+w*0.1,y0=rng(i+5,s)*h*0.7+h*0.1;let d=`M${x0},${y0}`,x=x0,y=y0;for(let k=0;k<3;k++){const dx=(rng(i*6+k,s)-0.4)*w*0.22,dy=(rng(i*6+k+1,s)-0.4)*h*0.22;x+=dx;y+=dy;d+=` L${x},${y}`;}e.push(<path key={i} d={d} fill="none" stroke={c} strokeWidth={rng(i+20,s)*2+0.5} opacity={rng(i+30,s)*0.5+0.1} strokeLinecap="round" strokeLinejoin="round"/>);}for(let i=0;i<5;i++){const x=rng(i+40,s)*w*0.85+w*0.07,y=rng(i+45,s)*h*0.85+h*0.07,r=rng(i+50,s)*5+1;e.push(<circle key={`c${i}`} cx={x} cy={y} r={r} fill={c} opacity={rng(i+60,s)*0.3+0.05}/>);}return <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{overflow:"visible"}}>{e}</svg>;}
function Leaves({seed:s=0,color:c=T.forest,w=100,h=70}){const e=[];for(let i=0;i<12;i++){const cx=rng(i,s)*w*0.8+w*0.1,cy=rng(i+5,s)*h*0.8+h*0.1,rx=rng(i+10,s)*12+4,ry=rng(i+15,s)*7+2,ang=rng(i+20,s)*Math.PI;e.push(<ellipse key={i} cx={cx} cy={cy} rx={rx} ry={ry} transform={`rotate(${ang*57},${cx},${cy})`} fill={c} opacity={rng(i+25,s)*0.3+0.08}/>);}for(let i=0;i<8;i++){const x0=rng(i+30,s)*w*0.8+w*0.1,y0=rng(i+35,s)*h*0.8+h*0.1;e.push(<line key={`l${i}`} x1={x0} y1={y0} x2={x0+(rng(i+40,s)-0.5)*25} y2={y0+(rng(i+45,s)-0.5)*18} stroke={c} strokeWidth={0.7} opacity={0.3} strokeLinecap="round"/>);}return <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{overflow:"visible"}}>{e}</svg>;}
function Paths({seed:s=0,color:c=T.sky,w=100,h=70}){const e=[];for(let i=0;i<4;i++){let x=rng(i,s)*w*0.3,y=rng(i+5,s)*h,d=`M${x},${y}`;for(let k=0;k<5;k++){x+=rng(i*8+k,s)*w*0.18+w*0.04;y+=(rng(i*8+k+1,s)-0.5)*h*0.3;d+=` Q${x+(rng(i*8+k+2,s)-0.5)*20},${y+(rng(i*8+k+3,s)-0.5)*15} ${x},${y}`;}e.push(<path key={i} d={d} fill="none" stroke={c} strokeWidth={rng(i+20,s)*3+1} opacity={rng(i+25,s)*0.35+0.1} strokeLinecap="round"/>);}return <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{overflow:"visible"}}>{e}</svg>;}

