function SapLeaf({seed:s=0,color:c=T.sapLight,w=100,h=70}){
  const e=[];
  for(let i=0;i<6;i++){const cx=rng(i,s)*w*0.7+w*0.15,cy=rng(i+5,s)*h*0.7+h*0.15,rx=rng(i+10,s)*18+6,ry=rng(i+15,s)*10+3,ang=rng(i+20,s)*Math.PI;e.push(<ellipse key={i} cx={cx} cy={cy} rx={rx} ry={ry} transform={`rotate(${ang*57.3},${cx},${cy})`} fill={c} opacity={rng(i+25,s)*0.28+0.08}/>);}
  for(let i=0;i<5;i++){const x0=rng(i+30,s)*w*0.6+w*0.2,y0=rng(i+35,s)*h*0.6+h*0.2;let d=`M${x0},${y0}`,x=x0,y=y0;for(let k=0;k<3;k++){x+=(rng(i*6+k,s)-0.4)*w*0.18;y+=(rng(i*6+k+1,s)-0.5)*h*0.22;d+=` L${x},${y}`;}e.push(<path key={`l${i}`} d={d} fill="none" stroke={c} strokeWidth={rng(i+40,s)*1.5+0.5} opacity={0.35} strokeLinecap="round"/>);}
  return <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{overflow:"visible"}}>{e}</svg>;
}
