function getTypeMeta(card){return card.deck==="choreo"?CT:card.deck==="milieux"?MT:card.deck==="terrains"?TT:card.deck==="vivant"?VT:card.deck==="traversees"?ST:card.deck==="corps_monde"?CMT:card.deck==="contaminations"?COT:card.deck==="natures_sociales"?NST:card.deck==="mythologies"?MYT:XT;}
function getTheme(deck){return deck==="choreo"?T.spore:deck==="milieux"?T.lichen:deck==="terrains"?T.terra:deck==="vivant"?T.forestLight:deck==="traversees"?T.sapLight:deck==="territoires"?T.water:deck==="corps_monde"?"#6a3a1a":deck==="contaminations"?"#8a2a1a":deck==="natures_sociales"?"#3a4a5a":deck==="mythologies"?"#5a3a6a":T.water;}
function isDarkDeck(deck){return deck==="choreo";}


const _D = JSON.parse(`{"mc":[{"id":"m-trajeter","deck":"milieux","type":"seuil","fr":{"title":"Trajeter","entry":"Sens l'endroit exact où tu te trouves. Pas le lieu en général — ce point précis, maintenant.","body":["Remarque comment cet endroit est déjà en toi — dans la température de ta peau, dans la direction de ton regard, dans ce que tu évites de regarder.","Tu ne perçois pas le milieu. Tu es le milieu en train de se percevoir.","Laisse cette idée traverser ton corps. Sens ce qui change dans ta posture, ta respiration, ton appui.","Commence à te mouvoir — très lentement. Observe comment chaque déplacement transforme à la fois toi et le lieu.","Trajection : ni toi ni le lieu ne restez les mêmes."],"retour":"Qu'est-ce que le lieu t'a fait ? Qu'est-ce que tu lui as fait ?","sources":["Augustin Berque, géographe et mésologiste — Écoumène (2000) — ce qui nous entoure, c'est ce que nous sommes »","Tim Ingold, anthropologue britannique — The Perception of the Environment (2000) — qui grandit dans un milieu, pas sur lui"]},"en":{"title":"Trajecting","entry":"Feel the exact place where you are. Not the place in general — this precise point, now.","body":["Notice how this place is already in you — in the temperature of your skin, in the direction of your gaze, in what you avoid looking at.","You don't perceive the milieu. You are the milieu perceiving itself.","Let this idea pass through your body. Feel what changes in your posture, your breath, your weight.","Begin to move — very slowly. Observe how each displacement transforms both you and the place.","Trajection: neither you nor the place remain the same."],"retour":"What did the place do to you? What did you do to it?","sources":["Berque : « le milieu n'est pas ce qui nous entoure, c'est ce que nous sommes »","Ingold : la perception comme compétence qui grandit dans un milieu, pas sur lui"]}},{"id":"m-remarquer","deck":"milieux","type":"seuil","fr":{"title":"Remarquer","entry":"Arrête-toi. Quelque chose dans cet espace existait avant que tu arrives.","body":["Cherche ce qui n'était pas là pour toi — une ligne sur un mur, un son que tu filtrais, une odeur déjà présente.","Remarquer n'est pas observer. Remarquer, c'est laisser quelque chose arriver jusqu'à toi.","Reste avec ce que tu as remarqué. Résiste à l'envie de le nommer immédiatement.","Laisse ton corps répondre à cette présence avant que ta tête ne l'explique.","Qu'est-ce que cela change dans la façon dont tu occupes l'espace ?"],"retour":"Qu'est-ce qui était là et que tu n'avais pas vu ? Qu'est-ce que ça fait de l'avoir vu ?","sources":["Tsing : « les arts du remarquer — apprendre à percevoir les temporalités multiples du vivant »","Lévi-Strauss : le bricoleur lit l'environnement comme système de signes"]},"en":{"title":"Noticing","entry":"Stop. Something in this space existed before you arrived.","body":["Look for what wasn't there for you — a line on a wall, a sound you were filtering, a smell already present.","Noticing is not observing. Noticing is letting something arrive all the way to you.","Stay with what you noticed. Resist the urge to name it immediately.","Let your body respond to this presence before your head explains it.","What does this change in how you occupy the space?"],"retour":"What was there that you hadn't seen? What does it feel like to have seen it?","sources":["Tsing : « les arts du remarquer — apprendre à percevoir les temporalités multiples du vivant »","Lévi-Strauss : le bricoleur lit l'environnement comme système de signes"]}},{"id":"m-dependre","deck":"milieux","type":"seuil","fr":{"title":"Dépendre","entry":"Pose tes deux pieds à plat sur le sol. Sens le poids de ton corps qui descend.","body":["Ce sol est fait de roches, de racines, de champignons, de bactéries, d'eau, de morts.","Tu dépends de tout cela pour être debout ici maintenant.","Sens cette dépendance non pas comme une faiblesse mais comme une appartenance.","Élargis lentement la conscience de ce dont tu dépends : l'air, la lumière, les autres corps dans l'espace.","La dépendance n'est pas une dette. C'est la texture de l'existence.","Laisse ce sentiment descendre dans tes jambes, dans tes pieds, dans tes os."],"retour":"De quoi dépends-tu que tu ne vois pas d'habitude ? Comment ça se sent dans le corps ?","sources":["Bruno Latour, philosophe et sociologue des sciences — Où atterrir ? (2017) — cette fine pellicule entre roche et atmosphère où tout se négocie","Naess : l'identification — « l'intérêt d'un autre être ressenti comme notre propre intérêt »"]},"en":{"title":"Depending","entry":"Place both feet flat on the ground. Feel the weight of your body descending.","body":["This ground is made of rocks, roots, fungi, bacteria, water, the dead.","You depend on all of this to be standing here now.","Feel this dependency not as weakness but as belonging.","Slowly expand awareness of what you depend on: air, light, other bodies.","Dependency is not a debt. It is the texture of existence.","Let this feeling descend into your legs, your feet, your bones."],"retour":"What do you depend on that you don't usually see? How does it feel in the body?","sources":["Latour : la zone critique — cette fine pellicule entre roche et atmosphère où tout se négocie","Naess : l'identification — « l'intérêt d'un autre être ressenti comme notre propre intérêt »"]}},{"id":"m-resonner","deck":"milieux","type":"seuil","fr":{"title":"Résonner","entry":"Cherche quelque chose dans cet espace qui t'appelle — pas ce que tu choisis, mais ce qui te choisit.","body":["La résonance ne se commande pas. Elle arrive ou n'arrive pas.","Approche-toi de ce qui t'a appelé. Reste à distance d'abord.","Observe ce qui se passe dans ton corps avant tout contact.","Laisse-toi transformer par cette présence — même légèrement.","La résonance transforme les deux termes de la relation. Tu changes. Quelque chose d'autre change.","Si rien ne t'appelle, reste avec cette absence. L'aliénation est aussi une expérience réelle."],"retour":"Qu'est-ce qui a résonné ? Qu'est-ce qui est resté muet ?","sources":["Rosa : la résonance comme événement relationnel non maîtrisable qui transforme les deux termes","Rosa : l'aliénation — l'absence de réponse est une expérience réelle, pas un échec"],"steps":["Approche-toi lentement. Arrête-toi à une distance qui te semble juste. Sens pourquoi tu t'es arrêté·e là.","Maintenant : fais un geste vers cet être ou objet — pas pour le toucher, pour lui répondre. Un geste qui dit 'je t'entends'.","La résonance transforme les deux termes de la relation. Tu changes. Quelque chose d'autre aussi, peut-être.","Si rien ne t'appelle : reste avec cette absence. L'aliénation est aussi une donnée sur ton rapport au monde aujourd'hui."]},"en":{"title":"Resonating","entry":"Look for something in this space that calls you — not what you choose, but what chooses you.","body":["Resonance cannot be commanded. It arrives or it doesn't.","Approach what called you. Stay at a distance first.","Observe what happens in your body before any contact.","Let yourself be transformed by this presence — even slightly.","Resonance transforms both terms of the relation. You change. Something else changes.","If nothing calls you, stay with this absence. Alienation is also a real experience."],"retour":"What resonated? What remained mute?","sources":["Rosa : la résonance comme événement relationnel non maîtrisable qui transforme les deux termes","Rosa : l'aliénation — l'absence de réponse est une expérience réelle, pas un échec"],"steps":["Approach slowly. Stop at a distance that feels right. Feel why you stopped there.","Now: make a gesture toward this being or object — not to touch it, to respond to it. A gesture that says 'I hear you'.","Resonance transforms both terms of the relation. You change. Something else does too, perhaps.","If nothing calls to you: stay with this absence. Alienation is also data about your relationship to the world today."]}},{"id":"m-suivre","deck":"milieux","type":"seuil","fr":{"title":"Suivre","entry":"Choisis une ligne dans l'espace — une fissure, un bord, une ombre, le tracé d'un mur.","body":["Suis cette ligne avec ton regard d'abord. Sans te presser.","Puis laisse ton corps suivre — pas en marchant dessus, mais en suivant son rythme, son intention.","La ligne a une vie. Elle hésite, s'interrompt, reprend, diverge.","Suivre n'est pas obéir. C'est s'accorder à un mouvement qui était déjà là.","À quel moment ta ligne devient-elle tienne ? À quel moment es-tu encore celle de l'espace ?"],"retour":"Où t'a emmenée cette ligne ? Qu'as-tu abandonné pour la suivre ?","sources":["Tim Ingold, anthropologue britannique — Lines (2007) — la ligne comme mode d'être-dans-le-monde, wayfaring plutôt que transport","François Jullien, philosophe sinologue français — Traité de l'efficacité (1996) — avancer par détour plutôt que vers un but"]},"en":{"title":"Following","entry":"Choose a line in the space — a crack, an edge, a shadow, the trace of a wall.","body":["Follow this line with your gaze first. Without hurrying.","Then let your body follow — not walking on it, but following its rhythm, its intention.","The line has a life. It hesitates, breaks off, resumes, diverges.","Following is not obeying. It is attuning to a movement that was already there.","At what point does the line become yours?"],"retour":"Where did this line take you? What did you abandon to follow it?","sources":["Ingold : « Lines » — la ligne comme mode d'être-dans-le-monde, wayfaring plutôt que transport","Jullien : le biais, l'oblique — avancer par détour plutôt que vers un but"]}},{"id":"m-cheminer","deck":"milieux","type":"seuil","fr":{"title":"Cheminer","entry":"Mets-toi en mouvement — sans destination. Pas un trajet. Un cheminement.","body":["Le wayfaring n'est pas un déplacement d'un point A à un point B. C'est habiter le chemin lui-même.","Laisse chaque pas décider du suivant. Pas de plan. Juste l'attention à ce qui est là.","Remarque comment le paysage change selon que tu te déplaces ou que tu chemines.","Dans le cheminement, tu ne traverses pas l'espace. Tu le tisses.","Continue jusqu'à ce que le cheminement te ramène à toi-même."],"retour":"Qu'as-tu tissé en cheminant ? Qu'as-tu laissé derrière toi ?","sources":["Tim Ingold, anthropologue britannique — Being Alive (2011) — habiter le chemin plutôt que se déplacer d'un point à un autre","Tim Ingold, anthropologue britannique — Making (2013), pas en le regardant de loin »"]},"en":{"title":"Wayfaring","entry":"Set yourself in motion — without destination. Not a journey. A wayfaring.","body":["Wayfaring is not displacement from A to B. It is inhabiting the path itself.","Let each step decide the next. No plan. Just attention to what is there.","Notice how the landscape changes depending on whether you travel or wayfare.","In wayfaring, you don't cross space. You weave it.","Continue until the wayfaring brings you back to yourself."],"retour":"What did you weave while wayfaring? What did you leave behind?","sources":["Ingold : le wayfaring — habiter le chemin plutôt que se déplacer d'un point à un autre","Ingold : « le monde se fait en marchant, pas en le regardant de loin »"]}},{"id":"m-bricoler","deck":"milieux","type":"seuil","fr":{"title":"Bricoler","entry":"Regarde ce qui est là. Pas ce que tu aurais voulu avoir — ce qui est là.","body":["Un objet, un son, une lumière, un coin d'espace. Quelque chose que tu n'as pas choisi.","Le bricoleur part toujours de ce qui est là. Il n'a pas de plan. Il a du matériau.","Laisse ce matériau te parler. Qu'est-ce qu'il peut faire ? Qu'est-ce qu'il veut ?","Construis quelque chose avec lui — un geste, une posture, une relation dans l'espace.","Pas de finalité préalable. La forme émerge du dialogue avec le matériau."],"retour":"Qu'est-ce que le matériau t'a enseigné que tu n'aurais pas découvert autrement ?","sources":["Lévi-Strauss : « La pensée sauvage » — le bricoleur construit avec les moyens du bord","John Dewey, philosophe pragmatiste américain — Logique : la théorie de l'enquête (1938) — la résistance du milieu comme condition de l'apprentissage"],"steps":["Regarde ce qui est là — un objet, une branche, une pierre, un coin d'ombre, un son. Quelque chose que tu n'as pas choisi.","Prends-le. Tiens-le. Retourne-le. Pose-le ailleurs. Observe comment l'espace change quand tu le déplaces.","Le bricoleur part de ce qui est là. Pas de plan. Le matériau lui parle — par sa résistance, son poids, sa forme.","Construis quelque chose avec ce que tu as — un geste, une position dans l'espace, une relation entre deux objets. Pas pour que ce soit beau. Pour que ce soit juste."]},"en":{"title":"Bricolage","entry":"Look around you. What is already here that could become something else?","body":["The bricoleur doesn't start from a plan. They start from what is available.","Take something at hand — an object, a gesture, a memory.","Use it for something it wasn't meant for.","Bricolage is not improvisation. It is a reading of the environment as a system of resources.","What does this environment offer that you haven't yet used?"],"retour":"What did you make with what was already here? What did the material ask of you?","sources":["Lévi-Strauss : « La pensée sauvage » — le bricoleur construit avec les moyens du bord","Dewey : l'enquête — la résistance du milieu comme condition de l'apprentissage"],"steps":["Look at what is there — an object, a branch, a stone, a corner of shadow, a sound. Something you didn't choose.","Pick it up. Hold it. Turn it over. Put it somewhere else. Notice how the space changes when you move it.","The bricoleur starts from what is there. No plan. The material speaks — through its resistance, its weight, its form.","Build something with what you have — a gesture, a position in the space, a relation between two objects. Not for beauty. For rightness."]}},{"id":"m-habiter","deck":"milieux","type":"seuil","fr":{"title":"Habiter","entry":"Tu n'es pas dans cet espace. Tu l'habites — ou tu peux commencer à l'habiter.","body":["Quelle est la différence entre être dans un lieu et l'habiter ?","Commence à faire des gestes d'habitation — non pas de décoration, mais d'attention.","Touche une surface. Écoute un coin. Sens une limite.","L'habitation est un soin continu. Elle prend du temps.","Sens comment le lieu commence à te reconnaître. Ou à t'ignorer. Les deux sont des données."],"retour":"Qu'est-ce que ce lieu demande de toi pour être habité ?","sources":["Augustin Berque, géographe et mésologiste — Poétique de la Terre (2014) — une fonction essentielle à ce qui tisse le monde »","Tim Ingold, anthropologue britannique — The Perception of the Environment (2000) — s'engager activement dans les constituants de l'environnement"]},"en":{"title":"Dwelling","entry":"You are not in this space. You dwell in it — or you can begin to dwell in it.","body":["What is the difference between being in a place and dwelling in it?","Begin making gestures of dwelling — not decoration, but attention.","Touch a surface. Listen to a corner. Feel a boundary.","Dwelling is continuous care. It takes time.","Feel how the place begins to recognise you. Or to ignore you. Both are data."],"retour":"What does this place ask of you in order to be dwelt in?","sources":["Berque : « habiter comporte une fonction essentielle à ce qui tisse le monde »","Ingold : le dwelling — s'engager activement dans les constituants de l'environnement"]}},{"id":"m-rater","deck":"milieux","type":"seuil","fr":{"title":"Rater","entry":"Tente quelque chose. N'importe quoi. Un geste, une direction, un contact.","body":["Observe ce qui ne fonctionne pas comme prévu.","Le ratage n'est pas un accident. C'est une information du milieu.","Reste avec le raté. Ne le corriges pas immédiatement.","Qu'est-ce que le milieu te dit par ce qui résiste ?","La résistance est la condition de l'expérience. Sans résistance, pas d'apprentissage.","Recommence. Différemment, pas mieux."],"retour":"Qu'est-ce que le ratage t'a appris que le succès n'aurait pas pu t'apprendre ?","sources":["John Dewey, philosophe pragmatiste américain — Experience and Nature (1925) — négociation continue entre organisme et milieu","Tsing : la précaution — apprendre à avancer dans ce qu'on ne maîtrise pas"]},"en":{"title":"Failing","entry":"Try something. Anything. A gesture, a direction, a contact.","body":["Observe what doesn't work as expected.","Failure is not an accident. It is information from the milieu.","Stay with the failure. Don't correct it immediately.","What is the milieu telling you through what resists?","Resistance is the condition of experience. Without resistance, no learning.","Try again. Differently, not better."],"retour":"What did failure teach you that success couldn't have?","sources":["Dewey : la transaction — négociation continue entre organisme et milieu","Tsing : la précaution — apprendre à avancer dans ce qu'on ne maîtrise pas"]}},{"id":"m-ralentir","deck":"milieux","type":"seuil","fr":{"title":"Ralentir","entry":"Va deux fois plus lentement que tu ne le ferais naturellement.","body":["Puis encore deux fois plus lentement.","Observe ce qui apparaît dans ce ralentissement — des textures, des hésitations, des micro-décisions.","Le monde vivant a des temporalités que la vitesse humaine normale ne perçoit pas.","Un champignon, une racine, un lichen — ils vivent à d'autres vitesses.","Sens ton corps ajuster sa perception à un rythme qui n'est pas le tien.","Qu'est-ce qui existait là et que tu ne voyais pas parce que tu allais trop vite ?"],"retour":"Qu'est-ce que le ralentissement a révélé ?","sources":["Tsing : sans le rythme du progrès, on peut remarquer d'autres temporalités","Macy : le conseil de tous les êtres — sortir temporairement du temps humain"]},"en":{"title":"Slowing Down","entry":"You are moving too fast for the milieu to respond.","body":["Slow down. Not to a stop — to a pace where things can happen.","Deceleration is not passivity. It is a different mode of attention.","Feel what becomes visible when you slow down.","What was always there that only slowness can reveal?","Stay at this pace for longer than feels comfortable."],"retour":"What appeared when you slowed down? What did slowness cost you?","sources":["Tsing : sans le rythme du progrès, on peut remarquer d'autres temporalités","Macy : le conseil de tous les êtres — sortir temporairement du temps humain"]}},{"id":"m-atterrir","deck":"milieux","type":"seuil","fr":{"title":"Atterrir","entry":"Où es-tu exactement ? Pas le nom du lieu — où est ton corps, sur quoi, dans quoi ?","body":["Atterrir n'est pas arriver. C'est reconnaître ce qui te porte.","Sous tes pieds : sol, dalle, herbe, bois — et en dessous, de la roche, de l'eau, des racines.","Autour de toi : de l'air, des particules, des spores, des gaz anciens.","Atterrir, c'est accepter d'être terrestre — pas planétaire en abstrait, mais ici, maintenant.","Sens le poids de cette appartenance. Elle n'est pas légère.","Elle est aussi une ressource."],"retour":"Sur quoi as-tu atterri ? Qu'est-ce que ça change de le savoir ?","sources":["Bruno Latour, philosophe et sociologue des sciences — Où atterrir ? (2017) » — la question politique et somatique de notre époque","Naess : l'ecosophie — une philosophie personnelle ancrée dans un lieu précis"]},"en":{"title":"Landing","entry":"Where are you exactly? Not the name of the place — where is your body, on what, in what?","body":["Landing is not arriving. It is recognising what carries you.","Under your feet: soil, slab, grass, wood — and below, rock, water, roots.","Around you: air, particles, spores, ancient gases.","Landing means accepting being terrestrial — not planetary in the abstract, but here, now.","Feel the weight of this belonging. It is not light. It is also a resource."],"retour":"What did you land on? What changes when you know it?","sources":["Latour : « Où atterrir ? » — la question politique et somatique de notre époque","Naess : l'ecosophie — une philosophie personnelle ancrée dans un lieu précis"]}},{"id":"m-echouer","deck":"milieux","type":"seuil","fr":{"title":"Échouer à résonner","entry":"Cherche quelque chose qui t'appelle. Cette fois, rien ne répond.","body":["Reste avec ce silence. Ne le comble pas avec de l'activité.","L'aliénation — quand le monde ne répond plus — est une expérience réelle, pas un échec personnel.","Sens le silence du milieu dans ton corps. Où le ressens-tu ?","Peut-être que c'est toi qui ne peux pas recevoir. Peut-être que c'est le milieu qui est muet.","Les deux possibilités méritent d'être habitées sans jugement.","Reste. Le silence lui-même est une donnée sur ton rapport au monde."],"retour":"Où était le silence ? En toi ou dans le milieu ? Comment ça s'est senti ?","sources":["Rosa : l'aliénation — l'expérience d'un monde muet, tout aussi réelle que la résonance","Rosa : la résonance suppose une disponibilité et un monde qui répond — les deux peuvent manquer"],"steps":["Cherche quelque chose qui pourrait t'appeler. Rien ne répond. Reste avec ça.","Fais quand même un geste vers quelque chose — une approche, un toucher. Sens la neutralité, l'indifférence du milieu.","Ce n'est pas un échec. C'est une information : sur le lieu, sur toi, sur ce moment.","Reste encore. Le silence du milieu est aussi une donnée — pas un manque. Quel bruit intérieur est-ce qu'il révèle ?"]},"en":{"title":"Failing to Resonate","entry":"Look for something that calls you. This time, nothing responds.","body":["Stay with this silence. Don't fill it with activity.","Alienation — when the world no longer responds — is a real experience, not a personal failure.","Feel the silence of the milieu in your body. Where do you feel it?","Perhaps you cannot receive. Perhaps the milieu is mute.","Both possibilities deserve to be inhabited without judgment."],"retour":"Where was the silence? In you or in the milieu? How did it feel?","sources":["Rosa : l'aliénation — l'expérience d'un monde muet, tout aussi réelle que la résonance","Rosa : la résonance suppose une disponibilité et un monde qui répond — les deux peuvent manquer"],"steps":["Look for something that might call to you. Nothing responds. Stay with that.","Make a gesture toward something anyway — an approach, a touch. Feel the neutrality, the indifference of the place.","This is not failure. It is information: about the place, about you, about this moment.","Stay longer. The silence of the place is also data — not an absence. What inner noise does it reveal?"]}},{"id":"m-negocier","deck":"milieux","type":"seuil","fr":{"title":"Négocier","entry":"Avance dans l'espace. Là où ton corps hésite ou résiste, arrête-toi.","body":["La résistance n'est pas un obstacle. C'est une proposition du milieu.","Négocie avec elle — pas en forçant, pas en reculant, mais en cherchant un accord.","Un accord corporel est une posture, une direction, un rythme qui convient aux deux parties.","Continue. Rencontre la prochaine résistance. Renégocie.","Tu cartographies ainsi la politique interne de cet espace."],"retour":"Avec quoi as-tu négocié ? Qu'as-tu cédé ? Qu'as-tu obtenu ?","sources":["Bruno Latour, philosophe et sociologue des sciences — Politiques de la nature (1999) — les non-humains comme parties prenantes à part entière","John Dewey, philosophe pragmatiste américain — Experience and Nature (1925) — négociation continue entre organisme et milieu"]},"en":{"title":"Negotiating","entry":"Something in this space resists you. Or you resist it.","body":["Negotiation is not compromise. It is a genuine encounter between two kinds of agency.","Feel the resistance. Don't overcome it immediately.","What does the resistance want? What do you want?","Find a gesture that neither submits nor dominates.","Negotiation takes time. Stay in it."],"retour":"What was negotiated? What remained irreducible on each side?","sources":["Latour : la politique des choses — les non-humains comme parties prenantes à part entière","Dewey : la transaction — négociation continue entre organisme et milieu"]}},{"id":"m-composer","deck":"milieux","type":"seuil","fr":{"title":"Composer","entry":"Tu n'es pas seul·e dans cet espace. Recense les autres présences — humaines et non-humaines.","body":["Des plantes, des insectes, des microbes, des matériaux, des sons venus de loin.","Comment est-ce que tu pourrais faire quelque chose avec ces autres présences ?","Pas les contrôler, pas les fuir — t'arranger avec elles.","Commence un mouvement qui tient compte d'une autre présence que toi.","Sens ce que cette présence fait à ton geste — comment elle le modifie, le ralentit, l'oriente.","Sym-poiesis : faire-avec, pas faire-seul."],"retour":"Avec quoi as-tu composé ? Qu'est-ce que cela a fait à ton mouvement ?","sources":["Haraway : sym-poiesis — « faire-avec » plutôt qu'autopoïesis","Bruno Latour, philosophe et sociologue des sciences — Enquête sur les modes d'existence (2012) — les non-humains comme acteurs à part entière"]},"en":{"title":"Composing","entry":"You are not alone in this space. Survey the other presences — human and non-human.","body":["Plants, insects, microbes, materials, sounds from afar.","How might you do something with these other presences?","Not control them, not flee them — arrange with them.","Begin a movement that accounts for a presence other than yourself.","Sym-poiesis: making-with, not making-alone."],"retour":"What did you compose with? What did this do to your movement?","sources":["Haraway : sym-poiesis — « faire-avec » plutôt qu'autopoïesis","Latour : composer un monde commun — les non-humains comme acteurs à part entière"]}},{"id":"m-devenir-avec","deck":"milieux","type":"seuil","fr":{"title":"Devenir-avec","entry":"Choisis un être non-humain dans l'espace — une plante, un insecte, une pierre, un courant d'air.","body":["Ne l'observe pas de loin. Approche-toi. Reste.","Laisse sa présence entrer dans ton corps — par la vue, l'odorat, le toucher si possible.","Commence à bouger en tenant compte de son existence. Pas à l'imiter. En tenant compte.","Devenir-avec n'est pas fusionner. C'est laisser l'autre modifier qui tu es, légèrement.","Remarque les résistances. Remarque les affinités.","Qui es-tu, légèrement différemment, après ce contact ?"],"retour":"Qu'est-ce qui a changé en toi à travers ce contact ?","sources":["Haraway : « staying with the trouble » — les pratiques tentaculaires du faire-avec","Tsing : la rencontre multi-espèces comme lieu de transformation mutuelle"]},"en":{"title":"Becoming-with","entry":"Choose something non-human in this space — a plant, a material, a sound, a shaft of light.","body":["You are not going to observe it. You are going to become-with it.","Becoming-with is not imitation. It is a genuine transformation of both.","Begin moving in relation to this presence — not around it, with it.","Allow something in you to change through this encounter.","What has become different in you through this becoming-with?"],"retour":"What became different in you? What became different in the other?","sources":["Haraway : « staying with the trouble » — les pratiques tentaculaires du faire-avec","Tsing : la rencontre multi-espèces comme lieu de transformation mutuelle"]}},{"id":"m-s-attarder","deck":"milieux","type":"seuil","fr":{"title":"S'attarder","entry":"Reste là où tu es. Même si une partie de toi veut déjà partir.","body":["S'attarder, c'est refuser l'efficacité. C'est offrir du temps à ce qui est là.","Remarque ce qui change quand tu restes plus longtemps que prévu.","Le lieu te révèle des couches supplémentaires — des détails, des rythmes, des présences.","Reste encore un peu. Juste un peu plus que confortable.","L'inconfort de rester est une information : qu'est-ce qui tire vers ailleurs ?"],"retour":"Qu'est-ce qui a émergé dans le fait de rester ?","sources":["Jullien : la fadeur — la disponibilité qui naît de la non-précipitation","Tim Ingold, anthropologue britannique — Being Alive (2011) — habiter le chemin plutôt que se déplacer d'un point à un autre"]},"en":{"title":"Lingering","entry":"Something here deserves more time than you would normally give it.","body":["Don't pass by. Don't move on to the next thing. Stay.","Lingering is not laziness. It is a form of fidelity.","What does this thing — this place, this moment — give you when you stay long enough?","Feel how the experience deepens with duration.","Allow the place to tell you when it's time to leave."],"retour":"What did lingering reveal that passing by would have missed?","sources":["Jullien : la fadeur — la disponibilité qui naît de la non-précipitation","Ingold : le wayfaring — habiter le chemin plutôt que se déplacer d'un point à un autre"]}},{"id":"m-le-sol","deck":"milieux","type":"figure","fr":{"title":"Le Sol","entry":"Le sol sous toi n'est pas une surface. C'est une archive vivante.","body":["Reste debout ou assis·e en contact avec le sol. Ferme les yeux.","Le sol que tu sens a une histoire de millions d'années.","Il contient des champignons, des bactéries, des racines, de l'eau, de la mémoire.","Sens le sol comme un milieu vivant qui te porte et qui t'ignore.","Ton corps est une couche temporaire sur cette archive.","Laisse cette idée descendre dans tes jambes, tes pieds, ta colonne."],"retour":"Qu'est-ce que le sol t'a communiqué ?","sources":["Bruno Latour, philosophe et sociologue des sciences — Où atterrir ? (2017) — la fine pellicule poreuse entre roche et atmosphère","Naess : l'appartenance — le soi écologique qui inclut le sol comme partie de soi"]},"en":{"title":"The Ground","entry":"The ground beneath you is not a surface. It is a living archive.","body":["Stay standing or seated in contact with the ground. Close your eyes.","The ground you feel has a history of millions of years.","It contains fungi, bacteria, roots, water, memory.","Feel the ground as a living milieu that carries you and ignores you.","Your body is a temporary layer on this archive.","Let this idea descend into your legs, your feet, your spine."],"retour":"What did the ground communicate to you?","sources":["Latour : la zone critique — la fine pellicule poreuse entre roche et atmosphère","Naess : l'appartenance — le soi écologique qui inclut le sol comme partie de soi"]}},{"id":"m-la-peau","deck":"milieux","type":"figure","fr":{"title":"La Peau","entry":"La peau n'est pas une frontière. C'est un organe de relation.","body":["Sens ta peau en contact avec l'air. C'est du contact — pas de l'isolement.","La peau perçoit la température, l'humidité, les courants, les présences proches.","Elle est la zone critique de ton corps — là où le dedans et le dehors se négocient.","Laisse la peau devenir l'organe principal de ta perception pendant quelques minutes.","Qu'est-ce que la peau sait que les yeux ne savent pas ?"],"retour":"Qu'est-ce que la peau a perçu que tu n'aurais pas remarqué autrement ?","sources":["Augustin Berque, géographe et mésologiste — Écoumène (2000) — le sujet est toujours déjà dehors par sa peau, son regard, son souffle","Tim Ingold, anthropologue britannique — Being Alive (2011) — de rencontre plutôt que de séparation"]},"en":{"title":"The Skin","entry":"The skin is not a boundary. It is an organ of relation.","body":["Feel your skin in contact with the air. This is contact — not isolation.","The skin perceives temperature, humidity, currents, nearby presences.","It is the critical zone of your body — where inside and outside are negotiated.","Let the skin become the primary organ of your perception for a few minutes.","What does the skin know that the eyes do not?"],"retour":"What did the skin perceive that you wouldn't otherwise have noticed?","sources":["Berque : la trajection — le sujet est toujours déjà dehors par sa peau, son regard, son souffle","Ingold : les surfaces comme lieux de rencontre plutôt que de séparation"]}},{"id":"m-l-ecart","deck":"milieux","type":"figure","fr":{"title":"L'Écart","entry":"Trouve deux choses qui ne se ressemblent pas. Résiste à l'envie de les comparer.","body":["L'écart n'est pas la différence. La différence classe. L'écart ouvre.","Laisse l'espace entre ces deux choses exister — sans le combler, sans le nommer.","Cet espace entre elles est productif. Quelque chose de nouveau peut y naître.","Ton corps peut habiter cet écart — physiquement, en se plaçant entre elles.","Sens ce que cet entre-deux fait à ta perception, à ta posture, à ta présence."],"retour":"Qu'est-ce qui a émergé dans l'écart ?","sources":["François Jullien, philosophe sinologue français — L'écart et l'entre (2012) — pas la différence (qui sépare) mais l'écart (qui ouvre)","François Jullien, philosophe sinologue français — L'écart et l'entre (2012) — qu'on déploie de l'altérité »"]},"en":{"title":"The Gap","entry":"Find two things that don't resemble each other. Resist the urge to compare them.","body":["The gap is not difference. Difference classifies. The gap opens.","Let the space between these two things exist — without filling it, without naming it.","This space between them is productive. Something new can be born there.","Your body can inhabit this gap — physically, by placing itself between them.","Feel what this in-between does to your perception, your posture."],"retour":"What emerged in the gap?","sources":["Jullien : l'écart et l'entre — pas la différence (qui sépare) mais l'écart (qui ouvre)","Jullien : « c'est en faisant travailler des écarts qu'on déploie de l'altérité »"]}},{"id":"m-la-zone","deck":"milieux","type":"figure","fr":{"title":"La Zone","entry":"Tu es dans une zone — pas un territoire, pas un lieu nommé. Une zone.","body":["La zone est poreuse. Elle n'a pas de frontières nettes.","Elle est traversée par des flux — d'air, d'eau, de lumière, d'organismes vivants.","Sens les flux qui traversent la zone où tu es.","Certains viennent de loin. Certains repartent vers des endroits que tu ne connaîtras jamais.","Tu es une intersection temporaire de ces flux.","Laisse cette idée traverser ton corps."],"retour":"Quels flux as-tu sentis ? Où allaient-ils ?","sources":["Bruno Latour, philosophe et sociologue des sciences, et Jérôme Gaillardet, géochimiste — : : la zone critique comme lieu de toutes les interdépendances terrestres","Tsing : la zone de contact — là où les espèces et les cultures se rencontrent"],"steps":["Marche lentement dans cet espace. À chaque pas, sens que tu traverses quelque chose de poreux — pas un espace vide mais un milieu traversé de flux.","Arrête-toi. Tends une main. L'air que tu touches a été ailleurs. Il ira ailleurs. Tu es dans un flux momentané.","Tourne-toi lentement à 360°. Sens les différentes qualités de l'air selon les directions — humidité, chaleur, mouvement.","Tu n'es pas dans un lieu fermé. Tu es à l'intersection de flux qui viennent de loin et vont loin. Commence à te mouvoir comme ça."]},"en":{"title":"The Zone","entry":"Every space has zones — areas of different intensity, temperature, attention.","body":["Move through this space paying attention to its zones.","Where does the energy change? Where does something thicken or thin out?","Find a zone that calls you. Enter it slowly.","Feel the zone as a specific quality of the milieu — not a location but a condition.","What does it mean to be in a zone rather than passing through space?"],"retour":"What zone did you find? What did it ask of you?","sources":["Latour et Gaillardet : la zone critique comme lieu de toutes les interdépendances terrestres","Tsing : la zone de contact — là où les espèces et les cultures se rencontrent"],"steps":["Walk slowly through this space. With each step, feel you are moving through something porous — not an empty space but a medium crossed by flows.","Stop. Extend a hand. The air you touch has been elsewhere. It will go elsewhere. You are in a momentary flow.","Turn slowly through 360°. Feel the different qualities of air in each direction — humidity, warmth, movement.","You are not in a closed place. You are at the intersection of flows coming from afar and going far. Begin to move like that."]}},{"id":"m-le-silence","deck":"milieux","type":"figure","fr":{"title":"Le Silence","entry":"Cherche le silence dans cet espace. Pas l'absence de son — le silence.","body":["Le silence n'est pas le vide sonore. Il est une présence.","Laisse le silence entrer dans ton corps par les oreilles, puis par la peau.","Observe ce que le silence révèle — des sons que le bruit couvrait, des sensations masquées.","Reste dans le silence aussi longtemps que tu peux.","Sens la différence entre le silence choisi et le silence subi."],"retour":"Qu'est-ce que le silence a rendu audible ?","sources":["Rosa : l'aliénation — quand le monde ne répond plus, cela aussi mérite d'être senti","Jullien : la fadeur — ce que la discrétion révèle quand on cesse de chercher l'intensité"],"steps":["Arrête de bouger. Complètement. Ferme les yeux. Trente secondes d'immobilité totale.","Laisse le silence des gestes révéler les sons que ton mouvement couvrait. Combien de sources sonores peux-tu compter ?","Commence à bouger à nouveau — mais en silence délibéré. Comme si chaque geste devait rester discret.","La différence entre ton silence et le silence du lieu — où est-elle ? Ton corps fait du bruit que tu n'entends pas."]},"en":{"title":"The Silence","entry":"Find the silence in this space. Not the absence of sound — the silence underneath the sounds.","body":["Silence is not empty. It is the condition that allows sounds to exist.","Listen for the silence between sounds, beneath sounds, around sounds.","Let the silence enter your body.","Move from within this silence — not making noise, not performing quiet.","What does the silence contain?"],"retour":"What was in the silence? How did moving from silence change the quality of movement?","sources":["Rosa : l'aliénation — quand le monde ne répond plus, cela aussi mérite d'être senti","Jullien : la fadeur — ce que la discrétion révèle quand on cesse de chercher l'intensité"],"steps":["Stop moving. Completely. Close your eyes. Thirty seconds of total stillness.","Let the silence of gesture reveal the sounds your movement covered. How many sound sources can you count?","Begin to move again — but in deliberate silence. As if each gesture had to remain discreet.","The difference between your silence and the silence of the place — where is it? Your body makes sounds you don't hear."]}},{"id":"m-la-dependance","deck":"milieux","type":"figure","fr":{"title":"La Dépendance","entry":"Liste mentalement tout ce dont tu as besoin pour exister en ce moment.","body":["L'air. L'eau. La chaleur. Les autres. Le sol. La nourriture que tu as mangée ce matin.","La chaîne de dépendances remonte très loin — vers des organismes, des processus, des temps géologiques.","Sens le poids de cette dépendance dans ton corps.","Puis sens-la comme une appartenance plutôt qu'une fragilité.","Dépendre, c'est être relié. C'est être vivant.","Qu'est-ce que tu dois à quoi ?"],"retour":"Qu'est-ce que cette prise de conscience de la dépendance modifie dans ton corps ?","sources":["Bruno Latour, philosophe et sociologue des sciences — Où atterrir ? (2017) — reconnaître les dépendances terrestres comme condition de l'existence","Macy : la gratitude comme première étape — reconnaître ce qui nous porte avant toute chose"],"steps":["Debout. Tends les deux bras devant toi, paumes ouvertes vers le haut.","Nomme à voix haute, en tendant les bras un peu plus à chaque fois : l'air, l'eau, le sol, la lumière, les bactéries qui digèrent pour toi, les plantes qui produisent l'oxygène que tu respires.","Continue jusqu'à sentir le poids de tout ce que tu nommes — pas un poids écrasant, un poids réel, comme tenir quelque chose de vivant.","Puis ramène les mains sur ta poitrine. Tu contiens tout ça — temporairement, de passage.","La dépendance n'est pas une dette. C'est la texture de l'existence vivante."]},"en":{"title":"The Dependency","entry":"Name one dependency that makes your presence here possible.","body":["Not a metaphorical dependency — a concrete one. Air. Light. Temperature. Other bodies.","Feel this dependency in your body right now.","The dependency is not shameful. It is the structure of existence.","Now name another. And another.","You are an assembly of dependencies. Feel the weight of this assembly — and its richness."],"retour":"Which dependency surprised you most? What does it feel like to be held by what you depend on?","sources":["Latour : atterrir — reconnaître les dépendances terrestres comme condition de l'existence","Macy : la gratitude comme première étape — reconnaître ce qui nous porte avant toute chose"],"steps":["Standing. Hold both arms out in front of you, palms open upward.","Name aloud, extending your arms a little more each time: air, water, ground, light, the bacteria that digest for you, the plants that produce the oxygen you breathe.","Continue until you feel the weight of everything you name — not a crushing weight, a real weight, like holding something alive.","Then bring your hands to your chest. You contain all of this — temporarily, in passage.","Dependence is not a debt. It is the texture of living existence."]}},{"id":"m-le-reste","deck":"milieux","type":"figure","fr":{"title":"Le Reste","entry":"Regarde ce qui reste dans cet espace — ce qui persiste malgré le temps, l'usage, l'oubli.","body":["Une trace sur un mur. Une plante dans un coin inattendu. Un son récurrent.","Le reste est une mémoire que le lieu porte malgré lui.","Approche-toi de ce reste. Laisse-le te parler.","Qu'est-ce que ce lieu a vécu avant que tu arrives ?","Ton corps est aussi un lieu qui porte des restes — des postures anciennes, des tensions héritées.","Quel est le reste que tu portes ici avec toi ?"],"retour":"Qu'est-ce qui persiste ? Dans le lieu, dans ton corps ?","sources":["Tsing : les ruines du capitalisme — chercher ce qui pousse dans les restes","Tim Ingold, anthropologue britannique — Being Alive (2011) — les compétences comme dépôts de l'expérience passée"]},"en":{"title":"The Remainder","entry":"Something in this space is left over — unnoticed, unincorporated, remaining.","body":["The remainder is not waste. It is what resists assimilation.","Find what has been left aside, overlooked, passed by.","Stay with the remainder. Don't try to integrate it.","Sometimes the remainder is the most important thing.","What does the remainder tell you about what has been selected, highlighted, prioritised?"],"retour":"What was in the remainder? What does it say about what was chosen?","sources":["Tsing : les ruines du capitalisme — chercher ce qui pousse dans les restes","Ingold : la mémoire incarnée — les compétences comme dépôts de l'expérience passée"]}},{"id":"m-le-bord","deck":"milieux","type":"figure","fr":{"title":"Le Bord","entry":"Trouve un bord dans cet espace — le bord d'une surface, d'une ombre, d'un son.","body":["Le bord est l'endroit où deux mondes se touchent sans se confondre.","Reste au bord. Ni entièrement dedans, ni entièrement dehors.","Sens la tension de cette position.","Le bord est un lieu de perception maximale — les deux côtés sont perceptibles depuis là.","Qu'est-ce que le bord te révèle sur chacun des côtés ?"],"retour":"Qu'est-ce que le bord t'a appris sur ce qu'il séparait ?","sources":["Haraway : les zones de contact — là où les différences se frottent","Augustin Berque, géographe et mésologiste — Médiance (1990) — la double appartenance toujours présente du sujet-milieu"]},"en":{"title":"The Edge","entry":"Find an edge in this space — the boundary between two different things.","body":["Edges are where the interesting things happen.","Stand at the edge. Feel both sides from here.","The edge is not a line. It is a zone of transition and negotiation.","Move along the edge rather than crossing it.","What is the edge protecting? What does it separate? What does it connect?"],"retour":"What did the edge reveal about the two territories it separates?","sources":["Haraway : les zones de contact — là où les différences se frottent","Berque : la médiance — la double appartenance toujours présente du sujet-milieu"]}},{"id":"m-l-air","deck":"milieux","type":"figure","fr":{"title":"L'Air","entry":"L'air dans lequel tu respires n'a pas de frontières. Il est déjà passé par d'autres poumons.","body":["Chaque inspiration est un acte de confiance dans le vivant.","L'air contient des spores, des pollens, des particules venues de continents lointains.","Sens l'air comme un milieu commun — partagé avec tous les êtres respirants ici.","Laisse l'air traverser ton corps comme si tu étais poreux·e.","Tu respires avec le monde. Le monde respire en toi.","Reste avec cette perméabilité."],"retour":"Qu'est-ce que l'air t'a apporté ? Qu'as-tu rendu à l'air ?","sources":["Augustin Berque, géographe et mésologiste — Écoumène (2000) — le dedans et le dehors se co-constituent à chaque respiration","Bruno Latour, philosophe et sociologue des sciences — Où atterrir ? (2017) — l'atmosphère comme couche vivante et négociée"]},"en":{"title":"The Air","entry":"The air you breathe has no boundaries. It has already passed through other lungs.","body":["Each breath is an act of trust in the living.","Air contains spores, pollens, particles from distant continents.","Feel air as a common milieu — shared with all breathing beings here.","Let air pass through your body as if you were porous.","You breathe with the world. The world breathes in you."],"retour":"What did the air bring you? What did you return to the air?","sources":["Berque : la trajection — le dedans et le dehors se co-constituent à chaque respiration","Latour : la zone critique — l'atmosphère comme couche vivante et négociée"]}},{"id":"m-la-racine","deck":"milieux","type":"figure","fr":{"title":"La Racine","entry":"Les racines ne cherchent pas la lumière. Elles cherchent l'eau, le contact, la résistance.","body":["Imagine une racine qui pousse sous toi — lentement, dans l'obscurité, par tâtonnement.","La racine ne planifie pas. Elle répond.","Sens ton propre système racinaire — les connexions souterraines que tu ne vois pas.","À quoi tiens-tu sans le savoir ? Qu'est-ce qui te tient ?","La racine est aussi ce qui permet à l'arbre de se pencher dans le vent.","L'enracinement n'est pas l'immobilité."],"retour":"Où sont tes racines ? Que tiennent-elles ?","sources":["Naess : l'identification — l'enracinement comme condition de l'élargissement du soi","Tsing : les réseaux mycorhiziens — les racines ne sont jamais seules, elles sont toujours en réseau"]},"en":{"title":"The Root","entry":"Roots don't seek the light. They seek water, contact, resistance.","body":["Imagine a root growing beneath you — slowly, in darkness, by trial.","The root doesn't plan. It responds.","Feel your own root system — the underground connections you cannot see.","What do you hold without knowing? What holds you?","Rootedness is not immobility. It is the condition of movement."],"retour":"Where are your roots? What do they hold?","sources":["Naess : l'identification — l'enracinement comme condition de l'élargissement du soi","Tsing : les réseaux mycorhiziens — les racines ne sont jamais seules, elles sont toujours en réseau"]}},{"id":"m-l-ombre","deck":"milieux","type":"figure","fr":{"title":"L'Ombre","entry":"Trouve ton ombre. Ou l'ombre d'une autre présence dans l'espace.","body":["L'ombre est la trace visible d'une opacité. Elle prouve que tu es là.","Observe comment ton ombre change avec le mouvement — elle exagère, elle précède, elle traîne.","L'ombre est aussi ce que tu portes mais ne vois pas directement.","Reste dans l'ombre d'une autre présence — sens ce que ça change.","La lumière et l'ombre se co-constituent. Pas l'une sans l'autre."],"retour":"Qu'est-ce que ton ombre révèle que ta présence cache ?","sources":["Tim Ingold, anthropologue britannique — Being Alive (2011) — on ne voit pas la lumière, on voit dans la lumière","François Jullien, philosophe sinologue français — De l'intime (2013) — que la clarté efface"]},"en":{"title":"The Shadow","entry":"Find a shadow in this space. Your own, or another's.","body":["The shadow is not an absence of light. It is a presence of darkness.","Move into the shadow. Stay there a moment.","The shadow tells you where the light comes from.","Feel the shadow as a quality of the milieu — not a lack but a texture.","What does the shadow contain that the light obscures?"],"retour":"What was in the shadow? What does the shadow tell you about the light?","sources":["Ingold : la lumière comme milieu — on ne voit pas la lumière, on voit dans la lumière","Jullien : ce que la pénombre révèle que la clarté efface"]}},{"id":"m-la-trace","deck":"milieux","type":"figure","fr":{"title":"La Trace","entry":"Cherche une trace dans cet espace — un passage, une marque, un reste de présence.","body":["La trace prouve qu'un être est passé sans être là maintenant.","Lis cette trace comme un signe — pas en cherchant à l'interpréter, mais en la laissant parler.","Qu'est-ce que cette trace raconte de l'être qui l'a laissée ?","Commence à te mouvoir en laissant une trace — un son, un déplacement d'air, un contact.","Sens la différence entre passer sans trace et passer en laissant une trace.","Quelle trace veux-tu laisser ici ?"],"retour":"Quelle trace as-tu lue ? Quelle trace as-tu laissée ?","sources":["Lévi-Strauss : la pensée sauvage — lire les signes du milieu comme un texte","Tim Ingold, anthropologue britannique — Being Alive (2011) — laisse toujours des traces — le chemin se fait en le parcourant"]},"en":{"title":"The Trace","entry":"Something has passed through this space before you. Look for its trace.","body":["A trace is not a sign. It doesn't mean something. It shows something passed.","Find the traces in this space — marks, wear, residues, absence.","Feel the presence of what left the trace without being here.","Leave your own trace — minimal, respectful, real.","What is the relation between presence and trace?"],"retour":"What traces did you find? What trace did you leave?","sources":["Lévi-Strauss : la pensée sauvage — lire les signes du milieu comme un texte","Ingold : le wayfaring laisse toujours des traces — le chemin se fait en le parcourant"]}},{"id":"m-la-fadeur","deck":"milieux","type":"figure","fr":{"title":"La Fadeur","entry":"Cherche quelque chose dans cet espace qui ne t'attire pas. Neutre. Ordinaire. Sans intérêt apparent.","body":["La fadeur n'est pas l'ennui. C'est une disponibilité.","Reste avec ce qui ne t'attire pas. Laisse-lui du temps.","La fadeur contient toutes les saveurs en puissance — elle est l'avant des intensités.","Sens comment la perception change quand on cesse de chercher l'intéressant.","Ce qui semblait fade commence à parler — doucement, sans forcer.","C'est cela, la fadeur : ce qui s'offre quand on cesse de vouloir."],"retour":"Qu'est-ce que la fadeur t'a révélé ? Qu'est-ce qui était là, en attente ?","sources":["François Jullien, philosophe sinologue français — Éloge de la fadeur (1991) — la saveur du neutre, la richesse du non-affirmé","François Jullien, philosophe sinologue français — Éloge de la fadeur (1991) — totale — l'état de celui qui ne s'est pas encore décidé"],"steps":["Approche-toi de lui. Pas pour l'examiner — pour être à côté, dans la même indifférence partagée.","Touche-le si tu peux. Tiens-toi face à lui sans attendre qu'il se révèle. Laisse le temps passer.","La fadeur n'est pas l'ennui — c'est ce qui précède toutes les saveurs. Commence à bouger très lentement autour de cet objet ou lieu, comme si tu le contournais sans raison.","À un moment, quelque chose changera — dans ta perception, dans ta posture, dans ce que tu vois. Ne le cherche pas. Laisse-le arriver."]},"en":{"title":"Blandness","entry":"Find something in this space that doesn't attract you. Neutral. Ordinary. Of no apparent interest.","body":["Blandness is not boredom. It is availability.","Stay with what doesn't attract you. Give it time.","Blandness contains all flavours in potential — it is the before of intensities.","Feel how perception changes when you stop seeking the interesting.","What seemed bland begins to speak — softly, without forcing."],"retour":"What did blandness reveal? What was there, waiting?","sources":["Jullien : « Éloge de la fadeur » — la saveur du neutre, la richesse du non-affirmé","Jullien : la fadeur comme disponibilité totale — l'état de celui qui ne s'est pas encore décidé"],"steps":["Approach it. Not to examine it — to be beside it, in shared indifference.","Touch it if you can. Stand facing it without waiting for it to reveal itself. Let time pass.","Fadeur is not boredom — it is what precedes all flavours. Begin to move very slowly around this object or place, as if circling it for no reason.","At some point, something will change — in your perception, your posture, what you see. Don't look for it. Let it arrive."]}},{"id":"m-l-echelle","deck":"milieux","type":"figure","fr":{"title":"L'Échelle","entry":"Ton corps perçoit à une échelle parmi des milliers d'échelles possibles.","body":["En ce moment, des bactéries se reproduisent sur ta peau. Des réactions chimiques font tes pensées.","En ce moment, la dalle sous toi est le résultat de millions d'années de pression géologique.","En ce moment, la lumière que tu vois a voyagé depuis une étoile.","Essaie de sentir, dans ton corps, une échelle plus petite que toi — cellulaire, moléculaire.","Puis une échelle plus grande — continentale, planétaire.","Ton corps est un point de rencontre entre ces échelles, pas leur centre."],"retour":"À quelle échelle es-tu le plus habituellement ? Qu'est-ce que les autres échelles changent ?","sources":["Bruno Latour, philosophe et sociologue des sciences — Où atterrir ? (2017) — existe à de multiples échelles simultanées","Naess : l'identification écologique — sentir sa propre vie comme partie d'une vie plus vaste"],"steps":["Allonge-toi au sol si tu peux. Ferme les yeux. Sens ton poids — toute ta masse, tirée vers le bas par la gravité.","Descends maintenant dans l'échelle : ta peau est peuplée de bactéries. Tes cellules font des échanges chimiques en ce moment. Tes atomes ont existé dans des étoiles.","Monte dans l'échelle : la dalle sous toi est comprimée par des millions d'années de pression. La lumière sur ta peau a voyagé depuis une étoile.","Lève-toi lentement. Tu es un point de rencontre entre ces échelles — pas leur centre, leur passage."]},"en":{"title":"The Scale","entry":"This space has a scale — a relation between your body and its dimensions.","body":["Feel your body in relation to the scale of this space. Too small? Too large? Just right?","Change your own scale — make yourself very small, or very expansive.","Scale is not size. It is a relationship.","Move at a scale different from the space's — observe the friction.","What does it mean to be in scale or out of scale with a milieu?"],"retour":"What scale felt most natural? What happened when you changed scale?","sources":["Latour : la zone critique existe à de multiples échelles simultanées","Naess : l'identification écologique — sentir sa propre vie comme partie d'une vie plus vaste"],"steps":["Lie on the ground if you can. Close your eyes. Feel your weight — your entire mass, pulled downward by gravity.","Descend in scale now: your skin is populated by bacteria. Your cells are making chemical exchanges right now. Your atoms once existed in stars.","Ascend in scale: the ground beneath you is compressed by millions of years of pressure. The light on your skin has travelled from a star.","Rise slowly. You are a meeting point between these scales — not their centre, their passage."]}},{"id":"m-ce-qui-te-porte","deck":"milieux","type":"situation","fr":{"title":"Ce qui te porte en ce moment","entry":"Pas de geste préalable. Simplement : qu'est-ce qui te porte là, maintenant ?","body":["Pas seulement le sol. Tout ce qui te porte — un état, une relation, une raison d'être là.","Laisse cette question travailler dans ton corps avant de chercher une réponse.","Le corps sait souvent avant la tête.","Commence à bouger depuis ce qui te porte. Non pas depuis ce que tu veux faire.","Observe comment le mouvement change quand il vient de ce soutien."],"retour":"Qu'est-ce qui te porte ? Comment ça se sent dans le corps en mouvement ?","sources":["Macy : la gratitude enracinée — partir de ce qui nous soutient avant de partir de ce qui manque","Naess : l'ecosophie — une pratique enracinée dans un lieu et un moment spécifiques"]},"en":{"title":"What carries you right now","entry":"No preliminary gesture. Simply: what is carrying you here, now?","body":["Not just the ground. Everything that carries you — a state, a relation, a reason for being here.","Let this question work in your body before seeking an answer.","The body often knows before the head.","Begin moving from what carries you. Not from what you want to do.","Observe how movement changes when it comes from this support."],"retour":"What carries you? How does it feel in the moving body?","sources":["Macy : la gratitude enracinée — partir de ce qui nous soutient avant de partir de ce qui manque","Naess : l'ecosophie — une pratique enracinée dans un lieu et un moment spécifiques"]}},{"id":"m-ce-qui-te-voit","deck":"milieux","type":"situation","fr":{"title":"Ce que tu ne vois pas mais qui te voit","entry":"Tu n'es pas le seul observateur dans cet espace. Des insectes, des plantes, des microbes — quelque chose te perçoit.","body":["Des insectes, des plantes, des microbes — quelque chose te perçoit.","Laisse cette idée entrer dans ton corps. Sens-toi perçu·e.","Comment ta posture change-t-elle quand tu te sais observé·e par le non-humain ?","L'environnement n'est pas un décor. C'est un assemblage de perceptions mutuelles.","Bouge en tenant compte du fait que tu es vu·e."],"retour":"Comment t'es-tu senti·e perçu·e ? Qu'est-ce que cela a changé ?","sources":["Tim Ingold, anthropologue britannique — Being Alive (2011) — à un monde qui nous perçoit »","Tsing : les rencontres multi-espèces — chaque être a sa propre sphère perceptive"],"steps":["Choisis un être non-humain dans cet espace. Tiens-toi face à lui — vraiment face à lui, comme tu le ferais avec quelqu'un.","Bouge en tenant compte du fait qu'il te voit. Pas pour performer — pour être davantage présent·e.","Maintenant : dis quelque chose à cet être. Une seule phrase, à voix basse. Ce qui vient."]},"en":{"title":"What you don't see but that sees you","entry":"You are not the only observer in this space. Insects, plants, microbes — something perceives you.","body":["Insects, plants, microbes — something perceives you.","Let this idea enter your body. Feel yourself perceived.","How does your posture change when you know you are observed by the non-human?","The environment is not a backdrop. It is an assembly of mutual perceptions.","Move taking into account the fact that you are seen."],"retour":"How did you feel perceived? What did it change?","sources":["Ingold : « être vivant, c'est être exposé à un monde qui nous perçoit »","Tsing : les rencontres multi-espèces — chaque être a sa propre sphère perceptive"],"steps":["Choose a non-human being in this space. Stand facing it — truly facing it, as you would with someone.","Move while acknowledging that it sees you. Not to perform — to be more fully present.","Now: say something to this being. One sentence, quietly. What comes."]}},{"id":"m-ce-qui-resiste","deck":"milieux","type":"situation","fr":{"title":"Ce qui résiste","entry":"Commence à faire quelque chose — n'importe quoi. Remarque ce qui résiste.","body":["La résistance peut être physique : un objet, un courant d'air, ton propre corps.","Elle peut être invisible : une hésitation, un malaise, une attention qui ne vient pas.","Ne surmonte pas la résistance. Étudie-la.","La résistance est une information sur le milieu et sur toi.","Reste avec la résistance. Qu'est-ce qu'elle dit ?"],"retour":"Qu'est-ce qui résistait ? Qu'est-ce que cela signifiait ?","sources":["John Dewey, philosophe pragmatiste américain — Art as Experience (1934) — comme condition de l'expérience réelle","Rosa : la résonance implique toujours la possibilité du silence — le monde peut ne pas répondre"]},"en":{"title":"What resists","entry":"Find something in this space that resists you — your presence, your movement, your attention.","body":["Resistance is not an obstacle. It is a form of agency.","Stay with the resistance rather than overcoming it.","Feel the resistance as information — about the milieu, about yourself.","What does the resistance want? What is it protecting?","Find a way to work with the resistance rather than against it."],"retour":"What resisted you? What did the resistance teach you?","sources":["Dewey : la résistance du milieu comme condition de l'expérience réelle","Rosa : la résonance implique toujours la possibilité du silence — le monde peut ne pas répondre"]}},{"id":"m-ce-qui-repond","deck":"milieux","type":"situation","fr":{"title":"Ce qui répond","entry":"Fais quelque chose de petit dans l'espace. Puis attends.","body":["Attends une réponse — pas nécessairement humaine.","Un son en écho. Un mouvement d'air. Un changement de lumière. Un oiseau.","La réponse peut être très discrète. Elle peut être très lente.","La résonance n'est pas un événement spectaculaire. C'est souvent un murmure.","Qu'est-ce qui a répondu ? De quelle façon ?"],"retour":"Qu'est-ce qui a répondu à ton geste ? Comment l'as-tu reconnu ?","sources":["Rosa : la résonance — quelque chose répond, et cela transforme les deux termes de la relation","Macy : le monde vivant répond si on lui parle — mais dans ses propres termes"],"steps":["Fais un geste très discret dans l'espace — frapper doucement dans ses mains, souffler, traîner un pied, poser quelque chose.","Attends. Pas une seconde — vraiment attendre. Ce lieu a ses propres temps de réponse.","La réponse peut être un son en écho, un mouvement d'air, un oiseau qui part, une feuille qui bouge. Elle peut être très lente.","Refais le même geste. Puis un différent. Explore la grammaire de ce lieu — ce qu'il répond à quoi."]},"en":{"title":"What responds","entry":"Do something small in the space. Then wait.","body":["Wait for a response — not necessarily human.","An echo of sound. A movement of air. A change of light. A bird.","The response may be very discreet. It may be very slow.","Resonance is not a spectacular event. It is often a whisper.","What responded? In what way?"],"retour":"What responded to your gesture? How did you recognise it?","sources":["Rosa : la résonance — quelque chose répond, et cela transforme les deux termes de la relation","Macy : le monde vivant répond si on lui parle — mais dans ses propres termes"],"steps":["Make a very quiet gesture in the space — clap softly, breathe out, drag a foot, place something down.","Wait. Not a second — truly wait. This place has its own response times.","The response might be an echo, an air movement, a bird leaving, a leaf shifting. It might be very slow.","Repeat the same gesture. Then a different one. Explore this place's grammar — what it responds to."]}},{"id":"m-ce-dont-tu-dependes","deck":"milieux","type":"situation","fr":{"title":"Ce dont tu dépends sans le savoir","entry":"Ferme les yeux. Respire. Quelque chose se passe sans que tu l'aies demandé.","body":["Ton cœur bat. Tes poumons travaillent. Le sol te tient.","Tu dépends de processus que tu n'as jamais décidés — biologiques, géologiques, sociaux.","Élargis lentement la conscience de ces dépendances invisibles.","Certaines sont très anciennes — des millions d'années de photosynthèse pour l'oxygène que tu respires.","Comment vivre en sachant cela ? Pas comme une dette, mais comme une relation."],"retour":"Qu'est-ce que tu as découvert dont tu dépendais ? Comment ça change ta présence ?","sources":["Bruno Latour, philosophe et sociologue des sciences — Où atterrir ? (2017) — nous dépendons d'une fine pellicule vivante que nous ne voyons pas","Naess : élargir le soi — reconnaître les dépendances comme extension de notre propre vie"],"steps":["Debout. Pose une main sur ta poitrine. Ton cœur bat sans que tu l'aies décidé. Tes poumons travaillent sans instruction.","Retire ta main et tends-la vers un élément de ce lieu — un arbre, le sol, l'air. Tu dépends de ce que ta main désigne. Vraiment.","Fais ce geste vers plusieurs choses : l'oxygène que produit cette plante, l'eau qui circule sous tes pieds, la photosynthèse qui a rendu cette lumière possible.","Chaque geste est une reconnaissance. Pas une dette — une relation. Sens la différence entre les deux dans le corps."]},"en":{"title":"What you depend on without knowing","entry":"You are depending on something right now that you haven't noticed.","body":["It might be structural — a floor, a wall, an atmosphere.","It might be relational — an assumption, a support, a convention.","Feel the hidden dependencies that make this moment possible.","What would disappear if this invisible support disappeared?","Acknowledge the dependency without needing to resolve it."],"retour":"What hidden dependency did you find? How does acknowledging it change your relation to it?","sources":["Latour : la zone critique — nous dépendons d'une fine pellicule vivante que nous ne voyons pas","Naess : élargir le soi — reconnaître les dépendances comme extension de notre propre vie"],"steps":["Standing. Place a hand on your chest. Your heart beats without your decision. Your lungs work without instruction.","Remove your hand and extend it toward an element of this place — a tree, the ground, the air. You depend on what your hand points to. Really.","Make this gesture toward several things: the oxygen this plant produces, the water circulating underfoot, the photosynthesis that made this light possible.","Each gesture is a recognition. Not a debt — a relation. Feel the difference between the two in your body."]}},{"id":"m-ce-qui-disparait","deck":"milieux","type":"situation","fr":{"title":"Ce qui est en train de disparaître","entry":"Quelque chose dans ce monde est en train de disparaître. Laisse cette idée entrer.","body":["Pas en abstrait — une espèce, un son, une langue, un type de sol, un glacier.","Laisse le deuil pour le monde entrer dans ton corps. Ne le rationalisez pas.","La douleur pour le monde est une forme d'amour. Elle prouve que tu es connecté·e.","Reste avec cette douleur. Elle n'est pas une faiblesse. C'est une relation.","Puis sens ce qui reste. Ce qui persiste malgré tout. Ce qui pousse dans les ruines."],"retour":"Qu'est-ce que tu as senti ? Comment passe-t-on de la douleur à la relation ?","sources":["Macy : « honorer notre douleur pour le monde » — deuxième étape de la spirale du TQR","Tsing : « le champignon pousse dans les ruines du capitalisme » — la vie dans ce qui reste"],"steps":["Pense à quelque chose qui est en train de disparaître — une espèce, un son, un lieu, une langue. Quelque chose de concret, pas une abstraction.","Mime son mouvement le plus caractéristique si c'est un être vivant. Ou fais un geste vers le lieu ou la langue. Prends le temps d'y être vraiment.","Gèle. Reste dans cette posture. Sens ce que ça fait dans le corps de tenir quelque chose qui n'existera peut-être plus.","Puis : lentement, depuis cette posture, laisse quelque chose qui reste entrer. Ce qui persiste. Ce qui pousse dans les ruines.","La douleur pour le monde est une forme d'amour. Elle prouve que tu es connecté·e."]},"en":{"title":"What is disappearing","entry":"Something in this world is disappearing. Let this idea in.","body":["Not in the abstract — a species, a sound, a language, a type of soil, a glacier.","Let grief for the world enter your body. Don't rationalise it.","Pain for the world is a form of love. It proves you are connected.","Stay with this pain. It is not weakness. It is a relation.","Then feel what remains. What grows in the ruins."],"retour":"What did you feel? How do we move from pain to relation?","sources":["Macy : « honorer notre douleur pour le monde » — deuxième étape de la spirale du TQR","Tsing : « le champignon pousse dans les ruines du capitalisme » — la vie dans ce qui reste"],"steps":["Think of something disappearing — a species, a sound, a place, a language. Something concrete, not an abstraction.","Mime its most characteristic movement if it's a living being. Or make a gesture toward the place or language. Take time to truly be there.","Freeze. Stay in this posture. Feel what it does in the body to hold something that may no longer exist.","Then: slowly, from this posture, let something that remains enter. What persists. What grows in the ruins.","Pain for the world is a form of love. It proves you are connected."]}},{"id":"m-ce-que-tu-ne-sais-pas","deck":"milieux","type":"situation","fr":{"title":"Ce que tu ne sais pas encore","entry":"Tu es dans un lieu que tu ne comprends pas complètement. C'est normal.","body":["La pensée sauvage ne part pas de ce qu'elle sait. Elle part de ce qui est là.","Reste dans le non-savoir un moment. Sens sa texture dans ton corps.","Le non-savoir n'est pas une ignorance à corriger. C'est une ouverture à habiter.","Commence à bouger depuis cette ouverture — pas pour la combler, mais pour l'explorer.","Qu'est-ce que tu pourrais découvrir si tu cessais de savoir d'avance ?"],"retour":"Qu'est-ce qui s'est ouvert dans le non-savoir ?","sources":["Lévi-Strauss : la pensée sauvage opère dans le contingent, le local, ce qui est là","John Dewey, philosophe pragmatiste américain — Logique : la théorie de l'enquête (1938) — commence dans une situation indéterminée, pas dans un problème résolu"]},"en":{"title":"What you don't know yet","entry":"There is something you don't know yet that is relevant to this moment.","body":["Not a lack — a potential. The unknown is not empty.","Feel the space of the not-yet-known in your body.","Move from within this space of unknowing — without trying to fill it.","What does it feel like to move without knowing where you're going?","Trust the body's intelligence when the mind doesn't have the answer."],"retour":"What did not-knowing open up? What did the body know that the mind didn't?","sources":["Lévi-Strauss : la pensée sauvage opère dans le contingent, le local, ce qui est là","Dewey : l'enquête commence dans une situation indéterminée, pas dans un problème résolu"]}},{"id":"m-ce-qui-compose","deck":"milieux","type":"situation","fr":{"title":"Ce qui se compose ici","entry":"Quelque chose se compose dans cet espace en ce moment. Tu en fais partie.","body":["Une composition n'est pas une harmonie. C'est un arrangement précaire entre des forces différentes.","Qu'est-ce qui est en train de s'assembler ici ? Des êtres, des flux, des tensions ?","Tu es l'un des éléments de cette composition, pas son auteur·e.","Commence à te mouvoir en sentant les autres éléments de la composition.","La composition change à chaque instant. Suis-la plutôt que de la diriger."],"retour":"Comment la composition t'a-t-elle modifié·e ? Qu'as-tu apporté à la composition ?","sources":["Bruno Latour, philosophe et sociologue des sciences — Enquête sur les modes d'existence (2012) — l'assemblage comme geste politique et sensoriel","Haraway : sym-poiesis — la composition comme faire-avec, jamais seul·e"]},"en":{"title":"What is composing here","entry":"Something is composing itself here, right now, without your direction.","body":["The light, the sounds, the presences, the temperatures — they are composing.","You are part of this composition whether you choose to be or not.","Feel yourself as one element in a larger composition.","What is the composition doing? Where is it going?","Find your role in the composition — not as director, as participant."],"retour":"What were you a part of? What was the composition making?","sources":["Latour : composer un monde commun — l'assemblage comme geste politique et sensoriel","Haraway : sym-poiesis — la composition comme faire-avec, jamais seul·e"]}},{"id":"m-seuil-texture","deck":"milieux","type":"seuil","fr":{"title":"La continuité des matières","entry":"Trouve une surface naturelle. Touche-la longuement, jusqu'à oublier que ta main et elle sont deux choses séparées.","steps":["La peau et l'écorce. Les deux sont des surfaces qui protègent et qui respirent.","Cherche avec l'autre main une partie de ton corps qui a la même densité, la même température, la même résistance.","La question n'est pas 'à quoi ça ressemble' — mais 'où est la frontière ?'"],"question":"Où s'arrête ta peau et où commence le monde ?","retour":"Le corps n'est pas une forteresse. Il est un seuil.","sources":["Karen Barad — Meeting the Universe Halfway (2007) : l'intra-action comme dissolution des frontières sujet-objet","Tim Ingold — Being Alive (2011) : la peau comme zone de contact, pas de séparation"]},"en":{"title":"The continuity of materials","entry":"Find a natural surface. Touch it for a long time, until you forget that your hand and it are two separate things.","steps":["Skin and bark. Both are surfaces that protect and breathe.","Search with the other hand for a part of your body that has the same density, same temperature, same resistance.","The question is not 'what does it feel like' — but 'where is the boundary?'"],"question":"Where does your skin end and the world begin?","retour":"The body is not a fortress. It is a threshold.","sources":["Barad K. — Meeting the Universe Halfway (2007): intra-action as dissolution of subject-object boundaries","Ingold T. — Being Alive (2011): skin as zone of contact, not separation"]}}],"cc":[{"id":"c-breathing","deck":"choreo","type":"score","fr":{"title":"Respirer","entry":"Inspire par le nez lentement et profondément, en reconnaissant que tu respires des gaz anciens.","body":["Expire lentement et doucement, en reconnaissant que les gaz anciens sont maintenant transformés par ta présence temporaire.","Considère que les gaz te transforment aussi.","Reconnais que tu es accompagné·e dans ta respiration par des substances et des créatures que tu partages avec ton environnement.","À travers l'air tu es connecté·e avec des spores fongiques, des particules de plantes et de corps d'animaux, des minéraux qui originent des temps préhistoriques.","Respire avec cette connexion.","Considère ceci comme une danse."],"retour":"Qu'est-ce que l'air ancien a apporté dans ton corps ? Quelles connexions as-tu senties ?","sources":[]},"en":{"title":"Breathing","entry":"Breathe in through your nose slowly and deeply, recognizing that you are breathing in ancient gases.","body":["Breathe out slowly and gently, recognizing that the ancient gases are now transformed by your temporary presence in this moment.","Consider that the gases transform you too.","Recognize you are accompanied in your breathing by substances and creatures you share your whereabouts with.","Through the air you are connected with fungal spores, particles of plants and bodies of animals, bits of waste, hormones and minerals that originate in pre-historic times.","Breathe with this connection.","Consider this a dance."],"retour":"What did the ancient air bring into your body?","sources":[]}},{"id":"c-recycling","deck":"choreo","type":"score","fr":{"title":"Recycler","entry":"Trouve un mouvement dans l'endroit où tu te trouves — un mouvement de ton corps, ou d'autre chose.","body":["Une fois trouvé, répète la recherche 3 fois — trouve 3 mouvements différents.","Compose-les en une séquence.","Enseigne la séquence à quelqu'un d'autre.","Observe comment les mouvements changent quand l'autre personne les apprend."],"retour":"Comment le mouvement a-t-il changé en passant par un autre corps ? Qu'est-ce qui s'est perdu ? Qu'est-ce qui s'est ajouté ?","sources":[]},"en":{"title":"Recycling","entry":"Find a movement in the place you find yourself in — a movement of your own body, or a movement of something else being or entity.","body":["Once you have found a movement, repeat the search 3 times, finding 3 different movements. Compose them into a sequence.","Teach the sequence to someone else.","See how the movements change when the other person learns them.","Consider this the recycling dance."],"retour":"How did the movement change as it passed through another body?","sources":[]}},{"id":"c-synchronizing","deck":"choreo","type":"score","fr":{"title":"Synchroniser","entry":"Commence à bouger tes bras continuellement.","body":["Observe et sens ce mouvement.","Synchronise doucement ton autre main avec ce mouvement, en incluant le coude. Utilise un toucher doux.","Synchronise le timing de tes pensées avec le mouvement.","Arrête et relâche ton attention.","Remarque ce qui se passe autour de toi.","Recommence.","Si tu travailles avec d'autres : remarque la synchronisation rythmique qui émerge entre vous."],"retour":"Où la synchronisation s'est-elle produite sans effort ? Que ça fait quand la pensée se synchronise avec le mouvement ?","sources":[]},"en":{"title":"Synchronizing","entry":"Start moving your arms continuously.","body":["Observe and feel this movement.","Softly synchronize your other hand with this movement, including the elbow. Use a soft touch.","This can take you to many kinds of movement. Keep your focus on your hands and your head.","Synchronize the timing of your thoughts with the movement.","Stop and release your attention.","Notice what is going around you.","Start again."],"retour":"Where did synchronization arise without effort?","sources":[]}},{"id":"c-wandering","deck":"choreo","type":"score","fr":{"title":"Errer","entry":"Laisse tes yeux s'ouvrir. Sens ton équilibre et les vibrations sonores autour de toi.","body":["Choisis un son dans l'endroit où tu te trouves.","Erre vers ce son, jusqu'à ce que tu l'atteignes — comme tu le souhaites.","De là, écoute à nouveau. Choisis un autre son dans l'espace.","Erre vers lui, jusqu'à ce que tu l'atteignes.","Répète, continue aussi longtemps que tu le veux.","Puis trouve un chemin de retour."],"retour":"Qu'est-ce qui t'a guidé ? Qu'as-tu découvert en errant ?","sources":[]},"en":{"title":"Wandering","entry":"Let your eyes open.","body":["Sense your balance and the sound vibrations around you.","Choose a sound from the place you find yourself in.","Wander toward that sound, until you reach it — however you wish.","From that point, listen again. Choose another sound in the space you find yourself in.","Wander toward it, until you reach it.","Repeat, continue for as long as you like.","Then find a way back."],"retour":"What drew you? What surprised you along the way?","sources":[]}},{"id":"c-waiting","deck":"choreo","type":"score","fr":{"title":"Attendre","entry":"Fais environ une minute de danse libre — mais avant de commencer :","body":["Attends que ta respiration change.","Attends que quelque chose passe.","Attends la réaction de ton compagnon.","Attends que la lumière change.","Attends un signe.","Attends une deuxième pensée.","Attends d'être prêt·e.","Puis danse la danse."],"retour":"Qu'est-ce qui est arrivé quand tu as attendu ? Combien de temps a-t-il fallu ?","sources":[]},"en":{"title":"Waiting","entry":"Make about one minute of free dance — but before you make it:","body":["Wait for your breathing to change.","Wait for something to pass by.","Wait for your companion's reaction.","Wait for the right light to change.","Wait for a sign.","Wait for a second thought.","Wait until you're ready.","Then dance the dance."],"retour":"What arrived when you waited?","sources":[]}},{"id":"c-signalling","deck":"choreo","type":"score","fr":{"title":"Signaler","entry":"Crée une danse en utilisant une seule partie visible de ton corps.","body":["Une main, une jambe, un pied, une épaule, un coude, un doigt — ou ce que tu veux.","Commence et termine la danse avec un acte de signalement.","Considère ceci comme une danse de signalement."],"retour":"Qu'est-ce que tu signalais, et à qui ? Quels signaux sont revenus vers toi ?","sources":[]},"en":{"title":"Signalling","entry":"Create a dance using just one visible part of your body — a hand, leg, foot, shoulder, elbow, a finger, or anything you like.","body":["Begin and end the dance with an act of signalling.","Consider this a dance of signalling."],"retour":"What were you signalling, and to whom?","sources":[]}},{"id":"c-holding","deck":"choreo","type":"score","fr":{"title":"Tenir","entry":"Tiens une main.","body":["Tiens un objet qui te réjouit.","Tiens ton souffle.","Tiens demain.","Tiens le savoir.","Tiens le mystère.","Tiens quelque chose de léger.","Tiens l'espoir.","Tiens des os.","Tiens des compagnons.","Tiens la joie.","Tiens la profondeur.","Tiens le nouveau."],"retour":"Quelle tenue était la plus difficile ? Laquelle t'a surpris·e ?","sources":[]},"en":{"title":"Holding","entry":"Hold a hand.","body":["Hold an object that brings you joy.","Hold your breath.","Hold tomorrow.","Hold knowledge.","Hold mystery.","Hold something light.","Hold hope.","Hold bones.","Hold companions.","Hold delight.","Hold depth.","Hold the new."],"retour":"Which holding was hardest?","sources":[]}},{"id":"c-reaching","deck":"choreo","type":"score","fr":{"title":"Atteindre","entry":"Reconnais le bord de l'espace dans lequel tu te trouves.","body":["Commence à atteindre vers ce bord — lentement, sans te précipiter, en traversant chaque moment.","Ne planifie pas ce que tu rencontreras en chemin.","Juste avant d'atteindre le bord, tourne légèrement dans une autre direction.","Arrête-toi et prête attention à ton état."],"retour":"Qu'est-ce qui s'est passé juste avant que tu te détournes ? Qu'est-ce qui t'a retenu·e ?","sources":[]},"en":{"title":"Reaching","entry":"Recognize the edge of the space you're in.","body":["Start reaching toward that edge — slowly, without hurrying, moving through every moment.","Do not plan what you will encounter on the way.","Just before reaching the edge, turn lightly away in another direction.","Stop and pay attention to your state.","Consider this a reaching dance."],"retour":"What happened just before you turned away?","sources":[]}},{"id":"c-nurturing","deck":"choreo","type":"score","fr":{"title":"Nourrir","entry":"Trouve un mouvement.","body":["Trouve une façon de nourrir ce seul mouvement — deviens le jardinier du mouvement.","Ne t'enferme pas dans ce que nourrir peut signifier ici.","Vois comment le mouvement change quand il est nourri.","Ne te juge pas en termes de ce que nourrir peut signifier ici."],"retour":"De quoi ce mouvement avait-il besoin ? Comment un mouvement grandit-il quand on en prend soin ?","sources":[]},"en":{"title":"Nurturing","entry":"Find one movement.","body":["Find a way to nurture this single movement — becoming the gardener of the movement.","Do not lock yourself in terms of what nurturing can mean here.","See how the movement changes when nurtured."],"retour":"What did the movement need from you?","sources":[]}},{"id":"c-timing","deck":"choreo","type":"score","fr":{"title":"Timing","entry":"Une personne commence une danse libre.","body":["La danse peut naître de l'exploration du mouvement lui-même.","Une autre personne cherche le bon timing pour soutenir la danse.","Le bon timing pour changer la danse.","Le bon timing pour faire taire la danse.","Le bon timing pour multiplier la danse.","Le bon timing pour interrompre la danse.","Le bon timing pour rejoindre la danse."],"retour":"Quand le timing était-il juste ? Que signifie trouver le bon moment pour interrompre ou soutenir ?","sources":[]},"en":{"title":"Timing","entry":"One person starts a free form dance.","body":["The dance can arise from the exploration of movement itself, with the tools this dancer has.","Another person or persons finds a way to explore finding the right timing to support the dance.","Finding the right timing to change the dance.","Finding the right timing to silence the dance.","Finding the right timing to multiply the dance.","Finding the right timing to interrupt the dance.","Finding the right timing to join the dance."],"retour":"When did the timing feel right?","sources":[]}},{"id":"c-decomposing","deck":"choreo","type":"score","fr":{"title":"Décomposer","entry":"Crée une danse où chaque partie de ton corps fait quelque chose de différent.","body":["Un mouvement connecté et ancré.","Profite de cette abondance et laisse-la te décomposer."],"retour":"Comment la décomposition s'est-elle sentie de l'intérieur ? Qu'est-ce qui restait après ?","sources":[]},"en":{"title":"Decomposing","entry":"Create a dance where every part of your body does something different — a connected and grounded movement.","body":["Enjoy this abundance and let it decompose you."],"retour":"What did decomposition feel like from the inside?","sources":[]}},{"id":"c-transforming","deck":"choreo","type":"score","fr":{"title":"Transformer","entry":"Transforme l'espace.","body":["Transforme les relations.","Transforme tes pensées.","Transforme ton habitat.","Transforme ta fréquence.","Transforme ton mouvement."],"retour":"Quelle transformation est venue le plus naturellement ? Laquelle semblait impossible ?","sources":[]},"en":{"title":"Transforming","entry":"Transform the space.","body":["Transform the relations.","Transform your thoughts.","Transform your habitat.","Transform your frequency.","Transform your movement."],"retour":"Which transformation came most naturally?","sources":[]}},{"id":"c-connecting","deck":"choreo","type":"score","fr":{"title":"Connecter","entry":"Trouve deux choses, créatures ou entités dans cet endroit à connecter.","body":["Ne suppose pas que les choses, personnes ou créatures répondront à cette tentative.","Concentre-toi — elles vont tenter une connexion.","Fais une danse qui danse ces connexions.","Sois ouvert·e à l'endroit où cela te mène."],"retour":"Qu'est-ce qui s'est connecté ? Qu'est-ce qui a résisté à la connexion ?","sources":[]},"en":{"title":"Connecting","entry":"Find two things, creatures or entities where you are now to connect with.","body":["Do not assume that the things, people, creatures or entities will respond to this attempt — concentrate, they will attempt to make a connection.","Do a dance that dances these connections.","Be open to where this leads you."],"retour":"What connected? What resisted connection?","sources":[]}},{"id":"c-growing","deck":"choreo","type":"score","fr":{"title":"Croître","entry":"Fais croître un petit mouvement de ton corps.","body":["Passe au petit mouvement suivant, en continuant depuis le précédent.","Laisse ces petits mouvements se transformer en un flux lent de danse sans excès d'effort."],"retour":"À quel moment les mouvements ont-ils commencé à sembler vivants ?","sources":[]},"en":{"title":"Growing","entry":"Grow a small movement out of your body.","body":["Move on to the next small movement, continuing from the previous small movement.","Allow these small movements to turn into a slow flow of dance without an excess of effort.","Consider this a dance of growing movement."],"retour":"At what point did the movements start to feel alive?","sources":[]}},{"id":"c-sensing","deck":"choreo","type":"score","fr":{"title":"Sentir","entry":"Sens la température de l'espace.","body":["Sens l'humidité de l'espace. Sens l'air de l'espace.","Sens les ondes dans l'espace. Sens les fantômes dans l'espace.","Sens la friction dans l'espace. Sens les odeurs autour de toi.","Sens les sons. Sens les traces de toucher.","Sens ce qui te touche et ce que tu touches.","Sens les mouvements dans l'espace. Sens que quelque chose remue.","Incarne cela et bouge. Considère ceci comme tes sens chorégraphiant ton attention."],"retour":"Quel sens était le plus vif ? Qu'as-tu senti que tu n'avais pas remarqué avant ?","sources":[]},"en":{"title":"Sensing","entry":"Sense the temperature of the room.","body":["Sense the moisture of the room.","Sense the air of the room.","Sense the waves in the room.","Sense the ghosts in the room.","Sense the friction in the room.","Sense the odours around you.","Sense the sounds.","Sense the traces of touch.","Sense what touches you and what you touch.","Sense the movements in the room.","Sense that something stirs.","Embody this and move.","Consider this to be your senses choreographing your attention."],"retour":"Which sense was most vivid?","sources":[]}},{"id":"c-entangling","deck":"choreo","type":"score","fr":{"title":"S'enchevêtrer","entry":"Enroule doucement ton corps autour de quelque chose que tu es maintenant.","body":["Un autre corps, un objet, un meuble, un arbre, un livre, quelque chose.","Appelons cela un petit enchevêtrement.","Continue à bouger avec ton enchevêtrement, très légèrement, avec un toucher léger.","Passe du temps dans cet enchevêtrement, en respirant, en attendant.","Garde un toucher léger.","Dissous l'enchevêtrement lentement et sens ce qui reste dans ton corps."],"retour":"Qu'est-ce que la chose avec laquelle tu t'es enchevêtré·e t'a offert ?","sources":[]},"en":{"title":"Entangling","entry":"Wrap your body gently around something you are near — another body, an object, a piece of furniture, a tree, a book, some thing.","body":["Let's call this a small entanglement.","Keep moving with your entanglement ever so slightly, with a light touch.","Spend time in this entanglement, breathing, waiting.","Keep a light touch.","Dissolve the entanglement slowly and feel what remains in your body."],"retour":"What did the thing you entangled with offer you?","sources":[]}},{"id":"c-decaying","deck":"choreo","type":"score","fr":{"title":"Se décomposer","entry":"Pense à quelque chose qui se décompose — un fruit, une feuille, un os.","body":["Laisse l'image de cette décomposition entrer dans ton corps.","Commence à bouger depuis cette image — lentement, sans forcer.","La décomposition n'est pas la mort. C'est une transformation.","Sens ce qui se libère quand quelque chose se défait."],"retour":"Qu'est-ce qui s'est libéré ? Qu'est-ce qui a changé de forme sans disparaître ?","sources":[]},"en":{"title":"Decaying","entry":"Lay down horizontally on the floor or ground. Let go of holding your muscles, bit by bit, relax.","body":["Let your breathing support your relaxation. Fall into decay.","Listen to the sound of your body deteriorating, decaying.","Recognize the movements of this decaying inside and on the surface of your body.","Follow the movements of decay and allow them to turn into a dance.","Sit near the person lying down. Tune in to their micro-movements and breathing.","Place your hands on their body. Gently squeeze, mobilize, softly touch connective tissue.","Do this with an intention to decay the person lying down.","Pay attention to the movements happening in their body. Follow them.","Recognize this to be a dance of decaying."],"retour":"What does it feel like to be decayed by another?","sources":[]}},{"id":"c-channelling","deck":"choreo","type":"score","fr":{"title":"Canaliser","entry":"Identifie quelque chose qui coule, se déplace, circule dans cet espace.","body":["L'air, la lumière, un son, une énergie, une intention.","Laisse ton corps devenir un canal pour ce mouvement.","Ne le dirige pas. Laisse-le te traverser.","Sens la différence entre générer un mouvement et le laisser passer."],"retour":"Qu'est-ce qui t'a traversé·e ? Comment ça se sent d'être canal plutôt que source ?","sources":[]},"en":{"title":"Channelling","entry":"Get on all fours, make this position comfortable for you.","body":["Tune in to the fungal consciousness below — imagine your body as a channel.","With open awareness and clarity, let your jaw relax and connect to the subtle movements of the mycelium below.","Activate the knowledge that your tongue is made of the same stuff as mycelium.","Allow the mycelium language to release and flow along your tongue.","Let fungal consciousness move along this channel on your breath.","Breathe in and out again, let the air flow and the fungal connections move with it.","Pay attention to the sound of your breathing.","Continue until you feel your mouth drying.","End by closing your eyes."],"retour":"What passed through you?","sources":[]}},{"id":"c-lifting","deck":"choreo","type":"score","fr":{"title":"Soulever","entry":"Quelque chose a besoin d'être soulevé dans cet espace.","body":["Pas nécessairement un objet. Quelque chose de lourd — un état, une atmosphère, un silence.","Commence à bouger comme si tu soulevais quelque chose.","Sens le poids. Sens l'effort. Sens ce qui change quand la chose se lève.","Pose-la doucement ailleurs."],"retour":"Qu'est-ce qui était lourd ? Qu'est-ce qui a changé quand c'est devenu plus léger ?","sources":[]},"en":{"title":"Lifting","entry":"Lift something impossible for you to lift.","body":["Lift something which is too light.","Lift something which has the same weight as your thoughts.","Lift something which is the same weight as your feelings.","Continue varying with some lifts for some time.","Expand the lifting to the room around you, to places further away, to the field of your awareness.","Expand the lifting to the realm of the invisible.","Consider this a dance of lifting, by itself."],"retour":"What was heaviest — the possible or the impossible?","sources":[]}},{"id":"c-healing","deck":"choreo","type":"score","fr":{"title":"Guérir","entry":"Touche une main avec l'autre main, en observant et en sentant le mouvement de toucher.","body":["Élargis ce toucher à d'autres parties de ton corps.","Fais attention à ton changement d'état.","Élargis ce mouvement de guérison à ton environnement, en caressant tout autour de toi.","Élargis le caressage à la pièce autour de toi, vers des endroits plus éloignés.","Élargis le caressage au domaine de l'invisible.","Considère ceci comme une danse de guérison, par elle-même."],"retour":"Qu'est-ce qui a changé en toi quand la guérison s'est élargie vers l'extérieur ?","sources":[]},"en":{"title":"Healing","entry":"Touch one hand with the other hand, observing and sensing the touching move.","body":["Expand this touch to other parts of your body.","Pay attention to your change of state.","Expand this healing movement to your environment, stroking everything around you.","Expand the stroking to the room around you, to places further away, to the field of your awareness.","Expand the stroking to the realm of the invisible.","Consider this a dance of healing, by itself."],"retour":"What changed in you as the healing expanded outward?","sources":[]}},{"id":"c-trickstering","deck":"choreo","type":"score","fr":{"title":"Tromper","entry":"Choisis quelque chose dans l'espace — une règle, une attente, une habitude.","body":["Décide de ne pas la respecter — avec douceur, sans violence.","Le trickster ne détruit pas. Il dévie.","Trouve le geste qui contourne, qui esquive, qui surprend.","Observe la réaction de l'espace et des autres."],"retour":"Qu'est-ce qui s'est ouvert en déviant ? Quelle règle était plus fragile que tu ne le pensais ?","sources":[]},"en":{"title":"Trickstering","entry":"Awaken a mood of trickstering in yourself.","body":["Invent secrets.","Take nothing for granted.","Tune laughter and lightness.","In this way, find new pathways through movement.","Consider this a dance of trickstering."],"retour":"What secrets did you invent?","sources":[]}},{"id":"c-travelling","deck":"choreo","type":"score","fr":{"title":"Voyager","entry":"Tu vas voyager à travers cet espace — mais pas comme tu le ferais normalement.","body":["Choisis une qualité de mouvement : très lent, très haut, très proche du sol.","Voyage à travers l'espace avec cette qualité.","Remarque comment le voyage change la perception de l'espace.","Arrive quelque part. Sens l'arrivée."],"retour":"Comment le voyage a-t-il transformé l'espace ? Qu'est-ce que l'arrivée a changé ?","sources":[]},"en":{"title":"Travelling","entry":"Set yourself in movement wherever you find yourself.","body":["With this movement, travel toward light, opportunities, pleasure, continuation.","End your journey by clapping your hands once and shouting 'joy-hitter'."],"retour":"What did you travel toward?","sources":[]}},{"id":"c-rooting","deck":"choreo","type":"score","fr":{"title":"S'enraciner","entry":"Sens les points de contact entre ton corps et le sol.","body":["Commence à imaginer des racines qui partent de ces points.","Les racines cherchent l'eau, le contact, la résistance — pas la lumière.","Laisse les racines s'étendre lentement, profondément.","Depuis cet enracinement, commence à bouger — vers le haut, vers le large.","L'enracinement n'est pas l'immobilité. C'est la condition du mouvement."],"retour":"Qu'est-ce que l'enracinement a permis que le flottement n'aurait pas permis ?","sources":[]},"en":{"title":"Rooting","entry":"Stand with your feet, firmly on the ground.","body":["Raise the soles of your feet.","Listen to the sources of movement under your feet, connecting you to ground, drawing on soil and roots.","Let your own movement connect to these underground movement roots.","Let this become a dance of rooting."],"retour":"What was beneath you?","sources":[]}},{"id":"c-energizing","deck":"choreo","type":"score","fr":{"title":"S'énergiser","entry":"Secoue tout ton corps pendant 5 à 15 minutes.","body":["Tente de faire de la place pour les impulsions électriques qui voyagent dans tes nerfs.","Prête attention à l'état énergisé qui naît de ce secouement.","Considère comment tout vibre aussi.","Invite-toi à te rendre à ce vaisseau d'abondance énergisante.","Considère ceci comme une danse énergisante."],"retour":"Qu'est-ce que le secouement a libéré ? Qu'est-ce qui vibrait encore après ?","sources":[]},"en":{"title":"Energizing","entry":"Shake your whole body for 5–15 minutes.","body":["Attempt to make space for the electric impulses travelling through your nerves.","Pay attention to the energized state arising from this shaking.","Consider how everything also vibrates.","Invite yourself to surrender to this vessel of energizing abundance.","Consider this an energizing dance."],"retour":"What did the shaking release?","sources":[]}},{"id":"c-disguising","deck":"choreo","type":"score","fr":{"title":"Se déguiser","entry":"Choisis quelque chose dans cet espace qui n'est pas toi.","body":["Un objet, une texture, une qualité de lumière, un son.","Laisse ton corps se déguiser en cette chose — pas en l'imitant, mais en l'habitant.","Déplace-toi comme si tu étais cette chose.","Observe ce que ce déguisement révèle de toi."],"retour":"Qu'est-ce qui était différent de toi dans ce déguisement ? Qu'est-ce qui était étrangement familier ?","sources":[]},"en":{"title":"Disguising","entry":"Move through the room as the space you find yourself in offers you possibilities.","body":["Consider this a dance of disguise."],"retour":"What were you disguising?","sources":[]}},{"id":"c-forming","deck":"choreo","type":"score","fr":{"title":"Former","entry":"Commence avec n'importe quelle forme — une forme que ton corps veut prendre maintenant.","body":["Reste dans cette forme un moment. Sens ses bords, ses volumes, ses tensions.","Laisse la forme évoluer — très lentement, sans rupture.","La forme n'est pas une posture. Elle est en mouvement même quand elle est immobile.","Arrive à une forme finale. Laisse-la exister quelques instants."],"retour":"Quelle forme voulait naître ? Qu'est-ce que la forme finale t'a dit ?","sources":[]},"en":{"title":"Forming","entry":"Make a form with your body — a deliberate formulation of a human posture.","body":["Recognize the feeling of this form.","Make another form.","Pay attention to how you transform from one form to another.","Continue as long as you like.","Dismantle the last form by melting your body down on the surface of the floor or ground."],"retour":"Which form felt most true?","sources":[]}},{"id":"c-shapeshifting","deck":"choreo","type":"score","fr":{"title":"Muer","entry":"Debout, yeux fermés, respire. Rassemble ta concentration.","body":["Derrière tes yeux fermés, invite la forme d'un champignon à t'apparaître comme une image intérieure.","Cela peut arriver tout de suite, ou prendre plus de temps.","Quand le champignon apparaît, prête attention à la forme de son corps.","Yeux toujours fermés, mue ton propre corps dans la forme du champignon tel qu'il t'est apparu.","Marque cette forme dans la mémoire de ton corps et invite-la à y rester comme amie.","Ouvre les yeux."],"retour":"Quel champignon est apparu ? Comment était-ce d'habiter une autre forme ?","sources":[]},"en":{"title":"Shape Shifting","entry":"Stand with eyes closed and breathe. Gather your concentration.","body":["Behind your closed eyes, invite a form of a mushroom to appear to you as an internal image.","This might happen right away, or it might take longer.","Maybe you know this mushroom from experience, maybe it's a new form.","When the mushroom appears, pay attention to the shape of its body.","With eyes still closed, shape shift your own body into the shape of the mushroom as it appeared to you.","What is this shape like, how does it feel? Pay attention to the form you shifted into.","Mark this shape in your body memory and invite it to stay there as a friend to return to later.","Open your eyes."],"retour":"What mushroom appeared?","sources":[]}},{"id":"c-spreading","deck":"choreo","type":"score","fr":{"title":"Se répandre","entry":"Commence à partir d'un point dans l'espace.","body":["Commence à te répandre à partir de ce point — lentement, dans toutes les directions.","Tu peux te répandre en te déplaçant, ou en étendant ton corps, ou par le regard et l'attention.","Sens la différence entre t'étendre et envahir.","Trouve les limites de ta propagation. Respecte-les."],"retour":"Jusqu'où t'es-tu répandu·e ? Qu'est-ce qui t'a arrêté·e ?","sources":[]},"en":{"title":"Spreading","entry":"Close your fingers as if holding something small in your hand.","body":["Concentrate on the space created inside your hand.","Connect this space to your whole body.","Open your fingers with a movement releasing the space.","Dispose your hands into the place you find yourself.","See where this leads you."],"retour":"What did you release?","sources":[]}},{"id":"c-touching","deck":"choreo","type":"score","fr":{"title":"Toucher","entry":"Le toucher est un état dans lequel il n'y a pas de séparation entre deux choses.","body":["Tu existes au point où ton pied touche le sol.","Touche une partie de ton corps avec ta main. Puis une autre, puis une autre.","Le son touche ton tympan, ou ton tympan le son.","Touche quelque chose de proche, puis touche autre chose.","Tu peux aussi toucher avec une pensée ou en regardant.","Continue aussi longtemps que tu veux. Considère ceci comme une danse."],"retour":"Où la frontière entre toi et la chose a-t-elle disparu ? Qu'est-ce qui a touché en retour ?","sources":[]},"en":{"title":"Touching","entry":"Touch is a state in which there is no separation between two things, creatures, matter or materials.","body":["You exist at the point where your foot touches the floor.","Touch a part of your body with your hand. Then another part, then another.","Sound touches your eardrum, or your eardrum the sound.","Touch something near you, then touch something else.","Continue — something further away, different things, surfaces, objects.","Notice what comes back and live.","You can also touch with a thought or by looking.","Continue as long as you like.","Consider this a dance."],"retour":"Where did the boundary between you and the thing disappear?","sources":[]}},{"id":"c-pushing","deck":"choreo","type":"score","fr":{"title":"Pousser","entry":"Sens la structure de ta tête — le crâne, le visage, le cerveau.","body":["Place ta main sur ton front et pousse doucement — expérimente la poussée qui traverse ton corps.","Change l'endroit de la main, répète et remarque la différence.","Sélectionne une surface, un objet, une plante dans l'espace — approche-toi et presse ta tête contre.","Remarque la force de la poussée selon ce que tu rencontres.","Arrête. Sélectionne autre chose, bouge vers elle et pousse à nouveau.","Varie la longueur et la force.","Puis sens à nouveau la structure de ta tête. Sens les traces de la poussée. Relâche."],"retour":"Qu'est-ce qui a poussé en retour ? Quelles traces la poussée a-t-elle laissées ?","sources":[]},"en":{"title":"Pushing","entry":"Feel the structure of your head — the skull, face, brain, the membranes and liquids inside.","body":["Place your hand on your forehead and push gently away — experience the push going through your body.","Change the place of the hand to the side, repeat and notice the different experience.","Select a surface, an object, a plant in the space — go next to it and press your head against it.","Notice the strength of the pushing according to what you meet and push against.","Stop pushing. Select some other thing, move to it and push again.","Vary the length and strength of the pushing. Continue for as long as you like.","Then, for a moment, feel the structure of your head again. Feel the traces of pushing.","Then let go. Release."],"retour":"What pushed back?","sources":[]}},{"id":"c-fruiting","deck":"choreo","type":"score","fr":{"title":"Fructifier","entry":"Quelque chose en toi est prêt à émerger.","body":["Pas nécessairement quelque chose de grand. Quelque chose de mûr.","Commence à bouger depuis cet endroit de maturité.","La fructification n'est pas une explosion. C'est une plénitude qui se donne.","Trouve le geste de l'offrande — pas de la performance.","Laisse ce qui était intérieur devenir extérieur."],"retour":"Qu'est-ce qui était mûr en toi ? À qui ou à quoi cette fructification s'adressait-elle ?","sources":[]},"en":{"title":"Fruiting","entry":"Find a place in the space where you might fruit.","body":["Let your body slowly build toward something — a form, a gesture, a presence.","Do not hurry this ripening.","When you feel the fruit is ready, offer it to the space.","Notice what the space does with what you have offered.","Slowly return to the ground.","Consider this a dance of fruiting."],"retour":"What ripened in you?","sources":[]}}],"tc":[{"id":"t-marcher-comme","deck":"terrains","type":"geste","fr":{"title":"Marcher comme","entry":"Choisis quelque chose qui n'est pas toi : un nuage, un crabe, de la mousse, une rivière paresseuse.","steps":["Marche comme cette chose. Pas en l'imitant exactement — en laissant son rythme, sa qualité, entrer dans tes pieds.","Continue jusqu'à ce que tu ne saches plus très bien qui marche."],"trace":null,"question":"Qu'est-ce que cette chose sait marcher que toi tu oublies ?","sources":[]},"en":{"title":"Walking like","entry":"Choose something that is not you: a cloud, a crab, some moss, a lazy river.","steps":["Walk like this thing. Not imitating it exactly — letting its rhythm, its quality, enter your feet.","Continue until you're not quite sure who is walking."],"trace":null,"question":"What does this thing know about walking that you forget?","sources":[]}},{"id":"t-tomber","deck":"terrains","type":"geste","fr":{"title":"Tomber lentement","entry":"Tu vas tomber. Mais très, très lentement.","steps":["Prends une minute entière pour tomber — en partant debout et en arrivant au sol.","Le sol n'est pas une destination. C'est une rencontre.","Reste au sol un moment. Sens ce qui te porte maintenant."],"trace":null,"question":"Qu'est-ce qui s'est passé dans la chute lente que tu n'avais pas prévu ?","sources":[]},"en":{"title":"Falling slowly","entry":"You are going to fall. But very, very slowly.","steps":["Take a full minute to fall — starting standing and arriving at the floor.","The floor is not a destination. It is an encounter.","Stay on the floor a moment. Feel what carries you now."],"trace":null,"question":"What happened in the slow fall that you hadn't expected?","sources":[]}},{"id":"t-tete","deck":"terrains","type":"geste","fr":{"title":"Objet sur la tête","entry":"Pose quelque chose sur ta tête. N'importe quoi qui traîne.","steps":["Bouge maintenant. Avec cet objet sur ta tête.","Remarque comment tout ton mouvement change — ton dos, tes yeux, ton rapport à l'espace.","Si l'objet tombe, c'est une information. Ramasse-le et recommence."],"trace":"Dessine la trajectoire que tu as faite avec l'objet sur la tête.","question":"Qu'est-ce que l'objet t'a appris sur ta façon d'habiter l'espace ?","sources":[]},"en":{"title":"Object on head","entry":"Put something on your head. Anything that's lying around.","steps":["Move now. With this object on your head.","Notice how your whole movement changes — your back, your eyes, your relation to space.","If the object falls, that's information. Pick it up and start again."],"trace":"Draw the trajectory you made with the object on your head.","question":"What did the object teach you about how you inhabit space?","sources":[]}},{"id":"t-tres-petit","deck":"terrains","type":"geste","fr":{"title":"Très petit","entry":"Fais-toi aussi petit·e que possible. Puis encore plus petit·e.","steps":["Reste dans cette petitesse. Respires-y.","Maintenant explore l'espace depuis cette taille. Qu'est-ce que tu vois que tu ne vois pas d'habitude ?","Quand tu es prêt·e, grandis lentement — mais garde quelque chose de la petitesse en toi."],"trace":null,"question":"Qu'est-ce qui était visible depuis là-bas en bas ?","sources":[]},"en":{"title":"Very small","entry":"Make yourself as small as possible. Then even smaller.","steps":["Stay in this smallness. Breathe there.","Now explore the space from this size. What do you see that you normally don't?","When you're ready, grow slowly — but keep something of the smallness in you."],"trace":null,"question":"What was visible from down there?","sources":[]}},{"id":"t-son","deck":"terrains","type":"geste","fr":{"title":"Danser un son","entry":"Fais un son avec ta bouche — n'importe lequel.","steps":["Maintenant laisse ce son bouger ton corps. Pas toi qui bouges — le son qui bouge ton corps.","Change le son. Sens comment le mouvement change.","Arrête le son. Observe ce qui reste dans le corps."],"trace":null,"question":"Le son et le corps — lequel commandait vraiment ?","sources":[]},"en":{"title":"Dancing a sound","entry":"Make a sound with your mouth — any sound.","steps":["Now let this sound move your body. Not you moving — the sound moving your body.","Change the sound. Feel how the movement changes.","Stop the sound. Observe what remains in the body."],"trace":null,"question":"The sound and the body — which one was really in charge?","sources":[]}},{"id":"t-yeux-fermes","deck":"terrains","type":"geste","fr":{"title":"Yeux fermés, mains ouvertes","entry":"Ferme les yeux. Ouvre les mains, paumes vers le haut.","steps":["Reste immobile un moment. Sens ce que tes mains reçoivent — chaleur, air, lumière, rien.","Commence à te déplacer lentement, yeux toujours fermés, mains toujours ouvertes.","Laisse les mains te guider plutôt que les yeux."],"trace":null,"question":"Que reçoivent les mains que les yeux ne peuvent pas recevoir ?","sources":[]},"en":{"title":"Eyes closed, hands open","entry":"Close your eyes. Open your hands, palms upward.","steps":["Stay still for a moment. Feel what your hands receive — warmth, air, light, nothing.","Start moving slowly, eyes still closed, hands still open.","Let your hands guide you rather than your eyes."],"trace":null,"question":"What do hands receive that eyes cannot?","sources":[]}},{"id":"t-lent-vite","deck":"terrains","type":"geste","fr":{"title":"Le plus lent possible","entry":"Déplace ta main de ton genou à ton visage. Prends au moins deux minutes.","steps":["Ce n'est pas une performance de lenteur — c'est une exploration de ce qui existe dans chaque millimètre.","Qu'est-ce qui se passe dans le trajet ? Quels muscles, quelles sensations, quels moments de doute ?","À l'arrivée : reste avec ta main sur ton visage un instant."],"trace":"Écris un mot pour chaque 'moment' que tu as traversé dans le trajet.","question":"Combien de pays y avait-il entre ton genou et ton visage ?","sources":[]},"en":{"title":"As slow as possible","entry":"Move your hand from your knee to your face. Take at least two minutes.","steps":["This is not a performance of slowness — it is an exploration of what exists in each millimetre.","What happens on the journey? Which muscles, which sensations, which moments of doubt?","On arrival: stay with your hand on your face for a moment."],"trace":"Write one word for each 'moment' you passed through on the journey.","question":"How many countries were there between your knee and your face?","sources":[]}},{"id":"t-imiter","deck":"terrains","type":"geste","fr":{"title":"Imiter sans savoir","entry":"Observe quelqu'un ou quelque chose qui bouge. En secret.","steps":["Imite ce mouvement — discrètement, dans ton propre corps, sans que l'autre le sache.","Laisse l'imitation devenir très petite — une qualité, pas une forme.","Maintenant seulement tu peux laisser cette qualité prendre toute la place."],"trace":null,"question":"Qu'est-ce que tu as volé ? Était-ce du vol ?","sources":[]},"en":{"title":"Imitating without knowing","entry":"Observe someone or something that moves. In secret.","steps":["Imitate this movement — discreetly, in your own body, without the other knowing.","Let the imitation become very small — a quality, not a shape.","Only now let this quality take up all the space."],"trace":null,"question":"What did you steal? Was it stealing?","sources":[]}},{"id":"t-objet-ami","deck":"terrains","type":"relation","fr":{"title":"L'objet ami","entry":"Choisis un objet dans cet espace — pas le plus beau, pas le plus intéressant. Le premier qui te regarde.","steps":["Tiens-le. Sens son poids, sa température, sa texture.","Déplace-toi avec lui comme s'il était un partenaire de danse, pas un accessoire.","À un moment : laisse l'objet mener."],"trace":"Écris une phrase que l'objet te dirait s'il pouvait parler.","question":"Qu'est-ce que cet objet sait de toi ?","sources":[]},"en":{"title":"The friendly object","entry":"Choose an object in this space — not the most beautiful, not the most interesting. The first one that looks at you.","steps":["Hold it. Feel its weight, its temperature, its texture.","Move with it as if it were a dance partner, not a prop.","At some point: let the object lead."],"trace":"Write one sentence the object would say to you if it could speak.","question":"What does this object know about you?","sources":[]}},{"id":"t-pierre","deck":"terrains","type":"relation","fr":{"title":"La pierre qui danse","entry":"Ramasse une pierre. Tiens-la dans ta paume fermée.","steps":["Commence à bouger — mais laisse la pierre décider du centre de gravité.","Laisse son poids organiser ton corps autour d'elle.","À un moment, pose la pierre au sol. Continue à bouger comme si tu la tenais encore."],"trace":"Dessine la pierre. Pas comme elle est — comme elle se sent.","question":"La pierre t'a-t-elle guidé·e quelque part ? Où ?","sources":[]},"en":{"title":"The dancing stone","entry":"Pick up a stone. Hold it in your closed palm.","steps":["Start moving — but let the stone decide the centre of gravity.","Let its weight organise your body around it.","At some point, set the stone down. Keep moving as if you were still holding it."],"trace":"Draw the stone. Not as it is — as it feels.","question":"Did the stone guide you somewhere? Where?","sources":[]}},{"id":"t-ombre-relation","deck":"terrains","type":"relation","fr":{"title":"Jouer avec son ombre","entry":"Trouve ta propre ombre (s'il y a de la lumière pour ça). Regarde-la.","steps":["L'ombre est toi — mais pas tout à fait toi. C'est toi vu par la lumière.","Commence à bouger pour l'ombre. Essaie de la surprendre.","À un moment, arrête de bouger. Observe l'ombre s'immobiliser juste après toi."],"trace":null,"question":"L'ombre est-elle toi ? Comment tu le sais ?","sources":[]},"en":{"title":"Playing with your shadow","entry":"Find your own shadow (if there's light for that). Look at it.","steps":["The shadow is you — but not quite you. It is you as seen by the light.","Start moving for the shadow. Try to surprise it.","At some point, stop moving. Watch the shadow stop just after you."],"trace":null,"question":"Is the shadow you? How do you know?","sources":[]}},{"id":"t-plante","deck":"terrains","type":"relation","fr":{"title":"La plante qui attend","entry":"Trouve une plante — une herbe, un arbuste, une plante d'intérieur. Approche-toi.","steps":["Observe-la pendant une minute entière. Vraiment.","Cette plante est en train de faire quelque chose maintenant — grandir, absorber, respirer. Rejoins son rythme.","Bouge à son rythme. Le rythme d'une plante est très lent. C'est bien."],"trace":"Écris un mot pour chaque chose que tu as remarqué dans la plante.","question":"Qu'est-ce que la plante attendait ?","sources":[]},"en":{"title":"The waiting plant","entry":"Find a plant — a blade of grass, a shrub, a houseplant. Come close.","steps":["Observe it for a full minute. Really.","This plant is doing something right now — growing, absorbing, breathing. Join its rhythm.","Move at its rhythm. A plant's rhythm is very slow. That's fine."],"trace":"Write one word for each thing you noticed in the plant.","question":"What was the plant waiting for?","sources":[]}},{"id":"t-inconnu","deck":"terrains","type":"relation","fr":{"title":"Danser vers quelqu'un","entry":"Il y a quelqu'un dans cet espace. Danse vers lui/elle/eux — sans qu'il/elle/ils le sache.","steps":["Pas de performance. Pas de séduction. Une attention.","Ton mouvement s'oriente vers cette personne comme une plante vers la lumière — sans le décider.","À un moment, détourne-toi. Sens ce que ça change."],"trace":null,"question":"La danse en direction de quelqu'un — est-ce que ça change ce qu'on danse ?","sources":[]},"en":{"title":"Dancing toward someone","entry":"There is someone in this space. Dance toward them — without them knowing.","steps":["Not a performance. Not seduction. An attention.","Your movement orients toward this person like a plant toward light — without deciding to.","At some point, turn away. Feel what changes."],"trace":null,"question":"Dancing in the direction of someone — does it change what you dance?","sources":[]}},{"id":"t-observer-ecrire","deck":"terrains","type":"trace","fr":{"title":"Observer, écrire","entry":"Choisis un endroit. Assieds-toi. Regarde pendant cinq minutes sans écrire.","steps":["Puis écris — pas ce que tu as vu, mais ce qui t'est arrivé pendant que tu regardais.","Pas de belle phrase. Des fragments, des mots, des lacunes.","Relis. Souligne une chose. Lève-toi et bouge depuis cette chose."],"trace":"Le texte lui-même est la trace.","question":null,"sources":[]},"en":{"title":"Observe, write","entry":"Choose a place. Sit down. Look for five minutes without writing.","steps":["Then write — not what you saw, but what happened to you while you were looking.","No beautiful sentences. Fragments, words, gaps.","Read it back. Underline one thing. Stand up and move from that thing."],"trace":"The text itself is the trace.","question":null,"sources":[]}},{"id":"t-dessiner-mouvement","deck":"terrains","type":"trace","fr":{"title":"Dessiner le mouvement","entry":"Prends un crayon ou un stylo. Pose-le sur une page.","steps":["Bouge ton corps — et laisse la main qui tient le crayon suivre le mouvement du reste du corps.","Pas de l'art. Un enregistrement.","Continue jusqu'à ce que tu ne saches plus si c'est le corps qui bouge le crayon ou le crayon qui bouge le corps."],"trace":"La page elle-même.","question":"Est-ce que ça ressemble à quelque chose ? Est-ce que ça doit ressembler à quelque chose ?","sources":[]},"en":{"title":"Drawing movement","entry":"Take a pencil or pen. Place it on a page.","steps":["Move your body — and let the hand holding the pencil follow the movement of the rest of the body.","Not art. A recording.","Continue until you no longer know if the body is moving the pencil or the pencil moving the body."],"trace":"The page itself.","question":"Does it look like something? Does it need to?","sources":[]}},{"id":"t-cartographie","deck":"terrains","type":"trace","fr":{"title":"Cartographier l'espace","entry":"Parcours l'espace dans lequel tu te trouves pendant deux minutes.","steps":["Puis dessine une carte de cet espace — pas une carte fidèle, une carte de ce qui compte.","Ce qui est grand sur ta carte est grand parce que c'est important, pas parce que c'est grand dans la réalité.","Montre ta carte à quelqu'un si tu veux. Explique-lui ce qui est grand et pourquoi."],"trace":"La carte.","question":"Qu'est-ce qui est devenu plus grand que dans la réalité ? Pourquoi ?","sources":[]},"en":{"title":"Mapping the space","entry":"Move through the space you're in for two minutes.","steps":["Then draw a map of this space — not an accurate map, a map of what matters.","What is big on your map is big because it's important, not because it's big in reality.","Show your map to someone if you want. Explain what is big and why."],"trace":"The map.","question":"What became bigger than in reality? Why?","sources":[]}},{"id":"t-ecrire-corps","deck":"terrains","type":"trace","fr":{"title":"Écrire avec le corps","entry":"Choisis une lettre de l'alphabet — ou une lettre de quelqu'un qui t'est cher.","steps":["Écris cette lettre avec ton corps entier. Dans l'espace. Lentement.","Puis écris un mot. Sens ce que chaque lettre demande à ton corps.","Choisis un mot qui compte pour toi aujourd'hui."],"trace":"Écris ce mot aussi sur papier, après, avec ta main. Est-ce que ça change quelque chose ?","question":"Le corps a-t-il une façon d'écrire différente de la main ?","sources":[]},"en":{"title":"Writing with the body","entry":"Choose a letter of the alphabet — or a letter from someone dear to you.","steps":["Write this letter with your whole body. In space. Slowly.","Then write a word. Feel what each letter asks of your body.","Choose a word that matters to you today."],"trace":"Write this word also on paper, afterward, with your hand. Does it change anything?","question":"Does the body have a different way of writing than the hand?","sources":[]}},{"id":"t-portrait","deck":"terrains","type":"trace","fr":{"title":"Portrait d'un lieu","entry":"Tu vas faire le portrait d'un lieu — pas une photo, un portrait.","steps":["Promène-toi dans ce lieu pendant cinq minutes. Sens-le.","Dessine son portrait. Un portrait montre le caractère, pas l'apparence.","Donne un titre au portrait."],"trace":"Le dessin avec son titre.","question":"Si ce lieu avait un visage, il ressemblerait à quoi ?","sources":[]},"en":{"title":"Portrait of a place","entry":"You are going to make a portrait of a place — not a photo, a portrait.","steps":["Walk through this place for five minutes. Feel it.","Draw its portrait. A portrait shows character, not appearance.","Give the portrait a title."],"trace":"The drawing with its title.","question":"If this place had a face, what would it look like?","sources":[]}},{"id":"t-liste","deck":"terrains","type":"trace","fr":{"title":"La liste","entry":"Écris une liste de tout ce que tu perçois en ce moment. Dix choses. Rapidement.","steps":["Puis lis la liste. Choisis la chose la plus surprenante.","Approche-toi de cette chose. Reste avec elle deux minutes.","Reviens à ta liste. Ajoute ce que tu n'avais pas vu d'abord."],"trace":"La liste annotée.","question":"Qu'est-ce qui était là et que tu n'avais pas mis sur la liste ?","sources":[]},"en":{"title":"The list","entry":"Write a list of everything you perceive right now. Ten things. Quickly.","steps":["Then read the list. Choose the most surprising thing.","Go close to this thing. Stay with it for two minutes.","Come back to your list. Add what you didn't see at first."],"trace":"The annotated list.","question":"What was there that you hadn't put on the list?","sources":[]}},{"id":"t-haiku","deck":"terrains","type":"trace","fr":{"title":"Haïku du corps","entry":"Bouge pendant deux minutes. Sans intention. Juste bouger.","steps":["Arrête-toi. Sans réfléchir, écris trois lignes sur ce mouvement.","La première ligne : ce que tu as senti.","La deuxième ligne : ce que tu as vu.","La troisième ligne : ce que tu ne sais pas encore."],"trace":"Le haïku.","question":"La troisième ligne — qu'est-ce qu'elle dit de ce que le mouvement a commencé ?","sources":[]},"en":{"title":"Body haiku","entry":"Move for two minutes. Without intention. Just move.","steps":["Stop. Without thinking, write three lines about this movement.","First line: what you felt.","Second line: what you saw.","Third line: what you don't know yet."],"trace":"The haiku.","question":"The third line — what does it say about what the movement began?","sources":[]}},{"id":"t-avant-apres","deck":"terrains","type":"trace","fr":{"title":"Avant et après","entry":"Avant de commencer : dessine comment tu te sens maintenant. Vite. N'importe comment.","steps":["Bouge pendant cinq à dix minutes. Ce que tu veux.","Après : dessine comment tu te sens maintenant. Vite. N'importe comment.","Regarde les deux dessins côte à côte."],"trace":"Les deux dessins.","question":"Qu'est-ce qui a bougé ? Est-ce que ça se voit dans les dessins ?","sources":[]},"en":{"title":"Before and after","entry":"Before you begin: draw how you feel right now. Quickly. Anyhow.","steps":["Move for five to ten minutes. Whatever you want.","After: draw how you feel now. Quickly. Anyhow.","Look at the two drawings side by side."],"trace":"The two drawings.","question":"What moved? Can you see it in the drawings?","sources":[]}},{"id":"t-repetition","deck":"terrains","type":"geste","fr":{"title":"La répétition","entry":"Trouve un tout petit mouvement — un clignement, un balancement, un doigt qui tape.","steps":["Répète ce mouvement. Beaucoup de fois.","Observe comment la répétition le transforme — il devient rituel, puis étrange, puis presque invisible, puis à nouveau là.","À quel moment la répétition est-elle devenue quelque chose d'autre ?"],"trace":null,"question":"La répétition change-t-elle le mouvement ou toi ?","sources":[]},"en":{"title":"The repetition","entry":"Find a very small movement — a blink, a sway, a tapping finger.","steps":["Repeat this movement. Many times.","Observe how repetition transforms it — it becomes ritual, then strange, then almost invisible, then present again.","At what point did the repetition become something else?"],"trace":null,"question":"Does repetition change the movement or you?","sources":[]}},{"id":"t-poids","deck":"terrains","type":"geste","fr":{"title":"Donner son poids","entry":"Trouve un mur. Appuie-toi contre lui — vraiment, laisse-lui ton poids.","steps":["Le mur tient. Tu n'as pas besoin de te tenir toi-même.","Explore d'autres surfaces : sol, table, fenêtre. Donne ton poids à chacune.","Puis reste debout sans appui. Sens la différence."],"trace":null,"question":"Qu'est-ce que ça fait de ne pas avoir à se tenir soi-même ?","sources":[]},"en":{"title":"Giving your weight","entry":"Find a wall. Lean against it — really, give it your weight.","steps":["The wall holds. You don't need to hold yourself.","Explore other surfaces: floor, table, window. Give your weight to each.","Then stand without support. Feel the difference."],"trace":null,"question":"What is it like not to have to hold yourself up?","sources":[]}},{"id":"t-sourire","deck":"terrains","type":"relation","fr":{"title":"Sourire à un objet","entry":"Choisis un objet dans cet espace. Souris-lui. Vraiment.","steps":["Pas ironiquement. Sincèrement. Comme tu sourirais à quelqu'un que tu es content·e de voir.","Reste avec ce sourire pendant trente secondes.","Observe si quelque chose change dans l'objet. Ou dans toi."],"trace":null,"question":"L'objet a-t-il changé ? Toi oui. Qu'est-ce qui a changé ?","sources":[]},"en":{"title":"Smiling at an object","entry":"Choose an object in this space. Smile at it. Really.","steps":["Not ironically. Sincerely. As you would smile at someone you're glad to see.","Stay with this smile for thirty seconds.","Observe if something changes in the object. Or in you."],"trace":null,"question":"Did the object change? You did. What changed?","sources":[]}},{"id":"t-sol-etude","deck":"terrains","type":"relation","fr":{"title":"Étude du sol","entry":"Allonge-toi au sol. Ferme les yeux. Reste là.","steps":["Sens le sol sous chaque partie de ton corps.","Le sol est le premier danseur — il tient tout le reste.","Roule lentement sur le côté, puis sur le ventre, puis sur l'autre côté. Prends le temps.","Reviens sur le dos. Le sol t'a-t-il appris quelque chose ?"],"trace":null,"question":"Quelle partie de toi n'avait pas touché le sol depuis longtemps ?","sources":[]},"en":{"title":"Study of the floor","entry":"Lie down on the floor. Close your eyes. Stay there.","steps":["Feel the floor beneath each part of your body.","The floor is the first dancer — it holds everything else.","Roll slowly to your side, then onto your front, then to the other side. Take your time.","Roll back onto your back. Did the floor teach you something?"],"trace":null,"question":"Which part of you hadn't touched the floor for a long time?","sources":[]}},{"id":"t-invisible","deck":"terrains","type":"geste","fr":{"title":"Le mouvement invisible","entry":"Bouge — mais de façon à ce que personne ne s'en aperçoive.","steps":["Ton corps entier peut être en mouvement tant que ce n'est pas visible de loin.","Cela peut être une respiration qui change, un poids qui se déplace, un muscle qui se relâche.","Explore l'espace entre l'immobilité apparente et le mouvement réel."],"trace":null,"question":"Où était le mouvement caché ? Est-ce qu'il compte si personne ne le voit ?","sources":[]},"en":{"title":"The invisible movement","entry":"Move — but in a way that no one would notice.","steps":["Your whole body can be in movement as long as it's not visible from a distance.","It can be a changing breath, a shifting weight, a releasing muscle.","Explore the space between apparent stillness and real movement."],"trace":null,"question":"Where was the hidden movement? Does it count if no one sees it?","sources":[]}},{"id":"t-recit","deck":"terrains","type":"trace","fr":{"title":"Le récit du mouvement","entry":"Quelqu'un bouge. Tu observes. Tu écris ce que tu vois — mais comme un récit, pas une description.","steps":["Pas « la personne lève le bras ». Plutôt : « quelque chose cherche à monter ».","Continue pendant que le mouvement continue.","Lis ton récit à voix haute après. Sens s'il correspond."],"trace":"Le texte.","question":"Le récit que tu as écrit parle de quoi — du mouvement ou de toi ?","sources":[]},"en":{"title":"The movement story","entry":"Someone moves. You observe. You write what you see — but as a story, not a description.","steps":["Not 'the person raises their arm'. Rather: 'something is trying to rise'.","Continue while the movement continues.","Read your story aloud afterward. Feel whether it corresponds."],"trace":"The text.","question":"What is the story you wrote about — the movement or you?","sources":[]}},{"id":"t-chaine","deck":"terrains","type":"geste","fr":{"title":"La chaîne","entry":"Trouve un mouvement. Fais-le.","steps":["Maintenant ajoute-y un deuxième mouvement. Les deux ensemble.","Ajoute un troisième. Puis un quatrième.","Ta chaîne devient une danse. Continue jusqu'à ce qu'elle soit trop longue pour se souvenir.","Recommence depuis le début. Ou depuis la fin."],"trace":null,"question":"À quel moment la chaîne est-elle devenue plus grande que toi ?","sources":[]},"en":{"title":"The chain","entry":"Find a movement. Do it.","steps":["Now add a second movement. Both together.","Add a third. Then a fourth.","Your chain becomes a dance. Continue until it's too long to remember.","Start again from the beginning. Or from the end."],"trace":null,"question":"At what point did the chain become larger than you?","sources":[]}},{"id":"t-frontiere","deck":"terrains","type":"geste","fr":{"title":"La frontière","entry":"Trace une frontière dans l'espace — avec du scotch, une ligne de craie, ou juste dans ton imagination.","steps":["D'un côté : tu te déplaces très librement, n'importe comment.","De l'autre côté : tu te déplaces très lentement, avec beaucoup de soin.","Traverse la frontière. Observe ce qui change dans ton corps.","Efface la frontière. Est-ce qu'elle existe encore ?"],"trace":null,"question":"La frontière était dans l'espace ou dans ta tête ?","sources":[]},"en":{"title":"The boundary","entry":"Draw a boundary in the space — with tape, a chalk line, or just in your imagination.","steps":["On one side: move very freely, any way at all.","On the other side: move very slowly, with great care.","Cross the boundary. Observe what changes in your body.","Erase the boundary. Does it still exist?"],"trace":null,"question":"Was the boundary in the space or in your head?","sources":[]}},{"id":"t-conduire","deck":"terrains","type":"relation","fr":{"title":"Conduire et être conduit·e","entry":"À deux. Une personne ferme les yeux. L'autre guide — avec un doigt sur l'épaule, une paume dans le dos, un souffle.","steps":["Pas de mots. Juste le contact et la confiance.","Changez les rôles après deux minutes.","Puis marchez ensemble, sans décider qui guide."],"trace":null,"question":"Conduire ou être conduit·e — lequel était plus difficile ?","sources":[]},"en":{"title":"Leading and being led","entry":"In pairs. One person closes their eyes. The other guides — with a finger on the shoulder, a palm on the back, a breath.","steps":["No words. Just contact and trust.","Switch roles after two minutes.","Then walk together, without deciding who leads."],"trace":null,"question":"Leading or being led — which was harder?","sources":[]}},{"id":"t-statues","deck":"terrains","type":"geste","fr":{"title":"La statue","entry":"Bouge dans l'espace. Quand quelqu'un dit « stop » — ou quand tu décides toi-même — gèle instantanément.","steps":["Sens ta forme. Tu es une statue maintenant.","Cette forme dit quelque chose — une émotion, une intention, une question.","Reste dans cette forme jusqu'à ce qu'elle te parle.","Puis reprends le mouvement depuis elle, pas depuis zéro."],"trace":null,"question":"Qu'est-ce que ta statue disait ?","sources":[]},"en":{"title":"The statue","entry":"Move through the space. When someone says 'stop' — or when you decide yourself — freeze instantly.","steps":["Feel your shape. You are a statue now.","This shape says something — an emotion, an intention, a question.","Stay in this shape until it speaks to you.","Then resume movement from it, not from scratch."],"trace":null,"question":"What was your statue saying?","sources":[]}},{"id":"t-portrait-corps","deck":"terrains","type":"trace","fr":{"title":"Portrait du corps depuis le lieu","entry":"Regarde autour de toi. Tu vas dessiner ton propre corps — mais avec les éléments de ce lieu.","steps":["La rivière devient tes artères. L'arbre ton squelette. Les feuilles ta peau. La boue tes intestins.","Dessine rapidement — ne pense pas trop. Laisse la main choisir.","Ce dessin dit quelque chose sur la façon dont tu t'habites et dont tu habites ce lieu."],"trace":"Le dessin.","question":"Quelle partie du corps était la plus facile à trouver dans le paysage ?","sources":[]},"en":{"title":"Portrait of the body from the place","entry":"Look around you. You are going to draw your own body — but with elements from this place.","steps":["The river becomes your arteries. The tree your skeleton. The leaves your skin. The mud your intestines.","Draw quickly — don't think too much. Let the hand choose.","This drawing says something about how you inhabit yourself and how you inhabit this place."],"trace":"The drawing.","question":"Which body part was easiest to find in the landscape?","sources":[]}}],"vc":[{"id":"v-oreille-tronc","deck":"vivant","type":"contact","fr":{"title":"Coller l'oreille","entry":"Trouve un arbre. Colle ton oreille contre son tronc. Ferme les yeux.","steps":["Reste comme ça au moins une minute. Vraiment.","L'arbre n'est pas silencieux. Il conduit les sons du sol, du vent, des insectes qui vivent dedans.","Sens la différence de température entre ton oreille et l'écorce."],"question":"Qu'est-ce que tu as entendu que tu n'avais pas entendu avant ?","trace":null,"sources":[]},"en":{"title":"Ear to bark","entry":"Find a tree. Press your ear against its trunk. Close your eyes.","steps":["Stay like that for at least one minute. Really.","The tree is not silent. It conducts sounds from the soil, the wind, the insects living inside.","Feel the temperature difference between your ear and the bark."],"question":"What did you hear that you hadn't heard before?","trace":null,"sources":[]}},{"id":"v-mains-terre","deck":"vivant","type":"contact","fr":{"title":"Mains dans la terre","entry":"Enfonce tes deux mains dans la terre ou dans l'herbe. Jusqu'aux poignets si tu peux.","steps":["Sens le froid, l'humidité, la texture.","Pense à tout ce qui vit là-dedans — des millions d'êtres que tu ne vois pas.","Tu es en contact avec eux maintenant."],"question":"Comment ça se sent d'être en contact avec quelque chose d'aussi vivant ?","trace":null,"sources":[]},"en":{"title":"Hands in earth","entry":"Push both hands into the soil or grass. Up to the wrists if you can.","steps":["Feel the cold, the moisture, the texture.","Think of everything living in there — millions of beings you can't see.","You are in contact with them now."],"question":"What does it feel like to touch something so alive?","trace":null,"sources":[]}},{"id":"v-pieds-nus","deck":"vivant","type":"contact","fr":{"title":"Pieds nus","entry":"Enlève tes chaussures et tes chaussettes. Pose tes pieds sur le sol — herbe, terre, mousse, pierre.","steps":["Fais quelques pas très lentement.","Sous chaque pied : une surface différente, une température, une résistance.","Cherche l'endroit qui te plaît le plus. Arrête-toi là."],"question":"Quel sol tu choisirais pour toujours ?","trace":null,"sources":[]},"en":{"title":"Bare feet","entry":"Take off your shoes and socks. Place your feet on the ground — grass, earth, moss, stone.","steps":["Take a few very slow steps.","Under each foot: a different surface, temperature, resistance.","Find the spot you like most. Stop there."],"question":"Which ground would you choose forever?","trace":null,"sources":[]}},{"id":"v-enlacement","deck":"vivant","type":"contact","fr":{"title":"Enlacer","entry":"Trouve quelque chose que tu peux enlacer — un arbre, un rocher, un arbuste épais.","steps":["Prends ton temps pour approcher. Comme tu t'approcherais de quelqu'un.","Enlace-le. Sens son volume, sa température, sa texture contre tout ton corps.","Reste au moins trente secondes."],"question":"Qu'est-ce qui s'est passé dans ton corps quand tu as enlacé ?","trace":null,"sources":[]},"en":{"title":"Embracing","entry":"Find something you can embrace — a tree, a boulder, a thick shrub.","steps":["Take your time approaching. As you would approach someone.","Embrace it. Feel its volume, temperature, texture against your whole body.","Stay for at least thirty seconds."],"question":"What happened in your body when you embraced?","trace":null,"sources":[]}},{"id":"v-eau","deck":"vivant","type":"contact","fr":{"title":"L'eau qui bouge","entry":"Trouve de l'eau — un ruisseau, une flaque, la rosée sur une feuille. Trempe un doigt, une main, ou les deux pieds.","steps":["Reste immobile et laisse l'eau bouger autour de toi.","C'est l'eau qui fait le geste — toi tu reçois.","Sens où l'eau est froide, où elle est plus chaude."],"question":"Est-ce que l'eau t'a touché·e ou est-ce toi qui l'as touchée ?","trace":null,"sources":[]},"en":{"title":"Moving water","entry":"Find water — a stream, a puddle, dew on a leaf. Dip a finger, a hand, or both feet.","steps":["Stay still and let the water move around you.","The water makes the gesture — you receive.","Feel where the water is cold, where it's warmer."],"question":"Did the water touch you, or did you touch it?","trace":null,"sources":[]}},{"id":"v-vent-peau","deck":"vivant","type":"contact","fr":{"title":"Recevoir le vent","entry":"Tourne-toi face au vent. Ferme les yeux. Ouvre les bras légèrement.","steps":["Le vent vient de quelque part. Il a traversé des forêts, des villes, des océans peut-être.","Sens-le sur chaque partie de ton visage — front, joues, lèvres.","Quand il s'arrête, sens le silence qui reste sur ta peau."],"question":"D'où venait ce vent ?","trace":null,"sources":[]},"en":{"title":"Receiving wind","entry":"Turn to face the wind. Close your eyes. Open your arms slightly.","steps":["The wind comes from somewhere. It has crossed forests, cities, maybe oceans.","Feel it on each part of your face — forehead, cheeks, lips.","When it stops, feel the silence it leaves on your skin."],"question":"Where did this wind come from?","trace":null,"sources":[]}},{"id":"v-immobile-insecte","deck":"vivant","type":"ecoute","fr":{"title":"Attendre qu'on t'ignore","entry":"Arrête-toi. Reste complètement immobile pendant trois minutes.","steps":["Au début les animaux proches savent que tu es là.","Peu à peu, si tu ne bouges pas, ils t'oublient. Ils reprennent leur vie.","Tu n'es plus un danger. Tu es juste... là."],"question":"À quel moment as-tu senti qu'on t'avait oublié·e ?","trace":null,"sources":[]},"en":{"title":"Waiting to be ignored","entry":"Stop. Stay completely still for three minutes.","steps":["At first, nearby animals know you're there.","Gradually, if you don't move, they forget you. They resume their lives.","You're no longer a danger. You're just... there."],"question":"At what moment did you feel you had been forgotten?","trace":null,"sources":[]}},{"id":"v-fermer-yeux","deck":"vivant","type":"ecoute","fr":{"title":"Fermer les yeux dehors","entry":"Ferme les yeux là où tu es. Dehors. Reste une minute entière.","steps":["Écoute d'abord les sons lointains. Puis les sons moyens. Puis les tout proches.","Sens les odeurs.","Sens la lumière sur ta peau — même les yeux fermés, tu sais d'où elle vient."],"question":"Qu'est-ce qui existait autour de toi et que tu n'avais pas remarqué ?","trace":null,"sources":[]},"en":{"title":"Closing eyes outside","entry":"Close your eyes where you are. Outside. Stay for a full minute.","steps":["Listen first to distant sounds. Then medium sounds. Then the closest.","Notice the smells.","Feel the light on your skin — even with eyes closed, you know where it comes from."],"question":"What existed around you that you hadn't noticed?","trace":null,"sources":[]}},{"id":"v-compter-vivants","deck":"vivant","type":"ecoute","fr":{"title":"Compter les vivants","entry":"Reste là où tu es. Commence à compter tous les êtres vivants que tu peux percevoir.","steps":["Pas seulement les gros — les insectes, les plantes, la mousse sur un mur, les oiseaux au loin.","Compte jusqu'à ce que tu perdes le compte.","Tu es entouré·e de beaucoup plus de vie que tu ne le pensais."],"question":"À combien tu es arrivé·e avant de perdre le fil ?","trace":null,"sources":[]},"en":{"title":"Counting the living","entry":"Stay where you are. Start counting every living being you can perceive.","steps":["Not just the big ones — insects, plants, moss on a wall, birds in the distance.","Count until you lose count.","You are surrounded by much more life than you thought."],"question":"How far did you get before losing track?","trace":null,"sources":[]}},{"id":"v-voix-lieu","deck":"vivant","type":"ecoute","fr":{"title":"La voix du lieu","entry":"Écoute ce lieu pendant deux minutes. Vraiment écouter — pas juste entendre.","steps":["Les sons que tu entends maintenant existent ici depuis longtemps avant toi.","Quels sons sont vivants ? Lesquels sont faits par des humains ? Lesquels par autre chose ?","Si ce lieu pouvait parler, quelle serait sa voix ?"],"question":"Qu'est-ce que ce lieu dirait s'il parlait ?","trace":null,"sources":[]},"en":{"title":"The voice of the place","entry":"Listen to this place for two minutes. Really listen — not just hear.","steps":["The sounds you hear now have existed here long before you.","Which sounds are alive? Which are made by humans? Which by something else?","If this place could speak, what would its voice be?"],"question":"What would this place say if it spoke?","trace":null,"sources":[]}},{"id":"v-insecte","deck":"vivant","type":"ecoute","fr":{"title":"Suivre un insecte","entry":"Trouve un insecte. N'importe lequel. Observe-le pendant deux minutes.","steps":["Suis-le avec tes yeux sans bouger trop.","Essaie de comprendre ce qu'il fait — où il va, ce qu'il cherche.","Il a une vie complète. Il va quelque part pour une raison."],"question":"Où allait-il ? Qu'est-ce qu'il cherchait ?","trace":null,"sources":[]},"en":{"title":"Following an insect","entry":"Find an insect. Any one. Watch it for two minutes.","steps":["Follow it with your eyes without moving too much.","Try to understand what it's doing — where it's going, what it's looking for.","It has a complete life. It's going somewhere for a reason."],"question":"Where was it going? What was it looking for?","trace":null,"sources":[]}},{"id":"v-silence","deck":"vivant","type":"ecoute","fr":{"title":"Le silence du vivant","entry":"Essaie de trouver un endroit silencieux. Pas un endroit sans sons — un endroit sans sons humains.","steps":["Si tu en trouves un : reste là. Écoute ce silence-là.","Il est plein. Pas vide.","Si tu n'en trouves pas : ça aussi, c'est une information sur cet endroit."],"question":"Ce silence-là — il ressemblait à quoi ?","trace":null,"sources":[]},"en":{"title":"The silence of the living","entry":"Try to find a quiet place. Not a place without sounds — a place without human sounds.","steps":["If you find one: stay there. Listen to that silence.","It is full. Not empty.","If you can't find one: that too is information about this place."],"question":"What did that silence feel like?","trace":null,"sources":[]}},{"id":"v-arbre-age","deck":"vivant","type":"presence","fr":{"title":"L'âge de l'arbre","entry":"Trouve un vieil arbre. Regarde-le vraiment.","steps":["Trouve un vieil arbre. Tiens-toi à côté de lui — pas face à lui, à côté. Comme deux personnes debout ensemble.","Pose une main sur son écorce. L'autre dans ta poche, ou sur ta hanche. Sens la différence de texture, de température.","Cet arbre a connu des hivers que tu n'as pas connus, des sécheresses, des tempêtes. Il est encore là.","Reste à côté de lui sans rien faire. Sens ce que ça fait d'être moins âgé·e que quelque chose de vivant."],"question":"Qu'est-ce que ça fait d'être en contact avec quelque chose d'aussi ancien ?","trace":null,"sources":[]},"en":{"title":"The age of the tree","entry":"Find an old tree. Really look at it.","steps":["Find an old tree. Stand beside it — not facing it, beside it. Like two people standing together.","Place one hand on its bark. The other in your pocket or on your hip. Feel the difference in texture, temperature.","This tree has known winters you haven't known, droughts, storms. It's still here.","Stay beside it doing nothing. Feel what it is to be less old than something alive."],"question":"What does it feel like to touch something so ancient?","trace":null,"sources":[]}},{"id":"v-sous-feuille","deck":"vivant","type":"presence","fr":{"title":"Regarder sous une feuille","entry":"Choisis une feuille. Retourne-la doucement. Regarde ce qu'il y a dessous.","steps":["Des œufs, des insectes, des champignons microscopiques, de la rosée, des traces.","Ce dessous existe tout le temps — tu ne le vois presque jamais.","Repose la feuille exactement comme elle était."],"question":"Combien de choses cachées existent en ce moment autour de toi ?","trace":null,"sources":[]},"en":{"title":"Looking under a leaf","entry":"Choose a leaf. Gently turn it over. Look at what's underneath.","steps":["Eggs, insects, microscopic fungi, dew, traces.","This underside exists all the time — you almost never see it.","Put the leaf back exactly as it was."],"question":"How many hidden things exist right now around you?","trace":null,"sources":[]}},{"id":"v-decomposition","deck":"vivant","type":"presence","fr":{"title":"La vie qui se défait","entry":"Trouve quelque chose qui se décompose — une feuille morte, du bois pourri, un fruit tombé.","steps":["Agenouille-toi ou accroupis-toi à sa hauteur. Regarde-le avec l'attention qu'on donne d'habitude aux choses intactes.","Touche-le si tu peux — doucement, comme tu toucherais quelque chose de précieux.","Cette matière est en train de devenir autre chose. Des champignons, des bactéries, des vers y travaillent maintenant. Tu es au-dessus d'une transformation."],"question":"Est-ce que c'est triste ou est-ce que c'est vivant ?","trace":null,"sources":[]},"en":{"title":"Life coming apart","entry":"Find something decomposing — a dead leaf, rotten wood, a fallen fruit.","steps":["Kneel or crouch to its level. Look at it with the attention usually given to intact things.","Touch it if you can — gently, as you would touch something precious.","This matter is becoming something else. Fungi, bacteria, worms are working in it right now. You are above a transformation."],"question":"Is this sad or is this alive?","trace":null,"sources":[]}},{"id":"v-lumiere","deck":"vivant","type":"presence","fr":{"title":"La lumière qui traverse","entry":"Trouve un endroit où la lumière traverse quelque chose — des feuilles, de l'eau, de la brume.","steps":["Place-toi dans cette lumière. Ferme les yeux. Laisse-la cartographier ton visage — front, joues, paupières.","Cette lumière a voyagé huit minutes depuis le soleil, puis traversé le vivant avant d'arriver sur toi.","Tourne très lentement. Sens comment la lumière change sur ta peau à chaque degré de rotation."],"question":"Comment cette lumière est différente d'une lumière artificielle ?","trace":null,"sources":[]},"en":{"title":"Light passing through","entry":"Find a place where light passes through something — leaves, water, mist.","steps":["Place yourself in this light. Close your eyes. Let it map your face — forehead, cheeks, eyelids.","This light travelled eight minutes from the sun, then through living matter before reaching you.","Turn very slowly. Feel how the light changes on your skin at each degree of rotation."],"question":"How is this light different from artificial light?","trace":null,"sources":[]}},{"id":"v-reseau","deck":"vivant","type":"presence","fr":{"title":"Les connexions invisibles","entry":"Regarde deux choses vivantes qui ne se touchent pas. Elles sont reliées quand même.","steps":["L'arbre là-bas et le champignon sous tes pieds échangent des sucres en ce moment. L'oiseau qui chante dépend des insectes qui dépendent des fleurs qui dépendent de la pluie.","Choisis deux êtres que tu vois. Deviens le lien entre eux — avec ton corps, dans l'espace.","Pas une métaphore : mets-toi physiquement entre eux, oriente-toi vers l'un puis vers l'autre.","Toi aussi tu es dans ce réseau. Où es-tu dans cette image ?"],"question":"Par combien d'êtres es-tu relié·e à l'arbre le plus proche ?","trace":null,"sources":[]},"en":{"title":"Invisible connections","entry":"Look at two living things that don't touch. They are connected anyway.","steps":["The tree over there and the fungus under your feet are exchanging sugars right now. The singing bird depends on insects that depend on flowers that depend on rain.","Choose two beings you can see. Become the link between them — with your body, in the space.","Not a metaphor: physically place yourself between them, orient toward one then the other.","You too are in this network. Where are you in this picture?"],"question":"How many beings connect you to the nearest tree?","trace":null,"sources":[]}},{"id":"v-meme-besoin","deck":"vivant","type":"presence","fr":{"title":"Les mêmes besoins","entry":"Choisis un être vivant près de toi. Observe-le vraiment — pas comme une illustration, comme un voisin.","steps":["Qu'est-ce qu'il cherche en ce moment ? De l'eau, de la lumière, un abri, un partenaire ?","Pense à ce que toi tu cherches en ce moment. Pas en général — maintenant, ici.","Bouge comme si vous cherchiez la même chose, de façons différentes.","Tu n'es pas au-dessus de lui dans une chaîne alimentaire. Tu es à côté, dans la même condition fondamentale."],"question":"Qu'est-ce que tu as en commun avec cet être que tu n'aurais pas dit avant ?","trace":null,"sources":[]},"en":{"title":"The same needs","entry":"Choose a living being near you. Observe it truly — not as an illustration, but as a neighbour.","steps":["What is it looking for right now? Water, light, shelter, a partner?","Think about what you are looking for right now. Not in general — now, here.","Move as if you were both looking for the same thing, in different ways.","You are not above it in a food chain. You are beside it, in the same fundamental condition."],"question":"What do you have in common with this being that you wouldn't have said before?","trace":null,"sources":[]}},{"id":"v-gratitude","deck":"vivant","type":"presence","fr":{"title":"Remercier","entry":"Quelque chose dans ce lieu t'a donné quelque chose aujourd'hui — de la lumière, de l'ombre, un son, une odeur, de l'air.","steps":["Approche-toi de ce quelque chose. Tiens-toi face à lui.","Fais un geste — pas symbolique, physique. Quelque chose que ton corps invente maintenant pour lui rendre ce qu'il t'a donné.","Pas besoin que ça soit beau. Pas besoin d'y croire. Juste : un geste vrai.","Reste un moment immobile après le geste. Sens ce qui reste."],"question":"Qu'est-ce qui a changé dans ton corps après ce geste ?","trace":null,"sources":[]},"en":{"title":"Giving thanks","entry":"Something in this place gave you something today — light, shade, a sound, a smell, air.","steps":["Approach it. Stand facing it.","Make a gesture — not symbolic, physical. Something your body invents now to give back what it gave you.","It doesn't need to be beautiful. You don't need to believe in it. Just: a true gesture.","Stay still for a moment after the gesture. Feel what remains."],"question":"What changed in your body after this gesture?","trace":null,"sources":[]}},{"id":"v-etre-vu","deck":"vivant","type":"presence","fr":{"title":"Être vu","entry":"Quelque chose dans ce lieu te perçoit en ce moment. Pas forcément de la façon dont tu perçois, toi.","steps":["Les plantes perçoivent ta chaleur. Les insectes tes vibrations. Les animaux ton odeur et ton ombre.","Tu n'es pas invisible ici. Tu es une présence parmi d'autres présences.","Bouge lentement, conscient·e d'être perçu·e."],"question":"Comment ça change ton comportement de savoir que tu es perçu·e ?","trace":null,"sources":[]},"en":{"title":"Being seen","entry":"Something in this place perceives you right now. Not necessarily the way you perceive.","steps":["Plants sense your warmth. Insects your vibrations. Animals your scent and shadow.","You are not invisible here. You are one presence among other presences.","Move slowly, aware of being perceived."],"question":"How does knowing you are perceived change your behaviour?","trace":null,"sources":[]}},{"id":"v-petitesse","deck":"vivant","type":"presence","fr":{"title":"Se sentir petit·e","entry":"Regarde quelque chose d'immense — un grand arbre, le ciel, une montagne, un horizon.","steps":["Étends les bras. Regarde ta propre envergure — à peu près deux mètres. Puis regarde ce qui est devant toi.","Laisse ton corps s'ajuster à cette différence d'échelle. Pas s'écraser — s'ajuster. Il y a une façon juste de tenir son corps face à l'immensité.","Fais un pas vers ce qui est immense. Puis un autre. Tu es petit·e et tu t'approches quand même."],"question":"Est-ce que se sentir petit·e peut être une bonne chose ?","trace":null,"sources":[]},"en":{"title":"Feeling small","entry":"Look at something immense — a great tree, the sky, a mountain, a horizon.","steps":["Extend your arms. Look at your own wingspan — about two metres. Then look at what is before you.","Let your body adjust to this difference in scale. Not collapse — adjust. There is a right way to hold your body before immensity.","Take a step toward what is immense. Then another. You are small and you approach anyway."],"question":"Can feeling small be a good thing?","trace":null,"sources":[]}},{"id":"v-saison","deck":"vivant","type":"presence","fr":{"title":"Lire la saison","entry":"Regarde autour de toi. Le lieu est en train de faire quelque chose — bourgeonnner, fleurir, fructifier, se préparer au froid.","steps":["Quels signes vois-tu ? Couleurs, textures, odeurs, comportements des animaux.","Ce moment précis ne reviendra jamais exactement pareil.","Sens-toi être là dans cette saison particulière, à cet instant particulier."],"question":"Qu'est-ce que ce lieu est en train de faire en ce moment ?","trace":null,"sources":[]},"en":{"title":"Reading the season","entry":"Look around. The place is doing something — budding, flowering, fruiting, preparing for cold.","steps":["What signs do you see? Colours, textures, smells, animal behaviours.","This precise moment will never come back exactly the same.","Feel yourself being here in this particular season, at this particular instant."],"question":"What is this place doing right now?","trace":null,"sources":[]}},{"id":"v-habitat","deck":"vivant","type":"presence","fr":{"title":"Qui habite ici ?","entry":"Cherche les signes d'habitation dans cet espace — terriers, nids, traces, tunnels dans l'écorce, toiles.","steps":["Quelqu'un vit ici. Peut-être plusieurs. Peut-être beaucoup.","Ces êtres connaissent cet espace infiniment mieux que toi.","Tu es l'étranger·ère, l'invité·e."],"question":"Comment tu te comporterais différemment si tu te sentais vraiment invité·e ici ?","trace":null,"sources":[]},"en":{"title":"Who lives here?","entry":"Look for signs of habitation in this space — burrows, nests, tracks, tunnels in bark, webs.","steps":["Someone lives here. Maybe several. Maybe many.","These beings know this space infinitely better than you.","You are the stranger, the guest."],"question":"How would you behave differently if you truly felt you were a guest here?","trace":null,"sources":[]}},{"id":"v-lettre","deck":"vivant","type":"presence","fr":{"title":"Écrire une lettre","entry":"Choisis un être vivant dans ce lieu — un arbre, un oiseau, une rivière, un champignon. Écris-lui une lettre courte.","steps":["Pas dans ta tête. Sur papier, ou en murmurant.","Dis-lui ce que tu remarques en lui. Ce que tu lui demandes. Ce que tu lui offres.","Tu n'as pas besoin d'y croire pour que ça fasse quelque chose en toi."],"trace":"La lettre.","question":"Qu'est-ce que cette lettre t'a appris sur toi ?","sources":[]},"en":{"title":"Writing a letter","entry":"Choose a living being in this place — a tree, a bird, a river, a fungus. Write it a short letter.","steps":["Not in your head. On paper, or by whispering.","Tell it what you notice in it. What you ask of it. What you offer it.","You don't need to believe in it for it to do something in you."],"trace":"The letter.","question":"What did this letter teach you about yourself?","sources":[]}},{"id":"v-appartenir","deck":"vivant","type":"presence","fr":{"title":"Appartenir","entry":"Tu respires l'air de ce lieu. Tu bois son eau. Sa lumière entre dans tes yeux et réchauffe ta peau.","steps":["Bouge dans l'espace comme si tu en faisais partie — pas comme un visiteur qui traverse, comme quelque chose qui appartient là.","Ralentis jusqu'à la vitesse du lieu. Pas ta vitesse — celle du lieu. Quelle est-elle ?","Arrête-toi. Sens ce qui te tient — le sol sous tes pieds, l'air autour, la lumière.","Ce lieu est en toi autant que tu es dans ce lieu. Les deux directions à la fois."],"question":"Quel mouvement appartient à ce lieu et pas à toi ?","trace":null,"sources":[]},"en":{"title":"Belonging","entry":"You breathe this place's air. You drink its water. Its light enters your eyes and warms your skin.","steps":["Move in the space as if you belong here — not as a visitor passing through, but as something that belongs.","Slow down to the speed of this place. Not your speed — the place's speed. What is it?","Stop. Feel what holds you — the ground under your feet, the air around, the light.","This place is in you as much as you are in it. Both directions at once."],"question":"What movement belongs to this place and not to you?","trace":null,"sources":[]}},{"id":"v-danser-arbre","deck":"vivant","type":"contact","fr":{"title":"Danser avec un arbre","entry":"Trouve un arbre. Approche-toi. Présente-toi — à ta façon.","steps":["L'arbre danse déjà — ses branches, ses racines, sa résistance au vent.","Rejoins sa danse. Ne l'imite pas. Danse avec lui.","Reste jusqu'à ce que quelque chose change entre vous."],"trace":"Dessine l'arbre de mémoire, après, sans le regarder.","question":"À quel moment avez-vous dansé ensemble plutôt que séparément ?","sources":[]},"en":{"title":"Dancing with a tree","entry":"Find a tree. Come close. Introduce yourself — in your own way.","steps":["The tree is already dancing — its branches, its roots, its resistance to wind.","Join its dance. Don't imitate it. Dance with it.","Stay until something changes between you."],"trace":"Draw the tree from memory, afterward, without looking at it.","question":"At what moment were you dancing together rather than separately?","sources":[]}},{"id":"v-danser-animal","deck":"vivant","type":"contact","fr":{"title":"Danser pour un animal","entry":"Trouve un animal — un oiseau, un insecte, un ver de terre, peu importe.","steps":["Danse pour lui. Pas pour le divertir — pour l'honorer.","Ce que tu fais n'a pas besoin d'être beau. Ça doit être sincère.","L'animal ne regardera peut-être pas. Danse quand même."],"trace":null,"question":"Qu'est-ce que ça change de danser pour quelqu'un qui n'a pas demandé à te voir ?","sources":[]},"en":{"title":"Dancing for an animal","entry":"Find an animal — a bird, an insect, an earthworm, anything.","steps":["Dance for it. Not to entertain it — to honour it.","What you do doesn't need to be beautiful. It needs to be sincere.","The animal may not watch. Dance anyway."],"trace":null,"question":"What changes when you dance for someone who didn't ask to see you?","sources":[]}},{"id":"v-textures","deck":"vivant","type":"contact","fr":{"title":"Les textures miroirs","entry":"Trouve une texture naturelle — mousse, écorce, pierre, sol, feuille. Touche-la avec une main.","steps":["Avec l'autre main, explore ton propre corps. Cherche un endroit qui ressemble à cette texture.","La mousse et l'intérieur de ton coude. L'écorce rugueuse et ta paume calleuse. La pierre froide et ton front.","Ce n'est pas une métaphore — c'est une reconnaissance. Tu es fait·e de matières similaires.","Bouge entre les deux — main dehors, main dedans — jusqu'à sentir la continuité."],"question":"Quelle partie de toi ressemble le plus à ce lieu ?","trace":null,"sources":["Robin Wall Kimmerer — Braiding Sweetgrass : la grammaire de l'animé comme reconnaissance de parenté"]},"en":{"title":"Mirror textures","entry":"Find a natural texture — moss, bark, stone, soil, leaf. Touch it with one hand.","steps":["With the other hand, explore your own body. Look for a place that resembles this texture.","Moss and the inside of your elbow. Rough bark and your calloused palm. Cold stone and your forehead.","This is not a metaphor — it is recognition. You are made of similar materials.","Move between the two — hand outside, hand inside — until you feel the continuity."],"question":"Which part of you most resembles this place?","trace":null,"sources":["Kimmerer R.W. — Braiding Sweetgrass: the grammar of animacy as recognition of kinship"]}},{"id":"v-observer-devenir","deck":"vivant","type":"presence","fr":{"title":"Observer, puis devenir","entry":"Choisis un espace, un être ou un élément du lieu. Observe-le sans bouger pendant dix minutes entières.","steps":["Vraiment dix minutes. Pas cinq. Dix. Laisse le temps faire son travail.","Remarque comment tu vois différemment au bout de cinq minutes. Puis au bout de dix.","Maintenant : bouge comme cet espace. Pas imiter sa forme — habiter sa qualité. Sa lenteur, sa façon d'être là.","Laisse entrer ce que tu as vraiment vu — pas ce que tu pensais voir au départ."],"question":"Qu'est-ce que l'observation longue t'a montré que l'observation courte ne pouvait pas montrer ?","trace":null,"sources":["Tim Ingold — Being Alive (2011) : l'attention comme mode d'habitation du monde"]},"en":{"title":"Observe, then become","entry":"Choose a space, a being or an element of the place. Observe it without moving for a full ten minutes.","steps":["Really ten minutes. Not five. Ten. Let time do its work.","Notice how you see differently after five minutes. Then after ten.","Now: move like this space. Not imitating its form — inhabiting its quality. Its slowness, its way of being there.","Let in what you truly saw — not what you thought you saw at the start."],"question":"What did long observation show you that short observation could not?","trace":null,"sources":["Ingold T. — Being Alive (2011): attention as mode of inhabiting the world"]}},{"id":"v-elements-corps","deck":"vivant","type":"presence","fr":{"title":"Cartographier son corps depuis le lieu","entry":"Regarde autour de toi. Ne cherche pas — laisse quelque chose te trouver.","steps":["Quelque chose dans ce paysage attire ton attention. Approche-toi. Observe-le un moment.","Maintenant : où dans ton corps cette chose résonne-t-elle ? Pas où tu devrais la sentir — où tu la sens vraiment.","Pose une main là. Sens le lien — pas symbolique, matériel. Tu es fait·e de la même matière que ce lieu.","Bouge depuis cette partie de ton corps qui résonne. Laisse-la guider."],"question":"Quelle partie de toi a reconnu quelque chose dans ce lieu ?","trace":null,"sources":["Lorena Cabnal — territorio-cuerpo-tierra : le corps et la terre comme un seul territoire","Karen Barad — Meeting the Universe Halfway : la matière comme réseau d'intra-actions"]},"en":{"title":"Mapping the body from the place","entry":"Look around you. Don't search — let something find you.","steps":["Something in this landscape catches your attention. Approach it. Observe it for a moment.","Now: where in your body does this thing resonate? Not where you should feel it — where you actually do.","Place a hand there. Feel the connection — not symbolic, material. You are made of the same matter as this place.","Move from this resonating part of your body. Let it guide."],"question":"Which part of you recognised something in this place?","trace":null,"sources":["Cabnal L. — territorio-cuerpo-tierra: body and earth as single territory","Barad K. — Meeting the Universe Halfway: matter as network of intra-actions"]}}],"xc":[{"id":"tc-corps-territoire","deck":"territoires","type":"ancrer","fr":{"title":"Le territoire dans le corps","entry":"Avant de parler de ce territoire, sens-le dans ton corps. Ferme les yeux un moment.","steps":["Pense à un moment où tu as été physiquement dans ce lieu — pas une réunion, un moment de présence réelle.","Où est-ce que ce souvenir se loge dans ton corps ? Dans la poitrine ? Les pieds ? L'estomac ?","Garde cette sensation. Tu vas parler depuis elle, pas depuis tes idées sur le territoire."],"question":"Qu'est-ce que ce territoire te fait physiquement ?","trace":null,"sources":[]},"en":{"title":"The territory in the body","entry":"Before talking about this territory, feel it in your body. Close your eyes for a moment.","steps":["Think of a moment when you were physically in this place — not a meeting, a moment of real presence.","Where does this memory lodge in your body? In the chest? The feet? The stomach?","Keep this sensation. You're going to speak from it, not from your ideas about the territory."],"question":"What does this territory do to you physically?","trace":null,"sources":[]}},{"id":"tc-premier-contact","deck":"territoires","type":"ancrer","fr":{"title":"Premier contact","entry":"Rappelle-toi la première fois que tu as mis les pieds sur ce territoire. Ou la première fois que tu t'en es vraiment soucié·e.","steps":["Quel sens a été touché en premier ? Une odeur, un son, une vue, une sensation sous les pieds ?","Qu'est-ce que tu ressentais à ce moment-là ? Est-ce que c'était familier ou étranger ?","Ce premier contact a coloré tout ce qui a suivi. Comment ?"],"question":"Qu'est-ce qui a fait que ce territoire t'a accroché·e ?","trace":null,"sources":[]},"en":{"title":"First contact","entry":"Remember the first time you set foot on this territory. Or the first time you really cared about it.","steps":["Which sense was touched first? A smell, a sound, a sight, a sensation underfoot?","What did you feel in that moment? Was it familiar or foreign?","This first contact coloured everything that followed. How?"],"question":"What made this territory catch you?","trace":null,"sources":[]}},{"id":"tc-ce-qui-porte","deck":"territoires","type":"ancrer","fr":{"title":"Ce qui te porte ici","entry":"Tu es dans ce processus pour une raison. Sens cette raison dans ton corps avant de la formuler.","steps":["Pose une main sur ta poitrine. Respire.","Qu'est-ce qui te tient debout dans ce projet — pas une obligation, une conviction profonde ?","Comment ça se sent dans le corps quand tu touches cette conviction ?"],"question":"Qu'est-ce qui te fait tenir bon dans ce territoire ?","trace":null,"sources":[]},"en":{"title":"What holds you here","entry":"You are in this process for a reason. Feel this reason in your body before putting it into words.","steps":["Place a hand on your chest. Breathe.","What keeps you standing in this project — not an obligation, a deep conviction?","What does it feel like in the body when you touch this conviction?"],"question":"What keeps you going in this territory?","trace":null,"sources":[]}},{"id":"tc-zone-vivante","deck":"territoires","type":"ancrer","fr":{"title":"La zone qui vit","entry":"Si tu devais choisir l'endroit de ce territoire où tu te sens le plus vivant·e — où est-il ?","steps":["Pas le plus beau ou le plus important. Celui où tu te sens vraiment là.","Lève-toi si tu peux. Oriente ton corps vers cet endroit.","Sens ce que ça fait dans le corps d'être orienté·e vers ce qui compte."],"question":"Cet endroit — qu'est-ce qu'il représente pour toi ?","trace":null,"sources":[]},"en":{"title":"The living zone","entry":"If you had to choose the place in this territory where you feel most alive — where is it?","steps":["Not the most beautiful or important. The one where you feel truly present.","Stand up if you can. Orient your body toward this place.","Feel what it does in the body to be oriented toward what matters."],"question":"What does this place represent for you?","trace":null,"sources":[]}},{"id":"tc-ce-qui-blesse","deck":"territoires","type":"ancrer","fr":{"title":"Ce qui blesse","entry":"Il y a quelque chose dans ce territoire qui te fait mal. Pas une opinion — une douleur réelle.","steps":["Pense à l'endroit ou à la situation qui te fait le plus de peine dans ce territoire.","Où est-ce que cette peine se loge dans ton corps ?","Reste avec cette douleur un moment. Elle te dit quelque chose d'important sur ce qui compte pour toi."],"question":"Qu'est-ce que cette douleur dit de ce que tu aimes dans ce territoire ?","trace":null,"sources":[]},"en":{"title":"What hurts","entry":"There is something in this territory that hurts you. Not an opinion — a real pain.","steps":["Think of the place or situation that causes you most pain in this territory.","Where does this pain lodge in your body?","Stay with this pain for a moment. It's telling you something important about what matters to you."],"question":"What does this pain say about what you love in this territory?","trace":null,"sources":[]}},{"id":"tc-geste-territoire","deck":"territoires","type":"ancrer","fr":{"title":"Le geste du territoire","entry":"Si ta relation à ce territoire était un geste — un seul geste —, lequel serait-ce ?","steps":["Prends le temps de le trouver. Ne pense pas — laisse le corps proposer.","Fais ce geste. Lentement. Plusieurs fois.","Partage-le avec le groupe si tu veux — sans l'expliquer d'abord."],"question":"Ce geste — qu'est-ce qu'il dit que les mots ne disent pas ?","trace":null,"sources":[]},"en":{"title":"The gesture of the territory","entry":"If your relationship to this territory were a gesture — a single gesture —, what would it be?","steps":["Take time to find it. Don't think — let the body propose.","Make this gesture. Slowly. Several times.","Share it with the group if you want — without explaining it first."],"question":"What does this gesture say that words don't?","trace":null,"sources":[]}},{"id":"tc-carte-corps","deck":"territoires","type":"ancrer","fr":{"title":"Carte sensible","entry":"Dessine une carte de ce territoire — mais uniquement avec ce que ton corps connaît de lui.","steps":["Pas une carte juste. Une carte qui montre ce que tu as touché, traversé, senti.","Ce qui est grand sur ta carte est grand parce que ça compte pour toi, pas parce que c'est grand en réalité.","Montre ta carte sans l'expliquer d'abord. Laisse les autres regarder."],"trace":"La carte sensible.","question":"Qu'est-ce qui est au centre de ta carte ? Pourquoi ?","sources":[]},"en":{"title":"Sensitive map","entry":"Draw a map of this territory — but only with what your body knows of it.","steps":["Not an accurate map. A map that shows what you have touched, crossed, smelled.","What is large on your map is large because it matters to you, not because it's large in reality.","Show your map without explaining it first. Let others look."],"trace":"The sensitive map.","question":"What is at the centre of your map? Why?","sources":[]}},{"id":"tc-marcher-comme","deck":"territoires","type":"traverser","fr":{"title":"Marcher dans ses pieds","entry":"Choisis quelqu'un dans le groupe dont tu perçois la vision du territoire comme différente de la tienne.","steps":["Observe comment cette personne se tient, comment elle occupe l'espace.","Commence à marcher comme elle — pas pour la moquer, pour comprendre ce que ça fait dans le corps.","Depuis cette façon de marcher : comment est-ce que tu vois le territoire ?"],"question":"Qu'est-ce qui a changé dans ta perception quand tu as changé ta façon de marcher ?","trace":null,"sources":[]},"en":{"title":"Walking in their feet","entry":"Choose someone in the group whose vision of the territory you perceive as different from yours.","steps":["Observe how this person stands, how they occupy space.","Start walking like them — not to mock, but to understand what it does in the body.","From this way of walking: how do you see the territory?"],"question":"What changed in your perception when you changed how you walked?","trace":null,"sources":[]}},{"id":"tc-voix-absente","deck":"territoires","type":"traverser","fr":{"title":"La voix absente","entry":"Quelle voix est absente de cette table ? Qui n'est pas là et devrait l'être ?","steps":["Pas une personne — une perspective : les enfants, les non-humains, les gens qui sont partis, les futurs habitants.","Lève-toi. Prends la place de cette voix absente dans l'espace.","Depuis cet endroit : qu'est-ce que cette voix dirait de ce territoire ?"],"question":"Qu'est-ce que cette voix absente change dans votre conversation ?","trace":null,"sources":[]},"en":{"title":"The absent voice","entry":"What voice is absent from this table? Who isn't here and should be?","steps":["Not a person — a perspective: children, non-humans, people who left, future inhabitants.","Stand up. Take this absent voice's place in the space.","From this position: what would this voice say about the territory?"],"question":"What does this absent voice change in your conversation?","trace":null,"sources":[]}},{"id":"tc-echanger-carte","deck":"territoires","type":"traverser","fr":{"title":"Échanger les cartes","entry":"Prenez cinq minutes : chacun·e dessine une carte sensible de ce territoire — pas une carte juste, une carte de ce qu'on a touché, traversé, ressenti.","steps":["Échangez votre carte avec quelqu'un. Tenez la carte de l'autre dans vos mains.","Regardez-la sans poser de questions. Qu'est-ce que vous voyez ?","Qu'est-ce qui est grand dans sa carte que vous n'auriez pas mis dans la vôtre ?","Marchez dans l'espace en tenant cette carte — comme si vous portiez sa façon de voir."],"question":"Qu'est-ce que la carte de l'autre vous a appris sur votre propre rapport à ce territoire ?","trace":null,"sources":[]},"en":{"title":"Exchanging maps","entry":"Take five minutes: each person draws a sensitive map of this territory — not an accurate map, a map of what you've touched, crossed, felt.","steps":["Exchange your map with someone. Hold the other's map in your hands.","Look at it without asking questions. What do you see?","What is large on their map that you wouldn't have put on yours?","Walk through the space holding this map — as if carrying their way of seeing."],"question":"What did the other's map teach you about your own relationship to this territory?","trace":null,"sources":[]}},{"id":"tc-defender","deck":"territoires","type":"traverser","fr":{"title":"Défendre ce qu'on ne défend pas","entry":"Choisissez une position sur ce territoire que vous ne défendez pas — celle qui vous est la plus étrangère.","steps":["Debout. Ancrez-vous dans votre corps.","Défendez cette position — pas pour vous convaincre, pour comprendre ce qui la tient debout.","Cherchez dans votre corps : est-ce qu'il y a quelque chose de vrai là-dedans pour vous aussi ?"],"question":"Qu'est-ce qui vous a surpris dans cette défense ?","trace":null,"sources":[]},"en":{"title":"Defending what we don't defend","entry":"Choose a position on this territory that you don't defend — the one most foreign to you.","steps":["Stand up. Ground yourself in your body.","Defend this position — not to convince yourself, but to understand what holds it up.","Search in your body: is there something true in it for you too?"],"question":"What surprised you in this defence?","trace":null,"sources":[]}},{"id":"tc-non-humain","deck":"territoires","type":"traverser","fr":{"title":"Parler pour le non-humain","entry":"Désignez ensemble un être non-humain de ce territoire — une rivière, un sol, une forêt, une espèce.","steps":["Quelqu'un se lève et parle depuis cet être.","Pas ce que vous pensez de lui — ce qu'il ressent, ce qu'il veut, ce qu'il craint.","Les autres écoutent. Vraiment."],"question":"Ce qu'a dit le non-humain — est-ce que ça change quelque chose dans la conversation ?","trace":null,"sources":[]},"en":{"title":"Speaking for the non-human","entry":"Designate together a non-human being of this territory — a river, a soil, a forest, a species.","steps":["Someone stands and speaks from this being.","Not what you think about it — what it feels, what it wants, what it fears.","The others listen. Really."],"question":"What the non-human said — does it change anything in the conversation?","trace":null,"sources":[]}},{"id":"tc-corps-conflit","deck":"territoires","type":"traverser","fr":{"title":"Le conflit dans le corps","entry":"Pensez à un point de désaccord concret sur ce territoire. Pas une idée — un endroit, une pratique, un usage.","steps":["Deux personnes se placent dans l'espace — chacune dans sa position.","Pas de mots encore. Juste la posture, l'orientation, la distance entre elles.","Qu'est-ce que les corps disent avant que les mots commencent ?"],"question":"Qu'est-ce que la posture de l'autre vous a appris sur le désaccord ?","trace":null,"sources":[]},"en":{"title":"Conflict in the body","entry":"Think of a concrete point of disagreement about this territory. Not an idea — a place, a practice, a use.","steps":["Two people place themselves in the space — each in their position.","No words yet. Just posture, orientation, the distance between them.","What do the bodies say before words begin?"],"question":"What did the other's posture teach you about the disagreement?","trace":null,"sources":[]}},{"id":"tc-horizon","deck":"territoires","type":"traverser","fr":{"title":"Se tourner vers l'horizon","entry":"Pensez à ce territoire dans vingt ans. Pas le scénario idéal — ce que vous sentez vraiment.","steps":["Debout. Orientez votre corps vers cet avenir.","Qu'est-ce que vous voyez depuis là ? Qu'est-ce que vous sentez dans le corps ?","Maintenant regardez derrière vous — d'où vient ce territoire, ce qui l'a construit."],"question":"Entre ce passé et cet avenir — où est-ce que vous vous situez aujourd'hui ?","trace":null,"sources":[]},"en":{"title":"Turning toward the horizon","entry":"Think about this territory in twenty years. Not the ideal scenario — what you really feel.","steps":["Stand. Orient your body toward this future.","What do you see from there? What do you feel in the body?","Now look behind you — where this territory comes from, what built it."],"question":"Between this past and this future — where do you stand today?","trace":null,"sources":[]}},{"id":"tc-carte-commune","deck":"territoires","type":"composer","fr":{"title":"La carte commune","entry":"Si des cartes sensibles ont déjà été dessinées, posez-les toutes au sol. Sinon, prenez cinq minutes maintenant pour que chacun·e en dessine une — pas une carte juste, une carte de ce qui compte.","steps":["Regardez l'ensemble des cartes. Qu'est-ce qui est présent dans toutes ? Qu'est-ce qui manque dans certaines ?","Commencez à bouger les cartes — pas pour les fusionner, pour voir ce qui dialogue.","Ensemble, tracez une nouvelle carte : pas la somme des cartes, mais ce qui émerge de leur rencontre."],"trace":"La carte commune.","question":"Qu'est-ce que cette carte dit que chaque carte seule ne pouvait pas dire ?","sources":[]},"en":{"title":"The common map","entry":"If sensitive maps have already been drawn, place them all on the floor. If not, take five minutes now for each person to draw one — not an accurate map, a map of what matters.","steps":["Look at all the maps together. What's present in all of them? What's missing from some?","Start moving the maps — not to merge them, but to see what speaks to each other.","Together, draw a new map: not the sum of the maps, but what emerges from their encounter."],"trace":"The common map.","question":"What does this map say that each map alone could not?","sources":[]}},{"id":"tc-geste-commun","deck":"territoires","type":"composer","fr":{"title":"Le geste commun","entry":"D'abord : prenez deux minutes, chacun·e en silence. Si ta relation à ce territoire était un geste — un seul —, lequel serait-ce ? Trouve-le. Fais-le. Plusieurs fois.","steps":["Chacun·e montre son geste au groupe, sans l'expliquer.","Maintenant, cherchez ensemble un geste commun — pas un compromis, quelque chose qui émerge de la rencontre de vos gestes.","Essayez plusieurs versions. Ça peut prendre du temps.","Quand vous l'avez trouvé : faites-le ensemble. En silence d'abord."],"question":"Ce geste commun — est-ce qu'il représente quelque chose que vous n'auriez pas pu formuler en mots ?","trace":null,"sources":[]},"en":{"title":"The common gesture","entry":"First: take two minutes, each in silence. If your relationship to this territory were a gesture — just one —, what would it be? Find it. Do it. Several times.","steps":["Each person shows their gesture to the group, without explaining it.","Now, look for a common gesture together — not a compromise, something that emerges from the encounter of your gestures.","Try several versions. It can take time.","When you find it: do it together. In silence first."],"question":"This common gesture — does it represent something you couldn't have put into words?","trace":null,"sources":[]}},{"id":"tc-phrase-commune","deck":"territoires","type":"composer","fr":{"title":"La phrase du territoire","entry":"Chacun·e dit une phrase — une seule — qui commence par : « Ce territoire est… »","steps":["Pas une description objective. Ce que vous ressentez vraiment.","Écoutez les phrases des autres sans réagir d'abord.","Ensemble : est-ce qu'il y a une phrase commune qui honore toutes les vôtres sans les effacer ?"],"trace":"Les phrases individuelles et la phrase commune.","question":"Qu'est-ce qui a résisté à la mise en commun ?","sources":[]},"en":{"title":"The phrase of the territory","entry":"Each person says one phrase — just one — beginning with: 'This territory is…'","steps":["Not an objective description. What you truly feel.","Listen to each other's phrases without reacting first.","Together: is there a common phrase that honours all of yours without erasing them?"],"trace":"Individual phrases and the common phrase.","question":"What resisted being put in common?","sources":[]}},{"id":"tc-accord-corps","deck":"territoires","type":"composer","fr":{"title":"L'accord par le corps","entry":"Il y a une proposition sur la table. Avant le vote ou le débat — ressentez-la dans le corps.","steps":["Chacun·e se place dans l'espace selon son accord : proche si vous êtes pour, loin si vous êtes contre, côté si vous êtes mitigé·e.","Regardez la géographie qui se crée dans l'espace. Elle dit quelque chose.","Avant de revenir aux mots : quelqu'un veut-il changer de place ? Peut-il dire pourquoi avec son corps d'abord ?"],"question":"Est-ce que la carte des corps ressemblait à ce que vous pensiez ?","trace":null,"sources":[]},"en":{"title":"Agreement through the body","entry":"There is a proposal on the table. Before the vote or debate — feel it in the body.","steps":["Each person places themselves in the space according to their agreement: close if for, far if against, to the side if mixed.","Look at the geography that creates itself in the space. It says something.","Before returning to words: does anyone want to change position? Can they say why with their body first?"],"question":"Did the map of bodies resemble what you thought?","trace":null,"sources":[]}},{"id":"tc-ce-quon-garde","deck":"territoires","type":"composer","fr":{"title":"Ce qu'on garde","entry":"À la fin de ce temps ensemble, chacun·e identifie quelque chose qu'il·elle garde — une image, une sensation, une surprise.","steps":["Pas une conclusion. Quelque chose qui s'est déposé dans le corps.","Chacun·e le dit en une phrase ou le montre avec un geste.","Ce que vous gardez ensemble — c'est la trace somatique de ce que vous avez construit."],"question":"Qu'est-ce qui a bougé en vous aujourd'hui ?","trace":null,"sources":[]},"en":{"title":"What we keep","entry":"At the end of this time together, each person identifies something they keep — an image, a sensation, a surprise.","steps":["Not a conclusion. Something that settled in the body.","Each person says it in one phrase or shows it with a gesture.","What you keep together — it is the somatic trace of what you have built."],"question":"What moved in you today?","trace":null,"sources":[]}},{"id":"tc-ce-qui-protege","deck":"territoires","type":"ancrer","fr":{"title":"Ce qui te protège","entry":"Avant de parler de ta position sur ce territoire, sens ce qui te défend en toi. Pas tes arguments — ton réflexe.","steps":["Il y a quelque chose en toi qui est prêt à tenir bon, à expliquer, à convaincre.","Ce réflexe est là pour une bonne raison. Qu'est-ce qu'il protège exactement ?","Sens-le dans le corps — une tension, une vigilance, une posture.","Tu n'as pas besoin de le faire disparaître. Juste de le voir."],"question":"Qu'est-ce que ton réflexe défensif protège — une valeur, une peur, quelque chose que tu as construit ?","trace":null,"sources":["Intelligence Relationnelle / IFS — R. Schwartz"]},"en":{"title":"What protects you","entry":"Before speaking about your position on this territory, feel what defends you. Not your arguments — your reflex.","steps":["There is something in you ready to hold firm, to explain, to convince.","This reflex is there for a good reason. What exactly does it protect?","Feel it in the body — a tension, a vigilance, a posture.","You don't need to make it disappear. Just to see it."],"question":"What does your defensive reflex protect — a value, a fear, something you have built?","trace":null,"sources":["Relational Intelligence / IFS — R. Schwartz"]}},{"id":"tc-peur-sous-position","deck":"territoires","type":"traverser","fr":{"title":"La peur sous la position","entry":"Choisissez quelqu'un dont vous percevez la position comme opposée à la vôtre sur ce territoire.","steps":["Ne pensez pas à ses arguments. Pensez à ce qui pourrait lui faire peur.","Qu'est-ce qu'il ou elle cherche à protéger — une façon de vivre, un travail, un avenir, une identité ?","Formulez sa peur en une phrase qui commence par : « Ce qu'il/elle ne voudrait pas perdre, c'est… »","Dites cette phrase à voix haute. Sentez si quelque chose résonne — même légèrement — avec vos propres peurs."],"question":"Quelle peur avez-vous en commun, même si vos positions sont opposées ?","trace":null,"sources":["François Le Doze, neurologue et praticien IFS — l'Intelligence Relationnelle","Stephen Porges, neuroscientifique — la théorie polyvagale (1994)"]},"en":{"title":"The fear beneath the position","entry":"Choose someone whose position on this territory you perceive as opposed to yours.","steps":["Don't think about their arguments. Think about what might frighten them.","What are they trying to protect — a way of life, a livelihood, a future, an identity?","Formulate their fear in a sentence beginning with: 'What they wouldn't want to lose is…'","Say this sentence aloud. Feel if something resonates — even slightly — with your own fears."],"question":"What fear do you share, even if your positions are opposed?","trace":null,"sources":["Relational Intelligence — François Le Doze","Polyvagal Theory — S. Porges"]}},{"id":"tc-inconfort-insecurite","deck":"territoires","type":"traverser","fr":{"title":"Inconfort ou insécurité ?","entry":"Dans cette conversation, quelque chose vous met mal à l'aise. Prenez un moment pour distinguer de quoi il s'agit vraiment.","steps":["L'inconfort : quelque chose remet en question vos habitudes, vos certitudes, votre confort. C'est difficile mais vous n'êtes pas en danger.","L'insécurité réelle : quelque chose menace votre existence concrète — votre travail, votre terre, votre droit d'être là.","Placez-vous dans l'espace : près de la porte si c'est de l'inconfort, au centre si c'est de l'insécurité.","Regardez où se placent les autres. Sans commenter d'abord."],"question":"Qu'est-ce que la géographie du groupe révèle que les mots ne disaient pas ?","trace":null,"sources":["François Le Doze, neurologue et praticien IFS — l'Intelligence Relationnelle","Leticia Nieto, psychologue — Beyond Inclusion, Beyond Empowerment (2010)"]},"en":{"title":"Discomfort or real insecurity?","entry":"In this conversation, something makes you uncomfortable. Take a moment to distinguish what it really is.","steps":["Discomfort: something questions your habits, certainties, comfort. It's difficult but you are not in danger.","Real insecurity: something threatens your concrete existence — your livelihood, your land, your right to be here.","Place yourself in the space: near the door if it's discomfort, at the centre if it's insecurity.","Look at where others place themselves. Without commenting first."],"question":"What does the geography of the group reveal that words were not saying?","trace":null,"sources":["Relational Intelligence — François Le Doze","IFS for Social Justice — L. Nieto"]}},{"id":"tc-douleur-partagee","deck":"territoires","type":"composer","fr":{"title":"La douleur partagée","entry":"Sous les positions, sous les désaccords, il y a quelque chose que tout le monde dans ce groupe ressent — et que personne n'a encore nommé.","steps":["Chacun·e prend un moment en silence. Sens ce qui est difficile dans cette situation — pas pour toi seul·e, mais pour le groupe entier.","Ce n'est pas une opinion. C'est un ressenti partagé : l'épuisement, la peur de l'échec, le deuil de quelque chose, l'impuissance.","Chacun·e dit une phrase : « Ce que je crois qu'on partage tous ici, c'est… »","Écoutez sans débattre. Cherchez ce qui résonne dans plusieurs voix."],"question":"Qu'est-ce qui souffre dans ce collectif — et que cette souffrance dit-elle de ce qui compte vraiment ?","trace":null,"sources":["Intelligence Relationnelle / IFS — R. Schwartz","Pratiques Restauratives — D. Barter"]},"en":{"title":"The shared pain","entry":"Beneath the positions, beneath the disagreements, there is something everyone in this group feels — and that no one has yet named.","steps":["Each person takes a moment in silence. Feel what is difficult in this situation — not for you alone, but for the whole group.","This is not an opinion. It's a shared feeling: exhaustion, fear of failure, grief for something, powerlessness.","Each person says one sentence: 'What I believe we all share here is…'","Listen without debating. Look for what resonates across several voices."],"question":"What is suffering in this collective — and what does this suffering say about what truly matters?","trace":null,"sources":["Relational Intelligence / IFS — R. Schwartz","Restorative Practices — D. Barter"]}}],"sc":[{"id":"tr-couler","deck":"traversees","type":"verbe_solo","fr":{"verb":"Couler","qualities":["gravité","abandon","niveau bas"],"invitation":"La gravité est ton alliée. Vers le bas."},"en":{"verb":"Flowing","qualities":["gravity","surrender","downward"],"invitation":"Gravity is your ally. Downward."}},{"id":"tr-germer","deck":"traversees","type":"verbe_solo","fr":{"verb":"Germer","qualities":["l'imperceptible","insistance","obscurité"],"invitation":"Si petit qu'on ne le voit pas encore."},"en":{"verb":"Sprouting","qualities":["imperceptible","insistence","darkness"],"invitation":"So small it cannot yet be seen."}},{"id":"tr-rayonner","deck":"traversees","type":"verbe_solo","fr":{"verb":"Fondre","qualities":["chaleur","dissolution","matière"],"invitation":"Quelque chose en toi cède à la chaleur. Pas s'effondrer — se transformer lentement.","fr":{"verb":"Fondre","qualities":["chaleur","dissolution","matière"],"invitation":"Quelque chose en toi cède à la chaleur. Pas s'effondrer — se transformer."},"en":{"verb":"Melting","qualities":["warmth","dissolution","matter"],"invitation":"Something in you yields to warmth. Not collapsing — transforming."}},"en":{"verb":"Melting","qualities":["warmth","dissolution","matter"],"invitation":"Something in you yields to warmth. Not collapsing — slowly transforming.","fr":{"verb":"Fondre","qualities":["chaleur","dissolution","matière"],"invitation":"Quelque chose en toi cède à la chaleur. Pas s'effondrer — se transformer."},"en":{"verb":"Melting","qualities":["warmth","dissolution","matter"],"invitation":"Something in you yields to warmth. Not collapsing — transforming."}}},{"id":"tr-vibrer","deck":"traversees","type":"verbe_solo","fr":{"verb":"Vibrer","qualities":["fréquence","résonance","dedans-dehors"],"invitation":"Ce qui vibre en toi vibre aussi autour de toi."},"en":{"verb":"Vibrating","qualities":["frequency","resonance","inside-out"],"invitation":"What vibrates in you also vibrates around you."}},{"id":"tr-tisser","deck":"traversees","type":"verbe_solo","fr":{"verb":"Tracer","qualities":["empreinte","passage","mémoire du sol"],"invitation":"Ce que tu traverses garde une trace de ton passage. Laisse-la.","fr":{"verb":"Tracer","qualities":["empreinte","passage","mémoire du sol"],"invitation":"Ce que tu traverses garde une trace de ton passage. Laisse-la."},"en":{"verb":"Tracing","qualities":["imprint","passage","ground memory"],"invitation":"What you cross keeps a trace of your passage. Leave it."}},"en":{"verb":"Tracing","qualities":["imprint","passage","ground memory"],"invitation":"What you cross keeps a trace of your passage. Leave it.","fr":{"verb":"Tracer","qualities":["empreinte","passage","mémoire du sol"],"invitation":"Ce que tu traverses garde une trace de ton passage. Laisse-la."},"en":{"verb":"Tracing","qualities":["imprint","passage","ground memory"],"invitation":"What you cross keeps a trace of your passage. Leave it."}}},{"id":"tr-muer","deck":"traversees","type":"verbe_solo","fr":{"verb":"Muer","qualities":["laisser tomber","peau ancienne","vulnérabilité"],"invitation":"Quelque chose doit partir pour que quelque chose d'autre arrive."},"en":{"verb":"Moulting","qualities":["letting fall","old skin","vulnerability"],"invitation":"Something must leave for something else to arrive."}},{"id":"tr-creuser","deck":"traversees","type":"verbe_solo","fr":{"verb":"Creuser","qualities":["retrait","intérieur","espace fait"],"invitation":"Faire de la place à l'intérieur de quelque chose."},"en":{"verb":"Burrowing","qualities":["withdrawal","interior","made space"],"invitation":"Making room inside something."}},{"id":"tr-attendre","deck":"traversees","type":"verbe_solo","fr":{"verb":"Attendre","qualities":["disponibilité","immobilité active","seuil"],"invitation":"Être prêt·e sans savoir quoi."},"en":{"verb":"Waiting","qualities":["availability","active stillness","threshold"],"invitation":"Being ready without knowing for what."}},{"id":"tr-suspendre","deck":"traversees","type":"verbe_solo","fr":{"verb":"Suspendre","qualities":["entre","ni l'un ni l'autre","retenu"],"invitation":"Rester entre deux. Ne pas décider encore."},"en":{"verb":"Suspending","qualities":["between","neither-nor","held"],"invitation":"Staying between two. Not deciding yet."}},{"id":"tr-plonger","deck":"traversees","type":"verbe_solo","fr":{"verb":"Plonger","qualities":["seuil","immersion","sans retour immédiat"],"invitation":"Le moment juste avant. Puis après."},"en":{"verb":"Diving","qualities":["threshold","immersion","no return yet"],"invitation":"The moment just before. Then after."}},{"id":"tr-traverser","deck":"traversees","type":"verbe_solo","fr":{"verb":"Traverser","qualities":["passage","milieu","trace"],"invitation":"Tu n'es pas une destination. Tu es un milieu que quelque chose traverse."},"en":{"verb":"Crossing","qualities":["passage","through","trace"],"invitation":"You are not a destination. You are a milieu something crosses."}},{"id":"tr-roder","deck":"traversees","type":"verbe_solo","fr":{"verb":"Rôder","qualities":["périphérie","instinct","vigilance"],"invitation":"Ni dedans ni dehors. Autour."},"en":{"verb":"Prowling","qualities":["periphery","instinct","vigilance"],"invitation":"Neither inside nor outside. Around."}},{"id":"tr-fleurir-faner","deck":"traversees","type":"verbe_dual","fr":{"verb":"Fleurir / Faner","qualities":["ouverture","déclin","cycle"],"invitation":"Les deux sont vrais. Les deux ensemble."},"en":{"verb":"Blooming / Wilting","qualities":["opening","decline","cycle"],"invitation":"Both are true. Both together."}},{"id":"tr-pousser-ceder","deck":"traversees","type":"verbe_dual","fr":{"verb":"Pousser / Céder","qualities":["force","résistance","dialogue"],"invitation":"L'un pousse. L'autre cède. Puis inversez. Puis cherchez le milieu."},"en":{"verb":"Pushing / Yielding","qualities":["force","resistance","dialogue"],"invitation":"One pushes. The other yields. Then reverse. Then find the middle."}},{"id":"tr-enraciner-elancer","deck":"traversees","type":"verbe_dual","fr":{"verb":"S'enraciner / S'élancer","qualities":["ancre","élan","tension féconde"],"invitation":"On ne s'élance que depuis un ancrage. L'ancrage n'est pas l'immobilité."},"en":{"verb":"Rooting / Leaping","qualities":["anchor","momentum","fertile tension"],"invitation":"You can only leap from an anchor. Anchoring is not stillness."}},{"id":"tr-contracter-expandre","deck":"traversees","type":"verbe_dual","fr":{"verb":"Se contracter / S'expandre","qualities":["intérieur","extérieur","respiration"],"invitation":"Le corps sait déjà. C'est ce qu'il fait depuis toujours."},"en":{"verb":"Contracting / Expanding","qualities":["interior","exterior","breathing"],"invitation":"The body already knows. It's what it's always done."}},{"id":"tr-bruler-steindre","deck":"traversees","type":"verbe_dual","fr":{"verb":"Brûler / S'éteindre","qualities":["intensité","fin","braise"],"invitation":"Ce qui s'éteint n'a pas disparu. Il reste une braise."},"en":{"verb":"Burning / Extinguishing","qualities":["intensity","ending","ember"],"invitation":"What is extinguished hasn't disappeared. An ember remains."}},{"id":"tr-monter-descendre","deck":"traversees","type":"verbe_dual","fr":{"verb":"Monter / Descendre","qualities":["verticalité","gravité","souffle"],"invitation":"Ce qui monte appelle ce qui descend."},"en":{"verb":"Rising / Descending","qualities":["verticality","gravity","breath"],"invitation":"What rises calls what descends."}},{"id":"tr-cacher-montrer","deck":"traversees","type":"verbe_dual","fr":{"verb":"Se cacher / Se montrer","qualities":["protection","vulnérabilité","jeu"],"invitation":"Qu'est-ce qui veut être vu ? Qu'est-ce qui veut rester dans l'ombre ?"},"en":{"verb":"Hiding / Showing","qualities":["protection","vulnerability","play"],"invitation":"What wants to be seen? What wants to stay in shadow?"}},{"id":"tr-veiller-dormir","deck":"traversees","type":"verbe_dual","fr":{"verb":"Naître / Mourir","qualities":["commencement","fin","cycle du vivant"],"invitation":"Chaque chose vivante dans ce lieu a commencé et finira. Ton corps connaît ces deux mouvements.","fr":{"verb":"Naître / Mourir","qualities":["commencement","fin","cycle du vivant"],"invitation":"Chaque chose qui vit dans ce lieu a commencé et finira. Ton corps aussi connaît ces deux mouvements."},"en":{"verb":"Being born / Dying","qualities":["beginning","ending","cycle of the living"],"invitation":"Everything alive in this place began and will end. Your body knows both these movements."}},"en":{"verb":"Being born / Dying","qualities":["beginning","ending","cycle of the living"],"invitation":"Everything alive in this place began and will end. Your body knows both these movements.","fr":{"verb":"Naître / Mourir","qualities":["commencement","fin","cycle du vivant"],"invitation":"Chaque chose qui vit dans ce lieu a commencé et finira. Ton corps aussi connaît ces deux mouvements."},"en":{"verb":"Being born / Dying","qualities":["beginning","ending","cycle of the living"],"invitation":"Everything alive in this place began and will end. Your body knows both these movements."}}},{"id":"tr-q-lent-soudain","deck":"traversees","type":"qualite","fr":{"verb":"Lent / Soudain","qualities":["tempo","surprise","rythme"],"invitation":"Commence lentement. Laisse la soudaineté décider d'elle-même."},"en":{"verb":"Slow / Sudden","qualities":["tempo","surprise","rhythm"],"invitation":"Start slowly. Let suddenness decide for itself."}},{"id":"tr-q-dense-poreux","deck":"traversees","type":"qualite","fr":{"verb":"Dense / Poreux·se","qualities":["masse","perméabilité","texture"],"invitation":"Le corps qui ne laisse rien passer. Le corps que tout traverse."},"en":{"verb":"Dense / Porous","qualities":["mass","permeability","texture"],"invitation":"The body that lets nothing through. The body everything crosses."}},{"id":"tr-q-direct-indirect","deck":"traversees","type":"qualite","fr":{"verb":"Direct / Indirect","qualities":["intention","détour","trajectoire"],"invitation":"Vers. Puis autour. Puis depuis."},"en":{"verb":"Direct / Indirect","qualities":["intention","detour","trajectory"],"invitation":"Toward. Then around. Then from."}},{"id":"tr-q-retenu-libre","deck":"traversees","type":"qualite","fr":{"verb":"Retenu / Libre","qualities":["contrôle","abandon","limite"],"invitation":"Sens ce que tu retiens. Puis laisse."},"en":{"verb":"Restrained / Free","qualities":["control","abandon","limit"],"invitation":"Feel what you hold back. Then release."}},{"id":"tr-q-aigu-grave","deck":"traversees","type":"qualite","fr":{"verb":"Léger / Lourd","qualities":["pesanteur","élévation","gravité"],"invitation":"Le sol sous toi est lourd. L'air au-dessus de toi est léger. Ton corps oscille entre les deux en permanence."},"en":{"verb":"Light / Heavy","qualities":["heaviness","elevation","gravity"],"invitation":"The ground beneath you is heavy. The air above you is light. Your body oscillates between them continuously."}},{"id":"tr-q-continu-pulse","deck":"traversees","type":"qualite","fr":{"verb":"Continu / Pulsé","qualities":["flux","battement","interruption"],"invitation":"Le souffle continu. Le cœur pulsé. Les deux ensemble."},"en":{"verb":"Continuous / Pulsed","qualities":["flow","beat","interruption"],"invitation":"Breath continuous. Heart pulsed. Both together."}},{"id":"tr-c-sol-suspension","deck":"traversees","type":"contrainte","fr":{"verb":"Au sol / En suspension","qualities":["gravité","légèreté","niveau"],"invitation":"Pas l'un puis l'autre. Les deux à la fois, autant que possible."},"en":{"verb":"On the ground / Suspended","qualities":["gravity","lightness","level"],"invitation":"Not one then the other. Both at once, as much as possible."}},{"id":"tr-c-fixe-errant","deck":"traversees","type":"contrainte","fr":{"verb":"Fixe / Errant·e","qualities":["ancre","dérive","territoire"],"invitation":"Revenir toujours au même point. Ou ne jamais revenir."},"en":{"verb":"Fixed / Wandering","qualities":["anchor","drift","territory"],"invitation":"Always return to the same point. Or never return."}},{"id":"tr-c-contact-distance","deck":"traversees","type":"contrainte","fr":{"verb":"En contact / À distance","qualities":["toucher","espace","relation"],"invitation":"Le contact sans se toucher. La distance comme lien."},"en":{"verb":"In contact / At distance","qualities":["touch","space","relation"],"invitation":"Contact without touching. Distance as connection."}},{"id":"tr-c-ensemble-seul","deck":"traversees","type":"contrainte","fr":{"verb":"Proche / Lointain","qualities":["distance","attraction","séparation"],"invitation":"Quelque chose dans ce lieu t'attire. Quelque chose t'en éloigne. Laisse ton corps naviguer cette tension."},"en":{"verb":"Near / Far","qualities":["distance","attraction","separation"],"invitation":"Something in this place draws you in. Something moves you away. Let your body navigate this tension."}},{"id":"tr-c-silence-son","deck":"traversees","type":"contrainte","fr":{"verb":"Dans le silence / Avec un son","qualities":["écoute","voix","résonance"],"invitation":"Le corps qui écoute. Le corps qui émet. Puis les deux."},"en":{"verb":"In silence / With sound","qualities":["listening","voice","resonance"],"invitation":"The body that listens. The body that emits. Then both."}},{"id":"tr-c-vue-aveugle","deck":"traversees","type":"contrainte","fr":{"verb":"Les yeux ouverts / Fermés","qualities":["regard","intériorité","espace"],"invitation":"Ce que les yeux fermés donnent que les yeux ouverts ne peuvent pas."},"en":{"verb":"Eyes open / Closed","qualities":["gaze","interiority","space"],"invitation":"What closed eyes give that open eyes cannot."}}],"cm":[{"id":"cm-microbiome","deck":"corps_monde","type":"echelle","fr":{"title":"Le microbiome","entry":"Tu n'es pas seul·e dans ton corps. Tu es une forêt habitée.","body":["Debout. Sens le volume de ton corps — sa surface, ses cavités, sa chaleur.","Maintenant : laisse entrer l'idée que ce volume est habité. 38 000 milliards de bactéries. Des communautés entières dans tes intestins, sur ta peau, dans tes poumons.","Commence à bouger très lentement — comme si tu bougeais non pas un corps seul mais un écosystème. Chaque mouvement déplace des millions d'êtres.","Arrête-toi. Pose une main sur ton ventre. C'est là que la majorité vit. Dis 'bonjour' — pas ironiquement."],"retour":"Qu'est-ce que ça change de se sentir communauté plutôt qu'individu ?","sources":["Marc-André Selosse — Jamais seul : ces microbes qui construisent les plantes, les animaux et les civilisations","Donna Haraway — Staying with the Trouble : l'holobionte, le corps comme assemblage d'espèces"]},"en":{"title":"The microbiome","entry":"You are not alone in your body. You are an inhabited forest.","body":["Standing. Feel the volume of your body — its surface, its cavities, its warmth.","Now: let in the idea that this volume is inhabited. 38 trillion bacteria. Entire communities in your intestines, on your skin, in your lungs.","Begin to move very slowly — as if moving not a single body but an ecosystem. Each movement displaces millions of beings.","Stop. Place a hand on your belly. That's where the majority lives. Say 'hello' — not ironically."],"retour":"What changes when you feel yourself as community rather than individual?","sources":["Selosse M.-A. — Never Alone: microbes that build plants, animals and civilisations","Haraway D. — Staying with the Trouble: the holobiont, the body as multispecies assemblage"]}},{"id":"cm-plastique","deck":"corps_monde","type":"echelle","fr":{"title":"Le plastique dans le sang","entry":"Des microplastiques ont été trouvés dans le sang humain, dans les poumons, dans le placenta, dans le lait maternel.","body":["Ferme les yeux. Parcours ton corps avec ton attention, de la tête aux pieds — pas pour relaxer, pour inventorier. Qu'est-ce qui est vraiment toi, et qu'est-ce qui a été déposé ?","Ouvre les yeux. Regarde ta main. Ces molécules de plastique qui circulent dans ton sang — elles sont arrivées par la nourriture, l'air, l'eau. Elles ont traversé ta peau, tes poumons, ton intestin.","Frotte lentement tes deux paumes l'une contre l'autre. Sens la chaleur qui apparaît. Ce frottement génère de l'électricité statique — le plastique aussi. Quelque chose de physique relie ces deux faits.","Maintenant : quelle décision dans ta vie quotidienne a laissé entrer du plastique dans ton corps cette semaine ? Pas pour culpabiliser — pour voir la chaîne."],"retour":"Cette contamination est-elle dehors ou dedans ? Où passe la frontière ?","sources":["Rachel Carson — Silent Spring (1962) : la contamination silencieuse","Lancet Diabetes & Endocrinology 2026 : microplastiques comme perturbateurs endocriniens ubiquitaires"]},"en":{"title":"Plastic in the blood","entry":"Microplastics have been found in human blood, lungs, placentas, and breast milk.","body":["Close your eyes. Move your attention through your body from head to feet — not to relax, to inventory. What is truly you, and what has been deposited?","Open your eyes. Look at your hand. These plastic molecules circulating in your blood arrived through food, air, water. They crossed your skin, your lungs, your intestine.","Slowly rub both palms together. Feel the heat that appears. This friction generates static electricity — so does plastic. Something physical connects these two facts.","Now: what decision in your daily life let plastic into your body this week? Not to feel guilt — to see the chain."],"retour":"Is this contamination outside or inside? Where is the boundary?","sources":["Carson R. — Silent Spring (1962): the silent contamination","Lancet Diabetes & Endocrinology 2026: microplastics as ubiquitous endocrine disruptors"]}},{"id":"cm-ancestral","deck":"corps_monde","type":"echelle","fr":{"title":"La mémoire ancestrale","entry":"Ton corps porte une mémoire de 3,8 milliards d'années de vie sur Terre.","body":["Tiens-toi debout, immobile. Pose une main sur ton sternum, au centre de la poitrine.","Sous cette main : un cœur qui bat selon un rythme hérité de tes ancêtres mammifères, reptiliens, marins.","Commence à bouger depuis ce centre — très lentement, comme si chaque geste contenait les gestes de tout ce qui t'a précédé·e : nager, ramper, grimper, marcher.","Tu n'es pas la fin de quelque chose. Tu es un passage. Laisse ce mouvement traverser des millions d'années jusqu'à maintenant."],"retour":"Qu'est-ce que ça fait de se sentir passage plutôt que destination ?","sources":["Robin Wall Kimmerer — Braiding Sweetgrass : 'nous sommes les cadets de la création'","Marc-André Selosse — Les origines symbiotiques de la vie complexe"]},"en":{"title":"Ancestral memory","entry":"Your body carries a memory of 3.8 billion years of life on Earth.","body":["Stand still. Place a hand on your sternum, at the centre of your chest.","Under this hand: a heart beating to a rhythm inherited from your mammalian, reptilian, marine ancestors.","Begin to move from this centre — very slowly, as if each gesture contained the gestures of all that preceded you: swimming, crawling, climbing, walking.","You are not the end of something. You are a passage. Let this movement travel across millions of years to now."],"retour":"What does it feel like to sense yourself as passage rather than destination?","sources":["Kimmerer R.W. — Braiding Sweetgrass: 'we are the younger siblings of creation'","Selosse M.-A. — The symbiotic origins of complex life"]}},{"id":"cm-respiration-mondiale","deck":"corps_monde","type":"echelle","fr":{"title":"La respiration du monde","entry":"Chaque souffle que tu prends a déjà été respiré par d'autres — humains, animaux, forêts, océans.","body":["Trouve le rythme de ta respiration sans le forcer. Juste l'observer entrer et sortir.","L'oxygène de ce souffle vient en partie du phytoplancton marin — des organismes microscopiques qui produisent la moitié de l'oxygène terrestre.","Élargis ta respiration : que les bras s'ouvrent à l'inspir, se referment à l'expir. Amplifie le geste de l'échange.","Des millions d'espèces respirent en ce moment, dans le même mouvement que toi. Tu n'inventes rien — tu rejoins quelque chose de très ancien."],"retour":"Si ta respiration te reliait à tout ce qui respire, que changerais-tu à ta façon de respirer ?","sources":["Davi Kopenawa & Bruce Albert — La Chute du ciel (2010) : la forêt amazonienne comme poumon du monde et être vivant à défendre","Karen Barad — Meeting the Universe Halfway (2007) : l'intra-action comme condition de toute respiration et échange"]},"en":{"title":"The world's breathing","entry":"Every breath you take has already been breathed by others — humans, animals, forests, oceans.","body":["Find the rhythm of your breath without forcing it. Just observe it enter and leave.","The oxygen of this breath comes partly from marine phytoplankton — microscopic organisms producing half the Earth's oxygen.","Widen your breathing: let the arms open on the inhale, close on the exhale. Amplify the gesture of exchange.","Millions of species are breathing right now, in the same movement as you. You invent nothing — you join something very old."],"retour":"If your breathing connected you to everything that breathes, what would you change in how you breathe?","sources":["Kopenawa D. & Bruce Albert — The Falling Sky (2010): the Amazon forest as world's lung and living being to defend","Barad K. — Meeting the Universe Halfway (2007): intra-action as condition of all breathing and exchange"]}},{"id":"cm-extinction","deck":"corps_monde","type":"echelle","fr":{"title":"Le deuil des espèces","entry":"Depuis ta naissance, des milliers d'espèces ont disparu pour toujours.","body":["Choisis une espèce disparue ou menacée que tu connais — par une rencontre, une image, un son, une description.","Mime son mouvement le plus caractéristique : le vol d'un oiseau, la nage d'un poisson, la façon dont un insecte se pose. Prends le temps d'y être vraiment.","Maintenant gèle. Reste dans cette position figée. Sens ce que ça fait de tenir immobile quelque chose qui n'existe plus — ou presque plus.","Solo : laisse très lentement ce corps figé revenir à un mouvement vivant — le tien. En groupe : quelqu'un peut modifier doucement ta posture vers quelque chose de vivant."],"retour":"Qu'est-ce que ce deuil dit de ce à quoi tu appartiens ?","sources":["Joanna Macy — Work That Reconnects : honorer la douleur pour le monde","Rachel Carson — Silent Spring : le printemps sans oiseaux"]},"en":{"title":"Grieving species","entry":"Since you were born, thousands of species have disappeared forever.","body":["Choose an extinct or endangered species you know — through an encounter, an image, a sound, a description.","Mime its most characteristic movement: a bird's flight, a fish's swim, the way an insect lands. Take time to truly be there.","Now freeze. Stay in that fixed position. Feel what it is to hold still something that no longer exists — or barely.","Alone: let this frozen body very slowly return to living movement — your own. In a group: someone can gently modify your posture toward something alive."],"retour":"What does this grief say about what you belong to?","sources":["Macy J. — Work That Reconnects: honouring pain for the world","Carson R. — Silent Spring: the spring without birds"]}},{"id":"cm-corps-territoire","deck":"corps_monde","type":"territoire_corps","fr":{"title":"Le corps comme territoire","entry":"Ton corps est un territoire. Il a été cartographié, extrait, contrôlé, défendu.","body":["Lorena Cabnal, féministe maya q'eqchi et xinka du Guatemala, pose cette équation : défendre son territoire, son corps et sa terre, c'est une seule et même lutte.","Les violences sur les corps et les violences sur les terres partagent une même logique d'extraction.","Pose les deux mains sur ton sternum. Puis fais-les voyager lentement le long de tes bras, tes épaules, ta nuque — comme si tu reconnaissais un territoire que tu habites.","Ce corps t'appartient. Bouge un instant comme quelqu'un qui occupe pleinement son propre territoire — sans s'excuser d'y être."],"retour":"Qu'est-ce que ça change d'habiter son corps comme un territoire plutôt que de l'utiliser comme un outil ?","sources":["Lorena Cabnal — Feminismo comunitario territorial : territorio-cuerpo-tierra (2010)","Arturo Escobar — Territories of Difference (2008) : les territoires comme lieux de vie, pas seulement de ressources","Dora Tania Cruz Hernández — Una mirada muy otra a los territorios-cuerpos (2020)"]},"en":{"title":"The body as territory","entry":"Your body is a territory. It has been mapped, extracted, controlled, defended.","body":["Lorena Cabnal, Maya q'eqchi and xinka feminist from Guatemala, poses this equation: defending one's territory, one's body and one's land is one and the same struggle.","Violence against bodies and violence against lands share the same logic of extraction.","Place both hands on your sternum. Then let them travel slowly along your arms, shoulders, neck — as if recognising a territory you inhabit.","This body is yours. Move for a moment like someone who fully occupies their own territory — without apologising for being there."],"retour":"What changes when you inhabit your body as a territory rather than use it as a tool?","sources":["Cabnal L. — Community territorial feminism: territorio-cuerpo-tierra (2010)","Escobar A. — Territories of Difference (2008): territories as places of life, not just resources","Dora Tania Cruz Hernández — Another look at body-territories (2020)"]}},{"id":"cm-animisme-grammaire","deck":"corps_monde","type":"territoire_corps","fr":{"title":"La grammaire de l'animé","entry":"Dans la langue Potawatomi, une colline, une baie, une fraise sont des êtres animés, des personnes — pas des choses.","body":["Choisis une chose non-humaine dans cet espace. Pas la plus belle — celle qui attire ton regard sans que tu saches pourquoi.","Approche-toi d'elle. Présente-toi à voix haute, comme tu te présenterais à quelqu'un que tu rencontres pour la première fois. Ton nom, d'où tu viens, ce que tu fais là.","Puis : écoute. Vraiment. Pas ce que tu imagines qu'elle dirait — ce qui se passe dans ton corps quand tu lui accordes cette attention.","En Potawatomi, les êtres animés ont une grammaire différente. Parle de cette chose à quelqu'un avec 'iel' à la place de 'il' ou 'elle'. Remarque si quelque chose change dans ta bouche."],"retour":"Qu'est-ce qui change dans notre rapport au vivant quand on lui refuse le statut de personne ?","sources":["Robin Wall Kimmerer — Braiding Sweetgrass : 'Learning the Grammar of Animacy'","Robin Wall Kimmerer — The Serviceberry : abondance et réciprocité"]},"en":{"title":"The grammar of animacy","entry":"In the Potawatomi language, a hill, a bay, a strawberry are animate beings, persons — not things.","body":["Choose a non-human thing in this space. Not the most beautiful — the one that catches your gaze without you knowing why.","Approach it. Introduce yourself aloud, as you would introduce yourself to someone you're meeting for the first time. Your name, where you're from, why you're here.","Then: listen. Really. Not what you imagine it would say — what happens in your body when you grant it this attention.","In Potawatomi, animate beings have a different grammar. Talk about this thing to someone using 'they' instead of 'it'. Notice if something changes in your mouth."],"retour":"What changes in our relation to the living when we deny it the status of person?","sources":["Kimmerer R.W. — Braiding Sweetgrass: 'Learning the Grammar of Animacy'","Kimmerer R.W. — The Serviceberry: abundance and reciprocity"]}},{"id":"cm-ruines-capitalistes","deck":"corps_monde","type":"territoire_corps","fr":{"title":"Vivre dans les ruines","entry":"Anna Tsing, anthropologue, l'a formulé ainsi : nous vivons déjà dans les ruines capitalistes. Et la vie y pousse quand même.","body":["Trouve dans cet espace quelque chose d'abîmé — une surface usée, une plante qui pousse dans une fissure, une trace d'humidité sur un mur, une mauvaise herbe dans du béton.","Accroupis-toi ou mets-toi à sa hauteur. Regarde-le avec l'attention qu'on accorde habituellement aux choses intactes.","Maintenant : imite son mouvement ou sa qualité avec ton corps. La fissure qui s'étire. La plante qui insiste. L'eau qui s'infiltre. Sans exagérer — juste la qualité.","Le matsutaké pousse dans les forêts dévastées. Ce que tu viens d'imiter — c'est de la vie après."],"retour":"Qu'est-ce qui pousse dans les ruines que tu connais ?","sources":["Anna Tsing — Mushroom at the End of the World (2015) : le capitalisme de sauvetage et la vie dans les ruines","Arturo Escobar — Designs for the Pluriverse (2018) : les mondes alternatifs qui persistent dans les fissures du système dominant"]},"en":{"title":"Living in the ruins","entry":"Anna Tsing says: we already live in capitalist ruins. And life grows there anyway.","body":["Find in this space something damaged — a worn surface, a plant growing in a crack, a moisture trace on a wall, a weed through concrete.","Crouch or get to its level. Look at it with the attention usually given to intact things.","Now: imitate its movement or quality with your body. The crack that stretches. The plant that insists. The water that seeps. Without exaggerating — just the quality.","Matsutake grows in devastated forests. What you just imitated — that's life after."],"retour":"What grows in the ruins you know?","sources":["Anna Tsing — Mushroom at the End of the World (2015): salvage capitalism and life in the ruins","Escobar A. — Designs for the Pluriverse (2018): alternative worlds persisting in the cracks of the dominant system"]}},{"id":"cm-cyborg","deck":"corps_monde","type":"territoire_corps","fr":{"title":"Le corps cyborg","entry":"Pour Donna Haraway, biologiste et philosophe, nous sommes tous et toutes déjà des cyborgs — des hybrides de machine et d'organisme.","body":["Ton téléphone est une prothèse cognitive. Les médicaments que tu prends modifient ta chimie. Les lunettes changent ta perception.","La frontière nature/culture est une fiction utilisée pour justifier des dominations.","Donna Haraway, biologiste et philosophe, insiste : le cyborg n'est pas une métaphore futuriste — c'est une description du présent.","Bouge. Sens où dans ton corps la limite entre toi et le technique est floue, poreuse, négociée."],"retour":"Où commence le 'naturel' dans ton corps ? Est-ce une question qui a un sens ?","sources":["Donna Haraway — A Cyborg Manifesto (1985) : science, technologie et féminisme socialiste","Karen Barad — Meeting the Universe Halfway (2007) : la matière comme acteur, pas comme décor"]},"en":{"title":"The cyborg body","entry":"Haraway says: we are all already cyborgs — hybrids of machine and organism.","body":["Your phone is a cognitive prosthesis. The medicines you take modify your chemistry. Glasses change your perception.","The nature/culture boundary is a fiction used to justify dominations.","Haraway says: the cyborg is not a futuristic metaphor. It is a description of the present.","Move. Feel where in your body the limit between you and the technical is blurred, porous, negotiated."],"retour":"Where does the 'natural' begin in your body? Is that a question that makes sense?","sources":["Haraway D. — A Cyborg Manifesto (1985): science, technology and socialist feminism","Barad K. — Meeting the Universe Halfway (2007): matter as actor, not backdrop"]}},{"id":"cm-poeme-pluie","deck":"corps_monde","type":"poeme_action","fr":{"title":"La pluie acide","entry":"Laisse cette image entrer dans ton corps : une pluie qui ne nourrit pas mais qui abîme. Une pluie acide.","body":["Rachel Carson, biologiste, décrivait en 1962 un printemps devenu silencieux — sans oiseaux, les pesticides remontant les chaînes alimentaires.","Depuis, des milliers d'études scientifiques ont documenté ce que les industries niaient.","Bouge lentement, comme si la pluie que tu reçois était acide. Sens ce que ça fait dans le corps de recevoir quelque chose qui devrait nourrir mais qui abîme.","Puis : bouge comme si la pluie était propre. Sens la différence — précisément, dans les épaules, la nuque, le souffle."],"retour":"Comment ton corps fait-il la différence entre ce qui nourrit et ce qui abîme ?","sources":["Rachel Carson — Silent Spring (1962) : la contamination que personne ne voulait voir","Le précautionnisme comme éthique somatique"]},"en":{"title":"Acid rain","entry":"Let this image enter your body: a rain that doesn't nourish but harms. An acid rain.","body":["Rachel Carson, biologist, described in 1962 a spring gone silent — no birds, pesticides moving up the food chains.","Since then, thousands of scientific studies have documented what industries denied.","Move slowly, as if the rain you receive were acid. Feel what it does in the body to receive something that should nourish but harms.","Then: move as if the rain were clean. Feel the difference — precisely, in the shoulders, the neck, the breath."],"retour":"How does your body tell the difference between what nourishes and what harms?","sources":["Carson R. — Silent Spring (1962): the contamination nobody wanted to see","Precautionism as somatic ethics"]}},{"id":"cm-recado","deck":"corps_monde","type":"poeme_action","fr":{"title":"Récado pour le futur","entry":"Tu es en lien avec des personnes qui n'existent pas encore.","body":["Berta Cáceres, militante hondurienne assassinée en 2016 pour avoir défendu le fleuve Gualcarque, disait : 'nous sommes millénaires'.","Son corps défendait un fleuve. Le fleuve nourrissait des communautés. Les communautés tenaient un avenir.","Tends une main devant toi, vers un point dans l'espace — un être, un lieu, une personne qui viendra après toi.","Fais un geste vers ce point. Pas symbolique — un geste réel, qui engage le corps. Tu tends quelque chose à ce qui n'est pas encore là."],"retour":"Qu'est-ce que tu défends, maintenant, pour quelqu'un qui ne t'a pas demandé de le faire ?","sources":["Berta Cáceres — discours du Prix Goldman 2015 : 'Despertemos!'","Lorena Cabnal — le féminisme communautaire territorial comme acte de sanación"]},"en":{"title":"Message to the future","entry":"You are connected to people who do not yet exist.","body":["Berta Cáceres, Honduran activist murdered in 2016 for defending the Gualcarque river, said: 'we are millennial'.","Her body defended a river. The river fed communities. The communities held a future.","Extend a hand in front of you, toward a point in the space — a being, a place, a person who will come after you.","Make a gesture toward this point. Not symbolic — a real gesture that engages the body. You are handing something to what is not yet here."],"retour":"What do you defend, now, for someone who didn't ask you to?","sources":["Berta Cáceres — Goldman Prize speech 2015: 'Despertemos!'","Cabnal L. — community territorial feminism as an act of sanación"]}},{"id":"cm-temps-geologique","deck":"corps_monde","type":"echelle","fr":{"title":"Le temps géologique","entry":"Tes mains contiennent du carbone qui a été forêt, puis roche, puis océan, puis toi.","body":["Tends les deux mains devant toi, paumes vers le haut. Regarde-les comme si tu les voyais pour la première fois — leur texture, leurs lignes, la façon dont la lumière joue sur la peau.","Ces mains ont été fabriquées par tout ce que tu as mangé, bu, respiré depuis ta naissance. Et le carbone de leur chair a circulé dans le monde pendant des centaines de millions d'années avant.","Ouvre et ferme les mains très lentement. Sens le jeu des tendons, des os, des muscles. Tu es en train de bouger avec des structures venues du Carbonifère.","Pose les mains sur tes genoux. Qu'est-ce que ça change dans ton rapport au temps de le tenir entre tes paumes ?"],"retour":"Qu'est-ce que ça change de se savoir parenthèse plutôt que centre ?","sources":["Robin Wall Kimmerer — Braiding Sweetgrass : le temps comme relation, pas comme ressource","Anna Tsing — la précaution comme orientation vers le passé profond"]},"en":{"title":"Geological time","entry":"Your hands contain carbon that was forest, then rock, then ocean, then you.","body":["Hold both hands out in front of you, palms up. Look at them as if seeing them for the first time — their texture, their lines, the way light plays on the skin.","These hands were made by everything you have eaten, drunk, breathed since birth. And the carbon in their flesh circulated through the world for hundreds of millions of years before.","Open and close your hands very slowly. Feel the play of tendons, bones, muscles. You are moving with structures from the Carboniferous.","Place your hands on your knees. What changes in your relationship to time when you hold it between your palms?"],"retour":"What changes when you see yourself as parenthesis rather than centre?","sources":["Kimmerer R.W. — Braiding Sweetgrass: time as relation, not resource","Anna Tsing — precarity as orientation toward deep past"]}},{"id":"cm-poumon-foret","deck":"corps_monde","type":"echelle","fr":{"title":"Le poumon et la forêt","entry":"Tes poumons et la forêt font un échange inversé : tu inspires l'oxygène qu'elle produit, elle absorbe le gaz que tu rejettes.","body":["Cet échange n'est pas une métaphore. C'est une relation biologique réelle, à distance, en ce moment même.","Inspire profondément. Quelque part, une feuille a fabriqué une partie de cet oxygène.","Retiens un instant. Sens l'air dans ta poitrine — emprunté, pas possédé.","Expire lentement, longuement. Quelque part, une plante va utiliser ce que tu viens de rendre."],"retour":"Avec quelle forêt respires-tu en ce moment, sans le savoir ?","sources":["Rachel Carson — l'atmosphère comme bien commun fragilisé","Donna Haraway — sympoiesis : faire-ensemble comme condition de vie"]},"en":{"title":"The lung and the forest","entry":"Your lungs and the forest make a reversed exchange: you inhale the oxygen it produces, it absorbs the gas you release.","body":["This exchange is not a metaphor. It is a real biological relationship, at a distance, right now.","Inhale deeply. Somewhere, a leaf made part of this oxygen.","Hold for a moment. Feel the air in your chest — borrowed, not owned.","Exhale slowly, at length. Somewhere, a plant will use what you've just returned."],"retour":"With which forest are you breathing right now, without knowing it?","sources":["Carson R. — the atmosphere as fragile common good","Haraway D. — sympoiesis: making-together as condition of life"]}},{"id":"cm-eau-corps","deck":"corps_monde","type":"echelle","fr":{"title":"L'eau du monde","entry":"Ton corps est à 60% de l'eau. Cette eau a été pluie, glacier, rivière, mer — bien avant d'être toi.","body":["À deux : l'un·e est l'eau, l'autre est le corps. L'eau commence à bouger — liquide, trouvant le chemin de moindre résistance, s'infiltrant partout.","Le corps accueille — il s'adapte, il laisse l'eau traverser, il se transforme légèrement sous ce passage.","Échangez les rôles. Puis : effacez les rôles. Qui est l'eau, qui est le corps ? Les deux se traversent.","Arrêtez. Chacun·e reste là où il est. 60% de toi est cette eau qui vient de partout et qui ira ailleurs."],"retour":"Si tu étais l'eau, qu'est-ce que tu dirais de ton passage dans ce corps ?","sources":["Lorena Cabnal — l'eau comme droit ancestral et comme être vivant","Berta Cáceres — 'le fleuve Gualcarque nous a appelés à le défendre'"]},"en":{"title":"The world's water","entry":"Your body is 60% water. This water was rain, glacier, river, sea — long before it was you.","body":["In pairs: one is the water, the other is the body. Water begins to move — liquid, finding the path of least resistance, seeping everywhere.","The body welcomes — it adapts, lets water pass through, transforms slightly under this passage.","Swap roles. Then: erase the roles. Who is water, who is body? Both cross through each other.","Stop. Each person stays where they are. 60% of you is this water that comes from everywhere and will go elsewhere."],"retour":"If you were the water, what would you say about your passage through this body?","sources":["Cabnal L. — water as ancestral right and living being","Berta Cáceres — 'the Gualcarque River called us to defend it'"]}},{"id":"cm-semences","deck":"corps_monde","type":"territoire_corps","fr":{"title":"Les semences mémoire","entry":"Une semence contient les instructions de toutes ses ancêtres. C'est une archive vivante.","body":["Recroqueville-toi au sol — le plus petit possible. Sens le poids de ton corps vers le bas, l'obscurité imaginaire.","Il y a en toi quelque chose qui veut monter. Pas une métaphore — une tension physique réelle. Résiste-lui d'abord. Puis, très lentement, laisse-la gagner.","Monte. Pas d'un coup — par petits mouvements irréguliers, comme quelque chose qui cherche la lumière à travers une résistance.","Vandana Shiva, physicienne et militante indienne : quand une semence disparaît, c'est des millénaires de relation entre humains et plantes qui s'effacent. Ce que tu viens de faire — quelqu'un l'a fait avant toi, pendant des siècles."],"retour":"Qu'est-ce que tu portes de tes ancêtres qui cherche encore à se déployer ?","sources":["Vandana Shiva — Monocultures of the Mind (1993) : les semences comme bien commun","Robin Wall Kimmerer — les Three Sisters : maïs, haricot, courge comme système de réciprocité"]},"en":{"title":"Seeds as memory","entry":"A seed contains the instructions of all its ancestors. It is a living archive.","body":["Curl up on the ground — as small as possible. Feel the weight of your body downward, the imaginary darkness.","There is something in you that wants to rise. Not a metaphor — a real physical tension. Resist it first. Then, very slowly, let it win.","Rise. Not all at once — in small irregular movements, like something searching for light through resistance.","Shiva: when a seed disappears, millennia of relationship between humans and plants are erased. What you just did — someone did it before you, for centuries."],"retour":"What do you carry from your ancestors that is still seeking to unfold?","sources":["Shiva V. — Monocultures of the Mind (1993): seeds as common good","Kimmerer R.W. — the Three Sisters: maize, bean, squash as reciprocity system"]}},{"id":"cm-skywoman","deck":"corps_monde","type":"territoire_corps","fr":{"title":"Skywoman","entry":"Dans la cosmologie Haudenosaunee, Skywoman tombe du ciel. Les animaux créent la Terre pour elle. Elle leur offre en retour.","body":["Debout. Ferme les yeux. Imagine que tu tombes — pas vite, lentement, comme si l'air te portait.","En tombant, tu n'es pas seul·e. Des oies te portent. Une tortue monte pour t'accueillir. Tu tiens des graines dans tes mains — des cadeaux que tu apportes à ce monde.","Laisse ton corps simuler cette chute douce — un léger balancement, un abandon du poids vers le bas, les mains légèrement ouvertes comme si tu tenais quelque chose de précieux.","Arrive. Tes pieds touchent le sol. Ce n'est pas une chute dans un monde hostile — c'est une bienvenue. Ouvre les yeux. Regarde ce monde qui t'a accueilli·e."],"retour":"Qu'est-ce que tu offrirais en échange de l'accueil du monde ?","sources":["Robin Wall Kimmerer — Braiding Sweetgrass : 'Skywoman Falling', la réciprocité comme cosmologie","vs. la chute d'Adam et Eve : deux façons d'arriver dans le monde"]},"en":{"title":"Skywoman","entry":"In Haudenosaunee cosmology, Skywoman falls from the sky. Animals create the Earth for her. She gives back in return.","body":["Standing. Close your eyes. Imagine you are falling — not fast, slowly, as if the air is carrying you.","Falling, you are not alone. Geese carry you. A turtle rises to welcome you. You hold seeds in your hands — gifts you bring to this world.","Let your body simulate this gentle fall — a slight swaying, a yielding of weight downward, hands slightly open as if holding something precious.","Arrive. Your feet touch the ground. This is not a fall into a hostile world — it is a welcome. Open your eyes. Look at this world that welcomed you."],"retour":"What would you offer in exchange for the world's welcome?","sources":["Kimmerer R.W. — Braiding Sweetgrass: 'Skywoman Falling', reciprocity as cosmology","vs. the fall of Adam and Eve: two ways of arriving in the world"]}},{"id":"cm-sol-vivant","deck":"corps_monde","type":"echelle","fr":{"title":"Le sol vivant","entry":"Une cuillère à café de sol de forêt contient plus d'êtres vivants que d'humains sur Terre.","body":["Mets-toi à quatre pattes. Pas pour jouer — pour changer ta relation au sol. Sens le sol sous tes paumes et tes genoux.","Commence à te déplacer très lentement — comme si tu traversais quelque chose de vivant. Pas de l'inerte. Une ville invisible.","Arrête-toi. Colle une oreille au sol. Écoute. Pas un exercice de méditation — une vraie tentative d'entendre des vibrations que tu ne perçois pas normalement.","Lève-toi. Sens tes pieds différemment. Ce n'est plus une surface. C'est quelque chose qui travaille."],"retour":"Si tu défendais un sol, quel sol défendrais-tu ?","sources":["Marc-André Selosse — Jamais seul : le sol comme écosystème, pas comme substrat","Vandana Shiva — la guerre contre les sols comme guerre contre la vie"]},"en":{"title":"Living soil","entry":"A teaspoon of forest soil contains more living beings than humans on Earth.","body":["Get on all fours. Not to play — to change your relationship to the ground. Feel the ground under your palms and knees.","Begin to move very slowly — as if crossing something alive. Not inert. An invisible city.","Stop. Press an ear to the ground. Listen. Not a meditation exercise — a real attempt to hear vibrations you don't normally perceive.","Stand up. Feel your feet differently. This is no longer a surface. It is something that works."],"retour":"If you were to defend a soil, which soil would you defend?","sources":["Selosse M.-A. — Never Alone: soil as ecosystem, not substrate","Shiva V. — the war against soils as a war against life"]}},{"id":"cm-contamination-tg","deck":"corps_monde","type":"echelle","fr":{"title":"La transmission transgénérationnelle","entry":"Ce que tu as vécu modifie ton expression génétique. Ce que tu transmets n'est pas seulement de l'ADN.","body":["Pense à quelqu'un de ta famille — un parent, un grand-parent, quelqu'un qui t'a précédé·e. Pas leur visage — leur façon de se tenir, de marcher, de tenir leurs mains.","Adopte cette posture. Pas pour imiter — pour sentir si quelque chose résonne. Y a-t-il une tension, une façon d'occuper l'espace, que tu reconnais dans ton propre corps ?","L'épigénétique dit : les stress traversent les générations dans l'expression des gènes. Mais les forces traversent aussi — les façons d'être debout, de résister, de s'adapter.","Depuis cette posture héritée : qu'est-ce que tu aimerais transmettre à ton tour — pas comme trauma, comme force ?"],"retour":"Qu'est-ce que tu aimerais transmettre qui ne soit pas un trauma ?","sources":["Donna Haraway — le corps comme archive multi-générationnelle","recherches en épigénétique : transmission des stress environnementaux"]},"en":{"title":"Transgenerational transmission","entry":"What you have experienced modifies your genetic expression. What you transmit is not only DNA.","body":["Think of someone in your family — a parent, a grandparent, someone who preceded you. Not their face — their way of standing, walking, holding their hands.","Adopt that posture. Not to imitate — to feel if something resonates. Is there a tension, a way of occupying space, that you recognise in your own body?","Epigenetics says: stresses cross generations in gene expression. But forces cross too — ways of standing, resisting, adapting.","From this inherited posture: what would you like to transmit in turn — not as trauma, as strength?"],"retour":"What would you like to transmit that is not a trauma?","sources":["Haraway D. — the body as multi-generational archive","epigenetics research: transmission of environmental stresses"]}},{"id":"cm-bioluminescence","deck":"corps_monde","type":"poeme_action","fr":{"title":"La bioluminescence","entry":"Des milliers d'espèces marines produisent leur propre lumière. Dans l'obscurité totale des abysses, le vivant brille.","body":["Ferme les yeux. Mets une main sur ta poitrine et laisse-la immobile le temps de sentir ton cœur battre. Puis bouge très lentement — comme si chaque mouvement produisait une lumière que tu ne vois pas mais que les autres peuvent voir.","Pas grand, pas démonstratif. Micro-mouvements d'abord — les doigts, les épaules, le souffle qui soulève la poitrine. Une lumière froide, lente, régulière.","Les méduses bioluminescentes émettent non pas pour se montrer mais parce que c'est leur chimie, leur nature, leur façon d'être dans l'obscurité.","Pendant une minute : bouge comme si émettre était aussi naturel que respirer."],"retour":"Qu'est-ce qui en toi émet de la lumière même dans l'obscurité ?","sources":["Davi Kopenawa & Bruce Albert — La Chute du ciel (2010) : les esprits de la forêt comme lumières vivantes dans l'obscurité amazonienne","Marc-André Selosse — Jamais seul : la bioluminescence comme langage chimique inter-espèces"]},"en":{"title":"Bioluminescence","entry":"Thousands of marine species produce their own light. In the total darkness of the abyss, the living glows.","body":["Close your eyes. Place a hand on your chest and hold it still until you feel your heart beat. Then move very slowly — as if each movement produces a light you can't see but others can.","Not large, not demonstrative. Micro-movements first — fingers, shoulders, the breath lifting the chest. A cold, slow, steady light.","Bioluminescent jellyfish emit not to show themselves but because it's their chemistry, their nature, their way of being in darkness.","For one minute: move as if emitting were as natural as breathing."],"retour":"What in you emits light even in darkness?","sources":["Kopenawa D. & Bruce Albert — The Falling Sky (2010): forest spirits as living lights in Amazonian darkness","Selosse M.-A. — Never Alone: bioluminescence as inter-species chemical language"]}},{"id":"cm-aluna","deck":"corps_monde","type":"territoire_corps","fr":{"title":"Aluna","entry":"Pour les peuples Kogi et Arhuaco de la Sierra Nevada de Santa Marta, Aluna est la conscience cosmique qui anime toute vie.","body":["Les Mamos passent des années dans l'obscurité totale pour apprendre à sentir ce que les yeux ne peuvent pas voir. Ferme les yeux. Pas pour t'endormir — pour activer d'autres modes de perception.","Écoute d'abord avec les oreilles. Puis avec la peau — la température, les courants d'air, les vibrations du sol. Puis avec quelque chose qu'on n'a pas de mot pour nommer.","Maintenant : dans le lieu où tu es, il y a une qualité particulière — une densité, un ton, une présence. Les Kogi appellent ça Aluna. Toi, tu l'appelleras comment ?","Fais un geste discret qui rend hommage à cette qualité. Pas symbolique — direct. Comme si tu lui répondais."],"retour":"Qu'est-ce que ça change de percevoir la nature comme un être qui pense plutôt que comme une ressource ?","sources":["Peuples Arhuaco, Kogi, Wiwa et Kankuamo — Loi des Origines, Sierra Nevada de Santa Marta (UNESCO patrimoine immatériel 2022)","Arturo Escobar — Designs for the Pluriverse (2018) : 'un monde où il y a place pour plusieurs mondes'"]},"en":{"title":"Aluna","entry":"For the Kogi and Arhuaco peoples of the Sierra Nevada de Santa Marta, Aluna is the cosmic consciousness that animates all life.","body":["The Mamos spend years in total darkness to learn to feel what eyes cannot see. Close your eyes. Not to sleep — to activate other modes of perception.","Listen first with your ears. Then with your skin — temperature, air currents, vibrations in the ground. Then with something we have no word to name.","Now: in this place where you are, there is a particular quality — a density, a tone, a presence. The Kogi call this Aluna. What would you call it?","Make a quiet gesture that pays tribute to this quality. Not symbolic — direct. As if you are responding to it."],"retour":"What changes when you perceive nature as a thinking being rather than a resource?","sources":["Arhuaco, Kogi, Wiwa and Kankuamo peoples — Law of Origin, Sierra Nevada de Santa Marta (UNESCO intangible heritage 2022)","Escobar A. — Designs for the Pluriverse (2018): 'a world where many worlds fit'"]}},{"id":"cm-chute-ciel","deck":"corps_monde","type":"poeme_action","fr":{"title":"La chute du ciel","entry":"Davi Kopenawa, chaman yanomami, avertit : si la forêt meurt, le ciel tombera. Ce n'est pas une métaphore.","body":["Lève les bras lentement au-dessus de ta tête. Sens le poids de l'air que tu déplaces. L'atmosphère pèse au-dessus de toi — cinq quadrillions de tonnes, tenues en place par la gravité et les forêts.","Maintenant : laisse tes bras descendre très lentement, comme si tu aidais le ciel à rester en place. Pas un geste magique — un geste de responsabilité physique.","Répète ce mouvement plusieurs fois — monter, tenir, descendre. Laisse-le devenir un rythme, presque une respiration.","Selon Davi Kopenawa, chaman et porte-parole yanomami, chaque chaman qui cesse de travailler laisse le ciel se pencher un peu plus. Qu'est-ce que tu fais, toi, pour que le ciel tienne ?"],"retour":"Qu'est-ce que tu portes comme responsabilité dans le fait de maintenir le ciel en place ?","sources":["Davi Kopenawa & Bruce Albert — La Chute du ciel : paroles d'un chaman yanomami (Plon, 2010)","Joanna Macy — Work That Reconnects : la conscience du danger comme amour du monde"]},"en":{"title":"The falling sky","entry":"Davi Kopenawa, Yanomami shaman, warns: if the forest dies, the sky will fall. This is not a metaphor.","body":["Slowly raise your arms above your head. Feel the weight of the air you displace. The atmosphere weighs above you — five quadrillion tonnes, held in place by gravity and forests.","Now: let your arms come down very slowly, as if helping the sky stay in place. Not a magical gesture — a gesture of physical responsibility.","Repeat this movement several times — rise, hold, descend. Let it become a rhythm, almost a breath.","Kopenawa says: every shaman who stops working lets the sky tilt a little more. What do you do to keep the sky in place?"],"retour":"What responsibility do you carry in keeping the sky in place?","sources":["Kopenawa D. & Bruce Albert — The Falling Sky: words of a Yanomami shaman (Plon, 2010)","Macy J. — Work That Reconnects: awareness of danger as love of the world"]}},{"id":"cm-plurivers","deck":"corps_monde","type":"territoire_corps","fr":{"title":"Le plurivers","entry":"Arturo Escobar, anthropologue colombien, le formule ainsi : nous ne vivons pas dans un seul monde. Nous vivons dans un plurivers — un monde fait de beaucoup de mondes.","body":["En groupe. Chacun·e choisit en silence une façon d'habiter l'espace qui n'est pas sa façon habituelle. Pas exagérée — juste légèrement déplacée.","Circulez ainsi pendant deux minutes sans interagir. Puis : laissez les façons se rencontrer — sans converger vers une seule.","Un plurivers : un monde fait de plusieurs mondes qui coexistent sans se dissoudre l'un dans l'autre. Votre espace en ce moment en est un.","Arrêtez. Regardez la géographie. Qui a trouvé un monde que les autres n'avaient pas ?"],"retour":"Quel monde tes pieds portent-ils que les autres ne voient pas ?","sources":["Arturo Escobar — Designs for the Pluriverse (2018) : interdépendance radicale, autonomie et fabrication de mondes","Arturo Escobar — Territories of Difference (2008) : lieu, mouvements, vie, réseaux"]},"en":{"title":"The pluriverse","entry":"Arturo Escobar says: we do not live in one world. We live in a pluriverse — a world made of many worlds.","body":["In a group. Each person silently chooses a way of inhabiting the space that is not their habitual way. Not exaggerated — just slightly displaced.","Move like this for two minutes without interacting. Then: let the ways meet — without converging into one.","A pluriverse: a world made of several worlds that coexist without dissolving into one another. Your space right now is one.","Stop. Look at the geography. Who found a world the others didn't have?"],"retour":"What world do your feet carry that others don't see?","sources":["Escobar A. — Designs for the Pluriverse (2018): radical interdependence, autonomy and world-making","Escobar A. — Territories of Difference (2008): place, movements, life, networks"]}},{"id":"cm-matiere-pense","deck":"corps_monde","type":"echelle","fr":{"title":"La matière qui pense","entry":"Karen Barad, physicienne et philosophe féministe, a montré que la distinction entre matière et signification n'existe pas au niveau quantique.","body":["Prends un objet naturel dans cet espace — une pierre, une branche, une feuille. Tiens-le dans ta main.","Maintenant : et si cet objet avait une forme d'attention ? Pas de conscience comme la tienne — une sensibilité à ce qui l'entoure, une façon d'être affecté.","Pour Karen Barad, physicienne et philosophe féministe, la frontière entre observer et être observé n'existe tout simplement pas au niveau quantique. Tiens cet objet en sachant qu'il te 'tient' aussi — que votre interaction est réelle, physique, mutuelle.","Bouge lentement avec cet objet — pas pour le transporter, pour bouger avec lui. Sens la différence."],"retour":"Si la matière pense, qu'est-ce que le rocher que tu touches est en train de faire ?","sources":["Karen Barad — Meeting the Universe Halfway (2007) : réalisme agentiel, intra-action, enchevêtrement matière-sens","Donna Haraway — Staying with the Trouble (2016) : sym-poiesis, faire-ensemble"]},"en":{"title":"Matter that thinks","entry":"Karen Barad, physicist and feminist, shows that the distinction between matter and meaning does not exist at the quantum level.","body":["Take a natural object from this space — a stone, a branch, a leaf. Hold it in your hand.","Now: what if this object had a form of attention? Not consciousness like yours — a sensitivity to what surrounds it, a way of being affected.","Barad says: the boundary between observing and being observed doesn't exist at the quantum level. Hold this object knowing it 'holds' you too — that your interaction is real, physical, mutual.","Move slowly with this object — not to carry it, to move with it. Feel the difference."],"retour":"If matter thinks, what is the rock you are touching doing right now?","sources":["Barad K. — Meeting the Universe Halfway (2007): agential realism, intra-action, matter-meaning entanglement","Haraway D. — Staying with the Trouble (2016): sym-poiesis, making-together"]}},{"id":"cm-plantation-corps","deck":"corps_monde","type":"territoire_corps","fr":{"title":"La plantation dans le corps","entry":"Malcom Ferdinand, chercheur caribéen, a montré que l'esclavage n'a pas seulement exploité des terres — il a extrait des êtres humains de leur propre corps, en les transformant en machines.","body":["Debout. Tiens-toi comme on te l'a appris — droit·e, productif·ve, efficace. Sens ce que cette posture exige de ton corps.","Maintenant : relâche progressivement cette posture. Pas t'effondrer — trouver comment ton corps veut se tenir quand personne ne lui demande d'être utile. Prends le temps.","Malcom Ferdinand, chercheur caribéen, voit dans le marronnage un acte fondateur : prendre son corps et partir. Bouge comme si ton corps t'appartenait vraiment — sa vitesse, ses directions, ses pauses.","En groupe : quelqu'un·e bouge librement, les autres observent. Qu'est-ce qui change quand on regarde un corps qui n'est pas en train de produire ?"],"retour":"Quels corps ton propre confort quotidien continue-t-il d'extraire ?","sources":["Malcom Ferdinand — Une écologie décoloniale (Seuil, 2019) : la plantation comme matrice du monde moderne","Donna Haraway & Anna Tsing — le Plantationocène comme alternative à l'Anthropocène"]},"en":{"title":"The plantation in the body","entry":"Malcom Ferdinand shows that slavery didn't only exploit land — it extracted human beings from their own bodies, transforming them into machines.","body":["Standing. Hold yourself as you were taught — upright, productive, efficient. Feel what this posture demands of your body.","Now: progressively release this posture. Not to collapse — to find how your body wants to stand when no one is asking it to be useful. Take your time.","Ferdinand says: marronage is taking your body and leaving. Move as if your body truly belonged to you — its speed, its directions, its pauses.","In a group: one person moves freely, the others watch. What changes when we watch a body that is not producing?"],"retour":"Which bodies does your daily comfort continue to extract?","sources":["Malcom Ferdinand — Decolonial Ecology (Seuil, 2019): the plantation as matrix of the modern world","Haraway D. & Anna Tsing — the Plantationocene as alternative to the Anthropocene"]}},{"id":"cm-navire-monde","deck":"corps_monde","type":"poeme_action","fr":{"title":"Le navire-monde","entry":"Dans la cale du bateau négrier, des êtres humains, des plantes, des animaux — tous arrachés à leur milieu, tous entassés, tous destinés à la plantation.","body":["Pour Malcom Ferdinand, chercheur caribéen, notre monde est encore ce navire. Certains sont sur le pont. D'autres dans la cale.","Il propose une utopie différente de l'Arche de Noé — qui sélectionne et sauve seulement certains.","Le navire-monde : monter tous les vivants de la cale vers le pont. Construire quelque chose ensemble, sur l'eau.","En groupe : imaginez la cale — l'obscurité, le manque d'espace, le mouvement subi. Puis imaginez le pont — l'horizon, l'air, la rencontre. Bougez de l'un à l'autre."],"retour":"Qui est encore dans la cale pendant que tu es sur le pont ?","sources":["Malcom Ferdinand — Une écologie décoloniale (Seuil, 2019) : le navire-monde comme utopie postcoloniale","Glissant É. — Poétique de la Relation (1990) : la mer des Caraïbes comme mémoire et ouverture"]},"en":{"title":"The world-ship","entry":"In the hold of the slave ship, human beings, plants, animals — all torn from their milieu, all packed together, all destined for the plantation.","body":["Ferdinand says: our world is still this ship. Some are on the deck. Others in the hold.","He proposes a different utopia from Noah's Ark — which selects and saves only some.","The world-ship: bringing all the living from the hold to the deck. Building something together, on the water.","In a group: imagine the hold — darkness, lack of space, undergone motion. Then imagine the deck — horizon, air, encounter. Move from one to the other."],"retour":"Who is still in the hold while you are on the deck?","sources":["Malcom Ferdinand — Decolonial Ecology (Seuil, 2019): the world-ship as postcolonial utopia","Glissant É. — Poetics of Relation (1990): the Caribbean sea as memory and opening"]}},{"id":"cm-marronage","deck":"corps_monde","type":"territoire_corps","fr":{"title":"Le marronnage","entry":"Les marrons étaient des esclaves fugitifs qui refusaient la plantation — qui prenaient leur corps et partaient dans les forêts, les montagnes, les marais.","body":["Le marronnage n'est pas seulement une résistance physique. C'est une pratique d'habiter autrement — recréer des liens avec le vivant que la plantation avait coupés.","Malcom Ferdinand, chercheur caribéen, et Thoreau : tous deux 'marrons' — l'un physiquement, l'autre 'civilement'. La forêt comme espace de désaliénation.","Qu'est-ce que tu as soustrait à la logique d'extraction ? Quel espace intérieur ou extérieur tu as refusé de laisser envahir ?","Bouge comme si tu portais quelque chose de précieux que tu ne veux pas laisser capturer."],"retour":"Qu'est-ce que tu protèges du système de plantation dans ta propre vie ?","sources":["Malcom Ferdinand — Une écologie décoloniale (2019) : le marronnage civil comme écologie décoloniale","Aimé Césaire — Cahier d'un retour au pays natal (1939) : le corps noir comme territoire de résistance"]},"en":{"title":"Marronage","entry":"Maroons were escaped enslaved people who refused the plantation — who took their bodies and left into forests, mountains, swamps.","body":["Marronage is not only physical resistance. It is a practice of inhabiting differently — recreating connections with the living that the plantation had severed.","Ferdinand and Thoreau: both 'maroons' — one physically, the other 'civilly'. The forest as space of de-alienation.","What have you withdrawn from the logic of extraction? What interior or exterior space have you refused to let be invaded?","Move as if carrying something precious that you don't want to let be captured."],"retour":"What do you protect from the plantation system in your own life?","sources":["Malcom Ferdinand — Decolonial Ecology (2019): civil marronage as decolonial ecology","Aimé Césaire — Notebook of a Return to the Native Land (1939): the Black body as territory of resistance"]}}],"co":[{"id":"co-heritage-chimique","deck":"contaminations","type":"trace","fr":{"title":"L'héritage chimique","entry":"Tu portes dans ton sang des traces de décisions industrielles prises avant ta naissance.","body":["Debout, yeux fermés. Mens tes deux paumes face à face, sans se toucher — à cinq centimètres l'une de l'autre.","Sens la chaleur entre elles. Cette chaleur, c'est ton corps qui émet — toi, mais aussi tout ce qui circule en toi en ce moment.","Ouvre les yeux. Regarde tes paumes comme si tu les voyais pour la première fois. Ces surfaces ont tout traversé — air, eau, contact, produits chimiques — depuis ta naissance.","Tes parents t'ont transmis leur corps. Leurs parents le leur. Le DDT interdit en 1972 se trouve encore dans des corps humains aujourd'hui. Tiens tes mains comme ce qu'elles sont : une archive vivante."],"retour":"Qui a décidé que ton corps pouvait être le dépôt de déchets industriels ?","sources":["Rachel Carson — Silent Spring : le DDT et la chaîne alimentaire","Endocrine Society 2020 : les plastiques comme perturbateurs endocriniens systémiques"]},"en":{"title":"Chemical heritage","entry":"You carry in your blood traces of industrial decisions made before you were born.","body":["Standing, eyes closed. Hold both palms facing each other, without touching — five centimetres apart.","Feel the warmth between them. This warmth is your body emitting — you, but also everything circulating in you right now.","Open your eyes. Look at your palms as if seeing them for the first time. These surfaces have traversed everything — air, water, contact, chemicals — since your birth.","Your parents transmitted their body to you. Their parents transmitted theirs. DDT banned in 1972 is still found in human bodies today. Hold your hands for what they are: a living archive."],"retour":"Who decided your body could be a storage site for industrial waste?","sources":["Carson R. — Silent Spring: DDT and the food chain","Endocrine Society 2020: plastics as systemic endocrine disruptors"]}},{"id":"co-corps-poreux","deck":"contaminations","type":"trace","fr":{"title":"Le corps poreux","entry":"Ton corps n'a pas de frontière nette avec son environnement. Il est poreux.","body":["Inspire lentement. Sens l'air entrer — vraiment entrer — dans tes poumons. Il n'est pas neutre. Il porte des particules fines, des molécules de plastique, des polluants industriels.","Expire. Tu rends quelque chose à l'air — CO2, vapeur d'eau, chaleur. Un échange constant.","Bouge maintenant en gardant cette conscience de porosité. Pas ton corps contre le monde — ton corps comme zone de passage. L'air t'traverse. Tu traverses l'air.","Un·e partenaire se place à côté de toi. Bougez ensemble sans vous toucher — juste conscient·es de l'air partagé entre vous deux."],"retour":"Que change le fait de se percevoir comme poreux·se plutôt que comme contenant étanche ?","sources":["Plastic Pollution Coalition 2025 : microplastiques dans l'utérus et le placenta","Donna Haraway — le cyborg comme critique de la clôture corporelle"]},"en":{"title":"The porous body","entry":"Your body has no clear boundary with its environment. It is porous.","body":["Inhale slowly. Feel the air enter — truly enter — your lungs. It is not neutral. It carries fine particles, plastic molecules, industrial pollutants.","Exhale. You return something to the air — CO2, water vapour, warmth. A constant exchange.","Move now keeping this awareness of porosity. Not your body against the world — your body as a zone of passage. Air crosses you. You cross air.","A partner stands beside you. Move together without touching — just aware of the shared air between you."],"retour":"What changes when you perceive yourself as porous rather than a sealed container?","sources":["Plastic Pollution Coalition 2025: microplastics in uterus and placenta","Haraway D. — the cyborg as critique of bodily closure"]}},{"id":"co-substitution-regrettable","deck":"contaminations","type":"performance","fr":{"title":"Substitution regrettable","entry":"On interdit un produit toxique. On le remplace par un autre, presque identique, avec un nom différent. Le danger reste.","body":["Un produit chimique est interdit. Un autre, presque identique, prend sa place avec un nom différent. Rien ne change vraiment.","Debout. Occupe une position dans l'espace — bien présent·e, bien visible. Puis déplace-toi de quelques pas et prends exactement la même posture, au même endroit.","Même posture, autre position. Quelque chose a changé — et rien n'a changé. Sens cette contradiction dans le corps.","Solo : reste dans cette seconde position et demande-toi ce qui est différent. En groupe : quelqu'un peut entrer et ajuster doucement ta posture — vers quelque chose d'honnête."],"retour":"Qu'est-ce que ça fait dans le corps de savoir qu'on t'a remplacé une chose toxique par une autre chose toxique ?","sources":["Endocrine Society : la substitution regrettable comme échec structurel de régulation","Rachel Carson — la complicité des institutions avec les industries qu'elles sont censées réguler"]},"en":{"title":"Regrettable substitution","entry":"A toxic product is banned. It's replaced by another, nearly identical, with a different name. The danger remains.","body":["A chemical is banned. Another, nearly identical, takes its place under a different name. Nothing really changes.","Standing. Occupy a position in the space — fully present, fully visible. Then move a few steps and take exactly the same posture, in the same spot.","Same posture, different position. Something has changed — and nothing has changed. Feel this contradiction in the body.","Alone: stay in this second position and ask yourself what is different. In a group: someone can gently adjust your posture — toward something honest."],"retour":"What does it feel like in the body to know that one toxic thing was replaced with another toxic thing?","sources":["Endocrine Society: regrettable substitution as structural regulatory failure","Carson R. — institutional complicity with the industries they are meant to regulate"]}},{"id":"co-races-corps","deck":"contaminations","type":"performance","fr":{"title":"Les corps qui absorbent plus","entry":"La contamination chimique n'est pas distribuée également. Certains corps absorbent plus.","body":["Certains corps naissent dans des quartiers proches des usines, des décharges, des axes routiers. D'autres naissent à distance. Ce n'est pas une coïncidence — c'est une géographie du pouvoir.","Solo : marche dans l'espace. À un moment, arrête-toi là où tu te sentirais 'protégé·e'. Puis marche vers l'endroit où tu te sentirais 'exposé·e'. Sens la différence dans le corps.","En groupe : sans parler, placez-vous dans l'espace selon votre relation au pouvoir dans ce contexte. Regardez la géographie qui se forme.","Quelqu'un peut alors traverser vers une autre zone. Qu'est-ce que ça fait de traverser cette ligne ?"],"retour":"Dont le corps est-il le 'bien commun' de quelqu'un d'autre ?","sources":["Robert Bullard — Dumping in Dixie (1990) : les fondements du racisme environnemental","Leticia Nieto — Beyond Inclusion, Beyond Empowerment : les corps comme site de domination systémique"]},"en":{"title":"The bodies that absorb more","entry":"Chemical contamination is not evenly distributed. Some bodies absorb more.","body":["Some bodies are born in neighbourhoods near factories, landfills, motorways. Others are born at a distance. This is not coincidence — it is a geography of power.","Alone: walk in the space. At some point, stop where you would feel 'protected'. Then walk toward where you would feel 'exposed'. Feel the difference in the body.","In a group: without speaking, place yourselves in the space according to your relationship to power in this context. Look at the geography that forms.","Someone can then cross to another zone. What does it feel like to cross this line?"],"retour":"Whose body is someone else's 'common good'?","sources":["Bullard R.D. — Dumping in Dixie (1990): the foundations of environmental racism","Nieto L. — Beyond Inclusion, Beyond Empowerment: bodies as sites of systemic domination"]}},{"id":"co-nommer","deck":"contaminations","type":"performance","fr":{"title":"Nommer ce qu'on a mis dans nos corps","entry":"Un exercice de nomination collective — pas pour faire peur, pour rendre réel.","body":["En cercle. Chacun·e nomme à voix haute une substance qui est probablement dans son corps en ce moment sans qu'il ou elle l'ait choisie.","Après chaque nomination : toute la groupe fait le même geste — une main sur une partie du corps, n'importe laquelle. Comme un accusé de réception collectif.","Pas de commentaire entre les nominations. Juste le nom, le geste, et le silence.","À la fin : restez dans le silence trente secondes. Tous ces noms dans l'air, tous ces gestes faits ensemble. C'est ça, témoigner collectivement."],"retour":"Qu'est-ce qui change quand on nomme ensemble ce qu'on porte seul ?","sources":["Thomas Hübl — Healing Collective Trauma (2020) : témoignage social global, nommer ce qui existe","Silvia Federici — Caliban and the Witch (2004) : nommer les responsables comme acte politique fondateur"]},"en":{"title":"Naming what was put in our bodies","entry":"A collective naming exercise — not to frighten, but to make real.","body":["In a circle. Each person names aloud a substance probably in their body right now without having chosen it.","After each naming: the whole group makes the same gesture — a hand on a part of the body, any part. Like a collective acknowledgement.","No commentary between namings. Just the name, the gesture, and the silence.","At the end: stay in silence for thirty seconds. All these names in the air, all these gestures made together. That is collective witnessing."],"retour":"What changes when we name together what we carry alone?","sources":["Hübl T. — Healing Collective Trauma (2020): global social witnessing, naming what exists","Federici S. — Caliban and the Witch (2004): naming the responsible as founding political act"]}},{"id":"co-silence-printemps","deck":"contaminations","type":"poeme_somatique","fr":{"title":"Écouter le silence","entry":"Rachel Carson a écrit en 1962 : 'Il était une fois une ville américaine où toute vie semblait vivre en harmonie avec son milieu... Puis un mal étrange envahit la région.'","body":["Fermez les yeux. Écoutez le paysage sonore de ce lieu pendant deux minutes complètes. Identifiez mentalement chaque source : biologique, humaine, industrielle.","Maintenant : imaginez que la moitié des sons biologiques disparaissent. Lesquels ? Ceux des insectes d'abord — les abeilles, les criquets. Puis les oiseaux.","Rouvrez les yeux. Bougez dans ce silence imaginaire — comme si le lieu était le même mais vidé de sa moitié vivante.","Ce printemps silencieux, quelqu'un l'a nommé pour réveiller ce que tout le monde avait cessé d'entendre. Qu'est-ce que tu as cessé d'entendre dans ce lieu ?"],"retour":"Qu'est-ce que ton corps reconnaît comme signe de vie dans ce lieu ?","sources":["Rachel Carson — Silent Spring (1962) : ouverture, 'Fable for Tomorrow'","Joanna Macy — la joie et la douleur pour le monde comme deux faces du même amour"]},"en":{"title":"Listening to the silence","entry":"Rachel Carson wrote in 1962: 'There was once a town in the heart of America where all life seemed to live in harmony with its surroundings... Then a strange blight crept over the area.'","body":["Close your eyes. Listen to the soundscape of this place for two full minutes. Mentally identify each source: biological, human, industrial.","Now: imagine half the biological sounds disappearing. Which ones? The insects first — bees, crickets. Then the birds.","Open your eyes. Move in this imaginary silence — as if the place were the same but emptied of its living half.","This silent spring was named to wake what everyone had stopped hearing. What have you stopped hearing in this place?"],"retour":"What does your body recognise as a sign of life in this place?","sources":["Carson R. — Silent Spring (1962): opening, 'Fable for Tomorrow'","Macy J. — joy and pain for the world as two faces of the same love"]}},{"id":"co-temoignage","deck":"contaminations","type":"poeme_somatique","fr":{"title":"Se faire témoin","entry":"Un sol contaminé. Une rivière morte. Un enfant né avec des malformations près d'une usine chimique.","body":["Trouve une posture qui représente quelque chose de difficile que tu sais sur le monde — pas ce que tu ressens, ce que tu sais.","Reste dans cette posture. Résiste à l'envie de la quitter ou de l'expliquer. Laisse-la exister.","Quelqu'un dans le groupe peut s'approcher et se placer à côté de toi — pas pour te réconforter, pour témoigner. Juste être là, dans sa propre posture.","Ce corps figé — ce n'est pas un problème à résoudre. C'est une information sur le monde."],"retour":"Qu'est-ce qui se passe dans le corps quand on accepte d'être le témoin de quelque chose de difficile ?","sources":["Thomas Hübl — Global Social Witnessing : présence incarnée face au traumatisme collectif","Joanna Macy — Work That Reconnects : rester ouvert à la douleur du monde"]},"en":{"title":"Bearing witness","entry":"Contaminated soil. A dead river. A child born with malformations near a chemical plant.","body":["Find a posture that represents something difficult you know about the world — not what you feel, what you know.","Stay in this posture. Resist the urge to leave it or explain it. Let it exist.","Someone in the group can approach and stand beside you — not to comfort, to witness. Just be there, in their own posture.","This frozen body is not a problem to be solved. It is information about the world."],"retour":"What happens in the body when you accept to be a witness to something difficult?","sources":["Hübl T. — Global Social Witnessing: embodied presence before collective trauma","Macy J. — Work That Reconnects: staying open to the world's pain"]}},{"id":"co-zones-sacrifiees","deck":"contaminations","type":"performance","fr":{"title":"Les zones sacrifiées","entry":"Certains territoires sont désignés, implicitement, comme sacrifiables. Ce sont souvent des territoires habités par des populations pauvres, racisées, autochtones.","body":["Dans certaines régions du monde, des communautés entières vivent au milieu des usines pétrochimiques, des décharges, des sites d'extraction. D'autres vivent dans des quartiers préservés. Ce n'est pas le hasard.","Solo : imagine que l'espace autour de toi est divisé en deux zones. De quel côté es-tu né·e ? De quel côté vis-tu maintenant ? Est-ce que c'est le même ?","Traverse imaginairement vers la zone que tu n'habites pas. Sens dans le corps ce que ça fait de changer de côté.","En groupe : chacun·e se place instinctivement, en silence. Regardez. Puis quelqu'un traverse. Qu'est-ce qui se passe ?"],"retour":"Qu'est-ce que ton corps sait de ce côté de la ligne que l'autre côté ne sait pas ?","sources":["Robert Bullard — Dumping in Dixie (1990) : Cancer Alley et les fondements du racisme environnemental","Rob Nixon — Slow Violence and the Environmentalism of the Poor (2011) : les corps sacrifiés en silence"]},"en":{"title":"Sacrifice zones","entry":"Some territories are designated, implicitly, as sacrificeable. They are often territories inhabited by poor, racialised, indigenous populations.","body":["In some parts of the world, entire communities live surrounded by petrochemical plants, landfills, extraction sites. Others live in preserved neighbourhoods. This is not chance.","Alone: imagine the space around you is divided into two zones. Which side were you born on? Which side do you live on now? Are they the same?","Imaginarily cross to the zone you don't inhabit. Feel in the body what it does to change sides.","In a group: each person places themselves instinctively, in silence. Look. Then someone crosses. What happens?"],"retour":"What does your body know about this side of the line that the other side doesn't know?","sources":["Bullard R.D. — Dumping in Dixie (1990): Cancer Alley and the foundations of environmental racism","Nixon R. — Slow Violence and the Environmentalism of the Poor (2011): bodies sacrificed in silence"]}},{"id":"co-lait-plastique","deck":"contaminations","type":"trace","fr":{"title":"Le lait et le plastique","entry":"Des microplastiques ont été trouvés dans le lait maternel humain. Le premier aliment porte l'empreinte de l'industrie.","body":["Pose une main sur ta poitrine. Sens ton cœur battre — ce rythme qui existait avant ta naissance, transmis de corps en corps depuis des générations.","Ce corps a reçu quelque chose de chaque personne qui l'a précédé. Et il a reçu aussi, sans demander, des molécules industrielles qui n'existaient pas il y a cent ans.","Déplace lentement cette main — sur ton épaule, ton bras, ton ventre. Ce corps qui donne et reçoit la vie porte aussi ce que l'industrie a produit. Les deux sont vrais en même temps.","En contact avec quelqu'un : une main sur l'épaule, en silence. Sens la transmission — ce qui passe de corps en corps, de génération en génération, voulu et non-voulu."],"retour":"Qu'est-ce que tu veux dire à ce corps que tu n'as jamais dit ?","sources":["Plastic Pollution Coalition 2025 : microplastiques dans le lait maternel, le placenta, l'utérus","Rachel Carson — Silent Spring : les mères comme première ligne de contamination"]},"en":{"title":"Milk and plastic","entry":"Microplastics have been found in human breast milk. The first food carries the imprint of industry.","body":["Place a hand on your chest. Feel your heart beat — this rhythm that existed before your birth, transmitted from body to body across generations.","This body received something from every person who preceded it. And it received too, without asking, industrial molecules that didn't exist a hundred years ago.","Move this hand slowly — to your shoulder, your arm, your belly. This body that gives and receives life also carries what industry produced. Both are true at the same time.","In contact with someone: a hand on the shoulder, in silence. Feel the transmission — what passes from body to body, generation to generation, wanted and unwanted."],"retour":"What do you want to say to this body that you've never said?","sources":["Plastic Pollution Coalition 2025: microplastics in breast milk, placenta, uterus","Carson R. — Silent Spring: mothers as first line of contamination"]}},{"id":"co-glyphosate-pollen","deck":"contaminations","type":"trace","fr":{"title":"Le glyphosate et le pollen","entry":"Du glyphosate a été trouvé dans l'urine de 99% des Européen·nes testé·es. Dans le pollen des fleurs sauvages. Dans l'eau de pluie.","body":["Imite une abeille en vol — pas pour faire rire, pour vraiment habiter ce mouvement. Le zigzag irrégulier, la façon de planer, d'atterrir, de repartir.","Maintenant : les fleurs que tu visites contiennent du glyphosate. Change légèrement ton mouvement — pas d'un coup, graduellement. Une légère hésitation dans le vol. Un atterrissage moins précis.","Les apidologues ont documenté : le glyphosate affecte la navigation des abeilles. Elles se perdent. Elles ne retrouvent pas la ruche.","Arrête. Tu es debout dans un espace que tu connais. Sens la différence entre savoir où tu es et ne plus le savoir."],"retour":"Quand le vecteur de vie devient porteur de poison — qu'est-ce qui change dans la façon de le voir ?","sources":["Rachel Carson — Silent Spring : les insecticides dans la chaîne du vivant","UE 2022 : glyphosate dans l'urine de 99% des Européen·nes testés"]},"en":{"title":"Glyphosate and pollen","entry":"Glyphosate has been found in the urine of 99% of Europeans tested. In wild flower pollen. In rainwater.","body":["Imitate a bee in flight — not to be funny, but to truly inhabit this movement. The irregular zigzag, the way of hovering, landing, departing.","Now: the flowers you visit contain glyphosate. Change your movement slightly — not all at once, gradually. A slight hesitation in flight. A less precise landing.","Apidologists have documented: glyphosate affects bee navigation. They get lost. They can't find the hive.","Stop. You are standing in a space you know. Feel the difference between knowing where you are and no longer knowing."],"retour":"When the vector of life becomes a carrier of poison — what changes in how you see it?","sources":["Carson R. — Silent Spring: insecticides in the chain of the living","EU 2022: glyphosate in urine of 99% of Europeans tested"]}},{"id":"co-charge-allostasique","deck":"contaminations","type":"performance","fr":{"title":"La charge allostasique","entry":"Les corps qui vivent sous oppression chronique — racisme, pauvreté, discrimination — vieillissent physiologiquement plus vite.","body":["Debout. Quelqu'un commence à poser de petits objets sur tes épaules — stylos, cailloux, livres légers. L'accumulation seule, rien de lourd.","Continue à te tenir normalement. Conversation normale. À un moment : tu peux dire 'stop'. Ou ne pas le dire. Jusqu'où vas-tu avant de nommer le poids ?","Solo : charge toi-même — tiens quelque chose dans chaque main, cale quelque chose sous le menton. Marche ainsi. Sens l'adaptation silencieuse que le corps fait.","Les corps qui vivent sous discrimination chronique font ça en permanence — s'adapter à une charge que personne ne voit, qui ne fait jamais les nouvelles."],"retour":"Quel poids portes-tu en ce moment que personne ne t'a demandé de nommer ?","sources":["Leticia Nieto — Beyond Inclusion, Beyond Empowerment : le corps comme site de domination systémique","recherches en santé publique : racism as a public health crisis"]},"en":{"title":"Allostatic load","entry":"Bodies living under chronic oppression — racism, poverty, discrimination — age physiologically faster.","body":["Standing. Someone begins to place small objects on your shoulders — pens, pebbles, light books. Accumulation alone, nothing heavy.","Keep holding yourself normally. Normal conversation. At some point: you can say 'stop'. Or not. How far do you go before naming the weight?","Alone: load yourself — hold something in each hand, balance something under your chin. Walk like this. Feel the silent adaptation the body makes.","Bodies living under chronic discrimination do this permanently — adapting to a load nobody sees, that never makes the news."],"retour":"What weight are you carrying right now that no one has asked you to name?","sources":["Nieto L. — Beyond Inclusion, Beyond Empowerment: the body as site of systemic domination","public health research: racism as a public health crisis"]}},{"id":"co-bruit","deck":"contaminations","type":"poeme_somatique","fr":{"title":"Le bruit comme pollutant","entry":"La pollution sonore est la deuxième cause environnementale de maladie en Europe après la pollution de l'air.","body":["En groupe. La moitié fait des sons — avec la voix, les mains, les pieds, le souffle. Des sons biologiques : voix, battements, souffle.","L'autre moitié essaie de communiquer quelque chose d'important — sans mots, seulement avec le corps — malgré le bruit.","Échangez. Puis : le silence. Tous ensemble, trente secondes de silence complet.","Schafer appelait ça le 'keynote sound' — le son de fond si permanent qu'on ne l'entend plus. Qu'est-ce qui vient de revenir dans ce silence ?"],"retour":"Quel silence as-tu déjà entendu qui te manque ?","sources":["R. Murray Schafer — The Tuning of the World (1977) : l'écologie du paysage sonore, le silence naturel comme bien commun","Bernie Krause — The Great Animal Orchestra (2012) : comment le bruit industriel détruit les biophonies"]},"en":{"title":"Noise as pollutant","entry":"Noise pollution is the second environmental cause of disease in Europe after air pollution.","body":["In a group. Half make sounds — with voice, hands, feet, breath. Biological sounds: voices, tapping, breathing.","The other half tries to communicate something important — without words, only with the body — despite the noise.","Swap. Then: silence. Everyone together, thirty seconds of complete silence.","Schafer called this the 'keynote sound' — the background sound so permanent we no longer hear it. What just came back in this silence?"],"retour":"What silence have you heard that you miss?","sources":["R. Murray Schafer — The Tuning of the World (1977): soundscape ecology, natural silence as common good","Bernie Krause — The Great Animal Orchestra (2012): how industrial noise destroys biophonies"]}},{"id":"co-temoignage-legal","deck":"contaminations","type":"performance","fr":{"title":"Corps-témoin","entry":"Dans certains procès environnementaux, des habitant·es de zones contaminées témoignent avec leur propre corps — maladies, malformations, morts.","body":["Une personne debout au centre. Elle dit : 'Mon corps sait ce qu'il a traversé.' Puis : 'Ce que j'ai vécu compte.'","Pas théâtral — dit simplement, debout, avec le poids de ce que c'est de dire ça.","Le reste du groupe écoute debout. Pas assis — debout. La différence dans le corps entre écouter assis et écouter debout.","Après : un silence. Puis quelqu'un d'autre peut prendre la place. Ou non."],"retour":"Qu'est-ce que ton corps pourrait témoigner que personne d'autre ne peut dire à ta place ?","sources":["Robert Bullard — les communautés comme témoins expertes de leur propre contamination","Leticia Nieto — les corps marginalisés comme sources de savoir"]},"en":{"title":"Body-witness","entry":"In some environmental trials, inhabitants of contaminated zones testify with their own bodies — illnesses, malformations, deaths.","body":["One person standing at the centre. They say: 'My body knows what it has been through.' Then: 'What I experienced matters.'","Not theatrical — said simply, standing, with the weight of what it is to say that.","The rest of the group listens standing. Not seated — standing. The difference in the body between listening seated and standing.","Afterwards: a silence. Then someone else can take the place. Or not."],"retour":"What could your body testify to that no one else can say in your place?","sources":["Bullard R.D. — communities as expert witnesses of their own contamination","Nieto L. — marginalised bodies as sources of knowledge"]}},{"id":"co-justice-reparatrice","deck":"contaminations","type":"performance","fr":{"title":"Justice réparatrice","entry":"Quand une industrie contamine un territoire, qui répare ? Qui paie ? Qui décide ce que 'réparer' veut dire ?","body":["Solo : trouve deux postures. La première : ce que ça fait dans le corps de causer du tort — et de ne pas en répondre. La seconde : ce que ça fait de subir ce tort sans réparation.","Reste dans chaque posture quelques instants. Pas pour juger — pour sentir.","En groupe : deux personnes jouent ces postures face à face. Quelqu'un peut modifier l'une ou l'autre — pas pour raconter sa version, pour chercher une image de justice. Une image, pas un discours.","Restez dans cette image finale. Qu'est-ce qu'elle demande que les mots ne demanderaient pas ?"],"retour":"La réparation — est-ce possible ? Qu'est-ce que ton corps dit sur ça ?","sources":["Robert Bullard — la justice environnementale comme droit civil","Dominic Barter — les pratiques restauratives appliquées aux dommages environnementaux collectifs"]},"en":{"title":"Restorative justice","entry":"When an industry contaminates a territory, who repairs? Who pays? Who decides what 'repair' means?","body":["Alone: find two postures. The first: what it feels like in the body to cause harm — and not to answer for it. The second: what it feels like to suffer this harm without repair.","Stay in each posture for a few moments. Not to judge — to feel.","In a group: two people hold these postures facing each other. Someone can modify one or the other — not to tell their version, but to search for an image of justice. An image, not a speech.","Stay in this final image. What does it ask for that words wouldn't?"],"retour":"Repair — is it possible? What does your body say about that?","sources":["Bullard R.D. — environmental justice as civil right","Barter D. — restorative practices applied to collective environmental harm"]}},{"id":"co-lumiere-artificielle","deck":"contaminations","type":"trace","fr":{"title":"La lumière qui ne s'éteint pas","entry":"La pollution lumineuse perturbe les cycles circadiens de millions d'espèces — et les nôtres.","body":["Commencez en mouvement libre — chacun·e dans son propre rythme, ses propres directions.","Progressivement, quelqu'un commence à 'allumer' des lumières — il pointe un doigt vers quelqu'un et celui-ci se fige instantanément. Puis un autre. Puis un autre.","Petit à petit, le mouvement se fige. Jusqu'à ce que tout le monde soit immobile sous ces 'lumières'.","Silence. Toutes les étoiles cachées par la lumière artificielle. Toutes les bêtes désorientées. Tous les rythmes perturbés. Puis éteignez les lumières — en ordre inverse. La vie reprend."],"retour":"Qu'est-ce qu'on perd quand on perd la nuit ?","sources":["Russell Foster & Leon Kreitzman — Rhythms of Life (2004) : la chronobiologie et les rythmes circadiens perturbés","Fabio Falchi et al. — New World Atlas of Artificial Night Sky Brightness (2016) : 83% de l'humanité vit sous pollution lumineuse"]},"en":{"title":"The light that doesn't go out","entry":"Light pollution disrupts the circadian cycles of millions of species — and ours.","body":["Begin in free movement — each person at their own rhythm, their own directions.","Gradually, someone begins to 'switch on lights' — they point a finger at someone who instantly freezes. Then another. Then another.","Little by little, movement freezes. Until everyone is still under these 'lights'.","Silence. All the stars hidden by artificial light. All the disoriented animals. All the disrupted rhythms. Then switch off the lights — in reverse order. Life resumes."],"retour":"What do we lose when we lose the night?","sources":["Foster R.G. & Leon Kreitzman — Rhythms of Life (2004): chronobiology and disrupted circadian rhythms","Fabio Falchi et al. — New World Atlas of Artificial Night Sky Brightness (2016): 83% of humanity lives under light pollution"]}},{"id":"co-memoire-cellulaire","deck":"contaminations","type":"poeme_somatique","fr":{"title":"La mémoire cellulaire","entry":"Tes cellules savent des choses que ton esprit conscient ne sait pas.","body":["Debout, immobile. Laisse quelque chose commencer à bouger sans le décider. Peut-être une main. Peut-être le souffle qui change. N'anticipe pas.","Pendant cinq minutes : laisse le mouvement venir du corps, pas de la tête. Si tu te surprends à planifier — arrête et recommence depuis l'immobilité.","Les cellules ont une mémoire que l'esprit conscient ne gère pas. Ce mouvement qui vient sans instruction — c'est cette mémoire qui parle.","À la fin : reste debout dans l'immobilité. Qu'est-ce qui a bougé que tu n'avais pas planifié ?"],"retour":"Qu'est-ce que ton corps sait que tu n'as pas besoin de comprendre pour le savoir ?","sources":["Bessel van der Kolk — Le Corps n'oublie rien : trauma et mémoire somatique","Donna Haraway — le corps comme archive vivante de ce qui a été traversé"]},"en":{"title":"Cellular memory","entry":"Your cells know things that your conscious mind doesn't know.","body":["Standing, still. Let something start to move without deciding it. Perhaps a hand. Perhaps the breath changing. Don't anticipate.","For five minutes: let movement come from the body, not the mind. If you catch yourself planning — stop and return to stillness.","Cells have a memory that conscious mind doesn't manage. This movement that comes without instruction — that is this memory speaking.","At the end: stay standing in stillness. What moved that you hadn't planned?"],"retour":"What does your body know that you don't need to understand to know?","sources":["van der Kolk B. — The Body Keeps the Score: trauma and somatic memory","Haraway D. — the body as living archive of what has been traversed"]}},{"id":"co-nommer-lindustrie","deck":"contaminations","type":"performance","fr":{"title":"Nommer l'industrie par son nom","entry":"On dit 'pollution'. Rarement : 'TotalEnergies a décidé de déverser.' 'BASF a choisi de ne pas filtrer.'","body":["Debout, les deux pieds bien plantés. Prends deux respirations profondes.","Maintenant, à voix haute, avec tout ton corps derrière les mots : nomme une industrie, une entreprise, une décision qui a causé du tort à un corps ou un territoire que tu connais.","Pas depuis la tête — depuis le ventre. Le nom sort avec du poids.","Puis : avec la même voix, le même corps, nomme quelqu'un qui a résisté, témoigné, défendu. Les deux ont besoin du même corps pour être dits."],"retour":"Qu'est-ce qui change dans le corps quand on nomme le responsable au lieu de la conséquence ?","sources":["Rachel Carson — Silent Spring comme acte d'accusation nommé","Robert Bullard — identifier les auteurs comme condition de la justice"]},"en":{"title":"Naming industry by its name","entry":"We say 'pollution'. Rarely: 'TotalEnergies decided to discharge.' 'BASF chose not to filter.'","body":["Standing, both feet well planted. Take two deep breaths.","Now, aloud, with your whole body behind the words: name an industry, a company, a decision that caused harm to a body or territory you know.","Not from the head — from the belly. The name comes out with weight.","Then: with the same voice, the same body, name someone who resisted, testified, defended. Both need the same body to be said."],"retour":"What changes in the body when we name the responsible party instead of the consequence?","sources":["Carson R. — Silent Spring as named indictment","Bullard R.D. — identifying perpetrators as condition of justice"]}},{"id":"co-corps-frontiere","deck":"contaminations","type":"trace","fr":{"title":"Les corps sans frontières","entry":"Les polluants ne respectent pas les frontières. Ils voyagent dans l'air, dans l'eau, dans les chaînes alimentaires.","body":["Étends les bras en croix. La portée de tes bras — c'est à peu près la largeur de ton corps, debout. C'est ta frontière visible.","Maintenant : ton corps réel s'étend bien au-delà. Les microplastiques dans ton sang viennent d'océans que tu n'as jamais vus. Le mercure dans tes tissus vient de centrales à charbon à des milliers de kilomètres.","Garde les bras étendus. Commence à tourner lentement sur toi-même — comme si tu balayais l'espace de toutes les origines de ce que ton corps contient.","Arrête-toi face à une direction. Quelque part là-bas, une décision industrielle a laissé une trace dans ton corps. Sans que personne te l'ait demandé."],"retour":"Où s'arrête ton corps ?","sources":["Raj Patel & Jason W. Moore — A History of the World in Seven Cheap Things (2017) : la chaîne alimentaire mondiale comme politique corporelle","Rob Nixon — Slow Violence and the Environmentalism of the Poor (2011) : les violences lentes invisibles sur les corps"]},"en":{"title":"Bodies without borders","entry":"Pollutants don't respect borders. They travel through air, water, food chains.","body":["Extend your arms in a cross. Your arm span — that's roughly the width of your standing body. That's your visible boundary.","Now: your real body extends far beyond. The microplastics in your blood come from oceans you've never seen. The mercury in your tissues comes from coal plants thousands of kilometres away.","Keep your arms extended. Begin to turn slowly — as if sweeping the space of all the origins of what your body contains.","Stop facing one direction. Somewhere out there, an industrial decision left a trace in your body. Without anyone asking you."],"retour":"Where does your body end?","sources":["Patel R. & Jason W. Moore — A History of the World in Seven Cheap Things (2017): the global food chain as body politics","Nixon R. — Slow Violence and the Environmentalism of the Poor (2011): slow invisible violence on bodies"]}},{"id":"co-enclosure-corps","deck":"contaminations","type":"performance","fr":{"title":"L'enclosure du corps","entry":"Silvia Federici, historienne féministe, a montré que la chasse aux sorcières n'était pas une folie religieuse — c'était une politique de contrôle des corps féminins pour les transformer en machines de reproduction.","body":["Solo : occupe l'espace librement pendant une minute. Fais ce que tu veux, va où tu veux.","Maintenant : réduis progressivement ton espace autorisé. D'abord moitié, puis quart. Continue à bouger dans ce qui reste.","Puis : quelqu'un d'autre décide de ton espace à ta place — sans te demander. Comment ton corps répond-il à ça ?","En groupe : chacun·e occupe librement l'espace, puis quelqu'un commence à délimiter des zones avec des gestes. Progressivement, l'espace commun disparaît."],"retour":"Comment ton corps répond-il à la réduction de l'espace qu'il considérait comme sien ?","sources":["Silvia Federici — Caliban and the Witch (2004) : histoire du corps dans la transition au capitalisme","Lorena Cabnal — le corps-territoire comme première ligne de résistance à l'extractivisme"]},"en":{"title":"The enclosure of the body","entry":"Silvia Federici shows that witch-hunting was not religious madness — it was a policy of controlling female bodies to transform them into reproduction machines.","body":["Alone: occupy the space freely for one minute. Do what you want, go where you want.","Now: progressively reduce your permitted space. First half, then a quarter. Keep moving in what remains.","Then: someone else decides your space for you — without asking. How does your body respond to that?","In a group: each person occupies the space freely, then someone begins to mark out zones with gestures. Gradually, common space disappears."],"retour":"How does your body respond to the reduction of space it considered its own?","sources":["Federici S. — Caliban and the Witch (2004): history of the body in the transition to capitalism","Cabnal L. — the body-territory as first line of resistance to extractivism"]}},{"id":"co-violence-lente","deck":"contaminations","type":"trace","fr":{"title":"La violence lente","entry":"Rob Nixon, universitaire zimbabwéen-américain, a nommé 'violence lente' ces violences environnementales qui s'étalent dans le temps et l'espace — invisibles parce que trop lentes pour faire les nouvelles.","body":["Choisis un mouvement très simple. Fais-le normalement. Puis refais-le dix fois plus lentement — si lent que c'est presque imperceptible.","Continue pendant deux minutes à cette vitesse infinitésimale. Quelqu'un qui ne te regarderait pas attentivement ne verrait rien. C'est exactement ça : trop lent pour être vu.","En groupe : la moitié bouge ainsi — presque immobile. L'autre moitié continue ses activités normales. À quel moment quelqu'un remarque-t-il ce qui se passe ?","Les violences qui s'étalent sur des décennies — élévation des eaux, contamination des sols, disparition des espèces — fonctionnent exactement comme ça."],"retour":"Qu'est-ce que tu as arrêté de voir parce que ça bouge trop lentement ?","sources":["Rob Nixon — Slow Violence and the Environmentalism of the Poor (2011) : les violences invisibles car trop lentes","Robert Bullard — Dumping in Dixie (1990) : les communautés qui portent les violences des autres"]},"en":{"title":"Slow violence","entry":"Rob Nixon names 'slow violence' the environmental violences that spread across time and space — invisible because too slow to make the news.","body":["Choose a very simple movement. Do it normally. Then do it ten times more slowly — so slow it's almost imperceptible.","Continue for two minutes at this infinitesimal speed. Someone not watching closely would see nothing. That is exactly it: too slow to be seen.","In a group: half move like this — almost still. The other half continues normal activities. At what point does someone notice what is happening?","Violences that unfold over decades — rising waters, soil contamination, species disappearing — work exactly like this."],"retour":"What have you stopped seeing because it moves too slowly?","sources":["Nixon R. — Slow Violence and the Environmentalism of the Poor (2011): violences invisible because too slow","Bullard R.D. — Dumping in Dixie (1990): communities carrying others' violences"]}}],"ns":[{"id":"ns-competition","deck":"natures_sociales","type":"deconstruire","fr":{"title":"La compétition n'est pas la loi de la jungle","entry":"On te dit que la compétition est naturelle. Que la loi du plus fort est inscrite dans la biologie.","body":["À deux. Face à face. Sans se consulter, chacun·e décide : est-ce que je pousse ou est-ce que je cède ? Pas à l'avance — dans le mouvement.","Placez les paumes l'une contre l'autre. Pendant deux minutes : explorez cette question avec les corps, pas avec les têtes.","Puis : explorez comment vous pouvez vous soutenir mutuellement en utilisant les mêmes corps, le même contact.","Piotr Kropotkine, géographe et anarchiste, en 1902 : dans les steppes sibériennes, les animaux s'entraident plus qu'ils ne se combattent. Ce que la biologie a longtemps appelé 'compétition' est souvent quelque chose d'autre. Ce que vos corps viennent de trouver — c'était quoi ?"],"retour":"Quand tu entends 'c'est naturel', qui ça sert politiquement ?","sources":["Piotr Kropotkine — L'Entraide, un facteur de l'évolution (1902)","Marc-André Selosse — Jamais seul : les réseaux mycorhiziens comme modèle de coopération","Alexandre Tesnière — L'entraide, l'autre loi de la jungle (2020)"]},"en":{"title":"Competition is not the law of the jungle","entry":"You are told that competition is natural. That the law of the strongest is inscribed in biology.","body":["In pairs. Face to face. Without consulting, each decides: do I push or do I yield? Not in advance — in the movement.","Place palms against each other. For two minutes: explore this question with bodies, not with heads.","Then: explore how you can support each other using the same bodies, the same contact.","Kropotkin, 1902: in the Siberian steppes, animals help each other more than they compete. What biology long called 'competition' is often something else. What your bodies just found — what was it?"],"retour":"When you hear 'it's natural', who does that serve politically?","sources":["Kropotkin P. — Mutual Aid: A Factor of Evolution (1902)","Selosse M.-A. — Never Alone: mycorrhizal networks as a model of cooperation","Alexandre Tesnière — Mutual Aid: the other law of the jungle (2020)"]}},{"id":"ns-nature-femme","deck":"natures_sociales","type":"deconstruire","fr":{"title":"La nature féminisée","entry":"'Mère Nature'. 'La Terre nourricière'. La nature est souvent femme dans nos langues. Pourquoi ?","body":["Choisis un mot qu'on utilise souvent pour décrire la nature : généreuse, sauvage, nourricière, capricieuse, vierge. Prononce-le à voix haute.","Bouge comme si tu étais ce mot. Pas la nature — le mot lui-même. Qu'est-ce que 'nourricière' fait dans un corps ? Qu'est-ce que 'vierge' impose comme posture ?","Maintenant : bouge comme si personne n'avait jamais eu ce mot pour te décrire. Comment ton corps occupe-t-il l'espace quand il n'est pas dans une catégorie ?","Ces deux mouvements côte à côte — qu'est-ce qui change entre les deux ?"],"retour":"Qu'est-ce qu'une relation à la nature sans domination et sans sentimentalisme ressemblerait ?","sources":["Val Plumwood — Feminism and the Mastery of Nature (1993) : l'antidualisme écologique","Françoise d'Eaubonne — Le féminisme ou la mort (1974) : premier usage du terme écoféminisme","Arturo Escobar — Territories of Difference (2008) : les ontologies relationnelles comme alternative"]},"en":{"title":"Feminised nature","entry":"'Mother Nature'. 'The nurturing Earth'. Nature is often female in our languages. Why?","body":["Choose a word often used to describe nature: generous, wild, nurturing, capricious, virgin. Say it aloud.","Move as if you were this word. Not nature — the word itself. What does 'nurturing' do in a body? What posture does 'virgin' impose?","Now: move as if no one had ever had this word to describe you. How does your body occupy space when it's not in a category?","These two movements side by side — what changes between them?"],"retour":"What would a relationship to nature without domination and without sentimentalism look like?","sources":["Plumwood V. — Feminism and the Mastery of Nature (1993): ecological anti-dualism","Françoise d'Eaubonne — Feminism or Death (1974): first use of the term ecofeminism","Escobar A. — Territories of Difference (2008): relational ontologies as alternative"]}},{"id":"ns-hiérarchies","deck":"natures_sociales","type":"deconstruire","fr":{"title":"Les hiérarchies qu'on dit naturelles","entry":"'C'est dans la nature humaine.' 'Il y aura toujours des dominants et des dominés.' Ces phrases — qu'est-ce qu'elles font ?","body":["En groupe. Sans parler, chacun·e prend une position dans l'espace qui représente sa place hiérarchique — réelle ou perçue — dans un contexte qu'il ou elle connaît.","Gel. Regardez la sculpture collective. Qui a mis qui où ?","Quelqu'un peut maintenant modifier la sculpture vers 'une image idéale' — pas utopique, une image qui dit quelque chose de vrai sur comment les choses pourraient être.","Donna Haraway, biologiste et philosophe, l'a bien documenté : nos projections sur les animaux révèlent nos préjugés sociaux. Cette sculpture — qu'est-ce qu'elle révèle ?"],"retour":"Qu'est-ce que ton corps sait de la domination que ton intellect préfère ne pas savoir ?","sources":["Val Plumwood — la logique de la colonisation comme logique de la naturalisation","Donna Haraway — Primate Visions (1989) : nos projections sur les animaux révèlent nos préjugés sociaux"]},"en":{"title":"The hierarchies called natural","entry":"'It's human nature.' 'There will always be dominants and dominated.' These phrases — what do they do?","body":["In a group. Without speaking, each person takes a position in the space representing their hierarchical place — real or perceived — in a context they know.","Freeze. Look at the collective sculpture. Who put whom where?","Someone can now modify the sculpture toward 'an ideal image' — not utopian, an image that says something true about how things could be.","Haraway says: our projections onto animals reveal our social prejudices. This sculpture — what does it reveal?"],"retour":"What does your body know about domination that your intellect prefers not to know?","sources":["Plumwood V. — the logic of colonisation as the logic of naturalisation","Haraway D. — Primate Visions (1989): our projections onto animals reveal our social prejudices"]}},{"id":"ns-symbiose","deck":"natures_sociales","type":"redecouvrir","fr":{"title":"La symbiose comme règle","entry":"Marc-André Selosse, mycologue, a renversé l'idée reçue : la symbiose n'est pas l'exception dans la nature — c'est la règle.","body":["À deux. Placez-vous dos à dos, en contact léger. Respirez ensemble quelques instants — pas synchronisé·es, juste conscient·es du souffle de l'autre.","L'un·e commence à se pencher très légèrement vers l'avant. L'autre, sans qu'on le lui dise, sent le changement et s'ajuste. Explorez jusqu'où vous pouvez aller en restant équilibrés.","Ce que vous faites — deux êtres qui ne tiennent qu'en s'appuyant l'un sur l'autre — les champignons et les arbres le font sous terre depuis 450 millions d'années.","Séparez-vous. Chacun·e marche seul·e. Qu'est-ce qui a changé dans votre façon d'occuper l'espace ?"],"retour":"Quels échanges invisibles font que tu existes en ce moment ?","sources":["Marc-André Selosse — Jamais seul (2017) : mycorrhizes, lichens et révolution symbiologique","Robin Wall Kimmerer — la réciprocité comme loi écologique fondamentale"]},"en":{"title":"Symbiosis as the rule","entry":"Selosse says: symbiosis is not the exception in nature. It is the rule.","body":["In pairs. Stand back to back, in light contact. Breathe together for a few moments — not synchronised, just aware of each other's breath.","One person begins to lean very slightly forward. The other, without being told, feels the change and adjusts. Explore how far you can go while staying balanced.","What you are doing — two beings holding each other up by leaning together — fungi and trees have done underground for 450 million years.","Separate. Each person walks alone. What has changed in how you occupy the space?"],"retour":"What invisible exchanges make your existence possible right now?","sources":["Selosse M.-A. — Never Alone (2017): mycorrhizas, lichens and the symbiological revolution","Kimmerer R.W. — reciprocity as fundamental ecological law"]}},{"id":"ns-sapiens-parmi","deck":"natures_sociales","type":"redecouvrir","fr":{"title":"Sapiens parmi","entry":"Homo sapiens est une espèce parmi d'autres. Cette phrase — est-ce que tu la crois vraiment ?","body":["On dit que l'humain est différent parce qu'il a le langage. Les fouets ont le langage aussi — des milliers de mots codés.","Parce qu'il a la culture. Les orques transmettent des chants et des techniques de chasse de génération en génération.","Parce qu'il ressent. Les éléphants pleurent leurs morts.","Debout. Déplace-toi comme une espèce parmi d'autres — ni au sommet, ni à part. Juste... là."],"retour":"Qu'est-ce qu'on perd en se pensant à part ? Qu'est-ce qu'on gagne ?","sources":["Robin Wall Kimmerer — 'nous sommes les cadets de la création'","Anna Tsing — les assemblages multi-espèces comme mode d'existence"]},"en":{"title":"Sapiens among","entry":"Homo sapiens is one species among others. This sentence — do you really believe it?","body":["We say humans are different because they have language. Whales have language too — thousands of coded words.","Because they have culture. Orcas transmit songs and hunting techniques across generations.","Because they feel. Elephants mourn their dead.","Stand up. Move as one species among others — neither at the top, nor apart. Just... here."],"retour":"What do we lose by thinking of ourselves as apart? What do we gain?","sources":["Kimmerer R.W. — 'we are the younger siblings of creation'","Anna Tsing — multispecies assemblages as a mode of existence"]}},{"id":"ns-le-vivant-parle","deck":"natures_sociales","type":"redecouvrir","fr":{"title":"Le vivant communique","entry":"Les forêts communiquent. Les plantes s'alertent mutuellement. Les arbres reconnaissent leurs proches.","body":["Reste vraiment immobile. Pas figé·e — disponible. Les pieds bien posés, les épaules relâchées, les mains ouvertes.","Pendant deux minutes : laisse les signaux du monde entrer. Pas les interpréter — juste les recevoir. Une variation de lumière, un son qui change, une légère brise, une odeur.","Les plantes perçoivent et répondent à des signaux chimiques en continu. Ton système nerveux fait pareil — mais tu ne lui laisses pas souvent l'espace de travailler sans que ton mental commente.","Après : sans parler, fais un geste qui traduit ce que tu as reçu. Un seul geste."],"retour":"Quels langages du vivant avons-nous désappris à percevoir ?","sources":["Suzanne Simard — Finding the Mother Tree (2021) : les réseaux de communication forestiers","Marc-André Selosse — les signaux chimiques inter-espèces","Robin Wall Kimmerer — la grammaire de l'animé : entendre ce qui parle"]},"en":{"title":"The living communicates","entry":"Forests communicate. Plants warn each other. Trees recognise their relatives.","body":["Stay truly still. Not frozen — available. Feet well planted, shoulders released, hands open.","For two minutes: let the world's signals come in. Not interpreting them — just receiving. A variation of light, a changing sound, a slight breeze, a smell.","Plants continuously perceive and respond to chemical signals. Your nervous system does the same — but you rarely give it the space to work without your mind commenting.","Afterwards: without speaking, make a gesture that translates what you received. Just one gesture."],"retour":"What languages of the living have we unlearned to perceive?","sources":["Simard S. — Finding the Mother Tree (2021): forest communication networks","Selosse M.-A. — interspecies chemical signals","Kimmerer R.W. — the grammar of animacy: hearing what speaks"]}},{"id":"ns-reciprocite","deck":"natures_sociales","type":"habiter_autrement","fr":{"title":"La réciprocité","entry":"Pour Robin Wall Kimmerer, botaniste de la nation Potawatomi, l'économie du don n'est pas de la naïveté — c'est la loi de l'écologie.","body":["À deux ou en petit groupe. Un·e commence : donne quelque chose à quelqu'un — un geste, un regard soutenu, un mouvement vers l'autre. Vraiment donné, pas simulé.","L'autre reçoit — vraiment. Pas se préparer à répondre, pas évaluer. Juste laisser entrer ce qui a été donné.","Puis l'autre donne à son tour. Ce qu'il a reçu a-t-il changé ce qu'il donne ?","La fraise donne ses fruits avant que la graine tombe. Elle ne comptabilise pas. Elle donne parce que c'est sa nature. Pendant cinq minutes : essayez ça."],"retour":"Où dans ta vie existe déjà une économie de don ? Est-ce qu'elle compte moins parce qu'elle n'est pas marchande ?","sources":["Robin Wall Kimmerer — The Serviceberry (2024) : l'économie du don comme modèle écologique","David Graeber — Debt: The First 5000 Years (2011) : les mythes fondateurs de l'échange marchand vs la réciprocité"]},"en":{"title":"Reciprocity","entry":"Kimmerer says: the gift economy is not naivety. It is the law of ecology.","body":["In pairs or small group. One person begins: give something to someone — a gesture, a sustained look, a movement toward the other. Really given, not simulated.","The other receives — really. Not preparing to respond, not evaluating. Just letting in what was given.","Then the other gives in turn. Has what they received changed what they give?","The strawberry gives its fruit before the seed falls. It doesn't keep accounts. It gives because that is its nature. For five minutes: try this."],"retour":"Where in your life does a gift economy already exist? Does it count less because it's not market-based?","sources":["Kimmerer R.W. — The Serviceberry (2024): the gift economy as ecological model","Graeber D. — Debt: The First 5000 Years (2011): founding myths of market exchange vs reciprocity"]}},{"id":"ns-deuil-futur","deck":"natures_sociales","type":"habiter_autrement","fr":{"title":"Ce qui n'existera pas","entry":"Il y a des espèces que tes enfants, ou leurs enfants, ne verront jamais.","body":["Choisis une espèce que tu aimes. Pas la plus symbolique — une que tu as vraiment rencontrée, entendue, touchée, ou que tu connais en images.","Mime son mouvement caractéristique. Le vol de cet oiseau. La façon dont cet insecte se pose. La lenteur de cet arbre dans le vent. Prends le temps de vraiment l'habiter.","Maintenant arrête-toi. Ce mouvement que tu viens de faire — dans cent ans, il ne sera peut-être plus dans le monde. Pas dans la nature. Nulle part.","Reste un moment avec ça dans le corps. Pas intellectuellement. Physiquement."],"retour":"Qu'est-ce que tu veux faire de ce 'peut-être' ?","sources":["Joanna Macy — Work That Reconnects : le Conseil de tous les Êtres","Rachel Carson — Silent Spring : le printemps sans oiseaux comme avertissement non-entendu"]},"en":{"title":"What will not exist","entry":"There are species that your children, or their children, will never see.","body":["Choose a species you love. Not the most symbolic — one you have actually encountered, heard, touched, or know through images.","Mime its characteristic movement. The flight of that bird. The way that insect lands. The slowness of that tree in wind. Take time to really inhabit it.","Now stop. This movement you just made — in a hundred years, it may no longer exist in the world. Not in nature. Nowhere.","Stay with that in your body for a moment. Not intellectually. Physically."],"retour":"What do you want to do with this 'perhaps'?","sources":["Macy J. — Work That Reconnects: the Council of All Beings","Carson R. — Silent Spring: the spring without birds as an unheeded warning"]}},{"id":"ns-mythe-sauvage","deck":"natures_sociales","type":"deconstruire","fr":{"title":"Le mythe du sauvage solitaire","entry":"Le loup solitaire. Le prédateur au sommet. L'individu qui conquiert la nature seul. Ce sont des mythes — et ils ont une fonction.","body":["En groupe. Quelqu'un joue 'le loup solitaire' — il ou elle occupe l'espace seul·e, avec une qualité de mouvement indépendante, non-relationnelle.","Les autres observent. Puis : quelqu'un rejoint. Sans parler — juste en mouvant. Puis un autre. Et un autre.","Le 'loup solitaire' du mythe est en réalité un loup marginalisé — exclu de sa meute. Sens dans le groupe ce que ça fait d'accueillir quelqu'un, et d'être accueilli.","La meute n'est pas la dissolution du moi. C'est autre chose. Quoi ?"],"retour":"Quelles décisions politiques sont justifiées par ce mythe du sauvage solitaire ?","sources":["L. David Mech — la famille de loups comme réalité vs le mythe de la hiérarchie alpha","Piotr Kropotkine — L'Entraide : les animaux sociaux comme norme, pas exception"]},"en":{"title":"The myth of the lone savage","entry":"The lone wolf. The apex predator. The individual who conquers nature alone. These are myths — and they have a function.","body":["In a group. Someone plays 'the lone wolf' — they occupy the space alone, with a quality of independent, non-relational movement.","The others observe. Then: someone joins. Without speaking — just by moving. Then another. And another.","The mythical 'lone wolf' is actually a marginalised wolf — excluded from its pack. Feel in the group what it does to welcome someone, and to be welcomed.","The pack is not the dissolution of the self. It is something else. What?"],"retour":"What political decisions are justified by the myth of the lone savage?","sources":["L. David Mech — the wolf family as reality vs the alpha hierarchy myth","Kropotkin P. — Mutual Aid: social animals as norm, not exception"]}},{"id":"ns-plantes-entraident","deck":"natures_sociales","type":"redecouvrir","fr":{"title":"Les plantes qui s'entraident","entry":"Les Three Sisters — maïs, haricot, courge — cultivées ensemble depuis des millénaires par les peuples autochtones d'Amérique. Elles se nourrissent mutuellement.","body":["Trois personnes. En silence, sans s'être concertées, placez-vous dans l'espace de façon à ce que chacun·e soutienne les deux autres d'une façon différente.","Pas avec les mains — avec la présence, la direction du corps, la distance choisie. Explorez pendant quelques minutes.","Le maïs donne le tuteur. Le haricot fixe l'azote. La courge couvre le sol. Aucun ne sait consciemment ce que font les autres. Et pourtant le système fonctionne.","Que s'est-il passé dans ce triangle ? Qui a soutenu qui, et comment ?"],"retour":"Qu'est-ce que 'se soutenir' veut dire quand aucun de vous ne dirige ?","sources":["Robin Wall Kimmerer — Braiding Sweetgrass : les Three Sisters comme pédagogie de la réciprocité","Vandana Shiva — la polyculture contre la monoculture comme modèle de vie"]},"en":{"title":"Plants that help each other","entry":"The Three Sisters — maize, bean, squash — cultivated together for millennia by indigenous peoples of the Americas. They nourish each other.","body":["Three people. In silence, without consulting, place yourselves in the space so that each supports the other two in a different way.","Not with hands — with presence, body direction, chosen distance. Explore for a few minutes.","Maize provides the stake. Bean fixes nitrogen. Squash covers the ground. None consciously knows what the others are doing. Yet the system works.","What happened in this triangle? Who supported whom, and how?"],"retour":"What does 'supporting each other' mean when neither of you is directing?","sources":["Kimmerer R.W. — Braiding Sweetgrass: the Three Sisters as pedagogy of reciprocity","Shiva V. — polyculture against monoculture as life model"]}},{"id":"ns-foret-commun","deck":"natures_sociales","type":"redecouvrir","fr":{"title":"La forêt comme commun","entry":"Pendant des millénaires, les forêts ont été des communs — gérées collectivement par des communautés, pas appropriées privativement.","body":["L'espace est un commun. Chacun·e peut l'utiliser — pas le posséder.","Quelqu'un commence à 'clôturer' une partie de l'espace avec ses bras, son corps, une ligne imaginaire. Puis un autre. Et un autre.","Que reste-t-il pour les autres ? Comment les corps s'adaptent-ils à la réduction de l'espace commun ?","Silvia Federici, historienne féministe, et Elinor Ostrom, économiste : l'enclosure n'est pas inévitable — elle est une décision. À quel moment quelqu'un dans le groupe aurait-il pu l'arrêter ?"],"retour":"Que signifie 'prendre soin' de quelque chose qui n'est pas 'à toi' ?","sources":["Elinor Ostrom — La gouvernance des biens communs (1990) : la tragédie des communs n'est pas inévitable","Silvia Federici — Caliban and the Witch (2004) : l'enclosure des communs comme condition du capitalisme"]},"en":{"title":"The forest as commons","entry":"For millennia, forests were commons — collectively managed by communities, not privately appropriated.","body":["The space is a common. Each person can use it — not own it.","Someone begins to 'fence off' part of the space with their arms, their body, an imaginary line. Then another. And another.","What is left for the others? How do bodies adapt to the reduction of the common space?","Federici and Ostrom together: enclosure is not inevitable — it is a decision. At what point could someone in the group have stopped it?"],"retour":"What does 'caring for' something that is not 'yours' mean?","sources":["Ostrom E. — Governing the Commons (1990): the tragedy of the commons is not inevitable","Federici S. — Caliban and the Witch (2004): enclosure of the commons as condition of capitalism"]}},{"id":"ns-wendigo","deck":"natures_sociales","type":"deconstruire","fr":{"title":"Le Wendigo","entry":"Dans les traditions algonquiennes, le Wendigo est un esprit qui ne peut jamais être rassasié — plus il mange, plus il a faim.","body":["Marche dans l'espace. À chaque objet ou personne que tu croises, arrête-toi une seconde et demande-toi : est-ce que j'en veux plus ? Est-ce que ce que j'ai suffit ?","Continue à marcher. Laisse cette question créer une friction légère dans ton corps — ni culpabilité ni satisfaction facile. Juste la friction.","Puis : arrête-toi. Tiens-toi là où tu es. Sens ce que c'est d'être là, maintenant, sans aller nulle part.","Le Wendigo ne peut jamais s'arrêter. Ton corps peut. C'est une forme de résistance."],"retour":"Quel est l'opposé du Wendigo ? Comment s'incarne-t-il dans un corps ?","sources":["Robin Wall Kimmerer — Braiding Sweetgrass : le Wendigo comme critique de l'économie capitaliste","traditions algonquiennes : l'accumulation comme maladie, pas comme vertu"]},"en":{"title":"The Wendigo","entry":"In Algonquin traditions, the Wendigo is a spirit that can never be satisfied — the more it eats, the hungrier it gets.","body":["Walk through the space. At each object or person you pass, stop for a second and ask: do I want more? Is what I have enough?","Keep walking. Let this question create a slight friction in your body — neither guilt nor easy satisfaction. Just the friction.","Then: stop. Stay where you are. Feel what it is to be here, now, going nowhere.","The Wendigo can never stop. Your body can. That is a form of resistance."],"retour":"What is the opposite of the Wendigo? How does it embody in a body?","sources":["Kimmerer R.W. — Braiding Sweetgrass: the Wendigo as critique of capitalist economy","Algonquin traditions: accumulation as illness, not virtue"]}},{"id":"ns-abeilles-travail","deck":"natures_sociales","type":"deconstruire","fr":{"title":"Les abeilles et le travail","entry":"On dit que les abeilles 'travaillent'. Elles 'produisent'. Elles ont une 'reine'. Ce langage révèle nos projections.","body":["Les abeilles ne 'travaillent' pas — elles vivent. La butineuse qui collecte du pollen exprime une capacité, pas une obligation.","La 'reine' ne commande rien. C'est une pondeuse dont le destin est décidé par la colonie.","Ces métaphores viennent de nos sociétés et retournent vers elles pour les légitimer.","Bouge comme une abeille sans penser à la production. Juste le mouvement, les sens, l'attention à l'environnement."],"retour":"Comment le travail serait-il différent si on l'appelait 'exprimer une capacité' ?","sources":["Donna Haraway — Primate Visions : nos projections sur les animaux comme révélateur culturel","Val Plumwood — le langage de la nature comme miroir de nos idéologies"]},"en":{"title":"Bees and work","entry":"We say bees 'work'. They 'produce'. They have a 'queen'. This language reveals our projections.","body":["Bees don't 'work' — they live. The forager collecting pollen expresses a capacity, not an obligation.","The 'queen' commands nothing. She is a layer whose fate is decided by the colony.","These metaphors come from our societies and return to legitimise them.","Move like a bee without thinking about production. Just movement, senses, attention to the environment."],"retour":"How would work be different if we called it 'expressing a capacity'?","sources":["Haraway D. — Primate Visions: our projections onto animals as cultural revealer","Plumwood V. — the language of nature as mirror of our ideologies"]}},{"id":"ns-mort-don","deck":"natures_sociales","type":"habiter_autrement","fr":{"title":"La mort comme don","entry":"Dans un écosystème forestier, un arbre mort est plus précieux que beaucoup d'arbres vivants.","body":["En groupe. Quelqu'un s'allonge lentement au sol — pas mort dramatiquement, juste se dépose. Les autres continuent à bouger autour de lui ou elle.","Progressivement, d'autres personnes s'approchent, s'agenouillent, s'assoient, touchent légèrement. Non pour secourir — pour composer.","La personne au sol commence à se transformer — pas à se lever, à changer de forme. Ses bras deviennent des branches. Son souffle, de l'humus.","Marc-André Selosse, mycologue : un tronc mort abrite 200 espèces. Ce corps au sol — qu'est-ce qu'il devient dans le groupe ?"],"retour":"Qu'est-ce que cette culture de la mort comme déchet fait à notre façon de vieillir ?","sources":["Marc-André Selosse — la décomposition comme fondement de la vie forestière","Anna Tsing — 'living and dying well' dans les ruines capitalistes"]},"en":{"title":"Death as gift","entry":"In a forest ecosystem, a dead tree is more valuable than many living ones.","body":["In a group. Someone slowly lies on the ground — not dramatically dead, just settles. The others continue to move around them.","Gradually, others approach, kneel, sit, touch lightly. Not to rescue — to compose.","The person on the ground begins to transform — not to rise, to change form. Their arms become branches. Their breath, humus.","Selosse: a dead trunk shelters 200 species. This body on the ground — what does it become in the group?"],"retour":"What does this culture of death-as-waste do to our way of ageing?","sources":["Selosse M.-A. — decomposition as foundation of forest life","Anna Tsing — 'living and dying well' in capitalist ruins"]}},{"id":"ns-soin-politique","deck":"natures_sociales","type":"habiter_autrement","fr":{"title":"Le soin comme acte politique","entry":"Le soin — soigner, nourrir, entretenir, réparer — est le travail le plus fondamental et le moins valorisé des sociétés capitalistes.","body":["En groupe, contact improvisation minimal. Commencez par trouver un point de contact avec quelqu'un — une épaule, un coude, un dos. Restez en mouvement lent.","Pas de rôles assignés. Pas de 'soignant·e' et 'soigné·e'. Juste deux corps qui s'adaptent l'un à l'autre en bougeant.","Progressivement, un troisième corps rejoint. Puis un quatrième. Le réseau de contact s'étend.","Vandana Shiva, physicienne et militante indienne : le soin est le fondement invisible des économies. Silvia Federici, historienne féministe : il a été dévalorisé exactement quand il a été attribué aux femmes. Qu'est-ce que vos corps viennent de faire, ensemble, sans que personne ne décide qui sert qui ?"],"retour":"Si le soin était au centre de l'économie plutôt qu'à sa périphérie — qu'est-ce qui changerait ?","sources":["Silvia Federici — Caliban and the Witch (2004) : le soin comme travail invisible et criminalisé","Arturo Escobar — Designs for the Pluriverse (2018) : la 'communalité' comme mode de vie alternatif"]},"en":{"title":"Care as political act","entry":"Care — caring, feeding, maintaining, repairing — is the most fundamental and least valued work in capitalist societies.","body":["In a group, minimal contact improvisation. Begin by finding a point of contact with someone — a shoulder, an elbow, a back. Stay in slow movement.","No assigned roles. No 'caregiver' and 'cared for'. Just two bodies adapting to each other while moving.","Gradually, a third body joins. Then a fourth. The contact network extends.","Shiva: care is the invisible foundation of economies. Federici: it was devalued exactly when it was assigned to women. What did your bodies just do, together, without anyone deciding who serves whom?"],"retour":"If care were at the centre of the economy rather than its periphery — what would change?","sources":["Federici S. — Caliban and the Witch (2004): care as invisible and criminalised labour","Escobar A. — Designs for the Pluriverse (2018): 'communality' as alternative way of life"]}},{"id":"ns-domestication","deck":"natures_sociales","type":"deconstruire","fr":{"title":"La domestication","entry":"On dit que les humains ont domestiqué les plantes et les animaux. Qui a domestiqué qui ?","body":["À deux. Décidez en silence : l'un·e est 'humain·e', l'autre est 'plante'.","La plante commence à bouger selon sa propre logique — lente, verticale, cherchant la lumière. L'humain·e observe, puis commence à interagir — sans forcer, juste en étant là.","Progressivement : qui guide qui ? La plante adapte-t-elle son mouvement à l'humain·e ? L'humain·e adapte-t-il·elle ses gestes à la plante ?","Harari : 'Le blé a domestiqué l'humain autant que l'humain a domestiqué le blé.' Qu'est-ce que vos corps viennent de confirmer ?"],"retour":"Qu'est-ce que ça change de voir la domestication comme une relation plutôt que comme une conquête ?","sources":["Yuval Noah Harari — Sapiens : 'le blé a domestiqué l'humain' comme hypothèse provocatrice","Anna Tsing — les assemblages comme co-constitution, pas comme domination"]},"en":{"title":"Domestication","entry":"We say humans domesticated plants and animals. Who domesticated whom?","body":["In pairs. Decide in silence: one is 'human', the other is 'plant'.","The plant begins to move according to its own logic — slow, vertical, seeking light. The human observes, then begins to interact — without forcing, just by being there.","Gradually: who guides whom? Does the plant adapt its movement to the human? Does the human adapt their gestures to the plant?","Harari: 'Wheat domesticated humans as much as humans domesticated wheat.' What did your bodies just confirm?"],"retour":"What changes when you see domestication as a relationship rather than a conquest?","sources":["Yuval Noah Harari — Sapiens: 'wheat domesticated humans' as provocative hypothesis","Anna Tsing — assemblages as co-constitution, not domination"]}},{"id":"ns-agriculture-corps","deck":"natures_sociales","type":"redecouvrir","fr":{"title":"L'agriculture comme relation","entry":"L'agriculture industrielle traite le sol comme un substrat inerte. L'agriculture paysanne le traite comme un partenaire.","body":["Accroupis-toi. Place tes deux mains sur le sol — ou imagine-le si tu es en intérieur. Sens la surface sous tes paumes : sa température, sa texture, sa résistance.","Reste dans cette position le temps de sentir que tu n'es pas au-dessus du sol, mais avec lui. Pas un observateur — un contact.","Lève-toi très lentement, en gardant l'attention dans tes paumes le plus longtemps possible. À quel moment perdre le contact devient-il inévitable ?","Pour Vandana Shiva, physicienne et militante indienne, connaître un sol c'est y vivre assez longtemps pour en sentir les variations. Qu'est-ce que tes mains auraient appris si tu restais là cent ans ?"],"retour":"Qu'est-ce que 'connaître' un sol veut dire — et qui a ce droit ?","sources":["Vandana Shiva — Monocultures of the Mind : la monoculture comme épistémologie","Robin Wall Kimmerer — la connaissance incarnée des plantes comme connaissance légitime"]},"en":{"title":"Agriculture as relationship","entry":"Industrial agriculture treats soil as an inert substrate. Peasant farming treats it as a partner.","body":["Crouch. Place both hands on the ground — or imagine it if you are indoors. Feel the surface under your palms: its temperature, texture, resistance.","Stay in this position long enough to feel that you are not above the ground, but with it. Not an observer — a contact.","Rise very slowly, keeping attention in your palms as long as possible. At what point does losing contact become inevitable?","Shiva says: to know a soil is to live in it long enough to feel its variations. What would your hands have learned if you stayed there a hundred years?"],"retour":"What does 'knowing' a soil mean — and who has that right?","sources":["Shiva V. — Monocultures of the Mind: monoculture as epistemology","Kimmerer R.W. — embodied knowledge of plants as legitimate knowledge"]}},{"id":"ns-corps-nature-dualisme","deck":"natures_sociales","type":"deconstruire","fr":{"title":"La séparation nature/culture","entry":"Quand a commencé l'idée que les humains étaient séparés de la nature ? Et pourquoi ?","body":["En groupe. Tracez imaginairement une ligne au milieu de l'espace. D'un côté : la Nature. De l'autre : la Culture.","Chacun·e se place où il ou elle se sent — puis commence à bouger uniquement de son côté. Qu'est-ce que 'bouger en nature' fait au corps ? Qu'est-ce que 'bouger en culture' fait ?","Maintenant : traversez la ligne. Revenez. Traversez encore. Jusqu'à ce que la ligne devienne floue.","Val Plumwood, philosophe écoféministe, et Karen Barad, physicienne : cette ligne n'a jamais existé dans la matière. Elle existe dans les têtes et dans les institutions. Vos corps viennent de le vérifier."],"retour":"Qu'est-ce que tu fais différemment quand tu te penses séparé·e de la nature ?","sources":["Val Plumwood — Feminism and the Mastery of Nature (1993) : généalogie du dualisme nature/culture","Karen Barad — Meeting the Universe Halfway (2007) : pas de frontière nette entre observateur et observé","Arturo Escobar — Designs for the Pluriverse (2018) : le 'monde à un seul monde' comme violence épistémique"]},"en":{"title":"The nature/culture separation","entry":"When did the idea that humans were separate from nature begin? And why?","body":["In a group. Imaginarily draw a line through the middle of the space. On one side: Nature. On the other: Culture.","Each person places themselves where they feel they are — then begins to move only on their side. What does 'moving in nature' do to the body? What does 'moving in culture' do?","Now: cross the line. Come back. Cross again. Until the line becomes blurred.","Plumwood and Barad together: this line has never existed in matter. It exists in minds and in institutions. Your bodies just verified that."],"retour":"What do you do differently when you think of yourself as separate from nature?","sources":["Plumwood V. — Feminism and the Mastery of Nature (1993): genealogy of nature/culture dualism","Barad K. — Meeting the Universe Halfway (2007): no clear boundary between observer and observed","Escobar A. — Designs for the Pluriverse (2018): the 'one-world world' as epistemic violence"]}},{"id":"ns-pachamama","deck":"natures_sociales","type":"redecouvrir","fr":{"title":"Pachamama","entry":"Dans les cosmologies quechua et aymara, Pacha signifie monde, univers, espace, temps, totalité. Pachamama est la Mère du cosmos — pas seulement de la terre.","body":["Debout, pieds nus si possible. Sens les points de contact entre tes pieds et le sol — la plante entière, pas seulement les talons.","Pacha signifie monde, temps et espace à la fois. Sens que tu ne te tiens pas SUR la terre — tu te tiens DANS le monde. Il y a une nuance physique là.","Fais un pas. Puis un autre. Marche comme si chaque pas était une conversation avec ce sol — pas une déambulation, un échange.","À un moment, arrête-toi et fais un geste que ce lieu t'inspire — pas ce que tu penses devoir faire. Ce qui vient."],"retour":"Qu'est-ce que reconnaître des droits à la nature change dans notre façon d'habiter la Terre ?","sources":["Cosmologies quechua et aymara : Pacha comme monde-temps-espace, Pachamama comme Mère du cosmos","Constitution de l'Équateur (2008) : droits de la Nature comme Pachamama, sous influence des mouvements autochtones"]},"en":{"title":"Pachamama","entry":"In Quechua and Aymara cosmologies, Pacha means world, universe, space, time, totality. Pachamama is the Mother of the cosmos — not just of the earth.","body":["Standing, bare feet if possible. Feel the contact points between your feet and the ground — the whole sole, not just the heels.","Pacha means world, time and space at once. Feel that you are not standing ON the earth — you are standing IN the world. There is a physical nuance there.","Take a step. Then another. Walk as if each step is a conversation with this ground — not a stroll, an exchange.","At a moment, stop and make a gesture that this place inspires — not what you think you should do. What comes."],"retour":"What does recognising rights for nature change in how we inhabit the Earth?","sources":["Quechua and Aymara cosmologies: Pacha as world-time-space, Pachamama as Mother of the cosmos","Ecuador's Constitution (2008): rights of Nature as Pachamama, under indigenous movements' influence"]}},{"id":"ns-cosmopolitique","deck":"natures_sociales","type":"deconstruire","fr":{"title":"Qui parle pour la nature ?","entry":"Qui représente les non-humains dans nos décisions politiques ? Qui parle au nom des forêts, des rivières, des espèces ?","body":["En groupe. Chacun·e choisit en silence un être non-humain de ce lieu — pas le même, pas concerté. Puis chacun·e prend une position dans l'espace qui représente cet être.","Regardez la géographie qui se forme. Qui est où ? Qui regarde qui ? Qui tourne le dos à qui ?","Maintenant : depuis votre position, chacun·e dit une phrase en commençant par 'Moi, la rivière...' ou 'Moi, le chêne...' — pas ce que vous pensez, ce que vous ressentez depuis ce lieu.","Après : revenez à vos postures humaines. Qu'est-ce que la carte des non-humains disait que la carte des humains ne dit pas ?"],"retour":"Qu'est-ce qui changerait dans nos décisions si les non-humains avaient une voix dans les assemblées ?","sources":["Arturo Escobar — Designs for the Pluriverse (2018) : la cosmopolitique et les ontologies relationnelles","Isabelle Stengers — Cosmopolitiques (1997-2003) : l'art de faire des mondes avec les non-humains"]},"en":{"title":"Who speaks for nature?","entry":"Who represents non-humans in our political decisions? Who speaks on behalf of forests, rivers, species?","body":["In a group. Each person silently chooses a non-human being from this place — not the same, not coordinated. Then each takes a position in the space that represents this being.","Look at the geography that forms. Who is where? Who looks at whom? Who turns their back on whom?","Now: from your position, each person says a sentence beginning with 'I, the river...' or 'I, the oak...' — not what you think, what you feel from this place.","Afterwards: return to your human postures. What did the map of non-humans say that the map of humans doesn't?"],"retour":"What would change in our decisions if non-humans had a voice in assemblies?","sources":["Escobar A. — Designs for the Pluriverse (2018): cosmopolitics and relational ontologies","Stengers I. — Cosmopolitics (1997-2003): the art of making worlds with non-humans"]}}],"my":[{"id":"my-rangi-papa","deck":"mythologies","type":"cosmogonie","fr":{"title":"Rangi et Papatūānuku","entry":"Au commencement, Ranginui le Ciel et Papatūānuku la Terre s'enlacent étroitement dans l'obscurité. Leurs enfants naissent entre eux, dans le noir.","body":["Les enfants grandissent dans cette étreinte. Ils débattent : faut-il les séparer pour laisser entrer la lumière ?","Tāne Mahuta, dieu des forêts, les sépare enfin — Rangi monte, Papa reste. La lumière entre pour la première fois.","Rangi pleure Papa — ses larmes tombent comme la pluie. Papa soupire — la brume monte des forêts.","Sens dans ton corps l'espace entre deux choses qui s'aimaient et ont été séparées pour que quelque chose de nouveau puisse naître."],"retour":"Quelle séparation dans ta vie a créé de la lumière ?","sources":["Cosmologie māori — Ranginui et Papatūānuku, ciel-père et terre-mère (Aotearoa/Nouvelle-Zélande)","Te Ara — Encyclopedia of New Zealand : les traditions de création māori"]},"en":{"title":"Rangi and Papatūānuku","entry":"At the beginning, Ranginui the Sky and Papatūānuku the Earth hold each other tightly in darkness. Their children are born between them, in the dark.","body":["The children grow in this embrace. They debate: should they separate their parents to let in the light?","Tāne Mahuta, god of forests, finally separates them — Rangi rises, Papa remains. Light enters for the first time.","Rangi weeps for Papa — his tears fall as rain. Papa sighs — mist rises from the forests.","Feel in your body the space between two things that loved each other and were separated so something new could be born."],"retour":"What separation in your life created light?","sources":["Māori cosmology — Ranginui and Papatūānuku, sky-father and earth-mother (Aotearoa/New Zealand)","Te Ara — Encyclopedia of New Zealand: Māori creation traditions"]}},{"id":"my-skywoman-creation","deck":"mythologies","type":"cosmogonie","fr":{"title":"Skywoman et la Tortue","entry":"Une femme tombe du monde d'en haut, tenant dans ses mains des graines et des plantes. Les animaux créent la terre pour elle.","body":["Les oies la portent sur leurs ailes. La tortue offre son dos. Le rat musqué plonge pour ramener de la terre.","Skywoman danse sur le dos de la tortue, et de ses pas, la terre s'étend. Elle plante. La vie commence.","Robin Wall Kimmerer, botaniste de la nation Potawatomi, souligne : dans cette histoire, les animaux n'attendaient pas qu'on les domine. Ils choisissaient de donner.","Bouge comme si la terre sous tes pieds était en train de naître de chacun de tes pas."],"retour":"Quelle différence entre arriver dans un monde hostile à conquérir, et tomber dans un monde qui t'accueille ?","sources":["Tradition Haudenosaunee (Iroquois) — la création de Turtle Island, transmise oralement depuis des générations","Robin Wall Kimmerer — Braiding Sweetgrass (2013) : 'Skywoman Falling', la réciprocité comme acte fondateur"]},"en":{"title":"Skywoman and the Turtle","entry":"A woman falls from the world above, holding seeds and plants in her hands. The animals create earth for her.","body":["The geese carry her on their wings. The turtle offers its back. The muskrat dives to bring up earth.","Skywoman dances on the turtle's back, and from her steps, the earth expands. She plants. Life begins.","Kimmerer says: in this story, the animals did not wait to be dominated. They chose to give.","Move as if the earth under your feet were being born from each of your steps."],"retour":"What is the difference between arriving in a hostile world to conquer, and falling into a world that welcomes you?","sources":["Haudenosaunee (Iroquois) tradition — the creation of Turtle Island, orally transmitted across generations","Kimmerer R.W. — Braiding Sweetgrass (2013): 'Skywoman Falling', reciprocity as founding act"]}},{"id":"my-dreamtime","deck":"mythologies","type":"cosmogonie","fr":{"title":"Le Temps du Rêve","entry":"Pour les peuples autochtones d'Australie, le Dreamtime n'est pas un passé révolu — c'est une réalité qui continue à exister en dessous du monde visible.","body":["Les Êtres ancestraux ont chanté le monde en existence, marchant sur la terre et laissant des pistes de chant — des lignes de force qui traversent le continent.","Chaque lieu a un chant. Connaître le pays, c'est connaître son chant.","Marche lentement. Imagine que tes pas suivent une ligne de chant — invisible, mais réelle.","Bruce Chatwin, écrivain voyageur, l'a consigné dans Les Chants du monde : les peuples autochtones australiens parcourent le continent en chantant le paysage en existence."],"retour":"Si ce lieu avait un chant, comment commencerait-il ?","sources":["Traditions des peuples autochtones australiens — Dreamtime, lignes de chant (songlines), être et paysage","Bruce Chatwin — The Songlines (1987) : les pistes de chant comme carte du monde"]},"en":{"title":"The Dreamtime","entry":"For the Indigenous peoples of Australia, the Dreamtime is not a past — it is a reality that continues to exist beneath the visible world.","body":["Ancestral Beings sang the world into existence, walking the earth and leaving song tracks — lines of force crossing the continent.","Every place has a song. To know the country is to know its song.","Walk slowly. Imagine your steps follow a song line — invisible, but real.","Bruce Chatwin writes in The Songlines: Indigenous Australian peoples cross the continent singing the landscape into existence."],"retour":"If this place had a song, how would it begin?","sources":["Indigenous Australian traditions — Dreamtime, songlines, being and landscape","Chatwin B. — The Songlines (1987): song tracks as map of the world"]}},{"id":"my-pachamama-creation","deck":"mythologies","type":"cosmogonie","fr":{"title":"Pachamama et le temps-espace","entry":"Pacha, en quechua et aymara, ne signifie pas seulement 'terre'. Il signifie monde, univers, espace, temps, totalité.","body":["Pachamama n'est pas 'dans' le temps et dans l'espace — elle est le temps et l'espace.","Chaque geste agricole est une relation avec elle — on lui demande, on lui offre, on lui rend.","La constitution équatorienne de 2008 lui a accordé des droits juridiques. Pas comme métaphore — comme être.","Pose les deux mains sur le sol. Tu touches quelque chose qui n'est pas seulement de la terre — tu touches du temps solidifié."],"retour":"Si tu devais demander permission à ce lieu pour faire quelque chose, que demanderais-tu ? Et comment ?","sources":["Cosmologies quechua et aymara — Pacha comme espace-temps, Pachamama comme être relationnel","Constitution de l'Équateur (2008), Article 71 : 'La nature ou Pachamama, où la vie se reproduit et se réalise, a le droit d'être intégralement respectée dans son existence'"]},"en":{"title":"Pachamama and space-time","entry":"Pacha, in Quechua and Aymara, doesn't only mean 'earth'. It means world, universe, space, time, totality.","body":["Pachamama is not 'in' time and space — she is time and space.","Every agricultural gesture is a relationship with her — one asks, one offers, one returns.","Ecuador's 2008 constitution granted her legal rights. Not as metaphor — as a being.","Place both hands on the ground. You are touching something that is not only earth — you are touching solidified time."],"retour":"If you had to ask permission from this place to do something, what would you ask? And how?","sources":["Quechua and Aymara cosmologies — Pacha as space-time, Pachamama as relational being","Ecuador's Constitution (2008), Article 71: 'Nature or Pachamama, where life is reproduced and occurs, has the right to integral respect for its existence'"]}},{"id":"my-omama","deck":"mythologies","type":"cosmogonie","fr":{"title":"Omama et les esprits de la forêt","entry":"Omama, le démiurge yanomami, a créé la forêt et y a placé des esprits — les xapiri — qui maintiennent l'ordre du monde.","body":["Ferme les yeux. Sens le lieu autour de toi comme peuplé — pas de présences humaines, d'êtres que tu ne perçois pas habituellement.","Commence à bouger très lentement dans l'espace, comme si tu naviguais entre des présences invisibles. Pas les éviter — les sentir.","Les xapiri dansent pour maintenir l'ordre du monde. Laisse ton mouvement devenir une forme de soin — comme si bouger ici contribuait à maintenir quelque chose.","Davi Kopenawa, chaman et porte-parole yanomami, prévient : si nous cessons de travailler, le ciel tombera. Sens dans ton corps ce que ça fait de porter cette responsabilité."],"retour":"Quel soin ton corps fait-il au monde en se mouvant ici ?","sources":["Davi Kopenawa & Bruce Albert — La Chute du ciel (2010) : cosmologie yanomami, xapiri et responsabilité chamanique","Bruce Albert — anthropologie de la forêt amazonienne comme être politique"]},"en":{"title":"Omama and the forest spirits","entry":"Omama, the Yanomami demiurge, created the forest and placed spirits in it — the xapiri — who maintain the world's order.","body":["Close your eyes. Feel the place around you as populated — not by human presences, but by beings you don't usually perceive.","Begin to move very slowly through the space, as if navigating between invisible presences. Not avoiding them — feeling them.","The xapiri dance to maintain the world's order. Let your movement become a form of care — as if moving here contributed to maintaining something.","Kopenawa says: if we stop working, the sky will fall. Feel in your body what it is to carry this responsibility."],"retour":"What care does your body give to the world in moving here?","sources":["Kopenawa D. & Bruce Albert — The Falling Sky (2010): Yanomami cosmology, xapiri and shamanic responsibility","Bruce Albert — anthropology of the Amazon forest as political being"]}},{"id":"my-loi-origines","deck":"mythologies","type":"cosmogonie","fr":{"title":"La Loi des Origines","entry":"Pour les peuples Arhuaco, Kogi, Wiwa et Kankuamo de la Sierra Nevada, la Loi des Origines gouverne les relations entre les humains, la nature et l'univers.","body":["La Sierra Nevada est le Cœur du Monde. Les Mamos — les guides spirituels — passent des années dans l'obscurité totale pour apprendre à écouter.","Ils 'paient' régulièrement la nature : ils rendent à la Mère ce qu'ils lui ont pris.","Ils nous avertissent depuis des décennies : les fils de la pensée du monde se déchirent. L'écosystème de la Sierra indique l'état de la planète.","Reste un moment en silence complet. Écoute avec une attention que tu n'utilises d'habitude pas."],"retour":"Qu'est-ce que tu pourrais 'payer' à ce lieu pour ce qu'il te donne ?","sources":["Peuples Arhuaco, Kogi, Wiwa et Kankuamo — Loi des Origines (Sierra Nevada, Colombie)","UNESCO — Système de connaissances ancestrales de la Sierra Nevada (patrimoine immatériel 2022)"]},"en":{"title":"The Law of Origins","entry":"For the Arhuaco, Kogi, Wiwa and Kankuamo peoples of the Sierra Nevada, the Law of Origins governs relations between humans, nature and the universe.","body":["The Sierra Nevada is the Heart of the World. The Mamos — spiritual guides — spend years in total darkness learning to listen.","They regularly 'pay' nature: they return to the Mother what they have taken.","They have been warning us for decades: the world's thought-threads are tearing. The Sierra Nevada ecosystem shows the state of the planet.","Stay in complete silence for a moment. Listen with an attention you don't usually use."],"retour":"What could you 'pay' to this place for what it gives you?","sources":["Arhuaco, Kogi, Wiwa and Kankuamo peoples — Law of Origins (Sierra Nevada, Colombia)","UNESCO — Ancestral Knowledge System of the Sierra Nevada (intangible heritage 2022)"]}},{"id":"my-coyote","deck":"mythologies","type":"figure","fr":{"title":"Coyote le trickster","entry":"Coyote est le trickster des traditions des peuples des Grandes Plaines d'Amérique du Nord — il transgresse, il joue, il fait des erreurs, il transforme le monde par accident.","body":["Il n'est ni bon ni mauvais. Il est rusé, créateur, imprévisible. Il apporte le feu aux humains, mais aussi le chaos.","Le trickster existe dans presque toutes les mythologies — Loki en Scandinavie, Anansi en Afrique de l'Ouest, Renard en France.","Bouge comme Coyote — curieux, changeant de direction, moquant les rigidités.","Qu'est-ce qui dans ce moment prend trop au sérieux ? Qu'est-ce qui mérite d'être un peu déraillé ?"],"retour":"Qu'est-ce que le trickster permet de faire que les héros sérieux ne peuvent pas faire ?","sources":["Traditions des Grandes Plaines (Lakota, Navajo, Crow) — Coyote comme trickster créateur","Lewis Hyde — Trickster Makes This World (1998) : les figures trickster dans les mythologies mondiales"]},"en":{"title":"Coyote the trickster","entry":"Coyote is the trickster of the Great Plains peoples of North America — he transgresses, plays, makes mistakes, transforms the world by accident.","body":["He is neither good nor bad. He is cunning, creative, unpredictable. He brings fire to humans, but also chaos.","The trickster exists in almost all mythologies — Loki in Scandinavia, Anansi in West Africa, the Fox in France.","Move like Coyote — curious, changing direction, mocking rigidities.","What in this moment is taking itself too seriously? What deserves to be slightly derailed?"],"retour":"What does the trickster allow that serious heroes cannot do?","sources":["Great Plains traditions (Lakota, Navajo, Crow) — Coyote as creator trickster","Hyde L. — Trickster Makes This World (1998): trickster figures in world mythologies"]}},{"id":"my-oshun","deck":"mythologies","type":"figure","fr":{"title":"Oshun, l'eau douce","entry":"Dans la cosmologie yoruba du Nigeria, Oshun est l'orisha des rivières, de l'amour, de la fertilité, de la douceur et de la transformation.","body":["Elle est représentée en jaune et or, dansant dans l'eau. Elle soigne, elle séduit, elle protège les femmes et les enfants.","Oshun est aussi la gardienne des eaux douces — sans elle, il n'y a pas de vie. Lors d'une sécheresse terrible, les autres orishas ne purent rien faire. Oshun descendit et pria. La pluie revint.","Bouge comme de l'eau douce — fluide, cherchant son chemin, contournant les obstacles, nourrissant.","Sans douceur, que devient la force ?"],"retour":"Qu'est-ce que la douceur peut faire que la force ne peut pas ?","sources":["Cosmologie yoruba (Nigeria, Bénin, diaspora) — Oshun, orisha des rivières et de la douceur","Rowland Abiodun — Yoruba Art and Language (2014) : les orishas comme forces vitales"]},"en":{"title":"Oshun, the sweet water","entry":"In Yoruba cosmology from Nigeria, Oshun is the orisha of rivers, love, fertility, sweetness and transformation.","body":["She is represented in yellow and gold, dancing in water. She heals, seduces, protects women and children.","Oshun is also the guardian of fresh waters — without her, there is no life. During a terrible drought, the other orishas could do nothing. Oshun descended and prayed. The rain returned.","Move like fresh water — fluid, finding your way, going around obstacles, nourishing.","Without sweetness, what does strength become?"],"retour":"What can sweetness do that strength cannot?","sources":["Yoruba cosmology (Nigeria, Benin, diaspora) — Oshun, orisha of rivers and sweetness","Abiodun R. — Yoruba Art and Language (2014): the orishas as vital forces"]}},{"id":"my-araignee","deck":"mythologies","type":"figure","fr":{"title":"Anansi l'araignée","entry":"Dans les traditions akan du Ghana, Anansi est l'araignée créatrice des histoires. Elle a obtenu toutes les histoires du monde d'Asase Ya, la déesse de la Terre.","body":["Tend les bras devant toi. Commence à tisser dans l'air — lentement, un fil imaginaire entre tes mains, puis tes bras, puis tout ton corps.","Une toile n'est pas construite d'un coup. C'est un aller-retour patient, une attention à la tension de chaque fil. Laisse ton mouvement avoir cette qualité.","Maintenant : quelque chose se prend dans ta toile. Qu'est-ce que ton mouvement a capturé — une émotion, une idée, une histoire ?","Anansi tisse les histoires du monde. Ce que tu viens de tisser — c'est une histoire. Dis-la en un mot ou un geste."],"retour":"Quelle histoire ton corps vient-il de tisser ?","sources":["Traditions akan (Ghana, Côte d'Ivoire) et afro-caribéennes — Anansi comme tisseuse d'histoires","Chinua Achebe — Things Fall Apart (1958) : la tradition orale africaine comme savoir politique"]},"en":{"title":"Anansi the spider","entry":"In Akan traditions from Ghana, Anansi is the spider who created stories. She obtained all the world's stories from Asase Ya, the Earth goddess.","body":["Extend your arms in front of you. Begin to weave in the air — slowly, an imaginary thread between your hands, then arms, then your whole body.","A web is not built at once. It is a patient back-and-forth, an attention to the tension of each thread. Let your movement have this quality.","Now: something catches in your web. What has your movement captured — an emotion, an idea, a story?","Anansi weaves the world's stories. What you just wove — that's a story. Say it in one word or one gesture."],"retour":"What story did your body just weave?","sources":["Akan traditions (Ghana, Côte d'Ivoire) and Afro-Caribbean — Anansi as story-weaver","Chinua Achebe — Things Fall Apart (1958): African oral tradition as political knowledge"]}},{"id":"my-izanami","deck":"mythologies","type":"figure","fr":{"title":"Izanami et la mort comme création","entry":"Dans la cosmologie shinto japonaise, Izanami crée les îles du Japon avec son époux Izanagi. Elle meurt en donnant naissance au feu.","body":["Izanagi descend aux Enfers pour la ramener. Il promet de ne pas la regarder. Il regarde — et fuit horrifié.","Izanami, en colère, jure de tuer mille humains par jour. Izanagi répond qu'il en fera naître mille cinq cents.","La mort et la naissance sont inséparables. Izanami est la mère de tout ce qui vit et de tout ce qui meurt.","Sens dans ton corps l'endroit où la fin d'une chose crée l'espace pour une autre."],"retour":"Qu'est-ce qui doit mourir en toi pour que quelque chose d'autre puisse naître ?","sources":["Kojiki (712 apr. J.-C.) — premier récit de la mythologie japonaise, Izanami et Izanagi","William George Aston — Nihongi (1896) : traduction et commentaire des mythes fondateurs japonais"]},"en":{"title":"Izanami and death as creation","entry":"In Japanese Shinto cosmology, Izanami creates the islands of Japan with her husband Izanagi. She dies giving birth to fire.","body":["Izanagi descends to the Underworld to bring her back. He promises not to look at her. He looks — and flees in horror.","Izanami, angry, swears to kill a thousand humans per day. Izanagi replies that he will cause fifteen hundred to be born.","Death and birth are inseparable. Izanami is the mother of everything that lives and everything that dies.","Feel in your body the place where the end of one thing creates space for another."],"retour":"What must die in you for something else to be born?","sources":["Kojiki (712 CE) — first account of Japanese mythology, Izanami and Izanagi","William George Aston — Nihongi (1896): translation and commentary on Japanese founding myths"]}},{"id":"my-inuit-sedna","deck":"mythologies","type":"figure","fr":{"title":"Sedna et les profondeurs","entry":"Dans les mythologies inuit, Sedna est jetée à la mer. Ses doigts, coupés, deviennent les animaux marins — phoques, morses, baleines.","body":["Sedna est maintenant la maîtresse de la mer et des animaux marins. Les chamans descendent vers elle pour démêler ses cheveux embroussaillés par les pêcheurs irrespectueux.","Si ses cheveux sont emmêlés, les animaux se cachent et les humains ont faim. Si les chamans prennent soin d'elle, les animaux reviennent.","La blessure originelle — les doigts coupés — est la source de la vie marine. Ce qui est brisé peut devenir fécond.","Bouge depuis un endroit blessé dans ton corps — pas pour le nier, pour voir ce qui en provient."],"retour":"Qu'est-ce que ta propre blessure a engendré que tu n'avais pas prévu ?","sources":["Mythologie inuit (Arctique canadien et groenlandais) — Sedna comme maîtresse des profondeurs marines","Frédéric Laugrand & Jarich Oosterhout — The World of Inuit Religion (2010) : le chamanisme inuit et la relation aux profondeurs"]},"en":{"title":"Sedna and the depths","entry":"In Inuit mythologies, Sedna is thrown into the sea. Her cut fingers become sea animals — seals, walruses, whales.","body":["Sedna is now mistress of the sea and sea animals. Shamans descend to her to untangle her hair, matted by disrespectful fishermen.","If her hair is tangled, the animals hide and humans go hungry. If shamans care for her, the animals return.","The original wound — the cut fingers — is the source of marine life. What is broken can become fertile.","Move from a wounded place in your body — not to deny it, but to see what comes from it."],"retour":"What has your own wound generated that you hadn't foreseen?","sources":["Inuit mythology (Canadian and Greenlandic Arctic) — Sedna as mistress of the marine depths","Laugrand F. & Jarich Oosterhout — The World of Inuit Religion (2010): Inuit shamanism and relation to the depths"]}},{"id":"my-offrande","deck":"mythologies","type":"invitation","fr":{"title":"L'offrande","entry":"Dans presque toutes les traditions humaines, on offre quelque chose à ce qui nous donne la vie — un geste de réciprocité avec le monde.","body":["Trouve quelque chose dans ce lieu qui te donne quelque chose — un arbre, la lumière, l'air, un son.","Tiens-toi face à cet être ou cet espace. Laisse entrer la sensation de recevoir — vraiment recevoir — ce qu'il t'offre.","Maintenant : offre quelque chose en retour. Pas un objet nécessairement. Un geste, un son, une attention, un mouvement de ton corps vers lui.","Laisse ce geste venir de lui-même. Pas ce que tu crois devoir faire — ce qui monte spontanément."],"retour":"Qu'est-ce qui a bougé en toi quand tu as offert quelque chose sans savoir si c'était 'correct' ?","sources":["Robin Wall Kimmerer — Braiding Sweetgrass (2013) : la Cérémonie du Monde comme acte quotidien de réciprocité","Traditions Arhuaco, Kogi, yoruba, andine, shinto : l'offrande comme relation, pas comme transaction"]},"en":{"title":"The offering","entry":"In almost all human traditions, something is offered to what gives us life — a gesture of reciprocity with the world.","body":["Find something in this place that gives you something — a tree, the light, the air, a sound.","Stand facing this being or space. Let in the sensation of receiving — truly receiving — what it offers you.","Now: offer something in return. Not necessarily an object. A gesture, a sound, an attention, a movement of your body toward it.","Let this gesture come by itself. Not what you think you should do — what rises spontaneously."],"retour":"What moved in you when you offered something without knowing if it was 'correct'?","sources":["Kimmerer R.W. — Braiding Sweetgrass (2013): the Ceremony of the World as daily act of reciprocity","Arhuaco, Kogi, Yoruba, Andean, Shinto traditions: the offering as relation, not transaction"]}},{"id":"my-ancetres","deck":"mythologies","type":"invitation","fr":{"title":"Les ancêtres qui sont là","entry":"Dans de nombreuses traditions, les ancêtres ne sont pas partis. Ils sont présents dans les plantes, les pierres, les rivières, les corps.","body":["Debout. Sens le poids de ton corps — ce poids est aussi celui de tout ce qui t'a précédé.","Commence à te mouvoir très lentement — comme si tu portais des gens invisibles derrière toi, sur tes épaules, dans tes mains.","Laisse ce poids orienter ton mouvement — pas l'alléger, l'habiter. Quelles directions te tirent ? Quelle lenteur t'est demandée ?","Puis : laisse une qualité de mouvement qui ne t'appartient pas entrer dans ton corps. Une façon de tenir les bras, de poser les pieds, que tu n'inventes pas."],"retour":"Qu'est-ce que ton corps a porté que tu ne savais pas qu'il portait ?","sources":["Traditions māori — whakapapa comme généalogie reliant humains, nature et cosmos","John Mbiti — African Religions and Philosophy (1969) : les ancêtres dans les traditions africaines comme force active"]},"en":{"title":"The ancestors who are here","entry":"In many traditions, ancestors have not gone. They are present in plants, stones, rivers, bodies.","body":["Standing. Feel the weight of your body — this weight is also that of everything that preceded you.","Begin to move very slowly — as if carrying invisible people behind you, on your shoulders, in your hands.","Let this weight orient your movement — not lighten it, inhabit it. What directions pull you? What slowness is asked of you?","Then: let a quality of movement that doesn't belong to you enter your body. A way of holding the arms, setting the feet, that you don't invent."],"retour":"What did your body carry that you didn't know it was carrying?","sources":["Māori traditions — whakapapa as genealogy linking humans, nature and cosmos","Mbiti J.S. — African Religions and Philosophy (1969): ancestors in African traditions as active force"]}},{"id":"my-corps-etoiles","deck":"mythologies","type":"invitation","fr":{"title":"Le corps et les étoiles","entry":"Dans de nombreuses cosmologies, les étoiles sont des ancêtres, des êtres, des forces. Le ciel n'est pas vide — il est peuplé.","body":["Allonge-toi si possible, ou debout les yeux fermés. Sens le poids de ton corps — la gravité qui te relie à la Terre.","Maintenant : laisse entrer l'idée inverse. Tu n'es pas seulement tiré vers le bas — tu rayonnes aussi vers le haut. Tu émets.","Commence à te mouvoir comme quelque chose qui irradie. Lentement. Pas des bras qui s'étendent — une lumière qui se diffuse depuis l'intérieur.","Les étoiles mortes dont tu es fait·e ont rayonné pendant des milliards d'années. Ce mouvement est une forme de mémoire de ça."],"retour":"Quelle différence entre te mouvoir comme un corps pesant et te mouvoir comme quelque chose qui émet ?","sources":["Traditions dogon (Mali) — connaissance de Sirius B et astronomie ancestrale","Ray Norris & Duane Hamacher — The Astronomy of Aboriginal Australians (2009) : 65 000 ans d'observation du ciel"]},"en":{"title":"The body and the stars","entry":"In many cosmologies, stars are ancestors, beings, forces. The sky is not empty — it is peopled.","body":["Lie down if possible, or standing with eyes closed. Feel the weight of your body — gravity linking you to the Earth.","Now: let in the opposite idea. You are not only pulled downward — you also radiate upward. You emit.","Begin to move like something that irradiates. Slowly. Not arms extending — a light diffusing from inside.","The dead stars you are made of radiated for billions of years. This movement is a form of memory of that."],"retour":"What is the difference between moving as a heavy body and moving as something that emits?","sources":["Dogon traditions (Mali) — knowledge of Sirius B and ancestral astronomy","Norris R.P. & Duane Hamacher — The Astronomy of Aboriginal Australians (2009): 65,000 years of sky observation"]}},{"id":"my-ceremonie","deck":"mythologies","type":"invitation","fr":{"title":"La cérémonie du monde","entry":"Robin Wall Kimmerer, botaniste de la nation Potawatomi, a transmis cette pratique : les Potawatomi ont une cérémonie quotidienne d'action de grâces. Chaque être du monde est nommé et remercié.","body":["Debout. Tourne-toi lentement vers chaque direction — nord, est, sud, ouest. Avant de te tourner, pose la main sur ton cœur.","À chaque direction, nomme à voix haute un être qui vit là — une plante, un animal, un élément, un vent. Pas ce que tu inventes : ce qui vient.","Reviens au centre. Les quatre directions sont maintenant présentes autour de toi.","Fais un geste de remerciement — pas un geste appris, un geste que ton corps invente maintenant pour remercier ce qui t'entoure."],"retour":"Qu'est-ce que ce tour d'horizon a changé dans ta façon d'être dans ce lieu ?","sources":["Robin Wall Kimmerer — Braiding Sweetgrass (2013) : 'Allegiance to Gratitude', la cérémonie comme pratique quotidienne","Tradition haudenosaunee — Thanksgiving Address, Ohén:ton Karihwatéhkwen : paroles qui précèdent toute réunion"]},"en":{"title":"The ceremony of the world","entry":"Kimmerer says: the Potawatomi have a daily ceremony of thanksgiving. Every being in the world is named and thanked.","body":["Standing. Turn slowly toward each direction — north, east, south, west. Before turning, place your hand on your heart.","At each direction, name aloud a being that lives there — a plant, an animal, an element, a wind. Not what you invent: what comes.","Return to centre. The four directions are now present around you.","Make a gesture of thanks — not a learned gesture, one your body invents right now to thank what surrounds you."],"retour":"What did this turn of horizon change in how you are in this place?","sources":["Kimmerer R.W. — Braiding Sweetgrass (2013): 'Allegiance to Gratitude', ceremony as daily practice","Haudenosaunee tradition — Thanksgiving Address, Ohén:ton Karihwatéhkwen: words that precede every gathering"]}},{"id":"my-feu-prométhée","deck":"mythologies","type":"invitation","fr":{"title":"Prométhée et le feu volé","entry":"Prométhée vole le feu aux dieux pour le donner aux humains. Il est condamné à avoir le foie dévoré chaque jour par un aigle — et il repousse chaque nuit.","body":["Le feu n'appartient pas aux humains — il a été pris. Et ce vol a un prix.","Le mythe dit : chaque capacité humaine d'agir sur le monde vient avec une responsabilité et une souffrance.","Sens dans ton corps quelque chose qui brûle — une passion, une colère, une créativité.","Ce feu — de qui l'as-tu reçu ? À qui appartient-il ? Quel est son prix ?"],"retour":"Qu'est-ce que tu as reçu — ou pris — qui vient avec une responsabilité que tu n'as pas encore complètement honorée ?","sources":["Hésiode — Théogonie et Les Travaux et les Jours (VIIe s. av. J.-C.) : Prométhée et le don du feu","Val Plumwood — Fire and the Death of Prometheus (2002) : le feu prométhéen comme métaphore de la modernité extractive"]},"en":{"title":"Prometheus and the stolen fire","entry":"Prometheus steals fire from the gods to give to humans. He is condemned to have his liver devoured each day by an eagle — and it regrows each night.","body":["Fire doesn't belong to humans — it was taken. And this theft has a price.","The myth says: every human capacity to act on the world comes with responsibility and suffering.","Feel in your body something that burns — a passion, an anger, a creativity.","This fire — from whom did you receive it? Who does it belong to? What is its price?"],"retour":"What have you received — or taken — that comes with a responsibility you haven't fully honoured yet?","sources":["Hesiod — Theogony and Works and Days (7th c. BCE): Prometheus and the gift of fire","Plumwood V. — Fire and the Death of Prometheus (2002): Promethean fire as metaphor for extractive modernity"]}},{"id":"my-inanna","deck":"mythologies","type":"figure","fr":{"title":"Inanna aux Enfers","entry":"Inanna, déesse sumérienne du ciel et de la guerre, descend aux Enfers voir sa sœur Ereshkigal. À chaque porte, elle doit déposer un ornement.","body":["Sept portes. À chaque porte, elle perd quelque chose — couronne, collier, robe, sandales. Elle arrive nue devant sa sœur.","Ereshkigal la tue. Pendant trois jours, rien ne pousse, rien n'est fertilisé. Puis Inanna remonte — transformée.","La descente est nécessaire. Ce qu'on perd à chaque porte n'est pas perdu — c'est déposé pour être retrouvé autrement.","Bouge comme si tu déposais quelque chose à chaque pas. Qu'est-ce qui se dépose ? Qu'est-ce qui reste ?"],"retour":"Qu'est-ce que tu as perdu dans une descente qui t'a paradoxalement rendu·e plus libre ?","sources":["Mythologie sumérienne (Mésopotamie, ~2000 av. J.-C.) — La Descente d'Inanna aux Enfers","Diane Wolkstein & Samuel Noah Kramer — Inanna, Queen of Heaven and Earth (1983) : traduction et commentaire"]},"en":{"title":"Inanna in the Underworld","entry":"Inanna, Sumerian goddess of sky and war, descends to the Underworld to visit her sister Ereshkigal. At each gate, she must deposit an ornament.","body":["Seven gates. At each gate, she loses something — crown, necklace, robe, sandals. She arrives naked before her sister.","Ereshkigal kills her. For three days, nothing grows, nothing is fertilised. Then Inanna rises — transformed.","The descent is necessary. What is lost at each gate is not lost — it is deposited to be found differently.","Move as if you were depositing something at each step. What is being deposited? What remains?"],"retour":"What have you lost in a descent that paradoxically made you freer?","sources":["Sumerian mythology (Mesopotamia, ~2000 BCE) — The Descent of Inanna to the Underworld","Wolkstein D. & Samuel Noah Kramer — Inanna, Queen of Heaven and Earth (1983): translation and commentary"]}},{"id":"my-mais-chair","deck":"mythologies","type":"cosmogonie","fr":{"title":"Le corps de maïs","entry":"Dans le Popol Vuh maya k'iche', les dieux ont essayé de créer les humains avec de la boue, puis avec du bois. Rien ne marchait. Puis ils ont broyé du maïs blanc et jaune — et de cette pâte, ils ont façonné les premiers humains.","body":["Pose une main sur ton ventre. Sens le poids de ce qui est là — des années de nourriture, d'eau, d'air transformés en toi.","Commence à te mouvoir comme une plante qui pousse — depuis le sol, lentement, une verticalité qui n'est pas rigidité mais poussée.","Les humains de maïs du Popol Vuh voyaient tout, jusqu'aux quatre coins du ciel. Les dieux ont brouillé leur vue. Ferme les yeux. Qu'est-ce que tu perçois mieux dans le noir ?","Ouvre les yeux. Bouge depuis cette perception — pas la vision qui domine, mais tout ce que le corps sait sans voir."],"retour":"Qu'est-ce que ton corps sait de ce lieu que tes yeux ne savent pas ?","sources":["Popol Vuh — livre sacré k'iche' maya (compilé au XVIe siècle, traditions orales bien antérieures)","Dennis Tedlock — Popol Vuh: The Mayan Book of the Dawn of Life (1985) : traduction et commentaire"]},"en":{"title":"The body of maize","entry":"In the Maya K'iche' Popol Vuh, the gods tried to create humans from mud, then from wood. Nothing worked. Then they ground white and yellow maize — and from this dough, they shaped the first humans.","body":["Place a hand on your belly. Feel the weight of what is there — years of food, water, air transformed into you.","Begin to move like a growing plant — from the ground, slowly, a verticality that is not rigidity but thrust.","The maize humans of the Popol Vuh saw everything, to the four corners of the sky. The gods clouded their sight. Close your eyes. What do you perceive better in the dark?","Open your eyes. Move from this perception — not the dominating vision, but everything the body knows without seeing."],"retour":"What does your body know of this place that your eyes don't know?","sources":["Popol Vuh — sacred K'iche' Maya book (compiled 16th century, oral traditions much older)","Tedlock D. — Popol Vuh: The Mayan Book of the Dawn of Life (1985): translation and commentary"]}},{"id":"my-tiamat-monde","deck":"mythologies","type":"cosmogonie","fr":{"title":"Tiamat et la création par violence","entry":"Dans l'Enuma Elish babylonien (~1250 av. J.-C.), le dieu Marduk tue la déesse primordiale Tiamat — les eaux salées, le chaos — et façonne le monde depuis son corps démembré.","body":["La moitié supérieure de Tiamat devient le ciel. La moitié inférieure, la terre. Ses yeux, le Tigre et l'Euphrate.","C'est le mythe fondateur de nombreuses civilisations : le monde est créé par la victoire de l'ordre sur le chaos, du masculin sur le féminin, du sec sur l'humide.","Val Plumwood, philosophe écoféministe australienne, a retracé comment ce mythe a traversé les siècles pour justifier la domination de la 'raison' sur la 'nature'.","Sens dans ton corps la différence entre construire quelque chose avec ce qui était déjà là, et construire quelque chose en détruisant ce qui était là."],"retour":"Quelles 'Tiamat' la civilisation actuelle continue-t-elle de démembrer pour exister ?","sources":["Enuma Elish — épopée babylonienne de création (~1250 av. J.-C.), tablettes cunéiformes retrouvées à Ninive","Val Plumwood — Feminism and the Mastery of Nature (1993) : la création par violence comme modèle fondateur de la domination"]},"en":{"title":"Tiamat and creation through violence","entry":"In the Babylonian Enuma Elish (~1250 BCE), the god Marduk kills the primordial goddess Tiamat — the salt waters, chaos — and shapes the world from her dismembered body.","body":["Tiamat's upper half becomes the sky. The lower half, the earth. Her eyes, the Tigris and Euphrates.","This is the founding myth of many civilisations: the world is created by victory of order over chaos, masculine over feminine, dry over wet.","Plumwood shows this myth has travelled through centuries to justify the domination of 'reason' over 'nature'.","Feel in your body the difference between building something with what was already there, and building something by destroying what was there."],"retour":"What 'Tiamats' does current civilisation continue to dismember in order to exist?","sources":["Enuma Elish — Babylonian creation epic (~1250 BCE), cuneiform tablets found at Nineveh","Plumwood V. — Feminism and the Mastery of Nature (1993): creation through violence as founding model of domination"]}},{"id":"my-purusha-sacifice","deck":"mythologies","type":"cosmogonie","fr":{"title":"Purusha, le sacrifice cosmique","entry":"Dans le Rig Veda (hymne 10.90, ~1200 av. J.-C.), l'être cosmique Purusha — mille têtes, mille yeux, mille pieds — est sacrifié par les dieux. De son corps naît l'univers entier.","body":["Allonge-toi si possible. Sens chaque partie de ton corps en contact avec le sol — ta nuque, tes épaules, ton dos, tes hanches, tes mollets, tes talons.","Laisse chaque partie devenir quelque chose du cosmos : tes pieds dans la terre, tes hanches dans l'eau, ta poitrine dans l'air, ta tête dans le feu ou le ciel.","Commence à te relever très lentement — comme si le cosmos se rassemblait en un seul point. Quand tu es debout : tu es l'univers entier tenu dans une forme.","Reste immobile un moment. Sens la densité de ça."],"retour":"Qu'est-ce que ça change de se sentir résumé du cosmos plutôt que fragment du monde ?","sources":["Rig Veda, hymne 10.90 — Purusha Sukta (~1200 av. J.-C.) : le sacrifice cosmique","Wendy Doniger — The Hindus: An Alternative History (2009) : le Purusha Sukta comme fondation de la cosmologie védique"]},"en":{"title":"Purusha, the cosmic sacrifice","entry":"In the Rig Veda (hymn 10.90, ~1200 BCE), the cosmic being Purusha — thousand heads, thousand eyes, thousand feet — is sacrificed by the gods. From his body the entire universe is born.","body":["Lie down if possible. Feel each part of your body in contact with the ground — nape, shoulders, back, hips, calves, heels.","Let each part become something of the cosmos: your feet in earth, your hips in water, your chest in air, your head in fire or sky.","Begin to rise very slowly — as if the cosmos is gathering into a single point. When standing: you are the entire universe held in one form.","Stay still for a moment. Feel the density of that."],"retour":"What changes when you feel yourself as a summary of the cosmos rather than a fragment of the world?","sources":["Rig Veda, hymn 10.90 — Purusha Sukta (~1200 BCE): the cosmic sacrifice","Doniger W. — The Hindus: An Alternative History (2009): the Purusha Sukta as foundation of Vedic cosmology"]}},{"id":"my-nommo-spirale","deck":"mythologies","type":"cosmogonie","fr":{"title":"Nommo et l'Oeuf du monde","entry":"Dans la cosmologie dogon (Mali), le dieu créateur Amma crée l'Œuf du monde — qui contient toutes les paires de jumeaux primordiales. L'un des jumeaux s'en échappe trop tôt.","body":["Ogo — le Renard Pâle — sort prématurément, volant un morceau de sa placenta. C'est de là que vient le désordre du monde.","Pour restaurer l'ordre, Amma sacrifie un autre Nommo. Son corps démembré est dispersé dans l'univers — et partout où tombe un morceau, naît un sanctuaire.","Les Dogon connaissent Sirius B — invisible à l'œil nu — depuis des siècles avant les télescopes. Les Nommo en viendraient.","Bouge en spirale, lentement. La spirale est la forme fondamentale de la création dans la cosmologie dogon — et dans la structure de l'ADN."],"retour":"Quelle partie de toi est sortie 'trop tôt' et crée du désordre ? Quel sanctuaire a-t-elle créé malgré tout ?","sources":["Marcel Griaule & Germaine Dieterlen — Le Renard pâle (1965) : cosmologie dogon du Mali","Marcel Griaule — Dieu d'eau (1948) : entretiens avec Ogotemmêli sur la cosmologie dogon"]},"en":{"title":"Nommo and the World Egg","entry":"In Dogon cosmology (Mali), the creator god Amma creates the World Egg — containing all primordial twin pairs. One of the twins escapes too early.","body":["Ogo — the Pale Fox — exits prematurely, stealing a piece of his placenta. From this comes the world's disorder.","To restore order, Amma sacrifices another Nommo. His dismembered body is scattered across the universe — and wherever a piece falls, a shrine is born.","The Dogon have known Sirius B — invisible to the naked eye — for centuries before telescopes. The Nommo are said to come from there.","Move in a spiral, slowly. The spiral is the fundamental form of creation in Dogon cosmology — and in the structure of DNA."],"retour":"What part of you emerged 'too early' and creates disorder? What shrine did it create anyway?","sources":["Griaule M. & Germaine Dieterlen — Le Renard pâle (1965): Dogon cosmology of Mali","Griaule M. — Dieu d'eau (1948): conversations with Ogotemmêli on Dogon cosmology"]}},{"id":"my-pangu-corps","deck":"mythologies","type":"cosmogonie","fr":{"title":"Pangu et le corps du monde","entry":"Dans la cosmologie chinoise ancienne, Pangu nait dans l'Œuf primordial du chaos. Il le sépare en deux — le yang léger monte vers le ciel, le yin dense descend vers la terre.","body":["Pangu grandit pendant dix-huit mille ans, maintenant ciel et terre écartés de ses bras. Quand il meurt, son corps devient le monde.","Ses yeux : le soleil et la lune. Son souffle : le vent et les nuages. Sa voix : le tonnerre. Sa chair : la terre. Ses os : les rochers. Son sang : les rivières. Ses cheveux : les étoiles.","Ce mythe dit : le monde n'a pas été fabriqué. Il est né. Il est un corps.","Allonge-toi. Imagine que chaque partie de ton corps est une partie du paysage. Tes os sont les rochers. Ton sang est les rivières. Ta respiration est le vent."],"retour":"Si tu étais le monde — pas dans le monde, mais le monde — que ressentirais-tu en ce moment ?","sources":["Mythologie chinoise ancienne — Pangu et la création du monde (tradition Sanwu Liji, IIIe-IVe s.)","Anthony Christie — Chinese Mythology (1983) : Pangu et les cosmogonies chinoises"]},"en":{"title":"Pangu and the world's body","entry":"In ancient Chinese cosmology, Pangu is born in the primordial Egg of chaos. He separates it in two — the light yang rises toward the sky, the dense yin descends toward the earth.","body":["Pangu grows for eighteen thousand years, holding sky and earth apart with his arms. When he dies, his body becomes the world.","His eyes: the sun and moon. His breath: wind and clouds. His voice: thunder. His flesh: the earth. His bones: the rocks. His blood: the rivers. His hair: the stars.","This myth says: the world was not made. It was born. It is a body.","Lie down. Imagine that each part of your body is a part of the landscape. Your bones are the rocks. Your blood is the rivers. Your breathing is the wind."],"retour":"If you were the world — not in the world, but the world — what would you feel right now?","sources":["Ancient Chinese mythology — Pangu and the creation of the world (Sanwu Liji tradition, 3rd-4th c.)","Christie A. — Chinese Mythology (1983): Pangu and Chinese cosmogonies"]}},{"id":"my-yggdrasil","deck":"mythologies","type":"figure","fr":{"title":"Yggdrasil, l'arbre du monde","entry":"Dans la cosmologie nordique, Yggdrasil est un frêne immense qui relie les neuf mondes. Ses racines plongent dans trois puits — le puits de la sagesse, le puits du destin, et le puits du chaos originel.","body":["Un aigle dans les hauteurs. Un serpent dans les racines. Un écureuil entre les deux, portant des messages — et des insultes.","Odin se pend à Yggdrasil pendant neuf jours pour obtenir les runes — la connaissance comme arrachée à soi-même au bord de la mort.","L'arbre ne relie pas les mondes comme un pont. Il est les mondes — chaque branche est une réalité, chaque racine une profondeur.","Trouve un arbre. Touche son écorce. Imagine ses racines dans l'obscurité, ses branches dans la lumière. Sens que tu es debout entre ces deux réalités."],"retour":"Entre quelle profondeur et quelle hauteur te tiens-tu en ce moment ?","sources":["Edda de Snorri Sturluson (~1220) : Yggdrasil et la cosmologie nordique","Kevin Crossley-Holland — The Norse Myths (1980) : traduction et commentaire des mythes scandinaves"]},"en":{"title":"Yggdrasil, the world tree","entry":"In Nordic cosmology, Yggdrasil is an immense ash tree linking the nine worlds. Its roots plunge into three wells — the well of wisdom, the well of fate, and the well of primal chaos.","body":["An eagle in the heights. A serpent in the roots. A squirrel between the two, carrying messages — and insults.","Odin hangs himself from Yggdrasil for nine days to obtain the runes — knowledge wrenched from oneself at the edge of death.","The tree does not connect the worlds like a bridge. It is the worlds — each branch a reality, each root a depth.","Find a tree. Touch its bark. Imagine its roots in the darkness, its branches in the light. Feel yourself standing between these two realities."],"retour":"Between what depth and what height are you standing right now?","sources":["Snorri Sturluson's Edda (~1220): Yggdrasil and Nordic cosmology","Crossley-Holland K. — The Norse Myths (1980): translation and commentary on Scandinavian myths"]}},{"id":"my-ubuntu","deck":"mythologies","type":"invitation","fr":{"title":"Ubuntu — je suis parce que nous sommes","entry":"Ubuntu est une philosophie bantu d'Afrique australe et centrale : 'Umuntu ngumuntu ngabantu' — une personne est une personne à travers d'autres personnes.","body":["En groupe : chacun·e debout, les bras légèrement écartés du corps. Sens ta propre présence dans l'espace — ton poids, ta chaleur, ton souffle.","Maintenant : sens les autres dans l'espace sans les regarder. Leur chaleur, leur mouvement, leur respiration. Tu existes dans leur champ.","Commence à te mouvoir lentement. Pas pour rejoindre les autres — pour être davantage toi-même en sachant qu'ils sont là.","Ubuntu ne dit pas 'sacrifie-toi pour le groupe'. Il dit : 'tu n'es pleinement toi-même qu'en relation'. Bouge depuis cette idée."],"retour":"Comment ta façon d'être toi-même change-t-elle quand tu sais que les autres t'existent ?","sources":["Philosophie ubuntu — tradition bantu d'Afrique australe et centrale","Desmond Tutu — No Future Without Forgiveness (1999) : ubuntu comme fondement de la réconciliation","John Mbiti — African Religions and Philosophy (1969) : 'Je suis parce que nous sommes'"]},"en":{"title":"Ubuntu — I am because we are","entry":"Ubuntu is a Bantu philosophy of Southern and Central Africa: 'Umuntu ngumuntu ngabantu' — a person is a person through other persons.","body":["In a group: everyone standing, arms slightly away from the body. Feel your own presence in the space — your weight, your warmth, your breath.","Now: feel the others in the space without looking at them. Their warmth, their movement, their breathing. You exist in their field.","Begin to move slowly. Not to join the others — to be more fully yourself knowing they are there.","Ubuntu doesn't say 'sacrifice yourself for the group'. It says: 'you are only fully yourself in relation'. Move from this idea."],"retour":"How does your way of being yourself change when you know the others exist you?","sources":["Ubuntu philosophy — Bantu tradition of Southern and Central Africa","Tutu D. — No Future Without Forgiveness (1999): ubuntu as foundation of reconciliation","Mbiti J.S. — African Religions and Philosophy (1969): 'I am because we are'"]}},{"id":"my-nuwa","deck":"mythologies","type":"figure","fr":{"title":"Nüwa et la réparation du ciel","entry":"Dans la mythologie chinoise, Nüwa crée les humains en modelant de la boue jaune. Puis le ciel se brise. Elle le répare avec des pierres de cinq couleurs.","body":["Elle fait les premiers humains rapidement, à la main, modelant chaque corps. Mais comme c'est long, elle plonge une corde dans la boue et la secoue — les gouttes qui tombent deviennent le peuple ordinaire.","Quand le pilier du ciel se brise et que la catastrophe menace, Nüwa fond des pierres colorées pour boucher les fissures du ciel.","Elle ne crée pas un monde parfait. Elle répare un monde abîmé — avec des matériaux hétéroclites.","Sens dans ton corps quelque chose qui a été réparé avec des 'pierres de cinq couleurs' — imparfaitement, mais solidement."],"retour":"Quelle réparation imparfaite dans ta vie est plus solide que la perfection d'origine ?","sources":["Mythologie chinoise — Nüwa (Nü Kua), créatrice des humains et réparatrice du ciel","Anne Birrell — Chinese Mythology: An Introduction (1993) : Nüwa et les mythes de création chinois"]},"en":{"title":"Nüwa and the repair of the sky","entry":"In Chinese mythology, Nüwa creates humans by modelling yellow mud. Then the sky breaks. She repairs it with stones of five colours.","body":["She makes the first humans slowly, by hand, shaping each body. But as it takes so long, she dips a cord in mud and shakes it — the falling drops become ordinary people.","When the pillar of the sky breaks and catastrophe threatens, Nüwa melts coloured stones to seal the sky's cracks.","She doesn't create a perfect world. She repairs a damaged world — with mismatched materials.","Feel in your body something that was repaired with 'five-colour stones' — imperfectly, but solidly."],"retour":"What imperfect repair in your life is more solid than the original perfection?","sources":["Chinese mythology — Nüwa (Nü Kua), creator of humans and repairer of the sky","Birrell A. — Chinese Mythology: An Introduction (1993): Nüwa and Chinese creation myths"]}},{"id":"my-maat","deck":"mythologies","type":"figure","fr":{"title":"Maât et la plume","entry":"Dans la cosmologie égyptienne ancienne, Maât est la déesse de l'ordre cosmique, de la vérité, de la justice et de l'harmonie. Après la mort, ton cœur est pesé contre sa plume.","body":["Si ton cœur est plus lourd que la plume — alourdi par les injustices commises — Ammit le dévore et tu n'existes plus.","Si ton cœur est aussi léger que la plume — tu peux continuer.","Maât n'est pas une déesse de la punition. Elle est la structure même du cosmos : les saisons, les crues du Nil, l'alternance du jour et de la nuit.","Pose une main sur ton cœur. Imagine la pesée. Qu'est-ce qui alourdit ton cœur en ce moment ? Qu'est-ce qui le rend léger ?"],"retour":"Qu'est-ce que la légèreté du cœur signifie pour toi — comme pratique, pas comme état ?","sources":["Mythologie égyptienne ancienne — Maât, la pesée du cœur (Livre des Morts, ~1550 av. J.-C.)","Jan Assmann — Death and Salvation in Ancient Egypt (2005) : Maât comme ordre cosmique"]},"en":{"title":"Maat and the feather","entry":"In ancient Egyptian cosmology, Maat is the goddess of cosmic order, truth, justice and harmony. After death, your heart is weighed against her feather.","body":["If your heart is heavier than the feather — weighted down by injustices committed — Ammit devours it and you cease to exist.","If your heart is as light as the feather — you may continue.","Maat is not a goddess of punishment. She is the very structure of the cosmos: the seasons, the Nile's floods, the alternation of day and night.","Place a hand on your heart. Imagine the weighing. What weighs your heart down right now? What makes it light?"],"retour":"What does lightness of heart mean to you — as a practice, not a state?","sources":["Ancient Egyptian mythology — Maat, the weighing of the heart (Book of the Dead, ~1550 BCE)","Assmann J. — Death and Salvation in Ancient Egypt (2005): Maat as cosmic order"]}},{"id":"my-sibu-terre","deck":"mythologies","type":"cosmogonie","fr":{"title":"Sibö et le corps de la Terre","entry":"Pour les Bribri de Talamanca (Costa Rica et Panama), la Terre est le corps d'une déesse — Sibö l'a façonnée pour que les humains puissent y vivre.","body":["Les montagnes sont ses os. Les rivières son sang. La forêt son vêtement.","Extraire des minéraux, c'est briser ses os. Polluer les rivières, c'est empoisonner son sang.","Les gardiens Bribri du territoire Talamanca — inscrit au patrimoine mondial de l'UNESCO — maintiennent cette responsabilité depuis des générations.","Marche dans ce lieu comme si tu marchais sur le corps d'un être vivant. Pas métaphoriquement — littéralement. Chaque pas."],"retour":"Comment marcher sur un corps change-t-il la façon dont tu poses tes pieds ?","sources":["Tradition Bribri — cosmologie de Talamanca, Costa Rica (patrimoine UNESCO La Amistad)","Marcos Guevara Berger — Perfil de los Pueblos Indígenas de Costa Rica (2000) : cosmologie et territoire Bribri"]},"en":{"title":"Sibö and the body of the Earth","entry":"For the Bribri of Talamanca (Costa Rica and Panama), the Earth is the body of a goddess — Sibö fashioned it so that humans could live there.","body":["The mountains are her bones. The rivers her blood. The forest her clothing.","Extracting minerals is breaking her bones. Polluting rivers is poisoning her blood.","The Bribri guardians of the Talamanca territory — inscribed on UNESCO's World Heritage list — have maintained this responsibility for generations.","Walk through this place as if walking on the body of a living being. Not metaphorically — literally. Each step."],"retour":"How does walking on a body change the way you set your feet down?","sources":["Bribri tradition — Talamanca cosmology, Costa Rica (UNESCO La Amistad heritage site)","Marcos Guevara Berger — Perfil de los Pueblos Indígenas de Costa Rica (2000): Bribri cosmology and territory"]}},{"id":"my-gaia","deck":"mythologies","type":"figure","fr":{"title":"Gaïa — avant les dieux","entry":"Dans la Théogonie d'Hésiode, Gaïa — la Terre — émerge du Chaos, avant même Éros et les Olympiens. Elle est là en premier.","body":["Pose les deux mains à plat sur le sol. Sens sa température, sa texture, sa résistance. Ce sol existait avant ta naissance et existera après.","Commence à peser sur tes mains — lentement, comme si tu essayais de sentir le poids de tout ce qui est au-dessus de ce sol. Et ce qui est en dessous.","Lève-toi très lentement, en gardant ce contact imaginaire. En debout : tu es la surface de quelque chose d'immense.","Gaïa n'est pas 'dans' le temps. Elle est le temps. Bouge comme quelque chose qui n'a pas d'âge mais qui a une présence."],"retour":"Qu'est-ce que tu ressentais différemment en te levant depuis ce sol ?","sources":["Hésiode — Théogonie (~700 av. J.-C.) : Gaïa comme principe originel","James Lovelock & Lynn Margulis — Hypothèse Gaïa (1972) : la Terre comme système vivant autorégulé"]},"en":{"title":"Gaia — before the gods","entry":"In Hesiod's Theogony, Gaia — the Earth — emerges from Chaos, before even Eros and the Olympians. She is there first.","body":["Place both hands flat on the ground. Feel its temperature, texture, resistance. This ground existed before your birth and will exist after.","Begin to press on your hands — slowly, as if trying to feel the weight of everything above this ground. And what is below.","Rise very slowly, keeping this imaginary contact. Standing: you are the surface of something immense.","Gaia is not 'in' time. She is time. Move like something that has no age but has presence."],"retour":"What did you feel differently rising from this ground?","sources":["Hesiod — Theogony (~700 BCE): Gaia as originary principle","James Lovelock & Lynn Margulis — Gaia Hypothesis (1972): the Earth as self-regulating living system"]}},{"id":"my-kami","deck":"mythologies","type":"invitation","fr":{"title":"Kami — l'esprit dans les choses","entry":"Dans le shinto japonais, tout être — montagne, rivière, arbre, pierre, lieu — peut être habité par un kami, une présence, une force spirituelle.","body":["Marche dans cet espace sans destination. Laisse quelque chose t'arrêter — une pierre, un coin d'ombre, un bruit, une lumière particulière.","Quand quelque chose t'arrête : arrête-toi vraiment. Reste là, face à ce qui a capté ton attention.","Approche-toi lentement. Sans toucher encore — juste être dans le même espace, en présence.","Si l'envie vient : touche. Écoute avec ta peau ce que tu ne pouvais pas entendre de loin."],"retour":"Ce qui t'a arrêté·e — qu'est-ce qu'il avait que les autres choses n'avaient pas ?","sources":["Shinto japonais — kannagara, le chemin des kami, présences dans les lieux et les êtres","Stuart Picken — Essentials of Shinto (1994) : les kami comme présences dans le monde naturel"]},"en":{"title":"Kami — the spirit in things","entry":"In Japanese Shinto, every being — mountain, river, tree, stone, place — can be inhabited by a kami, a presence, a spiritual force.","body":["Walk in this space without destination. Let something stop you — a stone, a shadow, a sound, a particular light.","When something stops you: truly stop. Stay there, facing what caught your attention.","Approach slowly. Without touching yet — just being in the same space, in presence.","If the impulse comes: touch. Listen with your skin to what you couldn't hear from far away."],"retour":"What stopped you — what did it have that other things didn't?","sources":["Japanese Shinto — kannagara, the way of kami, presences in places and beings","Picken S.D.B. — Essentials of Shinto (1994): kami as presences in the natural world"]}},{"id":"my-vague","deck":"mythologies","type":"invitation","fr":{"title":"La vague","entry":"Dans presque toutes les traditions de danse rituelle, le mouvement suit une vague — naissance, développement, dissolution. Le corps connaît cette vague.","body":["Commence immobile. Sens ton poids, ton ancrage. Laisse quelque chose commencer à bouger depuis le bas — les pieds, les jambes, le bassin. Lentement. C'est le flux.","Laisse ce mouvement monter. Devenir plus précis, plus défini, plus directionnel. Ton corps sait où aller. C'est le staccato.","Maintenant : lâche la direction. Laisse le mouvement se dissoudre, se fragmenter, partir dans plusieurs sens à la fois. C'est le chaos — pas la violence, l'abandon.","Doucement : laisse quelque chose de léger émerger du chaos. Un mouvement simple, presque enfantin, presque drôle. Puis : l'immobilité. L'immobilité qui vibre encore."],"retour":"Quel moment de la vague est le plus difficile pour toi ? Lequel est le plus naturel ?","sources":["Gabrielle Roth — Maps to Ecstasy (1989) : les 5 rythmes comme pratique somatique et spirituelle","traditions chamaniques mondiales : la danse comme voyage entre les mondes"]},"en":{"title":"The wave","entry":"In almost all traditions of ritual dance, movement follows a wave — birth, development, dissolution. The body knows this wave.","body":["Begin still. Feel your weight, your grounding. Let something begin to move from below — feet, legs, pelvis. Slowly. This is flow.","Let this movement rise. Become more precise, more defined, more directional. Your body knows where to go. This is staccato.","Now: release the direction. Let the movement dissolve, fragment, go in several directions at once. This is chaos — not violence, abandon.","Gently: let something light emerge from the chaos. A simple movement, almost childlike, almost playful. Then: stillness. Stillness that still vibrates."],"retour":"Which moment of the wave is hardest for you? Which is most natural?","sources":["Roth G. — Maps to Ecstasy (1989): the 5 rhythms as somatic and spiritual practice","world shamanic traditions: dance as journey between worlds"]}},{"id":"my-danser-ancetre","deck":"mythologies","type":"invitation","fr":{"title":"Danser un ancêtre","entry":"Dans de nombreuses traditions africaines, afro-brésiliennes, caribéennes et asiatiques, les ancêtres et les esprits peuvent parler à travers le corps des vivants.","body":["Ce n'est pas de la possession — c'est un emprunt consentant. Tu invites une qualité, une présence, à traverser ton corps sans effacer qui tu es.","Pense à quelqu'un qui t'a précédé·e — un ancêtre biologique, intellectuel, ou spirituel. Quelqu'un dont tu portes quelque chose.","Commence à bouger depuis ce que tu sais de cette personne. Pas imiter — résonner. Comment cette qualité se tient-elle dans un corps ? Comment marche-t-elle ?","Puis laisse ta propre façon de bouger revenir doucement — enrichie de ce passage."],"retour":"Qu'est-ce qui reste dans ton corps après ce passage ?","sources":["Traditions candomblé, vodou, shinto — l'incarnation des ancêtres et esprits","John Mbiti — African Religions and Philosophy (1969) : les ancêtres comme forces actives dans le monde des vivants"]},"en":{"title":"Dancing an ancestor","entry":"In many African, Afro-Brazilian, Caribbean and Asian traditions, ancestors and spirits can speak through the bodies of the living.","body":["This is not possession — it is a consenting loan. You invite a quality, a presence, to pass through your body without erasing who you are.","Think of someone who preceded you — a biological, intellectual or spiritual ancestor. Someone whose quality you carry.","Begin to move from what you know of this person. Not imitate — resonate. How does this quality stand in a body? How does it walk?","Then let your own way of moving return gently — enriched by this passage."],"retour":"What remains in your body after this passage?","sources":["Candomblé, Vodou, Shinto traditions — the embodiment of ancestors and spirits","Mbiti J.S. — African Religions and Philosophy (1969): ancestors as active forces in the world of the living"]}},{"id":"my-seuil-danse","deck":"mythologies","type":"invitation","fr":{"title":"Danser le seuil","entry":"Les mythes du monde sont pleins de seuils — le passage vers les Enfers, la porte entre les mondes, le moment de l'initiation. Le seuil n'est pas une frontière. C'est un lieu.","body":["Trouve un seuil physique dans ce lieu — une porte, le bord d'un espace, la ligne entre ombre et lumière, l'orée d'un bois.","Tiens-toi sur ce seuil. Ni dedans ni dehors. Les deux à la fois.","Commence à bouger depuis cet entre-deux. Pas choisir un côté — habiter l'oscillation. Un pied de chaque côté, un mouvement qui revient.","Laisse le corps explorer ce que ça fait de ne pas décider encore — d'être en transit, en passage, entre deux états."],"retour":"Quel seuil dans ta vie ressemble à celui-ci ?","sources":["Arnold van Gennep — Les Rites de passage (1909) : le seuil comme espace de transformation","Victor Turner — The Ritual Process (1969) : la liminalité comme état créateur"]},"en":{"title":"Dancing the threshold","entry":"The world's myths are full of thresholds — the passage to the Underworld, the door between worlds, the moment of initiation. The threshold is not a boundary. It is a place.","body":["Find a physical threshold in this place — a doorway, the edge of a space, the line between shadow and light, the edge of a wood.","Stand on this threshold. Neither inside nor outside. Both at once.","Begin to move from this in-between. Not choosing a side — inhabiting the oscillation. One foot each side, a movement that returns.","Let the body explore what it feels like to not decide yet — to be in transit, in passage, between two states."],"retour":"What threshold in your life resembles this one?","sources":["Arnold van Gennep — Les Rites de passage (1909): the threshold as space of transformation","Turner V. — The Ritual Process (1969): liminality as creative state"]}},{"id":"my-conseil-etres","deck":"mythologies","type":"invitation","fr":{"title":"Le Conseil des êtres","entry":"Dans le Conseil de tous les Êtres de Joanna Macy, les humains parlent au nom d'autres formes de vie — une montagne, un insecte, une rivière, une espèce disparue.","body":["Ferme les yeux. Laisse venir un être — animal, plante, élément, espèce disparue — sans le choisir. Accueille ce qui se présente.","Commence à sentir comment cet être habite l'espace. Son poids, sa vitesse, sa relation au sol, à l'air. Laisse ton corps s'ajuster — imperceptiblement d'abord.","Depuis ce corps-là — pas en imitant, en résonant — qu'est-ce que cet être ressent de ce moment, de ce lieu, de la présence des humains ici ?","Dis-le. Une phrase. Depuis cet être. Pas 'je pense que cet être...' — directement, à la première personne de cet être."],"retour":"Qu'est-ce que tu ne pouvais pas dire en tant qu'humain que cet être a pu dire ?","sources":["Joanna Macy & John Seed — Conseil de tous les Êtres (1985) : rituel écologique pour parler depuis d'autres formes de vie","Joanna Macy — Coming Back to Life (2014) : pratiques pour retrouver notre lien au vivant"]},"en":{"title":"The Council of Beings","entry":"In Joanna Macy's Council of All Beings, humans speak on behalf of other life forms — a mountain, an insect, a river, an extinct species.","body":["Close your eyes. Let a being come — animal, plant, element, extinct species — without choosing it. Welcome what presents itself.","Begin to feel how this being inhabits space. Its weight, speed, relationship to ground, to air. Let your body adjust — imperceptibly at first.","From this body — not imitating, resonating — what does this being feel of this moment, this place, the presence of the humans here?","Say it. One sentence. From this being. Not 'I think this being...' — directly, in the first person of this being."],"retour":"What could you not say as a human that this being could say?","sources":["Macy J. & John Seed — Council of All Beings (1985): ecological ritual for speaking from other life forms","Macy J. — Coming Back to Life (2014): practices for restoring our connection to the living"]}}],"intros":{"vivant":{"fr":{"context":"Nous vivons dans des espaces qui nous séparent du non-humain — villes, écrans, intérieurs. Ce deck propose de traverser ce seuil par la sensation directe.","intention":"Créer des rencontres concrètes avec le vivant — un arbre, un insecte, le vent, la terre sous les pieds. Pas d'observation, pas d'analyse. Du contact.","pratique":"Dehors de préférence. Pas besoin de 'nature sauvage' — un jardin, un parc, une plante sur un trottoir suffisent. Solo ou en groupe silencieux. Durée : 5 à 20 min par carte."},"en":{"context":"We live in spaces that separate us from the non-human — cities, screens, interiors. This deck offers to cross that threshold through direct sensation.","intention":"Create concrete encounters with the living — a tree, an insect, wind, soil underfoot. Not observation, not analysis. Contact.","pratique":"Outdoors preferred. No need for 'wild nature' — a garden, a park, a plant on a pavement is enough. Solo or in silent group. Duration: 5 to 20 min per card."}},"terrains":{"fr":{"context":"Le corps sait des choses que le langage ne sait pas. Ce deck utilise le mouvement, le geste et l'écriture comme modes d'attention à un lieu.","intention":"Approfondir la relation à un espace par le jeu et l'exploration corporelle. Accessible à tou·tes — pas de pratique préalable.","pratique":"Dedans ou dehors selon les cartes. Certaines demandent de quoi écrire. Utilisable seul·e, en duo ou en petit groupe. Idéal comme porte d'entrée vers les decks plus exigeants."},"en":{"context":"The body knows things that language doesn't. This deck uses movement, gesture and writing as modes of attention to a place.","intention":"Deepen relationship to a space through play and bodily exploration. Accessible to everyone — no prior practice needed.","pratique":"Inside or outside depending on the card. Some require something to write with. Usable alone, in pairs or small groups. Ideal as entry point to more demanding decks."}},"traversees":{"fr":{"context":"Ces cartes sont des partitions pour le corps dans le vivant. Pas des exercices — des invitations à se laisser traverser par un verbe, une qualité, une contrainte.","intention":"Improviser seul·e ou à plusieurs dans un espace naturel. Révéler les qualités sensibles du lieu. Composer un score avec 1 à 4 cartes.","pratique":"Dehors de préférence. Commencer par piocher 1 verbe seul. Ajouter une qualité ou une contrainte pour complexifier. Public bienvenu — ces scores se présentent aussi devant des spectateurs."},"en":{"context":"These cards are scores for the body in the living world. Not exercises — invitations to let a verb, a quality, a constraint pass through you.","intention":"Improvise alone or together in a natural space. Reveal the sensory qualities of the place. Compose a score with 1 to 4 cards.","pratique":"Outdoors preferred. Start by drawing 1 solo verb. Add a quality or constraint to complexify. Audience welcome — these scores can also be performed before spectators."}},"choreo":{"fr":{"context":"Mycoscores / Choreospores est une œuvre de Maija Hirvanen, artiste chorégraphique finlandaise, publiée en 2024. Ces scores s'inspirent de la conscience fongique et du réseau mycélien.","intention":"Explorer le mouvement somatique depuis une logique non-humaine — spores, filaments, décomposition, propagation. Seul·e ou avec d'autres.","pratique":"Un espace pour bouger librement. Commencer par lire la carte entièrement avant de bouger. Laisser du temps — ces scores demandent de la lenteur. Recommandé : revenir à la même carte plusieurs fois."},"en":{"context":"Mycoscores / Choreospores is a work by Finnish choreographic artist Maija Hirvanen, published in 2024. These scores draw on fungal consciousness and mycelial networks.","intention":"Explore somatic movement from a non-human logic — spores, filaments, decomposition, propagation. Alone or with others.","pratique":"A space to move freely. Read the card entirely before moving. Allow time — these scores require slowness. Recommended: return to the same card multiple times."}},"milieux":{"fr":{"context":"Inspiré des pensées de l'habitation (Berque, Ingold), ce deck explore la trajection — ce mouvement où sujet et milieu se constituent mutuellement. Le corps comme seuil.","intention":"Pratiquer une attention incarnée et philosophique au vivant. Traverser les frontières entre soi et le milieu. Pour praticien·nes engagé·es dans l'éco-somatique.","pratique":"Peut se pratiquer assis·e, en marche ou en mouvement. Les cartes Seuil orientent la pratique, les cartes Situation la situent dans un contexte, les cartes Figure proposent une incarnation."},"en":{"context":"Inspired by inhabitation thinking (Berque, Ingold), this deck explores trajection — the movement where subject and milieu mutually constitute each other. The body as threshold.","intention":"Practice an embodied and philosophical attention to the living. Cross the borders between self and milieu. For practitioners engaged in ecosomatics.","pratique":"Can be practised seated, walking, or in movement. Threshold cards orient the practice, Situation cards situate it in context, Figure cards propose an embodiment."}},"territoires":{"fr":{"context":"Les conflits de territoire ne se résolvent pas par plus d'arguments. Ce deck crée les conditions somatiques d'un dialogue réel — en trois temps : ancrer, traverser, composer.","intention":"Permettre à des acteurs aux visions divergentes de sentir leur relation au lieu avant de débattre, de traverser le point de vue de l'autre, et de construire quelque chose de commun.","pratique":"Idéal avec un·e facilitateur·rice. Suivre la séquence des trois phases pour un processus complet. Pioche libre possible pour un·e facilita·teur·rice expérimenté·e. Fonctionne en salle ou sur le terrain."},"en":{"context":"Territory conflicts are not resolved by more arguments. This deck creates the somatic conditions for real dialogue — in three stages: ground, cross, compose.","intention":"Allow actors with diverging visions to feel their relationship to the place before debating, to cross into another's perspective, and to build something in common.","pratique":"Ideal with a facilitator. Follow the three-phase sequence for a complete process. Free draw possible for experienced facilitators. Works indoors or in the field."}},"corps_monde":{"fr":{"context":"Ton corps porte l'histoire du monde — plastique dans le sang, mémoire ancestrale, appartenance cosmique. Ce deck fait habiter ces échelles irreprésentables.","intention":"Explorer par le corps des réalités scientifiques et politiques souvent trop abstraites pour être senties. Relier la théorie critique à la présence somatique.","pratique":"Peut se pratiquer seul·e ou en groupe. Certaines cartes demandent du temps et de la disponibilité. Les cartes Poème-action peuvent être présentées devant un groupe. Lire la source après la pratique enrichit l'expérience."},"en":{"context":"Your body carries the history of the world — plastic in the blood, ancestral memory, cosmic belonging. This deck inhabits these unrepresentable scales.","intention":"Explore through the body scientific and political realities often too abstract to be felt. Connect critical theory to somatic presence.","pratique":"Can be practised alone or in group. Some cards require time and openness. Poem-action cards can be presented before a group. Reading the source after the practice enriches the experience."}},"contaminations":{"fr":{"context":"Des milliers de molécules industrielles circulent dans nos corps sans que nous l'ayons demandé. Ce deck transforme ce fait en présence incarnée et en acte politique.","intention":"Nommer et sentir ce que l'industrie a déposé dans les corps. Passer de l'anesthésie à la lucidité — pas à la sidération. Présentable devant un groupe.","pratique":"Ces cartes sont plus intenses que d'autres decks. Recommandé en groupe avec tenu·e de sécurité. Certaines cartes Performance peuvent se faire devant un public. Prévoir du temps pour intégrer après."},"en":{"context":"Thousands of industrial molecules circulate in our bodies without our asking. This deck transforms this fact into embodied presence and political act.","intention":"Name and feel what industry has deposited in bodies. Move from anaesthesia to lucidity — not to paralysis. Performable before a group.","pratique":"These cards are more intense than other decks. Recommended in group with holding/safety. Some Performance cards can be done before an audience. Allow time to integrate afterwards."}},"natures_sociales":{"fr":{"context":"Ce qu'on dit 'naturel' — la compétition, les hiérarchies, la domination — est souvent une projection idéologique sur le vivant. La science le montre. L'écoféminisme aussi.","intention":"Déconstruire les fictions naturalistes par le corps. Redécouvrir ce que la biologie réelle dit — symbiose, réciprocité, communication. S'inspirer des savoirs autochtones et des pensées décoloniales.","pratique":"Convient à un public sensibilisé aux enjeux écologiques et sociaux. Les cartes Déconstruire peuvent générer du débat — laisser de l'espace pour ça. Les cartes Redécouvrir sont plus contemplatives."},"en":{"context":"What we call 'natural' — competition, hierarchies, domination — is often an ideological projection onto the living. Science shows this. Ecofeminism too.","intention":"Deconstruct naturalistic fictions through the body. Rediscover what real biology says — symbiosis, reciprocity, communication. Draw on indigenous knowledges and decolonial thinking.","pratique":"Suitable for a public sensitised to ecological and social issues. Deconstruct cards may generate debate — allow space for that. Rediscover cards are more contemplative."}},"mythologies":{"fr":{"context":"Les mythes de création du monde entier disent une chose commune : le corps humain et le corps du monde sont faits de la même matière. Montagnes-os, rivières-sang, souffle-vent.","intention":"Habiter des cosmologies par le corps — non pour y croire, mais pour sentir d'autres façons de se tenir dans le monde. Chaque mythe devient une partition somatique.","pratique":"Seul·e ou en groupe. Lire le récit entièrement avant de bouger. Ces cartes demandent du temps et de la disponibilité intérieure — elles ne se pressent pas."},"en":{"context":"Creation myths from around the world say one common thing: the human body and the body of the world are made of the same matter. Mountain-bones, river-blood, breath-wind.","intention":"Inhabit cosmologies through the body — not to believe in them, but to feel other ways of standing in the world. Each myth becomes a somatic score.","pratique":"Alone or in a group. Read the whole narrative before moving. These cards ask for time and inner availability — they are not to be rushed."}}}}`);
const MC=_D.mc; const CC=_D.cc; const TC=_D.tc;
const VC=_D.vc; const XC=_D.xc; const SC=_D.sc;
const CM=_D.cm; const CO=_D.co; const NS=_D.ns; const MY=_D.my;
const _INTROS=_D.intros;


const ALL=[...MC,...CC,...TC,...VC,...XC,...SC,...CM,...CO,...NS,...MY];


function Pill({children,onClick,active,color="#4a6840",small,outline,dark,full,disabled,style:ex}){
  const bg=dark?T.charcoal:active?color:outline?"transparent":T.paperWarm;
  const border=active?color:outline?color:T.paperDark;
  const col=dark?T.paperWarm:active?"#fff":outline?color:T.inkLight;
  return <button onClick={onClick} disabled={disabled} style={{padding:small?"5px 12px":"10px 20px",borderRadius:"999px",border:`1.5px solid ${border}`,background:bg,color:col,cursor:disabled?"default":"pointer",fontFamily:"'Lora',Georgia,serif",fontSize:small?"12px":"14px",fontStyle:"italic",letterSpacing:"0.02em",transition:"all 0.18s",width:full?"100%":undefined,whiteSpace:"nowrap",boxShadow:active?`0 2px 12px ${color}30`:"none",opacity:disabled?0.4:1,...ex}}>{children}</button>;
}

function Timer({onClose,lang}){
  const L=LANG[lang];const[total,setTotal]=useState(30*60);const[left,setLeft]=useState(30*60);const[running,setRunning]=useState(false);const[done,setDone]=useState(false);const ref=useRef(null);
  useEffect(()=>{if(running){ref.current=setInterval(()=>setLeft(l=>{if(l<=1){clearInterval(ref.current);setRunning(false);setDone(true);return 0;}return l-1;}),1000);}else clearInterval(ref.current);return()=>clearInterval(ref.current);},[running]);
  const set=m=>{setTotal(m*60);setLeft(m*60);setRunning(false);setDone(false);};
  const m=Math.floor(left/60),s=left%60,r=48,circ=2*Math.PI*r,prog=total>0?(total-left)/total:0;
  return(<div style={{position:"fixed",inset:0,background:"rgba(30,26,16,0.85)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:200,backdropFilter:"blur(8px)"}}>
    <div style={{background:T.cream,borderRadius:"24px",padding:"32px",maxWidth:"300px",width:"90%",textAlign:"center",fontFamily:"'Lora',Georgia,serif"}}>
      <div style={{fontSize:"9px",letterSpacing:"0.4em",color:T.inkFaint,textTransform:"uppercase",marginBottom:"16px"}}>{L.timerLabel}</div>
      <div style={{position:"relative",width:"100px",height:"100px",margin:"0 auto 18px"}}>
        <svg width="100" height="100" style={{transform:"rotate(-90deg)"}}><circle cx="50" cy="50" r={r} fill="none" stroke={T.paperDark} strokeWidth="3"/><circle cx="50" cy="50" r={r} fill="none" stroke={T.lichen} strokeWidth="3" strokeDasharray={circ} strokeDashoffset={circ*(1-prog)} strokeLinecap="round" style={{transition:"stroke-dashoffset 1s linear"}}/></svg>
        <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center"}}>{done?<div style={{color:T.ochre,fontSize:"11px"}}>{L.timeToReturn}</div>:<div style={{fontSize:"26px",color:T.ink,fontVariantNumeric:"tabular-nums"}}>{String(m).padStart(2,"0")}:{String(s).padStart(2,"0")}</div>}</div>
      </div>
      <div style={{display:"flex",gap:"5px",flexWrap:"wrap",justifyContent:"center",marginBottom:"14px"}}>{[10,20,30,45,60].map(p=><Pill key={p} small active={total===p*60} color={T.lichen} onClick={()=>set(p)}>{p}min</Pill>)}</div>
      <div style={{display:"flex",gap:"8px",justifyContent:"center",marginBottom:"16px"}}><Pill color={T.lichen} active onClick={()=>{setRunning(!running);setDone(false);}}>{running?"Pause":lang==="fr"?"Commencer":"Start"}</Pill><Pill color={T.stone} outline onClick={()=>{setRunning(false);setLeft(total);setDone(false);}}>↺</Pill></div>
      <button onClick={onClose} style={{background:"none",border:"none",color:T.inkFaint,cursor:"pointer",fontSize:"12px",fontFamily:"inherit",textDecoration:"underline"}}>{L.close}</button>
    </div>
  </div>);
}

