function SessionSetup({onStart,onCancel,activeDeck,lang}){
  useScrollTop(true);
  const L=LANG[lang];const[context,setContext]=useState(null);const[duration,setDuration]=useState(null);const canStart=context&&duration;
  const primary=getTheme(activeDeck);const isDark=isDarkDeck(activeDeck);
  return(<div style={{minHeight:"100vh",background:isDark?"#0f0c14":T.paper,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"32px 20px",fontFamily:"'Lora',Georgia,serif",color:isDark?"#e0d8f0":T.ink}}>
    <div style={{maxWidth:"380px",width:"100%"}}>
      <button onClick={onCancel} style={{background:"none",border:"none",color:isDark?T.stone:T.inkFaint,cursor:"pointer",fontSize:"11px",letterSpacing:"0.2em",textTransform:"uppercase",marginBottom:"32px",display:"block",fontFamily:"inherit",textDecoration:"underline"}}>{L.back}</button>
      <div style={{fontSize:"9px",letterSpacing:"0.4em",color:primary,textTransform:"uppercase",marginBottom:"6px"}}>{L.sessionLabel}</div>
      <h2 style={{fontSize:"26px",fontWeight:"400",fontStyle:"italic",marginBottom:"24px",lineHeight:1.2}}>{L.howToday}</h2>
      {[{label:L.context,items:[{id:"seul",l:L.alone},{id:"duo",l:L.duo},{id:"groupe",l:L.group}],val:context,set:setContext},{label:L.duration,items:[{id:20,l:"20 min"},{id:30,l:"30 min"},{id:60,l:"1h"},{id:"ouvert",l:L.open}],val:duration,set:setDuration}].map(({label,items,val,set})=>(
        <div key={label} style={{marginBottom:"18px"}}>
          <div style={{fontSize:"9px",letterSpacing:"0.3em",color:isDark?T.stone:T.inkFaint,textTransform:"uppercase",marginBottom:"8px"}}>{label}</div>
          <div style={{display:"flex",gap:"7px",flexWrap:"wrap"}}>{items.map(c=><Pill key={c.id} active={val===c.id} color={primary} outline={val!==c.id} onClick={()=>set(c.id)}>{c.l}</Pill>)}</div>
        </div>
      ))}
      <div style={{marginTop:"22px"}}><Pill full color={canStart?primary:T.stone} active={canStart} outline={!canStart} onClick={()=>canStart&&onStart({context,duration})}>{canStart?L.enterSession:L.chooseFirst}</Pill></div>
    </div>
  </div>);
}


// ── DECK INTRO BANNER ────────────────────────────────────────────────
function DeckIntro({intro, color, isDark, lang}){
  const [open, setOpen] = React.useState(false);
  if(!intro) return null;
  const bg = isDark ? "#1a1528" : `${color}0a`;
  const border = isDark ? "#2e2540" : `${color}30`;
  return(
    <div style={{background:bg,border:`1px solid ${border}`,borderRadius:"14px",marginBottom:"12px",overflow:"hidden"}}>
      <button onClick={()=>setOpen(!open)} style={{
        width:"100%",padding:"12px 16px",background:"none",border:"none",
        cursor:"pointer",fontFamily:"'Lora',Georgia,serif",display:"flex",
        justifyContent:"space-between",alignItems:"center",gap:"10px"
      }}>
        <div style={{display:"flex",alignItems:"center",gap:"8px"}}>
          
          <span style={{fontSize:"11px",color,letterSpacing:"0.15em",textTransform:"uppercase"}}>
            {lang==="fr"?"à propos de ce deck":"about this deck"}
          </span>
        </div>
        <span style={{fontSize:"14px",color,opacity:0.7,flexShrink:0}}>{open?"∧":"∨"}</span>
      </button>
      {open&&(
        <div style={{padding:"0 16px 16px"}}>
          {intro.context&&(
            <div style={{marginBottom:"10px"}}>
              <div style={{fontSize:"8px",letterSpacing:"0.3em",color,textTransform:"uppercase",marginBottom:"5px"}}>Contexte</div>
              <p style={{fontSize:"13px",color:isDark?"#c0b0d8":T.inkMid,lineHeight:1.65,margin:0}}>{intro.context}</p>
            </div>
          )}
          {intro.intention&&(
            <div style={{marginBottom:"10px"}}>
              <div style={{fontSize:"8px",letterSpacing:"0.3em",color,textTransform:"uppercase",marginBottom:"5px"}}>Intention</div>
              <p style={{fontSize:"13px",color:isDark?"#c0b0d8":T.inkMid,lineHeight:1.65,margin:0}}>{intro.intention}</p>
            </div>
          )}
          {intro.pratique&&(
            <div>
              <div style={{fontSize:"8px",letterSpacing:"0.3em",color,textTransform:"uppercase",marginBottom:"5px"}}>Pratique</div>
              <p style={{fontSize:"13px",color:isDark?"#c0b0d8":T.inkMid,lineHeight:1.65,margin:0}}>{intro.pratique}</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}


// ── SÈVE CARD VIEW ──────────────────────────────────────────────────────
function SeveCardView({card,lang,onAddToScore,inScore,onRemoveFromScore,compact}){
  const d=card[lang]||card.fr;
  const isDual=card.type==="dual";
  const color=isDual?T.sap:T.sapLight;
  const seed=seedOf(card.id);
  if(compact) return(
    <div style={{background:inScore?`${color}15`:"#fff",border:`1.5px solid ${inScore?color:T.paperDark}`,borderRadius:"16px",padding:"16px 14px",position:"relative",overflow:"hidden",cursor:onAddToScore?"pointer":"default",transition:"all 0.18s"}}
         onClick={()=>onAddToScore&&!inScore&&onAddToScore(card)}>
      <div style={{position:"absolute",bottom:-8,right:-8,opacity:0.1}}><SapLeaf seed={seed} color={color} w={65} h={45}/></div>
      {inScore&&<div style={{position:"absolute",top:7,right:7,width:"6px",height:"6px",background:color,borderRadius:"50%"}}/>}
      <div style={{fontSize:"8px",letterSpacing:"0.3em",color,textTransform:"uppercase",marginBottom:"6px"}}>{lang==="fr"?card.type==="dual"?"Duale":"Solo":card.type==="dual"?"Dual":"Solo"}</div>
      <div style={{fontSize:"22px",fontWeight:"400",fontStyle:"italic",color:T.ink,lineHeight:1.1,marginBottom:"8px"}}>{d.verb}</div>
      <div style={{display:"flex",gap:"5px",flexWrap:"wrap"}}>
        {d.qualities.map((q,i)=><span key={i} style={{fontSize:"10px",color:T.inkFaint,background:T.paperWarm,padding:"2px 7px",borderRadius:"999px"}}>{q}</span>)}
      </div>
    </div>
  );
  return(
    <div style={{background:"#fafdf6",borderRadius:"20px",border:`2px solid ${color}`,padding:"24px 22px",position:"relative",overflow:"hidden",marginBottom:"14px"}}>
      <div style={{position:"absolute",bottom:-20,right:-20,opacity:0.08}}><SapLeaf seed={seed+5} color={color} w={140} h={100}/></div>
      <div style={{display:"inline-flex",alignItems:"center",gap:"8px",marginBottom:"14px"}}>
        <div style={{width:"20px",height:"1.5px",background:color}}/>
        <span style={{fontSize:"9px",letterSpacing:"0.4em",textTransform:"uppercase",color}}>{lang==="fr"?card.type==="dual"?"Duale":"Solo":card.type==="dual"?"Dual":"Solo"}</span>
        <div style={{width:"20px",height:"1.5px",background:color}}/>
      </div>
      <div style={{fontSize:"48px",fontWeight:"400",fontStyle:"italic",color:T.sap,lineHeight:1.0,letterSpacing:"-0.02em",marginBottom:"16px"}}>{d.verb}</div>
      <div style={{display:"flex",gap:"7px",flexWrap:"wrap",marginBottom:"16px"}}>
        {d.qualities.map((q,i)=><span key={i} style={{fontSize:"12px",color:T.inkLight,background:T.paperWarm,padding:"4px 10px",borderRadius:"999px",fontStyle:"italic"}}>{q}</span>)}
      </div>
      {d.invitation&&<p style={{fontSize:"15px",color:T.inkMid,lineHeight:1.65,fontStyle:"italic",margin:0,borderLeft:`2px solid ${color}`,paddingLeft:"14px"}}>{d.invitation}</p>}
    </div>
  );
}

// ── SCORE COMPOSER ──────────────────────────────────────────────────────
function MultiDraw({cards, lang, onBack}){
  useScrollTop("multidraw");
  const L=LANG[lang];
  return(
    <div style={{minHeight:"100vh",background:"#f4faf0",fontFamily:"'Lora',Georgia,serif",color:T.ink}}>
      <div style={{position:"fixed",top:-30,right:-30,opacity:0.06,pointerEvents:"none"}}><SapLeaf seed={9} color={T.sapLight} w={250} h={175}/></div>
      <div style={{padding:"16px 22px",display:"flex",justifyContent:"space-between",alignItems:"center",position:"relative",zIndex:1}}>
        <button onClick={onBack} style={{background:"none",border:"none",color:T.inkFaint,cursor:"pointer",fontSize:"11px",letterSpacing:"0.15em",textTransform:"uppercase",fontFamily:"inherit",textDecoration:"underline"}}>{L.back}</button>
        <div style={{fontSize:"9px",letterSpacing:"0.3em",color:T.sapLight,textTransform:"uppercase"}}>{cards.length} {lang==="fr"?"cartes":"cards"}</div>
      </div>
      <div style={{padding:"8px 22px 60px",maxWidth:"560px",margin:"0 auto",position:"relative",zIndex:1}}>
        <div style={{display:"flex",alignItems:"center",gap:"10px",marginBottom:"24px"}}>
          <div style={{width:"20px",height:"1.5px",background:T.sapLight}}/>
          <span style={{fontSize:"9px",letterSpacing:"0.4em",color:T.sapLight,textTransform:"uppercase"}}>
            {"Traversées · "}{lang==="fr"?"Score pioché":"Drawn score"}
          </span>
          <div style={{flex:1,height:"1px",background:T.paperDark}}/>
        </div>
        {cards.map((card,i)=>{
          const d=card[lang]||card.fr;
          const isDual=card.type!=="verbe_solo";
          const color=isDual?T.sap:T.sapLight;
          const seed=seedOf(card.id);
          return(
            <div key={card.id} style={{background:"#fff",borderRadius:"16px",padding:"22px",marginBottom:"16px",position:"relative",overflow:"hidden",boxShadow:"0 2px 12px rgba(58,90,26,0.08)",borderLeft:`4px solid ${color}`}}>
              <div style={{position:"absolute",bottom:-16,right:-16,opacity:0.08,pointerEvents:"none"}}><SapLeaf seed={seed+i} color={color} w={110} h={78}/></div>
              <div style={{display:"flex",alignItems:"center",gap:"8px",marginBottom:"12px"}}>
                <span style={{fontSize:"8px",letterSpacing:"0.35em",color,textTransform:"uppercase"}}>{lang==="fr"?({verbe_solo:"Verbe",verbe_dual:"Verbe dual",qualite:"Qualité",contrainte:"Contrainte"})[card.type]:({verbe_solo:"Verb",verbe_dual:"Dual verb",qualite:"Quality",contrainte:"Constraint"})[card.type]}</span>
                {cards.length>1&&<span style={{fontSize:"9px",color:T.inkFaint,marginLeft:"auto"}}>{i+1}/{cards.length}</span>}
              </div>
              <div style={{fontSize:cards.length<=2?"48px":cards.length===3?"36px":"30px",fontWeight:"400",fontStyle:"italic",color:T.sap,lineHeight:1.0,letterSpacing:"-0.02em",marginBottom:"14px"}}>{d.verb}</div>
              <div style={{display:"flex",gap:"6px",flexWrap:"wrap",marginBottom:d.invitation?"14px":"0"}}>
                {d.qualities.map((q,qi)=><span key={qi} style={{fontSize:"12px",color:T.inkLight,background:T.paperWarm,padding:"4px 10px",borderRadius:"999px",fontStyle:"italic"}}>{q}</span>)}
              </div>
              {d.invitation&&<p style={{fontSize:"15px",color:T.inkMid,lineHeight:1.65,fontStyle:"italic",margin:0,borderLeft:`2px solid ${color}`,paddingLeft:"12px"}}>{d.invitation}</p>}
            </div>
          );
        })}
        <div style={{marginTop:"8px",textAlign:"center"}}>
          <p style={{fontSize:"13px",color:T.inkFaint,fontStyle:"italic",lineHeight:1.6}}>
            {lang==="fr"
              ?"Improvise depuis ces cartes — seul·e ou à plusieurs. Laisse l'espace répondre."
              :"Improvise from these cards — alone or together. Let the space respond."}
          </p>
        </div>
      </div>
    </div>
  );
}


function SeveFullCard({card,lang,onBack,onAddToTray,inTray,sessionActive}){
  useScrollTop(card.id);
  const d=card[lang]||card.fr;
  const isDual=card.type==="verbe_dual"||card.type==="qualite"||card.type==="contrainte";
  const color=isDual?T.sap:T.sapLight;
  const L=LANG[lang];
  const seed=seedOf(card.id);
  return(
    <div style={{minHeight:"100vh",background:"#f4faf0",fontFamily:"'Lora',Georgia,serif",color:T.ink,position:"relative",overflow:"hidden"}}>
      <div style={{position:"fixed",bottom:-40,right:-40,opacity:0.07,pointerEvents:"none",zIndex:0}}><SapLeaf seed={seed+5} color={color} w={280} h={200}/></div>
      <div style={{padding:"16px 22px",display:"flex",justifyContent:"space-between",alignItems:"center",position:"relative",zIndex:1}}>
        <button onClick={onBack} style={{background:"none",border:"none",color:T.inkFaint,cursor:"pointer",fontSize:"11px",letterSpacing:"0.15em",textTransform:"uppercase",fontFamily:"inherit",textDecoration:"underline"}}>{L.back}</button>
        <div style={{display:"flex",gap:"8px",alignItems:"center"}}>
          {sessionActive&&!inTray&&<Pill small color={color} outline onClick={()=>onAddToTray(card)}>{L.addToTray}</Pill>}
          {inTray&&<span style={{padding:"4px 12px",borderRadius:"999px",background:`${color}20`,border:`1.5px solid ${color}`,color,fontSize:"12px",fontStyle:"italic"}}>{L.onTray}</span>}
        </div>
      </div>
      <div style={{flex:1,padding:"8px 28px 56px",maxWidth:"480px",margin:"0 auto",position:"relative",zIndex:1}}>
        <div style={{display:"inline-flex",alignItems:"center",gap:"10px",marginBottom:"14px"}}>
          <div style={{width:"22px",height:"1.5px",background:color}}/>
          <span style={{fontSize:"9px",letterSpacing:"0.4em",textTransform:"uppercase",color}}>Traversées · {lang==="fr"?({verbe_solo:"Verbe",verbe_dual:"Verbe dual",qualite:"Qualité",contrainte:"Contrainte"})[card.type]||card.type:({verbe_solo:"Verb",verbe_dual:"Dual verb",qualite:"Quality",contrainte:"Constraint"})[card.type]||card.type}</span>
          <div style={{width:"22px",height:"1.5px",background:color}}/>
        </div>
        <div style={{fontSize:"64px",fontWeight:"400",fontStyle:"italic",color:T.sap,lineHeight:0.95,letterSpacing:"-0.02em",marginBottom:"20px"}}>{d.verb}</div>
        <div style={{height:"1.5px",background:`linear-gradient(90deg,${color},${color}40,transparent)`,marginBottom:"22px"}}/>
        <div style={{display:"flex",gap:"8px",flexWrap:"wrap",marginBottom:"24px"}}>
          {d.qualities.map((q,i)=><span key={i} style={{fontSize:"14px",color:T.inkLight,background:"#fff",padding:"6px 14px",borderRadius:"999px",border:`1px solid ${T.paperDark}`,fontStyle:"italic"}}>{q}</span>)}
        </div>
        {d.invitation&&(
          <div style={{borderLeft:`3px solid ${color}`,paddingLeft:"18px",marginBottom:"28px"}}>
            <p style={{fontSize:"19px",fontStyle:"italic",color:T.inkMid,lineHeight:1.7,margin:0}}>{d.invitation}</p>
          </div>
        )}
        {isDual&&(
          <div style={{background:"#fff",border:`1px solid ${T.paperDark}`,borderRadius:"14px",padding:"16px 18px",marginBottom:"14px"}}>
            <div style={{fontSize:"9px",letterSpacing:"0.3em",color:T.inkFaint,textTransform:"uppercase",marginBottom:"10px"}}>{lang==="fr"?({verbe_dual:"verbe dual — deux pôles en tension",qualite:"qualité — un spectre à explorer",contrainte:"contrainte — deux espaces à habiter"})[card.type]||"":({verbe_dual:"dual verb — two poles in tension",qualite:"quality — a spectrum to explore",contrainte:"constraint — two spaces to inhabit"})[card.type]||""}</div>

          </div>
        )}
        <div style={{background:T.paperWarm,borderRadius:"12px",padding:"14px 16px",fontSize:"13px",color:T.inkFaint,fontStyle:"italic",lineHeight:1.6}}>
          {lang==="fr"
            ?"Improvise depuis ce verbe — seul·e ou à plusieurs, avec ou sans public. Laisse l'espace naturel répondre."
            :"Improvise from this verb — alone or together, with or without audience. Let the natural space respond."}
        </div>
      </div>
    </div>
  );
}


function CardDetail({card,onBack,onAddToTray,inTray,sessionActive,lang}){
  useScrollTop(card.id);
  const [showRetour,setShowRetour]=useState(false);
  
  const L=LANG[lang];
  const isDark=isDarkDeck(card.deck);
  const isTerrains=card.deck==="terrains";
  const isVivant=card.deck==="vivant";
  const isTerritoires=card.deck==="territoires";
  const isTraversees=card.deck==="traversees";
  if(isTraversees) return <SeveFullCard card={card} lang={lang} onBack={onBack} onAddToTray={onAddToTray} inTray={inTray} sessionActive={sessionActive}/>;
  const tMeta=getTypeMeta(card);
  const meta=tMeta[card.type];
  const color=meta?.color||T.lichen;
  const Tex=meta?.Tex;
  const data=card[lang]||card.fr;
  const seed=seedOf(card.id);
  const bg=isDark?"#0f0c14":isTerrains?"#fdf8f0":isVivant?"#f0f5ec":isTerritoires?"#f0f4f8":T.cream;
  const textColor=isDark?"#e0d8f0":T.ink;
  const borderColor=isDark?"#2e2540":T.paperDark;

  const bodyItems=data.steps||data.body||[];
  const question=data.q||data.question||null;
  const trace=data.tr||data.trace||null;
  const retour=data.r||data.retour||null;

  const avgLen=bodyItems.length?bodyItems.reduce((a,b)=>a+b.length,0)/bodyItems.length:0;
  const bodyShape=(avgLen<38&&bodyItems.length>3)?"list":"flow";

  const phaseNames={ancrer:L.phaseAncrer,traverser:L.phaseTraverser,composer:L.phaseComposer};
  const phaseDescs={ancrer:L.phaseAncrerDesc,traverser:L.phaseTraverserDesc,composer:L.phaseComposerDesc};

  function renderBody(){
    if(!bodyItems.length) return null;
    if(bodyShape==="list") return(
      <div style={{marginBottom:"24px"}}>{bodyItems.map((text,i)=><p key={i} style={{fontSize:"16px",color:isDark?"#a090b8":T.inkLight,fontStyle:"italic",lineHeight:"1.6",margin:i===0?"0 0 10px 0":"0 0 10px 8px"}}>{text}</p>)}</div>
    );
    return(
      <div style={{marginBottom:"24px"}}>{bodyItems.map((text,i)=>{
        const isShort=text.length<55;const prevShort=i>0&&bodyItems[i-1].length<55;
        const marginTop=(isShort||prevShort)&&i>0?"18px":i>0?"10px":"0";
        return <p key={i} style={{fontSize:"15px",color:isShort?(isDark?"#9888b8":T.inkFaint):(isDark?"#c8b8e0":T.inkMid),fontStyle:isShort?"italic":"normal",lineHeight:isShort?"1.6":"1.8",margin:`${marginTop} 0 0 0`,textAlign:isShort?"center":"left"}}>{text}</p>;
      })}</div>
    );
  }

  return(
    <div style={{minHeight:"100vh",background:bg,display:"flex",flexDirection:"column",fontFamily:"'Lora',Georgia,serif",color:textColor,position:"relative",overflow:"hidden"}}>
      <div style={{position:"fixed",bottom:-50,right:-50,opacity:isDark?0.1:0.06,pointerEvents:"none",zIndex:0,transform:"rotate(-10deg)"}}>{Tex&&<Tex seed={seed+5} color={color} w={260} h={180} size={220}/>}</div>
      <div style={{padding:"16px 20px",display:"flex",justifyContent:"space-between",alignItems:"center",position:"relative",zIndex:1}}>
        <button onClick={onBack} style={{background:"none",border:"none",color:isDark?T.stone:T.inkFaint,cursor:"pointer",fontSize:"11px",letterSpacing:"0.15em",textTransform:"uppercase",fontFamily:"inherit",textDecoration:"underline"}}>{L.back}</button>
        <div style={{display:"flex",gap:"8px",alignItems:"center"}}>
          {sessionActive&&!inTray&&<Pill small color={color} outline onClick={()=>onAddToTray(card)}>{L.addToTray}</Pill>}
          {inTray&&<span style={{padding:"4px 12px",borderRadius:"999px",background:`${color}20`,border:`1.5px solid ${color}`,color,fontSize:"12px",fontStyle:"italic"}}>{L.onTray}</span>}
        </div>
      </div>
      <div style={{flex:1,padding:"8px 26px 52px",maxWidth:"520px",margin:"0 auto",width:"100%",position:"relative",zIndex:1}}>
        {/* Phase indicator for territoires */}
        {isTerritoires && (
          <div style={{background:`${color}12`,border:`1px solid ${color}30`,borderRadius:"10px",padding:"8px 12px",marginBottom:"14px",display:"flex",alignItems:"center",gap:"10px"}}>
            <span style={{fontSize:"8px",letterSpacing:"0.35em",color,textTransform:"uppercase"}}>{L.phaseLabel} 1/3</span>
            <span style={{fontSize:"12px",color:isDark?"#a0b8c8":T.inkMid,fontStyle:"italic"}}>{phaseNames[card.type]} — {phaseDescs[card.type]}</span>
          </div>
        )}
        <div style={{display:"inline-flex",alignItems:"center",gap:"10px",marginBottom:"12px"}}>
          <div style={{width:"22px",height:"1.5px",background:color,borderRadius:"999px"}}/>
          <span style={{fontSize:"9px",letterSpacing:"0.4em",textTransform:"uppercase",color}}>
            {card.deck==="choreo"?"Choreospores":card.deck==="milieux"?"Milieux":card.deck==="terrains"?"Terrains":card.deck==="vivant"?(lang==="fr"?"Avec le vivant":"With the living"):card.deck==="territoires"?(lang==="fr"?"Territoires croisés":"Crossed territories"):card.deck==="corps_monde"?"Corps-Monde":card.deck==="contaminations"?"Contaminations":card.deck==="natures_sociales"?"Natures Sociales":"Mythologies"} · {lang==="fr"?meta?.fr:meta?.en}
          </span>
          <div style={{width:"22px",height:"1.5px",background:color,borderRadius:"999px"}}/>
        </div>
        <h1 style={{fontSize:"40px",fontWeight:"400",fontStyle:"italic",color:textColor,margin:"0 0 14px",lineHeight:1.0,letterSpacing:"-0.01em"}}>{data.title}</h1>
        <div style={{borderLeft:`3px solid ${color}`,paddingLeft:"18px",marginBottom:"26px"}}>
          <p style={{fontSize:"18px",fontStyle:"italic",color:textColor,lineHeight:1.7,margin:0}}>{data.entry}</p>
        </div>
        {bodyItems.length>0&&<div style={{display:"flex",alignItems:"center",gap:"12px",marginBottom:"20px"}}><div style={{flex:1,height:"1px",background:borderColor}}/><div style={{width:"5px",height:"5px",borderRadius:"50%",background:color,opacity:0.5}}/><div style={{flex:1,height:"1px",background:borderColor}}/></div>}
        {renderBody()}
        {trace&&(
          <div style={{borderLeft:`3px solid ${color}`,paddingLeft:"14px",marginBottom:"16px"}}>
            <div style={{fontSize:"8px",letterSpacing:"0.3em",textTransform:"uppercase",color,marginBottom:"6px"}}>✎ trace</div>
            <p style={{fontSize:"14px",color:isDark?"#b0a0c0":T.inkMid,lineHeight:1.65,margin:0,fontStyle:"italic"}}>{trace}</p>
          </div>
        )}
        {question&&(
          <div style={{border:`1.5px solid ${color}`,borderRadius:"14px",padding:"16px",marginBottom:"14px",background:`${color}06`}}>
            <div style={{fontSize:"8px",letterSpacing:"0.3em",textTransform:"uppercase",color,marginBottom:"10px"}}>
              {lang==="fr"?"pour écrire, dessiner, rêver...":"to write, draw, dream..."}
            </div>
            <p style={{fontSize:"16px",color:isDark?"#c8b8e0":T.inkMid,lineHeight:1.7,fontStyle:"italic",margin:0}}>{question}</p>
          </div>
        )}
        {retour&&!isTerrains&&!isVivant&&!isTerritoires&&Object.keys(getTypeMeta(card)).length>1&&(
          <><Pill full color={color} active={showRetour} outline={!showRetour} onClick={()=>setShowRetour(!showRetour)} style={{marginBottom:"10px"}}>{showRetour?L.closeRetour:L.openRetour}</Pill>
          {showRetour&&<div style={{border:`1.5px solid ${color}`,borderRadius:"14px",padding:"18px",marginBottom:"10px",background:`${color}08`}}><p style={{fontSize:"15px",color:isDark?"#c0b0d8":T.inkMid,lineHeight:1.7,margin:"0 0 12px",fontStyle:"italic",textAlign:"center"}}>{retour}</p></div>}</>
        )}
        {data.sources&&data.sources.length>0&&<div style={{padding:"10px 14px",borderLeft:`2px solid ${borderColor}`,marginTop:"8px"}}><div style={{fontSize:"8px",letterSpacing:"0.35em",color:isDark?T.stone:T.inkFaint,textTransform:"uppercase",marginBottom:"6px"}}>références</div>{data.sources.map((s,i)=><p key={i} style={{fontSize:"12px",color:isDark?T.stone:T.inkFaint,lineHeight:1.55,margin:"0 0 4px",fontStyle:"italic"}}>— {s}</p>)}</div>}
      </div>
    </div>
  );
}

function SessionTray({cards,onOpen,onRemove,onDraw,config,lang,activeDeck}){
  const L=LANG[lang];const accent=getTheme(activeDeck);
  return(<div style={{background:T.charcoal,borderTop:`2px solid ${accent}`,padding:"10px 16px"}}>
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:"8px"}}>
      <div style={{fontSize:"9px",letterSpacing:"0.2em",color:T.stone,textTransform:"uppercase"}}>{L.tray} · {cards.length} {cards.length===1?L.card:L.cards} · {config?.context} · {config?.duration==="ouvert"?L.openDur:`${config?.duration}min`}</div>
      <Pill small dark color={accent} onClick={onDraw}>+ {lang==="fr"?"piocher":"draw"}</Pill>
    </div>
    <div style={{display:"flex",gap:"7px",overflowX:"auto",paddingBottom:"4px",scrollbarWidth:"none"}}>
      {cards.length===0&&<div style={{color:T.stone,fontSize:"13px",fontStyle:"italic",padding:"4px 0"}}>{lang==="fr"?"Pioche une carte pour commencer":"Draw a card to begin"}</div>}
      {cards.map((card,i)=>{const color=getTypeMeta(card)[card.type]?.color||T.lichen;const d=card[lang]||card.fr;return(<div key={card.id} style={{background:`${color}18`,border:`1.5px solid ${color}50`,borderRadius:"12px",padding:"7px 12px",minWidth:"95px",flexShrink:0}}><div style={{fontSize:"8px",letterSpacing:"0.2em",color,textTransform:"uppercase",marginBottom:"3px"}}>{i+1}</div><div style={{fontSize:"13px",fontStyle:"italic",color:T.paperWarm,marginBottom:"5px",cursor:"pointer"}} onClick={()=>onOpen(card)}>{d.title}</div><button onClick={()=>onRemove(card.id)} style={{background:"none",border:"none",color:T.stone,cursor:"pointer",fontSize:"10px",padding:0,fontFamily:"inherit",textDecoration:"underline"}}>{L.remove}</button></div>);})}
    </div>
  </div>);
}

function BrowseScreen({activeDeck,onBack,lang,setLang}){
  useScrollTop(activeDeck);
  const allCards=[...MC,...CC,...TC,...VC,...XC,...SC,...CM,...CO,...NS,...MY];
  const pool=activeDeck==="milieux"?allCards.filter(c=>c.deck==="milieux"):activeDeck==="choreo"?allCards.filter(c=>c.deck==="choreo"):activeDeck==="terrains"?allCards.filter(c=>c.deck==="terrains"):activeDeck==="vivant"?allCards.filter(c=>c.deck==="vivant"):activeDeck==="territoires"?allCards.filter(c=>c.deck==="territoires"):activeDeck==="traversees"?allCards.filter(c=>c.deck==="traversees"):activeDeck==="corps_monde"?allCards.filter(c=>c.deck==="corps_monde"):activeDeck==="contaminations"?allCards.filter(c=>c.deck==="contaminations"):activeDeck==="natures_sociales"?allCards.filter(c=>c.deck==="natures_sociales"):activeDeck==="mythologies"?allCards.filter(c=>c.deck==="mythologies"):allCards;

  const [filterType,setFilterType]=useState("all");
  const [phase,setPhase]=useState("ancrer");
  const [selectedCard,setSelectedCard]=useState(null);
  const [showTimer,setShowTimer]=useState(false);
  const [drawCount,setDrawCount]=useState(1);
  const [drawnCards,setDrawnCards]=useState(null);

  const L=LANG[lang];
  const isDark=isDarkDeck(activeDeck);
  const isTerritoires=activeDeck==="territoires";
  const isTraversees=activeDeck==="traversees";
  const isVivant=activeDeck==="vivant";

  const primary=getTheme(activeDeck);
  const tMetas=activeDeck==="choreo"?CT:activeDeck==="milieux"?MT:activeDeck==="terrains"?TT:activeDeck==="vivant"?VT:activeDeck==="traversees"?ST:activeDeck==="corps_monde"?CMT:activeDeck==="contaminations"?COT:activeDeck==="natures_sociales"?NST:activeDeck==="mythologies"?MYT:XT;

  const displayed=isTerritoires?pool.filter(c=>c.type===phase):filterType==="all"?pool:pool.filter(c=>c.type===filterType);

  const bg=isDark?"#0f0c14":isVivant?"#f0f5ec":isTerritoires?"#f0f4f8":isTraversees?"#f4faf0":activeDeck==="corps_monde"?"#faf5ed":activeDeck==="contaminations"?"#fdf3f0":activeDeck==="natures_sociales"?"#f0f3f8":activeDeck==="mythologies"?"#f5f0f8":activeDeck==="terrains"?"#fdf8f0":T.paper;

  const deckName=activeDeck==="choreo"?"Choreospores":activeDeck==="milieux"?"Milieux":activeDeck==="terrains"?"Terrains":activeDeck==="vivant"?(lang==="fr"?"Avec le vivant":"With the living"):activeDeck==="territoires"?(lang==="fr"?"Territoires croisés":"Crossed territories"):activeDeck==="traversees"?"Traversées":activeDeck==="corps_monde"?"Corps-Monde":activeDeck==="contaminations"?"Contaminations":activeDeck==="natures_sociales"?"Natures Sociales":activeDeck==="mythologies"?"Mythologies":(lang==="fr"?"Tous":"All");
  const deckSub=activeDeck==="choreo"?"Mycoscores — Maija Hirvanen":activeDeck==="milieux"?(lang==="fr"?"Deck éco-somatique":"Ecosomatic deck"):activeDeck==="terrains"?(lang==="fr"?"Jeu de paysage":"Landscape play"):activeDeck==="vivant"?(lang==="fr"?"Rencontres dehors":"Encounters outside"):activeDeck==="territoires"?(lang==="fr"?"Acteurs de territoire":"Territory actors"):activeDeck==="traversees"?(lang==="fr"?"Scores dans le vivant":"Scores in the living world"):activeDeck==="corps_monde"?(lang==="fr"?"Échelles et appartenance":"Scales and belonging"):activeDeck==="contaminations"?(lang==="fr"?"Corps et industrie":"Bodies and industry"):activeDeck==="natures_sociales"?(lang==="fr"?"Déconstruire le naturel":"Deconstructing the natural"):activeDeck==="mythologies"?(lang==="fr"?"Cosmologies du monde":"World cosmologies"):(lang==="fr"?"Session mixte":"Mixed session");

  if(isTraversees&&drawnCards)return <MultiDraw cards={drawnCards} lang={lang} onBack={()=>setDrawnCards(null)}/>;
  if(selectedCard)return(<>{isDark||isTraversees||isVivant||isTerritoires||activeDeck==="corps_monde"||activeDeck==="contaminations"||activeDeck==="natures_sociales"||activeDeck==="mythologies"?<CardDetail card={selectedCard} onBack={()=>setSelectedCard(null)} lang={lang}/>:<CardDetail card={selectedCard} onBack={()=>setSelectedCard(null)} lang={lang}/>}{showTimer&&<Timer onClose={()=>setShowTimer(false)} lang={lang}/>}</>);

  return(
    <div style={{minHeight:"100vh",background:bg,fontFamily:"'Lora',Georgia,serif",color:isDark?"#e0d8f0":T.ink,position:"relative",overflow:"hidden"}}>
      {isDark?<div style={{position:"fixed",top:-30,right:-40,opacity:0.06,pointerEvents:"none",zIndex:0}}><Spores seed={44} color={T.spore} size={240}/></div>
        :isVivant?<div style={{position:"fixed",top:-30,right:-40,opacity:0.07,pointerEvents:"none",zIndex:0}}><Leaves seed={44} color={T.forest} w={240} h={168}/></div>
        :isTraversees?<div style={{position:"fixed",top:-30,right:-40,opacity:0.07,pointerEvents:"none",zIndex:0}}><SapLeaf seed={44} color={T.sapLight} w={240} h={168}/></div>
        :isTerritoires?<div style={{position:"fixed",top:-30,right:-40,opacity:0.06,pointerEvents:"none",zIndex:0}}><Paths seed={44} color={T.water} w={240} h={168}/></div>
        :<><div style={{position:"fixed",top:-30,right:-40,opacity:0.06,pointerEvents:"none",zIndex:0}}><Rings seed={44} color={T.lichen} size={240}/></div><div style={{position:"fixed",bottom:-40,left:-30,opacity:0.05,pointerEvents:"none",zIndex:0}}><Sprig seed={22} color={T.ochre} w={260} h={180}/></div></>}

      <div style={{position:"relative",zIndex:1,maxWidth:"580px",margin:"0 auto",padding:"18px 20px 0"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"16px"}}>
          <button onClick={onBack} style={{background:"none",border:"none",color:isDark?T.stone:T.inkFaint,cursor:"pointer",fontSize:"11px",letterSpacing:"0.15em",textTransform:"uppercase",fontFamily:"inherit",textDecoration:"underline"}}>{L.backToChoice}</button>
          <div style={{display:"flex",gap:"6px",alignItems:"center"}}>
            {["fr","en"].map(l=><button key={l} onClick={()=>setLang(l)} style={{padding:"3px 9px",borderRadius:"999px",border:`1.5px solid ${lang===l?primary:(isDark?"#3a3020":T.paperDark)}`,background:lang===l?primary:"transparent",color:lang===l?"#fff":isDark?T.stone:T.inkFaint,cursor:"pointer",fontFamily:"inherit",fontSize:"11px",letterSpacing:"0.1em",textTransform:"uppercase"}}>{l}</button>)}
            <button onClick={()=>setShowTimer(true)} style={{background:"none",border:`1.5px solid ${isDark?"#3a3020":T.paperDark}`,borderRadius:"50%",width:"30px",height:"30px",color:isDark?T.stone:T.inkFaint,cursor:"pointer",fontSize:"13px",display:"flex",alignItems:"center",justifyContent:"center"}}>⏱</button>
          </div>
        </div>

        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:"12px"}}>
          <div>
            <div style={{display:"flex",alignItems:"center",gap:"8px",marginBottom:"5px"}}><div style={{width:"18px",height:"1.5px",background:primary}}/><span style={{fontSize:"8px",letterSpacing:"0.45em",color:primary,textTransform:"uppercase"}}>{deckSub}</span></div>
            <h1 style={{fontSize:"42px",fontWeight:"400",fontStyle:"italic",margin:0,lineHeight:0.95,letterSpacing:"-0.02em",color:isDark?"#e0d8f0":T.ink}}>{deckName}</h1>
            <div style={{fontSize:"12px",color:isDark?T.stone:T.inkFaint,marginTop:"5px",fontStyle:"italic"}}>{displayed.length} {lang==="fr"?"cartes":"cards"}</div>
          </div>
          <div style={{opacity:0.28,marginTop:"8px"}}>{isDark?<Spores seed={77} color={T.spore} size={52}/>:isVivant?<Leaves seed={77} color={T.forest} w={62} h={44}/>:isTraversees?<SapLeaf seed={77} color={T.sapLight} w={62} h={44}/>:isTerritoires?<Paths seed={77} color={T.water} w={62} h={44}/>:<Rings seed={77} color={T.lichen} size={52}/>}</div>
        </div>

        <div style={{height:"1.5px",background:`linear-gradient(90deg,${primary},${primary}40,transparent)`,marginBottom:"12px"}}/>

        {_INTROS&&_INTROS[activeDeck]&&(
          <DeckIntro intro={_INTROS[activeDeck][lang]||_INTROS[activeDeck].fr} color={primary} isDark={isDark} lang={lang}/>
        )}

        {isTerritoires&&(
          <div style={{background:`${primary}10`,border:`1px solid ${primary}30`,borderRadius:"12px",padding:"12px 14px",marginBottom:"12px"}}>
            <div style={{fontSize:"9px",letterSpacing:"0.3em",color:primary,textTransform:"uppercase",marginBottom:"8px"}}>{lang==="fr"?"Protocole en trois temps":"Three-phase protocol"}</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:"6px"}}>
              {[{key:"ancrer",n:"1",label:L.phaseAncrer,desc:lang==="fr"?"Chacun ancre":"Each grounds"},{key:"traverser",n:"2",label:L.phaseTraverser,desc:lang==="fr"?"Habiter l'autre":"Cross views"},{key:"composer",n:"3",label:L.phaseComposer,desc:lang==="fr"?"Construire ensemble":"Build together"}].map(p=>(
                <button key={p.key} onClick={()=>setPhase(p.key)} style={{padding:"8px 6px",borderRadius:"10px",border:`1.5px solid ${phase===p.key?primary:T.paperDark}`,background:phase===p.key?`${primary}18`:T.cream,cursor:"pointer",textAlign:"left",fontFamily:"'Lora',Georgia,serif"}}>
                  <div style={{fontSize:"8px",color:primary,marginBottom:"2px"}}>{p.n} /</div>
                  <div style={{fontSize:"13px",fontStyle:"italic",color:phase===p.key?primary:T.inkMid}}>{p.label}</div>
                  <div style={{fontSize:"10px",color:T.inkFaint,lineHeight:1.3,marginTop:"2px"}}>{p.desc}</div>
                </button>
              ))}
            </div>
          </div>
        )}

        {isTraversees&&(
          <div style={{marginBottom:"10px"}}>
            <div style={{display:"flex",alignItems:"center",gap:"8px",marginBottom:"8px"}}>
              <span style={{fontSize:"12px",color:T.inkFaint,fontStyle:"italic"}}>{lang==="fr"?"Piocher":"Draw"}</span>
              {[1,2,3,4].map(n=>(
                <button key={n} onClick={()=>setDrawCount(n)} style={{width:"32px",height:"32px",borderRadius:"50%",border:`1.5px solid ${drawCount===n?T.sapLight:T.paperDark}`,background:drawCount===n?T.sapLight:"transparent",color:drawCount===n?"#fff":T.inkFaint,cursor:"pointer",fontFamily:"'Lora',Georgia,serif",fontSize:"14px",fontStyle:"italic",transition:"all 0.15s"}}>{n}</button>
              ))}
              <span style={{fontSize:"12px",color:T.inkFaint,fontStyle:"italic"}}>{lang==="fr"?drawCount===1?"carte":"cartes":drawCount===1?"card":"cards"}</span>
            </div>
          </div>
        )}

        <button onClick={()=>{
          if(isTraversees){
            const p=[...pool];const picks=[];const used=new Set();
            while(picks.length<Math.min(drawCount,p.length)){const idx=Math.floor(Math.random()*p.length);if(!used.has(idx)){used.add(idx);picks.push(p[idx]);}}
            setDrawnCards(picks);
          } else {
            const p=displayed;if(!p.length)return;setSelectedCard(p[Math.floor(Math.random()*p.length)]);
          }
        }} style={{width:"100%",padding:"13px 18px",marginBottom:"10px",background:`linear-gradient(135deg,${primary},${isDark?T.water:isVivant?T.sage:isTraversees?T.sage:isTerritoires?T.skyLight:T.lichenLight})`,border:"none",borderRadius:"999px",color:"#fff",cursor:"pointer",fontFamily:"'Lora',Georgia,serif",fontSize:"14px",fontStyle:"italic",letterSpacing:"0.03em",boxShadow:`0 4px 18px ${primary}40`,position:"relative",overflow:"hidden"}}>
          <div style={{position:"absolute",right:-8,top:-8,opacity:0.15}}>{isDark?<Spores seed={55} color="#fff" size={72}/>:isVivant?<Leaves seed={55} color="#fff" w={90} h={62}/>:isTraversees?<SapLeaf seed={55} color="#fff" w={90} h={62}/>:<Sprig seed={55} color="#fff" w={105} h={72}/>}</div>
          <span style={{position:"relative"}}>{"✦ "}{isTraversees?(lang==="fr"?`Piocher ${drawCount} ${drawCount===1?"carte":"cartes"}`:`Draw ${drawCount} ${drawCount===1?"card":"cards"}`):L.drawCard}{!isTerritoires&&!isTraversees&&filterType!=="all"?` — ${lang==="fr"?tMetas[filterType]?.fr:tMetas[filterType]?.en}`:""}{isTerritoires?` — ${({ancrer:L.phaseAncrer,traverser:L.phaseTraverser,composer:L.phaseComposer})[phase]}`:""}
          </span>
        </button>

        {!isTerritoires&&Object.keys(tMetas).length>1&&(
          <div style={{display:"flex",gap:"6px",marginBottom:"14px",overflowX:"auto",scrollbarWidth:"none",paddingBottom:"2px"}}>
            <Pill small active={filterType==="all"} color={primary} outline={filterType!=="all"} onClick={()=>setFilterType("all")}>{L.allCards}</Pill>
            {Object.entries(tMetas).map(([k,v])=><Pill key={k} small active={filterType===k} color={v.color} outline={filterType!==k} onClick={()=>setFilterType(k)}>{lang==="fr"?v.fr+"s":v.en+"s"}</Pill>)}
          </div>
        )}
      </div>

      <div style={{maxWidth:"580px",margin:"0 auto",padding:"0 20px 56px",display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px",position:"relative",zIndex:1}}>
        {displayed.map(card=>{
          const tM=getTypeMeta(card);const color=tM[card.type]?.color||T.lichen;const Tex=tM[card.type]?.Tex;const d=card[lang]||card.fr;const seed=seedOf(card.id);
          return(<button key={card.id} onClick={()=>setSelectedCard(card)} style={{background:isDark?"#1a1528":"#fff",border:`1.5px solid ${isDark?"#2e2540":T.paperDark}`,borderRadius:"14px",padding:"14px 13px",textAlign:"left",cursor:"pointer",position:"relative",overflow:"hidden",transition:"all 0.18s"}}>
            <div style={{position:"absolute",bottom:-8,right:-8,opacity:0.12,pointerEvents:"none"}}>{Tex&&<Tex seed={seed} color={color} w={62} h={44} size={52}/>}</div>
            {activeDeck==="mixed"&&<div style={{fontSize:"7px",letterSpacing:"0.2em",color:isDark?T.stone:T.inkFaint,textTransform:"uppercase",marginBottom:"2px"}}>{card.deck}</div>}
            <div style={{fontSize:"8px",letterSpacing:"0.28em",textTransform:"uppercase",color,marginBottom:"5px"}}>{lang==="fr"?tM[card.type]?.fr:tM[card.type]?.en}</div>
            <div style={{fontSize:"17px",fontStyle:"italic",color:isDark?"#e0d8f0":T.ink,lineHeight:1.2,marginBottom:"5px"}}>{d.title||d.verb}</div>
            <div style={{fontSize:"11px",color:isDark?"#6a5a7a":T.inkFaint,lineHeight:1.5,fontStyle:"italic"}}>{d.verb&&!d.title?(d.qualities||[]).join(" · "):(d.entry||(d.body&&d.body[0])||"").slice(0,50)+((d.entry||(d.body&&d.body[0])||"").length>50?"…":"")}</div>
          </button>);
        })}
      </div>
      {showTimer&&<Timer onClose={()=>setShowTimer(false)} lang={lang}/>}
    </div>
  );
}


export default function App(){
  const[activeDeck,setActiveDeck]=useState(null);const[lang,setLang]=useState("fr");
  const savedScroll=useRef(0);
  const handleBack=()=>{const y=savedScroll.current;setActiveDeck(null);requestAnimationFrame(()=>window.scrollTo(0,y));};
  if(!activeDeck)return (<><SpeedInsights /><ChoiceScreen onChoose={(deck)=>{savedScroll.current=window.scrollY;setActiveDeck(deck);}} onMixed={()=>{savedScroll.current=window.scrollY;setActiveDeck("mixed");}} lang={lang} setLang={setLang}/></>);
  return(<><SpeedInsights /><BrowseScreen activeDeck={activeDeck} onBack={handleBack} lang={lang} setLang={setLang}/><style>{`@import url('https://fonts.googleapis.com/css2?family=Lora:ital,wght@0,400;0,500;1,400;1,500&display=swap');*{box-sizing:border-box;}::-webkit-scrollbar{display:none;}button:focus{outline:none;}textarea:focus{outline:none;}`}</style></>);
}
